fn try_build_generated_body_shape_from_reactive_block(
    cx: &mut Context,
    block: &[ReactiveStatement],
) -> Option<GeneratedBodyShape> {
    let trace = std::env::var("DEBUG_DIRECT_BODY_SHAPE_BLOCK_TRACE").is_ok();
    match block {
        [] => Some(GeneratedBodyShape::ExpressionStatements(vec![])),
        [ReactiveStatement::Scope(scope_block), rest @ ..] => {
            if let Some((prefix, consumed_following)) =
                try_build_direct_fused_ternary_source_scope(cx, scope_block, rest)
            {
                let inner = try_build_generated_body_shape_from_reactive_block(
                    cx,
                    &rest[consumed_following..],
                )?;
                if generated_body_shape_is_empty(&inner) {
                    return Some(prefix);
                }
                return Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(prefix),
                    inner: Box::new(inner),
                });
            }
            if let Some((prefix, consumed_following)) =
                try_build_direct_fused_zero_dep_literal_store_prefix(cx, scope_block, rest)
            {
                let inner = try_build_generated_body_shape_from_reactive_block(
                    cx,
                    &rest[consumed_following..],
                )?;
                if generated_body_shape_is_empty(&inner) {
                    return Some(prefix);
                }
                return Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(prefix),
                    inner: Box::new(inner),
                });
            }
            if let Some(shape) =
                try_build_direct_inline_zero_dep_literal_into_following_scope(cx, scope_block, rest)
            {
                return Some(shape);
            }
            if let Some((prefix, consumed_following)) =
                try_build_direct_fused_zero_dep_ternary_default_scope(cx, scope_block, rest)
            {
                let inner = try_build_generated_body_shape_from_reactive_block(
                    cx,
                    &rest[consumed_following..],
                )?;
                if generated_body_shape_is_empty(&inner) {
                    return Some(prefix);
                }
                return Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(prefix),
                    inner: Box::new(inner),
                });
            }
            if let [ReactiveStatement::Terminal(term_stmt)] = rest
                && let Some(shape) = try_build_generated_body_shape_from_reactive_scope_return(
                    cx,
                    scope_block,
                    term_stmt,
                )
            {
                return Some(shape);
            }
            if can_inline_direct_scope_shape(&scope_block.scope) {
                let prefix = try_build_generated_body_shape_from_reactive_block(
                    cx,
                    &scope_block.instructions,
                );
                let Some(prefix) = prefix else {
                    if trace {
                        eprintln!(
                            "[DIRECT_BODY_SHAPE_BLOCK_TRACE] inline scope prefix none scope={}",
                            scope_block.scope.id.0
                        );
                    }
                    return None;
                };
                if rest.is_empty() {
                    return Some(prefix);
                }
                let inner = try_build_generated_body_shape_from_reactive_block(cx, rest);
                let Some(inner) = inner else {
                    if trace {
                        eprintln!(
                            "[DIRECT_BODY_SHAPE_BLOCK_TRACE] inline scope inner none scope={}",
                            scope_block.scope.id.0
                        );
                    }
                    return None;
                };
                if generated_body_shape_is_empty(&prefix) {
                    return Some(inner);
                }
                return Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(prefix),
                    inner: Box::new(inner),
                });
            }
            let prefix =
                try_build_generated_body_shape_from_reactive_scope_statement(cx, scope_block);
            let Some(prefix) = prefix else {
                if trace {
                    eprintln!(
                        "[DIRECT_BODY_SHAPE_BLOCK_TRACE] scope statement none scope={}",
                        scope_block.scope.id.0
                    );
                }
                return None;
            };
            let inner = try_build_generated_body_shape_from_reactive_block(cx, rest);
            let Some(inner) = inner else {
                if trace {
                    eprintln!(
                        "[DIRECT_BODY_SHAPE_BLOCK_TRACE] scope statement inner none scope={}",
                        scope_block.scope.id.0
                    );
                }
                return None;
            };
            Some(GeneratedBodyShape::Sequential {
                prefix: Box::new(prefix),
                inner: Box::new(inner),
            })
        }
        [ReactiveStatement::PrunedScope(scope_block), rest @ ..] => {
            if can_inline_direct_pruned_scope_shape(&scope_block.scope) {
                let prefix = try_build_generated_body_shape_from_reactive_block(
                    cx,
                    &scope_block.instructions,
                );
                let Some(prefix) = prefix else {
                    if trace {
                        eprintln!(
                            "[DIRECT_BODY_SHAPE_BLOCK_TRACE] inline pruned scope prefix none scope={}",
                            scope_block.scope.id.0
                        );
                    }
                    return None;
                };
                if rest.is_empty() {
                    return Some(prefix);
                }
                let inner = try_build_generated_body_shape_from_reactive_block(cx, rest);
                let Some(inner) = inner else {
                    if trace {
                        eprintln!(
                            "[DIRECT_BODY_SHAPE_BLOCK_TRACE] inline pruned scope inner none scope={}",
                            scope_block.scope.id.0
                        );
                    }
                    return None;
                };
                if generated_body_shape_is_empty(&prefix) {
                    return Some(inner);
                }
                return Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(prefix),
                    inner: Box::new(inner),
                });
            }
            let prefix = try_build_generated_body_shape_from_scope_statement_parts(
                cx,
                &scope_block.scope,
                &scope_block.instructions,
            );
            let Some(prefix) = prefix else {
                if trace {
                    eprintln!(
                        "[DIRECT_BODY_SHAPE_BLOCK_TRACE] pruned scope statement none scope={}",
                        scope_block.scope.id.0
                    );
                }
                return None;
            };
            let inner = try_build_generated_body_shape_from_reactive_block(cx, rest);
            let Some(inner) = inner else {
                if trace {
                    eprintln!(
                        "[DIRECT_BODY_SHAPE_BLOCK_TRACE] pruned scope statement inner none scope={}",
                        scope_block.scope.id.0
                    );
                }
                return None;
            };
            Some(GeneratedBodyShape::Sequential {
                prefix: Box::new(prefix),
                inner: Box::new(inner),
            })
        }
        [ReactiveStatement::Instruction(instr), rest @ ..] => {
            if rest.len() == 1
                && matches!(
                    &rest[0],
                    ReactiveStatement::Terminal(term_stmt)
                        if matches!(
                            &term_stmt.terminal,
                            ReactiveTerminal::Return { value, .. }
                                if matches!(value.identifier.type_, Type::Primitive)
                        )
                )
                && matches!(
                    &instr.value,
                    InstructionValue::LoadLocal { place, .. }
                        | InstructionValue::LoadContext { place, .. }
                            if instr.lvalue.is_none() && place.identifier.name.is_some()
                )
            {
                let inner = try_build_generated_body_shape_from_reactive_block(cx, rest)?;
                let (InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. }) = &instr.value
                else {
                    unreachable!();
                };
                return Some(GeneratedBodyShape::PrefixedExpressionStatements {
                    expressions: vec![codegen_place_to_expression(cx, place)],
                    inner: Box::new(inner),
                });
            }
            let should_wrap = apply_direct_prefix_codegen_state(cx, instr);
            let inner = try_build_generated_body_shape_from_reactive_block(cx, rest)?;
            if let Some(expression) = unused_temp_named_load_expression(cx, rest, instr) {
                return Some(GeneratedBodyShape::PrefixedExpressionStatements {
                    expressions: vec![expression],
                    inner: Box::new(inner),
                });
            }
            if !should_wrap
                && (matches!(inner, GeneratedBodyShape::ReturnVoid)
                    || generated_body_shape_is_empty(&inner))
                && matches!(
                    &instr.value,
                    InstructionValue::LoadLocal { place, .. }
                        | InstructionValue::LoadContext { place, .. }
                            if instr.lvalue.is_none() && place.identifier.name.is_some()
                )
            {
                let (InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. }) = &instr.value
                else {
                    unreachable!();
                };
                return Some(GeneratedBodyShape::PrefixedExpressionStatements {
                    expressions: vec![codegen_place_to_expression(cx, place)],
                    inner: Box::new(inner),
                });
            }
            if should_wrap {
                let shape = try_wrap_generated_body_shape_with_instruction_prefix(cx, instr, inner);
                if shape.is_none() && trace {
                    eprintln!(
                        "[DIRECT_BODY_SHAPE_BLOCK_TRACE] instruction prefix none tag={} lvalue={:?}",
                        instruction_value_tag(&instr.value),
                        instr.lvalue.as_ref().and_then(|place| place
                            .identifier
                            .name
                            .as_ref()
                            .map(|name| name.value()))
                    );
                }
                shape
            } else {
                Some(inner)
            }
        }
        [ReactiveStatement::Terminal(term_stmt)] => {
            try_build_generated_body_shape_from_terminal_statement(cx, term_stmt)
        }
        [ReactiveStatement::Terminal(term_stmt), rest @ ..] => {
            let prefix = try_build_generated_body_shape_from_terminal_statement(cx, term_stmt)?;
            if matches!(
                prefix,
                GeneratedBodyShape::ReturnVoid
                    | GeneratedBodyShape::ReturnIdentifier(_)
                    | GeneratedBodyShape::ReturnExpression(_)
                    | GeneratedBodyShape::ThrowExpression(_)
                    | GeneratedBodyShape::Break(_)
                    | GeneratedBodyShape::Continue(_)
            ) {
                return None;
            }
            let inner = try_build_generated_body_shape_from_reactive_block(cx, rest)?;
            Some(GeneratedBodyShape::Sequential {
                prefix: Box::new(prefix),
                inner: Box::new(inner),
            })
        }
    }
}

fn try_render_statement_sources_from_generated_body_shape_with_cache_binding(
    shape: &GeneratedBodyShape,
    cache_binding_name: &str,
) -> Option<Vec<String>> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let cache_prologue = CachePrologue {
        binding_name: cache_binding_name.to_string(),
        size: 64,
        fast_refresh: None,
    };
    let body = build_function_body_from_generated_shape_for_ast_codegen(
        builder,
        &allocator,
        &FunctionBodyRenderSpec {
            params: &[],
            param_names: &[],
            body_shape: shape,
            directives: &[],
            cache_prologue: Some(&cache_prologue),
            needs_function_hook_guard_wrapper: false,
            is_async: false,
            is_generator: false,
        },
    )?;
    let mut statements = Vec::new();
    let mut blank_line_before_next = false;
    for statement in body.statements.iter() {
        if is_internal_blank_line_marker_statement_ast(statement) {
            blank_line_before_next = true;
            continue;
        }
        let mut rendered = codegen_statement_with_flow_cast_restore(statement);
        if blank_line_before_next {
            rendered = add_statement_blank_line_marker(rendered);
            blank_line_before_next = false;
        }
        statements.push(rendered);
    }
    Some(statements)
}

fn try_render_statement_sources_from_generated_body_shape(
    shape: &GeneratedBodyShape,
) -> Option<Vec<String>> {
    try_render_statement_sources_from_generated_body_shape_with_cache_binding(shape, "$")
}

fn normalize_rendered_generated_body_source(source: &str) -> String {
    source
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>()
        .join("\n")
}

fn canonicalize_rendered_generated_body_source(source: &str) -> String {
    let allocator = Allocator::default();
    if let Ok(statements) =
        parse_statement_list_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), source)
    {
        codegen_statements_with_oxc(statements.as_slice())
            .trim()
            .to_string()
    } else {
        normalize_rendered_generated_body_source(source)
    }
}

fn generated_body_shapes_render_equivalent(
    direct: &GeneratedBodyShape,
    analyzed: &GeneratedBodyShape,
) -> bool {
    let Some(direct_source) = try_render_statement_sources_from_generated_body_shape(direct) else {
        return false;
    };
    let Some(analyzed_source) = try_render_statement_sources_from_generated_body_shape(analyzed)
    else {
        return false;
    };
    canonicalize_rendered_generated_body_source(&direct_source.join("\n"))
        == canonicalize_rendered_generated_body_source(&analyzed_source.join("\n"))
}

/// Normalize rendered output for lenient comparison.
fn normalize_for_lenient_compare(source: &str) -> String {
    // Step 1: Strip blank line markers and empty lines
    let lines: Vec<&str> = source
        .lines()
        .filter(|line| {
            let trimmed = line.trim();
            !trimmed.is_empty()
                && trimmed != "\"__REACT_COMPILER_INTERNAL_BLANK_LINE_MARKER__\";"
                && trimmed != "__REACT_COMPILER_INTERNAL_BLANK_LINE_MARKER__"
        })
        .collect();

    // Step 2: Inline const/let alias bindings (e.g., `const x = t0;` → replace t0 with x everywhere)
    // This handles the AliasedReturn pattern difference.
    let mut result_lines: Vec<String> = lines.iter().map(|l| l.to_string()).collect();
    loop {
        let mut inlined = false;
        for i in 0..result_lines.len() {
            let trimmed = result_lines[i].trim();
            // Match patterns: `const NAME = tN;` or `let NAME = tN;`
            let binding = trimmed
                .strip_prefix("const ")
                .or_else(|| trimmed.strip_prefix("let "));
            if let Some(rest) = binding {
                // Check for `NAME = tN;` where tN is a temp variable
                if let Some(eq_pos) = rest.find(" = ") {
                    let name = &rest[..eq_pos];
                    let value = rest[eq_pos + 3..].trim_end_matches(';').trim();
                    // Only inline if value is a simple temp var (t followed by digits)
                    if value.starts_with('t')
                        && value.len() > 1
                        && value[1..].chars().all(|c| c.is_ascii_digit())
                        && name
                            .chars()
                            .all(|c| c.is_alphanumeric() || c == '_' || c == '$')
                    {
                        // Replace all occurrences of `value` with `name` (word boundary)
                        let mut new_lines: Vec<String> = Vec::with_capacity(result_lines.len());
                        for (j, line) in result_lines.iter().enumerate() {
                            if j == i {
                                // Remove this binding line
                                continue;
                            }
                            new_lines.push(replace_word(line, value, name));
                        }
                        result_lines = new_lines;
                        inlined = true;
                        break;
                    }
                }
            }
        }
        if !inlined {
            break;
        }
    }

    // Step 3: Also remove `let tN;` declarations for inlined temps that no longer appear
    let snapshot = result_lines.clone();
    result_lines.retain(|line| {
        let trimmed = line.trim();
        if let Some(rest) = trimmed.strip_prefix("let ") {
            let rest = rest.trim_end_matches(';').trim();
            if rest.starts_with('t')
                && rest.len() > 1
                && rest[1..].chars().all(|c| c.is_ascii_digit())
            {
                let temp_name = rest;
                let appears_elsewhere = snapshot
                    .iter()
                    .any(|l| l.trim() != trimmed && contains_word(l, temp_name));
                return appears_elsewhere;
            }
        }
        true
    });

    // Step 4: Normalize labeled blocks: `label: { body }` → `label: body`
    // Remove redundant block wrappers around labeled statements.
    let joined = result_lines.join("\n");
    let result = normalize_labeled_blocks(&joined);

    // Step 5: De-shadow temp declarations. If `let tN;` appears more than once,
    // rename later declarations to unique names.
    let result = de_shadow_temp_decls(&result);

    // Step 6: Normalize temp variable numbering
    let mut temp_map: HashMap<String, String> = HashMap::new();
    let mut next_temp = 0u32;
    let mut normalized = String::with_capacity(result.len());
    let chars: Vec<char> = result.chars().collect();
    let mut i = 0;
    while i < chars.len() {
        if chars[i] == 't' && (i == 0 || !chars[i - 1].is_alphanumeric() && chars[i - 1] != '_') {
            let start = i;
            i += 1;
            if i < chars.len() && chars[i].is_ascii_digit() {
                while i < chars.len() && chars[i].is_ascii_digit() {
                    i += 1;
                }
                if i >= chars.len() || (!chars[i].is_alphanumeric() && chars[i] != '_') {
                    let original: String = chars[start..i].iter().collect();
                    let mapped = temp_map
                        .entry(original)
                        .or_insert_with(|| {
                            let name = format!("t{next_temp}");
                            next_temp += 1;
                            name
                        })
                        .clone();
                    normalized.push_str(&mapped);
                    continue;
                }
            }
            for c in &chars[start..i] {
                normalized.push(*c);
            }
        } else {
            normalized.push(chars[i]);
            i += 1;
        }
    }

    // Step 7: Final whitespace normalization
    normalized
        .lines()
        .map(str::trim)
        .collect::<Vec<_>>()
        .join("\n")
}

/// De-shadow temp variable declarations: if `let tN;` appears more than once,
/// rename subsequent declarations (and their uses until the next redeclaration)
/// to unique temp names.
fn de_shadow_temp_decls(source: &str) -> String {
    let lines: Vec<&str> = source.lines().collect();
    let mut result_lines: Vec<String> = lines.iter().map(|l| l.to_string()).collect();
    let mut seen_temps: HashMap<String, u32> = HashMap::new();
    let mut next_shadow = 900_000u32;

    for i in 0..result_lines.len() {
        let trimmed = result_lines[i].trim();
        let Some(rest) = trimmed.strip_prefix("let ") else {
            continue;
        };
        let temp_end = rest
            .find(|c: char| !c.is_alphanumeric() && c != '_')
            .unwrap_or(rest.len());
        let temp_name = &rest[..temp_end];
        if temp_name.starts_with('t')
            && temp_name.len() > 1
            && temp_name[1..].chars().all(|c| c.is_ascii_digit())
        {
            let entry = seen_temps.entry(temp_name.to_string()).or_insert(0);
            if *entry > 0 {
                let shadow_name = format!("t{next_shadow}");
                next_shadow += 1;
                let temp_owned = temp_name.to_string();
                result_lines[i] = replace_word(&result_lines[i], &temp_owned, &shadow_name);
                for line in result_lines.iter_mut().skip(i + 1) {
                    let t = line.trim();
                    if let Some(r) = t.strip_prefix("let ") {
                        let e = r
                            .find(|c: char| !c.is_alphanumeric() && c != '_')
                            .unwrap_or(r.len());
                        if r[..e] == *temp_owned {
                            break;
                        }
                    }
                    *line = replace_word(line, &temp_owned, &shadow_name);
                }
            }
            *entry += 1;
        }
    }

    result_lines.join("\n")
}

/// Replace word-bounded occurrences of `from` with `to` in `source`.
fn replace_word(source: &str, from: &str, to: &str) -> String {
    let mut result = String::with_capacity(source.len());
    let chars: Vec<char> = source.chars().collect();
    let from_chars: Vec<char> = from.chars().collect();
    let mut i = 0;
    while i < chars.len() {
        if i + from_chars.len() <= chars.len() && chars[i..i + from_chars.len()] == from_chars[..] {
            let before_ok = i == 0 || !chars[i - 1].is_alphanumeric() && chars[i - 1] != '_';
            let after_ok = i + from_chars.len() >= chars.len()
                || !chars[i + from_chars.len()].is_alphanumeric()
                    && chars[i + from_chars.len()] != '_';
            if before_ok && after_ok {
                result.push_str(to);
                i += from_chars.len();
                continue;
            }
        }
        result.push(chars[i]);
        i += 1;
    }
    result
}

/// Check if `source` contains `word` as a word-bounded occurrence.
fn contains_word(source: &str, word: &str) -> bool {
    let chars: Vec<char> = source.chars().collect();
    let word_chars: Vec<char> = word.chars().collect();
    for i in 0..chars.len() {
        if i + word_chars.len() <= chars.len() && chars[i..i + word_chars.len()] == word_chars[..] {
            let before_ok = i == 0 || !chars[i - 1].is_alphanumeric() && chars[i - 1] != '_';
            let after_ok = i + word_chars.len() >= chars.len()
                || !chars[i + word_chars.len()].is_alphanumeric()
                    && chars[i + word_chars.len()] != '_';
            if before_ok && after_ok {
                return true;
            }
        }
    }
    false
}

/// Remove redundant `{ }` wrappers around labeled statement bodies.
/// Transforms `label: { body }` to `label: body` when the block contains
/// a single compound statement (if/while/for/switch).
fn normalize_labeled_blocks(source: &str) -> String {
    let lines: Vec<&str> = source.lines().collect();
    let mut result_lines: Vec<String> = Vec::with_capacity(lines.len());
    let mut i = 0;
    while i < lines.len() {
        let trimmed = lines[i].trim();
        // Look for `label: {` pattern
        if let Some(colon_pos) = trimmed.find(": {") {
            let label_part = &trimmed[..colon_pos];
            let after_colon = trimmed[colon_pos + 2..].trim();
            if after_colon == "{"
                && !label_part.is_empty()
                && label_part.chars().all(|c| c.is_alphanumeric() || c == '_')
            {
                // Find the matching closing `}` by counting braces
                let indent = lines[i].len() - lines[i].trim_start().len();
                let indent_str = &lines[i][..indent];
                let mut brace_depth = 1;
                let mut close_line = None;
                for (j, line) in lines.iter().enumerate().skip(i + 1) {
                    for ch in line.chars() {
                        match ch {
                            '{' => brace_depth += 1,
                            '}' => {
                                brace_depth -= 1;
                                if brace_depth == 0 {
                                    close_line = Some(j);
                                    break;
                                }
                            }
                            _ => {}
                        }
                    }
                    if close_line.is_some() {
                        break;
                    }
                }
                if let Some(close_j) = close_line {
                    // Check that the closing line is just `}` (possibly with indent)
                    if lines[close_j].trim() == "}" {
                        // Emit `label:` without `{`, skip the closing `}`
                        // Check if the next line after `label: {` starts with a control keyword
                        if i + 1 < close_j {
                            let next_trimmed = lines[i + 1].trim();
                            let is_control = next_trimmed.starts_with("if ")
                                || next_trimmed.starts_with("if(")
                                || next_trimmed.starts_with("while ")
                                || next_trimmed.starts_with("while(")
                                || next_trimmed.starts_with("for ")
                                || next_trimmed.starts_with("for(")
                                || next_trimmed.starts_with("switch ");
                            if is_control {
                                // Emit `label: <body>` merging with next line
                                let body_indent =
                                    lines[i + 1].len() - lines[i + 1].trim_start().len();
                                // Dedent body lines by the difference
                                let dedent = body_indent.saturating_sub(indent + 2);
                                result_lines.push(format!(
                                    "{}{}: {}",
                                    indent_str,
                                    label_part,
                                    lines[i + 1].trim()
                                ));
                                for line in lines.iter().take(close_j).skip(i + 2) {
                                    let line_indent = line.len() - line.trim_start().len();
                                    let new_indent = line_indent.saturating_sub(dedent);
                                    result_lines.push(format!(
                                        "{}{}",
                                        " ".repeat(new_indent),
                                        line.trim()
                                    ));
                                }
                                i = close_j + 1;
                                continue;
                            }
                        }
                    }
                }
            }
        }
        result_lines.push(lines[i].to_string());
        i += 1;
    }
    result_lines.join("\n")
}

fn generated_body_shape_renders_equivalent_to_string_body(
    shape: &GeneratedBodyShape,
    string_body: &str,
) -> bool {
    let Some(rendered_shape_source) = try_render_statement_sources_from_generated_body_shape(shape)
    else {
        return false;
    };
    let rendered = rendered_shape_source.join("\n");
    let rendered_norm = normalize_for_lenient_compare(&rendered);
    let body_norm = normalize_for_lenient_compare(string_body);
    rendered_norm == body_norm
}

#[cfg(test)]
#[allow(dead_code)]
fn generated_body_shape_matches_rendered_body(
    shape: &GeneratedBodyShape,
    rendered_body: &str,
) -> bool {
    let Some(rendered_shape_source) = try_render_statement_sources_from_generated_body_shape(shape)
    else {
        return false;
    };
    canonicalize_rendered_generated_body_source(&rendered_shape_source.join("\n"))
        == canonicalize_rendered_generated_body_source(rendered_body)
}

fn generated_body_shape_reanalyzes_equivalent(
    shape: &GeneratedBodyShape,
    analyzed: &GeneratedBodyShape,
    is_async: bool,
    is_generator: bool,
) -> bool {
    let Some(rendered_shape_source) = try_render_statement_sources_from_generated_body_shape(shape)
    else {
        return false;
    };
    let rendered_shape_source = rendered_shape_source.join("\n");
    let rendered_shape_source =
        strip_trailing_bare_return(&rendered_shape_source, is_async, is_generator);
    let rendered_shape_source =
        prune_unused_const_literal_decls(&rendered_shape_source, is_async, is_generator);
    let reparsed = fully_canonicalize_generated_body_shape(analyze_generated_body_shape(
        &rendered_shape_source,
    ));
    &reparsed == analyzed
}

fn maybe_mark_direct_zero_dep_scope_outputs_stable(
    cx: &mut Context,
    scope: &ReactiveScope,
    instructions: &ReactiveBlock,
) {
    if !scope.dependencies.is_empty() || !scope.reassignments.is_empty() || instructions.len() != 1
    {
        return;
    }
    let ReactiveStatement::Instruction(instr) = &instructions[0] else {
        return;
    };
    if !matches!(
        instr.value,
        InstructionValue::FunctionExpression { .. }
            | InstructionValue::ObjectMethod { .. }
            | InstructionValue::Primitive { .. }
            | InstructionValue::ArrayExpression { .. }
            | InstructionValue::ObjectExpression { .. }
    ) {
        return;
    }
    for decl in scope.declarations.values() {
        cx.stable_zero_dep_decls
            .insert(decl.identifier.declaration_id);
    }
}

fn try_build_generated_body_shape_from_scope_statement_parts(
    cx: &mut Context,
    scope: &ReactiveScope,
    instructions: &ReactiveBlock,
) -> Option<GeneratedBodyShape> {
    let trace = std::env::var("DEBUG_DIRECT_SCOPE_STATEMENT_TRACE").is_ok();
    if scope.merged_id.is_some() {
        return None;
    }
    let dep_exprs = collect_direct_scope_dependency_exprs(cx, scope, instructions)?;
    let mut computation_cx = cx.clone();
    computation_cx.inline_temp_zero_dep_scope_shapes = true;
    let computation_shape = canonicalize_generated_body_shape(
        try_build_generated_body_shape_from_reactive_block(&mut computation_cx, instructions)?,
    );
    cx.next_cache_index = computation_cx.next_cache_index;
    let mut declarations = Vec::new();
    let mut output_names = Vec::new();
    let mut output_decl_ids = Vec::new();
    let mut seen_output_decls = HashSet::new();
    if !scope.declarations.is_empty() {
        let mut sorted_decls: Vec<_> = scope.declarations.values().collect();
        sorted_decls.sort_by(|a, b| {
            identifier_name_static(&a.identifier)
                .cmp(&identifier_name_static(&b.identifier))
                .then_with(|| {
                    a.identifier
                        .declaration_id
                        .0
                        .cmp(&b.identifier.declaration_id.0)
                })
        });
        for output_decl in sorted_decls {
            if !seen_output_decls.insert(output_decl.identifier.declaration_id) {
                continue;
            }
            let value_name = identifier_name_with_cx(cx, &output_decl.identifier);
            cx.declare(&output_decl.identifier);
            cx.declared_names.insert(value_name.clone());
            cx.mark_decl_runtime_emitted(output_decl.identifier.declaration_id);
            declarations.push(GeneratedDeclaration {
                kind: ast::VariableDeclarationKind::Let,
                pattern: value_name.clone(),
            });
            output_names.push(value_name);
            output_decl_ids.push(output_decl.identifier.declaration_id);
        }
    }
    if !scope.reassignments.is_empty() {
        // Preserve reassignments in scope traversal order so the direct-body
        // fast path matches the generic cache-slot assignment path.
        for reassignment in &scope.reassignments {
            if !seen_output_decls.insert(reassignment.declaration_id) {
                continue;
            }
            cx.declare(reassignment);
            cx.mark_decl_runtime_emitted(reassignment.declaration_id);
            let value_name = identifier_name_with_cx(cx, reassignment);
            cx.declared_names.insert(value_name.clone());
            output_names.push(value_name);
            output_decl_ids.push(reassignment.declaration_id);
        }
    }
    if output_names.is_empty() {
        if trace {
            eprintln!(
                "[DIRECT_SCOPE_STATEMENT_TRACE] unsupported outputs scope={} decls={} reassignments={}",
                scope.id.0,
                scope.declarations.len(),
                scope.reassignments.len()
            );
        }
        return None;
    }
    let primary_output_name = output_names.first()?.clone();
    let primary_output_decl_id = *output_decl_ids.first()?;
    let output_name_set: HashSet<String> = output_names.iter().cloned().collect();
    let block_is_flat_instructions = instructions
        .iter()
        .all(|stmt| matches!(stmt, ReactiveStatement::Instruction(_)));
    if let Some(early_return) = scope.early_return_value.as_ref() {
        let mut setup_statements =
            try_render_statement_sources_from_generated_body_shape(&computation_shape)?;
        setup_statements = rewrite_generated_setup_statements(setup_statements);
        if !declarations.is_empty() {
            setup_statements = rewrite_cached_setup_statements_for_outer_declarations(
                setup_statements,
                &declarations,
            );
        }
        if setup_statements.is_empty() {
            return None;
        }
        let (setup_statements, deferred_post_scope_expressions) = if block_is_flat_instructions {
            split_deferred_readonly_output_calls_from_setup_statements(
                setup_statements,
                &output_name_set,
            )?
        } else {
            (setup_statements, Vec::new())
        };
        if setup_statements.is_empty() {
            return None;
        }
        let mut deps = Vec::with_capacity(dep_exprs.len());
        let mut outer_slots = Vec::with_capacity(dep_exprs.len() + output_names.len());
        for dep_expr in dep_exprs {
            deps.push((cx.alloc_cache_slot(), dep_expr));
            outer_slots.push(deps.last().expect("dep inserted").0);
        }
        let mut cached_values = output_names
            .iter()
            .cloned()
            .map(|name| GeneratedCachedValue { name, slot: 0 })
            .collect::<Vec<_>>();
        if cached_values.is_empty() {
            return None;
        }
        for cached_value in &mut cached_values {
            cached_value.slot = cx.alloc_cache_slot();
            outer_slots.push(cached_value.slot);
        }
        let setup_statements =
            rebase_nested_cache_slots_for_outer_wrapper(setup_statements, &mut outer_slots);
        let dep_count = deps.len();
        for ((dep_slot, _), slot) in deps.iter_mut().zip(outer_slots.iter().copied()) {
            *dep_slot = slot;
        }
        for (cached_value, slot) in cached_values
            .iter_mut()
            .zip(outer_slots.into_iter().skip(dep_count))
        {
            cached_value.slot = slot;
        }
        let restored_values = cached_values.clone();
        let sentinel_name = identifier_name_with_cx(cx, &early_return.value);
        if !cached_values
            .iter()
            .any(|value| value.name == sentinel_name)
        {
            return None;
        }
        let inner = GeneratedBodyShape::MemoizedEarlyReturnSentinel {
            deps,
            setup_statements,
            cached_values,
            restored_values,
            sentinel_name,
            final_return: None,
            fallback_body: None,
        };
        let inner = if deferred_post_scope_expressions.is_empty() {
            inner
        } else {
            GeneratedBodyShape::Sequential {
                prefix: Box::new(inner),
                inner: Box::new(GeneratedBodyShape::ExpressionStatements(
                    deferred_post_scope_expressions,
                )),
            }
        };
        return if declarations.is_empty() {
            Some(inner)
        } else {
            Some(GeneratedBodyShape::PrefixedDeclarations {
                declarations,
                inner: Box::new(inner),
            })
        };
    }
    let cache_binding_name = cx.synthesize_name("$");
    let mut setup_statements = try_build_simple_scope_setup_statements(
        &primary_output_name,
        &computation_shape,
        &cache_binding_name,
    )
    .or_else(|| {
        if std::env::var("DEBUG_SCOPE_STATEMENT_FALLBACK").is_ok() {
            eprintln!(
                "[SCOPE_STATEMENT_FALLBACK] outputs={:?} deps={:?} shape={:#?}",
                output_names, dep_exprs, computation_shape
            );
        }
        try_render_statement_sources_from_generated_body_shape(&computation_shape)
    })?;
    if trace {
        eprintln!(
            "[DIRECT_SCOPE_STATEMENT_TRACE] scope={} output={} deps={:?} shape={:#?} setup={:#?}",
            scope.id.0, primary_output_name, dep_exprs, computation_shape, setup_statements
        );
    }
    setup_statements = rewrite_generated_setup_statements(setup_statements);
    if !declarations.is_empty() {
        setup_statements =
            rewrite_cached_setup_statements_for_outer_declarations(setup_statements, &declarations);
    }
    setup_statements = preserve_scope_setup_statement_blank_lines(
        cx,
        scope,
        instructions,
        &declarations,
        setup_statements,
    );
    if setup_statements.is_empty() {
        if let Some(Some(expr_value)) = computation_cx.temp.get(&primary_output_decl_id).cloned() {
            if is_codegen_temp_name(&primary_output_name) {
                let inner = if declarations.is_empty() {
                    GeneratedBodyShape::PrefixedAssignments {
                        assignments: vec![GeneratedAssignment {
                            target: primary_output_name.clone(),
                            value: expr_value.expr,
                        }],
                        inner: Box::new(GeneratedBodyShape::ExpressionStatements(vec![])),
                    }
                } else {
                    GeneratedBodyShape::PrefixedDeclarations {
                        declarations,
                        inner: Box::new(GeneratedBodyShape::PrefixedAssignments {
                            assignments: vec![GeneratedAssignment {
                                target: primary_output_name.clone(),
                                value: expr_value.expr,
                            }],
                            inner: Box::new(GeneratedBodyShape::ExpressionStatements(vec![])),
                        }),
                    }
                };
                if trace {
                    eprintln!(
                        "[DIRECT_SCOPE_STATEMENT_TRACE] temp-only direct scope={} output={} inline",
                        scope.id.0, primary_output_name
                    );
                }
                maybe_mark_direct_zero_dep_scope_outputs_stable(cx, scope, instructions);
                return Some(inner);
            }
            setup_statements.push(
                render_reactive_assignment_statement_ast(&primary_output_name, &expr_value.expr)?
                    .trim_end()
                    .to_string(),
            );
            if trace {
                eprintln!(
                    "[DIRECT_SCOPE_STATEMENT_TRACE] materialized temp scope={} output={} expr={}",
                    scope.id.0, primary_output_name, expr_value.expr
                );
            }
        } else {
            return None;
        }
    }
    let (setup_statements, deferred_post_scope_expressions) = if block_is_flat_instructions {
        split_deferred_readonly_output_calls_from_setup_statements(
            setup_statements,
            &output_name_set,
        )?
    } else {
        (setup_statements, Vec::new())
    };
    if setup_statements.is_empty() {
        return None;
    }
    let inner = if dep_exprs.is_empty() {
        let mut cached_values = Vec::with_capacity(output_names.len());
        let mut outer_slots = Vec::with_capacity(output_names.len());
        for output_name in &output_names {
            let slot = cx.alloc_cache_slot();
            outer_slots.push(slot);
            cached_values.push(GeneratedCachedValue {
                name: output_name.clone(),
                slot,
            });
        }
        let setup_statements =
            rebase_nested_cache_slots_for_outer_wrapper(setup_statements, &mut outer_slots);
        for (cached_value, slot) in cached_values.iter_mut().zip(outer_slots.iter().copied()) {
            cached_value.slot = slot;
        }
        let sentinel_slot = cached_values.first()?.slot;
        let restored_values = cached_values.clone();
        if let Some(shape) = build_option_sensitive_cached_values_shape(
            cx,
            OptionSensitiveCachedValuesShapeSpec {
                scope,
                instructions,
                deps: &[],
                zero_dep_sentinel_slot: Some(sentinel_slot),
                setup_statements: &setup_statements,
                cached_values: &cached_values,
                restored_values: &restored_values,
            },
        ) {
            shape
        } else {
            GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
                sentinel_slot,
                setup_statements,
                cached_values,
                restored_values,
            }
        }
    } else {
        let mut deps = Vec::with_capacity(dep_exprs.len());
        let mut outer_slots = Vec::with_capacity(dep_exprs.len() + output_names.len());
        for dep_expr in dep_exprs {
            let slot = cx.alloc_cache_slot();
            outer_slots.push(slot);
            deps.push((slot, dep_expr));
        }
        let mut cached_values = Vec::with_capacity(output_names.len());
        for output_name in &output_names {
            let slot = cx.alloc_cache_slot();
            outer_slots.push(slot);
            cached_values.push(GeneratedCachedValue {
                name: output_name.clone(),
                slot,
            });
        }
        let setup_statements =
            rebase_nested_cache_slots_for_outer_wrapper(setup_statements, &mut outer_slots);
        for ((dep_slot, _), slot) in deps.iter_mut().zip(outer_slots.iter().copied()) {
            *dep_slot = slot;
        }
        let dep_count = deps.len();
        for (cached_value, slot) in cached_values
            .iter_mut()
            .zip(outer_slots.into_iter().skip(dep_count))
        {
            cached_value.slot = slot;
        }
        let restored_values = cached_values.clone();
        if let Some(shape) = build_option_sensitive_cached_values_shape(
            cx,
            OptionSensitiveCachedValuesShapeSpec {
                scope,
                instructions,
                deps: &deps,
                zero_dep_sentinel_slot: None,
                setup_statements: &setup_statements,
                cached_values: &cached_values,
                restored_values: &restored_values,
            },
        ) {
            shape
        } else {
            GeneratedBodyShape::MemoizedCachedValues {
                deps,
                setup_statements,
                cached_values,
                restored_values,
            }
        }
    };
    let inner = if deferred_post_scope_expressions.is_empty() {
        inner
    } else {
        GeneratedBodyShape::Sequential {
            prefix: Box::new(inner),
            inner: Box::new(GeneratedBodyShape::ExpressionStatements(
                deferred_post_scope_expressions,
            )),
        }
    };
    let shape = if declarations.is_empty() {
        inner
    } else {
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner: Box::new(inner),
        }
    };
    maybe_mark_direct_zero_dep_scope_outputs_stable(cx, scope, instructions);
    Some(shape)
}

fn generated_shape_is_empty_expression_body(shape: &GeneratedBodyShape) -> bool {
    matches!(shape, GeneratedBodyShape::ExpressionStatements(expressions) if expressions.is_empty())
}

fn statement_has_blank_line_marker(statement: &str) -> bool {
    statement.starts_with('\n')
}

fn strip_statement_blank_line_marker(statement: &str) -> &str {
    statement.trim_start_matches('\n')
}

fn add_statement_blank_line_marker(mut statement: String) -> String {
    if !statement_has_blank_line_marker(&statement) {
        statement.insert(0, '\n');
    }
    statement
}

fn strip_statement_blank_line_markers(statements: &[String]) -> Vec<String> {
    statements
        .iter()
        .map(|statement| strip_statement_blank_line_marker(statement).to_string())
        .collect()
}

fn split_statement_sources_preserving_blank_lines(body_source: &str) -> Option<Vec<String>> {
    if body_source.trim().is_empty() {
        return Some(Vec::new());
    }

    let allocator = Allocator::default();
    let (offset, body) = parse_function_body_for_ast_codegen_with_offset(
        &allocator,
        SourceType::mjs().with_jsx(true),
        false,
        false,
        body_source,
    )
    .ok()?;

    let mut statements = Vec::with_capacity(body.statements.len());
    let mut previous_end = 0usize;
    for (index, statement) in body.statements.iter().enumerate() {
        let start = statement.span().start as usize;
        let end = statement.span().end as usize;
        let start = start.checked_sub(offset)?;
        let end = end.checked_sub(offset)?;
        if end > body_source.len() || start > end {
            return None;
        }

        let mut statement_source = body_source[start..end].trim().to_string();
        if statement_source.is_empty() {
            return None;
        }
        if index > 0 {
            let between = &body_source[previous_end..start];
            let newline_count = between.chars().filter(|&ch| ch == '\n').count();
            if newline_count >= 2 {
                statement_source = add_statement_blank_line_marker(statement_source);
            }
        }
        statements.push(statement_source);
        previous_end = end;
    }

    Some(statements)
}

fn preserve_scope_setup_statement_blank_lines(
    cx: &Context,
    scope: &ReactiveScope,
    instructions: &ReactiveBlock,
    declarations: &[GeneratedDeclaration],
    setup_statements: Vec<String>,
) -> Vec<String> {
    let debug = std::env::var("DEBUG_BLANK_LINE_PRESERVE").is_ok();
    if setup_statements.len() < 2 {
        if debug {
            eprintln!(
                "[BLANK_LINE_PRESERVE] scope={} skip: <2 setup_statements (len={})",
                scope.id.0,
                setup_statements.len()
            );
        }
        return setup_statements;
    }

    let mut render_cx = cx.clone();
    render_cx.inline_temp_zero_dep_scope_shapes = false;
    let rendered = codegen_scope_computation_no_reset(&mut render_cx, scope, instructions);
    if debug {
        eprintln!(
            "[BLANK_LINE_PRESERVE] scope={} rendered:\n{}",
            scope.id.0, rendered
        );
    }
    let Some(mut rendered_statements) = split_statement_sources_preserving_blank_lines(&rendered)
    else {
        if debug {
            eprintln!(
                "[BLANK_LINE_PRESERVE] scope={} skip: split failed",
                scope.id.0
            );
        }
        return setup_statements;
    };
    rendered_statements = rewrite_generated_setup_statements(rendered_statements);
    if !declarations.is_empty() {
        rendered_statements = rewrite_cached_setup_statements_for_outer_declarations(
            rendered_statements,
            declarations,
        );
    }

    let stripped_rendered = strip_statement_blank_line_markers(&rendered_statements);
    let stripped_setup = strip_statement_blank_line_markers(&setup_statements);
    let should_prefer_rendered = stripped_rendered == stripped_setup
        || statement_sources_are_sequence_recomposition_candidate(
            &stripped_rendered,
            &stripped_setup,
        );
    if should_prefer_rendered {
        if debug {
            let has_markers = rendered_statements.iter().any(|s| s.starts_with('\n'));
            eprintln!(
                "[BLANK_LINE_PRESERVE] scope={} {} has_markers={}",
                scope.id.0,
                if stripped_rendered == stripped_setup {
                    "MATCH"
                } else {
                    "SEQUENCE_MATCH"
                },
                has_markers
            );
            if has_markers {
                for (i, s) in rendered_statements.iter().enumerate() {
                    eprintln!("[BLANK_LINE_PRESERVE]   [{}] {:?}", i, s);
                }
            }
        }
        rendered_statements
    } else {
        if debug {
            eprintln!("[BLANK_LINE_PRESERVE] scope={} MISMATCH", scope.id.0);
            eprintln!("[BLANK_LINE_PRESERVE]   rendered: {:?}", stripped_rendered);
            eprintln!("[BLANK_LINE_PRESERVE]   setup:    {:?}", stripped_setup);
        }
        setup_statements
    }
}

fn statement_sources_are_sequence_recomposition_candidate(
    rendered_statements: &[String],
    setup_statements: &[String],
) -> bool {
    if rendered_statements.len() >= setup_statements.len() {
        return false;
    }
    statement_sources_contain_sequence_expression(rendered_statements)
        && !statement_sources_contain_sequence_expression(setup_statements)
        && statement_sources_are_sequence_recomposition_friendly(setup_statements)
}

fn statement_sources_contain_sequence_expression(statement_sources: &[String]) -> bool {
    struct SequenceDetector {
        found: bool,
    }

    impl<'a> Visit<'a> for SequenceDetector {
        fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
            if matches!(
                expression.without_parentheses(),
                ast::Expression::SequenceExpression(_)
            ) {
                self.found = true;
                return;
            }
            walk::walk_expression(self, expression);
        }
    }

    let allocator = Allocator::default();
    let mut detector = SequenceDetector { found: false };
    for statement_source in statement_sources {
        let Ok(statement) = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            statement_source.trim(),
        ) else {
            continue;
        };
        detector.visit_statement(&statement);
        if detector.found {
            return true;
        }
    }
    false
}

fn statement_sources_are_sequence_recomposition_friendly(statement_sources: &[String]) -> bool {
    let allocator = Allocator::default();
    statement_sources.iter().all(|statement_source| {
        let Ok(statement) = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            statement_source.trim(),
        ) else {
            return false;
        };
        matches!(
            statement,
            ast::Statement::ExpressionStatement(_)
                | ast::Statement::VariableDeclaration(_)
                | ast::Statement::WhileStatement(_)
        )
    })
}

fn rewrite_generated_setup_statements(mut setup_statements: Vec<String>) -> Vec<String> {
    fn parse_assignment_target_name(stmt: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        match statement {
            ast::Statement::VariableDeclaration(declaration) => {
                if declaration.declarations.len() != 1 {
                    return None;
                }
                let declarator = declaration.declarations.first()?;
                let _ = declarator.init.as_ref()?;
                let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
                    return None;
                };
                Some(identifier.name.to_string())
            }
            ast::Statement::ExpressionStatement(expression_statement) => {
                let ast::Expression::AssignmentExpression(assignment) =
                    expression_statement.expression.without_parentheses()
                else {
                    return None;
                };
                if assignment.operator != AssignmentOperator::Assign {
                    return None;
                }
                let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) =
                    &assignment.left
                else {
                    return None;
                };
                Some(identifier.name.to_string())
            }
            _ => None,
        }
    }

    fn parse_identifier_expression_name(stmt: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        let ast::Statement::ExpressionStatement(expression_statement) = statement else {
            return None;
        };
        let ast::Expression::Identifier(identifier) =
            expression_statement.expression.without_parentheses()
        else {
            return None;
        };
        Some(identifier.name.to_string())
    }

    fn drop_redundant_assignment_tail_identifier_reads(
        setup_statements: Vec<String>,
    ) -> Vec<String> {
        let mut rewritten: Vec<String> = Vec::with_capacity(setup_statements.len());
        for statement in setup_statements {
            let current_name = parse_identifier_expression_name(&statement);
            let previous_target = rewritten
                .last()
                .and_then(|previous| parse_assignment_target_name(previous));
            if current_name.is_some() && current_name == previous_target {
                continue;
            }
            rewritten.push(statement);
        }
        rewritten
    }

    if setup_statements.is_empty() {
        return setup_statements;
    }
    let original = setup_statements.clone();
    let computation = strip_statement_blank_line_markers(&setup_statements).join("\n");
    let rewritten = rewrite_named_test_reassign_ternary_in_scope_computation(&computation);
    let rewritten = rewrite_named_test_sequence_ternary_in_scope_computation(&rewritten);
    let rewritten = rewrite_named_temp_ternary_in_scope_computation(&rewritten);
    if rewritten == computation {
        return drop_redundant_assignment_tail_identifier_reads(setup_statements);
    }
    match split_statement_sources_preserving_blank_lines(&rewritten) {
        Some(statements) => {
            setup_statements = statements;
            drop_redundant_assignment_tail_identifier_reads(setup_statements)
        }
        None => drop_redundant_assignment_tail_identifier_reads(original),
    }
}

fn rewrite_memoized_bindings_into_setup_statements(
    memoized_bindings: Vec<GeneratedBinding>,
    setup_statements: Vec<String>,
) -> (Vec<GeneratedBinding>, Vec<String>) {
    if memoized_bindings.is_empty() || setup_statements.is_empty() {
        return (memoized_bindings, setup_statements);
    }

    let mut combined = Vec::with_capacity(memoized_bindings.len() + setup_statements.len());
    for binding in &memoized_bindings {
        let Some(statement) = render_generated_binding_statement(binding) else {
            return (memoized_bindings, setup_statements);
        };
        combined.push(statement.trim_end().to_string());
    }
    combined.extend(setup_statements.clone());

    let rewritten = rewrite_generated_setup_statements(combined.clone());
    if rewritten == combined {
        return (memoized_bindings, setup_statements);
    }

    extract_leading_generated_bindings_from_setup_statements(rewritten)
}

fn drop_redundant_assignment_tail_identifier_read_lines(source: String) -> String {
    fn parse_assignment_target_name(stmt: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        match statement {
            ast::Statement::VariableDeclaration(declaration) => {
                if declaration.declarations.len() != 1 {
                    return None;
                }
                let declarator = declaration.declarations.first()?;
                let _ = declarator.init.as_ref()?;
                let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
                    return None;
                };
                Some(identifier.name.to_string())
            }
            ast::Statement::ExpressionStatement(expression_statement) => {
                let ast::Expression::AssignmentExpression(assignment) =
                    expression_statement.expression.without_parentheses()
                else {
                    return None;
                };
                if assignment.operator != AssignmentOperator::Assign {
                    return None;
                }
                let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) =
                    &assignment.left
                else {
                    return None;
                };
                Some(identifier.name.to_string())
            }
            _ => None,
        }
    }

    fn parse_identifier_expression_name(stmt: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        let ast::Statement::ExpressionStatement(expression_statement) = statement else {
            return None;
        };
        let ast::Expression::Identifier(identifier) =
            expression_statement.expression.without_parentheses()
        else {
            return None;
        };
        Some(identifier.name.to_string())
    }

    let had_trailing_newline = source.ends_with('\n');
    let mut retained: Vec<String> = source.lines().map(|line| line.to_string()).collect();
    let last_non_empty_index = retained.iter().rposition(|line| !line.trim().is_empty());
    if let Some(last_index) = last_non_empty_index {
        let previous_non_empty = retained[..last_index]
            .iter()
            .rev()
            .find(|line| !line.trim().is_empty());
        let current_name = parse_identifier_expression_name(&retained[last_index]);
        let previous_target =
            previous_non_empty.and_then(|line| parse_assignment_target_name(line));
        if current_name.is_some() && current_name == previous_target {
            retained.remove(last_index);
        }
    }
    let mut rewritten = retained.join("\n");
    if had_trailing_newline && !rewritten.is_empty() {
        rewritten.push('\n');
    }
    rewritten
}

fn try_build_simple_scope_setup_statements(
    output_name: &str,
    computation_shape: &GeneratedBodyShape,
    cache_binding_name: &str,
) -> Option<Vec<String>> {
    match computation_shape {
        GeneratedBodyShape::PrefixedBindings { bindings, inner }
            if generated_shape_is_empty_expression_body(inner)
                && bindings.len() == 1
                && bindings[0].pattern == output_name =>
        {
            let binding = bindings.first()?;
            let assignment =
                render_reactive_assignment_statement_ast(output_name, &binding.expression)?;
            Some(vec![assignment.trim_end().to_string()])
        }
        GeneratedBodyShape::PrefixedBindings { bindings, inner } => {
            let mut statements = Vec::new();
            for binding in bindings {
                statements.push(
                    render_reactive_variable_statement_ast(
                        binding.kind,
                        &binding.pattern,
                        Some(&binding.expression),
                    )?
                    .trim_end()
                    .to_string(),
                );
            }
            statements.extend(try_build_simple_scope_setup_statements(
                output_name,
                inner,
                cache_binding_name,
            )?);
            Some(statements)
        }
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } => {
            let mut statements = Vec::new();
            for declaration in declarations {
                statements.push(
                    render_reactive_variable_statement_ast(
                        declaration.kind,
                        &declaration.pattern,
                        None,
                    )?
                    .trim_end()
                    .to_string(),
                );
            }
            statements.extend(try_build_simple_scope_setup_statements(
                output_name,
                inner,
                cache_binding_name,
            )?);
            Some(statements)
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner }
            if generated_shape_is_empty_expression_body(inner)
                && assignments.len() == 1
                && assignments[0].target == output_name =>
        {
            let assignment = assignments.first()?;
            let statement =
                render_reactive_assignment_statement_ast(&assignment.target, &assignment.value)?;
            Some(vec![statement.trim_end().to_string()])
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner } => {
            let mut statements = Vec::new();
            for assignment in assignments {
                statements.push(
                    render_reactive_assignment_statement_ast(
                        &assignment.target,
                        &assignment.value,
                    )?
                    .trim_end()
                    .to_string(),
                );
            }
            statements.extend(try_build_simple_scope_setup_statements(
                output_name,
                inner,
                cache_binding_name,
            )?);
            Some(statements)
        }
        GeneratedBodyShape::PrefixedExpressionStatements { expressions, inner } => {
            let mut statements = Vec::new();
            for expression in expressions {
                statements.push(
                    render_reactive_expression_statement_ast(expression)?
                        .trim_end()
                        .to_string(),
                );
            }
            statements.extend(try_build_simple_scope_setup_statements(
                output_name,
                inner,
                cache_binding_name,
            )?);
            Some(statements)
        }
        GeneratedBodyShape::ExpressionStatements(expressions) => {
            let mut statements = Vec::new();
            for expression in expressions {
                statements.push(
                    render_reactive_expression_statement_ast(expression)?
                        .trim_end()
                        .to_string(),
                );
            }
            Some(statements)
        }
        GeneratedBodyShape::AssignmentStatements(assignments) => {
            let mut statements = Vec::new();
            for assignment in assignments {
                statements.push(
                    render_reactive_assignment_statement_ast(
                        &assignment.target,
                        &assignment.value,
                    )?
                    .trim_end()
                    .to_string(),
                );
            }
            Some(statements)
        }
        GeneratedBodyShape::Block { .. }
        | GeneratedBodyShape::Labeled { .. }
        | GeneratedBodyShape::Switch { .. }
        | GeneratedBodyShape::ConditionalBranches { .. }
        | GeneratedBodyShape::GuardedBody { .. }
        | GeneratedBodyShape::GuardedAssignments { .. }
        | GeneratedBodyShape::GuardedAssignmentExpressions { .. }
        | GeneratedBodyShape::GuardedExpressionStatements { .. }
        | GeneratedBodyShape::GuardedReturnPrefix { .. }
        | GeneratedBodyShape::WhileLoop { .. }
        | GeneratedBodyShape::DoWhileLoop { .. }
        | GeneratedBodyShape::ForLoop { .. }
        | GeneratedBodyShape::ForInLoop { .. }
        | GeneratedBodyShape::ForOfLoop { .. }
        | GeneratedBodyShape::TryCatch { .. }
        | GeneratedBodyShape::Break(_)
        | GeneratedBodyShape::Continue(_)
        | GeneratedBodyShape::ReturnVoid
        | GeneratedBodyShape::ReturnIdentifier(_)
        | GeneratedBodyShape::ReturnExpression(_)
        | GeneratedBodyShape::ThrowExpression(_) => {
            try_render_statement_sources_from_generated_body_shape(computation_shape)
        }
        GeneratedBodyShape::MemoizedCachedValues {
            deps,
            setup_statements,
            cached_values,
            restored_values,
        } if cached_values.len() == 1
            && restored_values.len() == 1
            && cached_values[0].name == restored_values[0].name =>
        {
            let value_name = &cached_values[0].name;
            let value_slot = cached_values[0].slot;
            let mut consequent = String::new();
            for statement in setup_statements {
                consequent.push_str(statement);
                if !statement.ends_with('\n') {
                    consequent.push('\n');
                }
            }
            for (dep_slot, dep_expr) in deps {
                let cache_access =
                    render_cache_slot_access_expression_ast(cache_binding_name, *dep_slot)?;
                consequent.push_str(&render_reactive_assignment_statement_ast(
                    &cache_access,
                    dep_expr,
                )?);
            }
            let value_cache_access =
                render_cache_slot_access_expression_ast(cache_binding_name, value_slot)?;
            consequent.push_str(&render_reactive_assignment_statement_ast(
                &value_cache_access,
                value_name,
            )?);
            let alternate =
                render_reactive_assignment_statement_ast(value_name, &value_cache_access)?;
            let test = deps
                .iter()
                .map(|(dep_slot, dep_expr)| {
                    render_cache_slot_comparison_expression_ast(
                        cache_binding_name,
                        *dep_slot,
                        BinaryOperator::StrictNotEq,
                        dep_expr,
                    )
                })
                .collect::<Option<Vec<_>>>()?
                .join(" || ");
            Some(vec![
                render_reactive_if_statement_ast_with_context(
                    &test,
                    &consequent,
                    Some(&alternate),
                    false,
                    false,
                )?
                .trim_end()
                .to_string(),
            ])
        }
        GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
            sentinel_slot,
            setup_statements,
            cached_values,
            restored_values,
        } if cached_values.len() == 1
            && restored_values.len() == 1
            && cached_values[0].name == restored_values[0].name
            && cached_values[0].slot == *sentinel_slot =>
        {
            let value_name = &cached_values[0].name;
            let mut consequent = String::new();
            for statement in setup_statements {
                consequent.push_str(statement);
                if !statement.ends_with('\n') {
                    consequent.push('\n');
                }
            }
            let sentinel_cache_access =
                render_cache_slot_access_expression_ast(cache_binding_name, *sentinel_slot)?;
            consequent.push_str(&render_reactive_assignment_statement_ast(
                &sentinel_cache_access,
                value_name,
            )?);
            let alternate =
                render_reactive_assignment_statement_ast(value_name, &sentinel_cache_access)?;
            Some(vec![
                render_reactive_if_statement_ast_with_context(
                    &render_cache_slot_comparison_expression_ast(
                        cache_binding_name,
                        *sentinel_slot,
                        BinaryOperator::StrictEq,
                        &render_symbol_for_call_expression_source(MEMO_CACHE_SENTINEL),
                    )?,
                    &consequent,
                    Some(&alternate),
                    false,
                    false,
                )?
                .trim_end()
                .to_string(),
            ])
        }
        GeneratedBodyShape::Sequential { prefix, inner } => {
            let mut statements =
                try_build_simple_scope_setup_statements(output_name, prefix, cache_binding_name)?;
            statements.extend(try_build_simple_scope_setup_statements(
                output_name,
                inner,
                cache_binding_name,
            )?);
            Some(statements)
        }
        _ => None,
    }
}

fn try_build_generated_body_shape_from_reactive_scope_statement(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
) -> Option<GeneratedBodyShape> {
    try_build_generated_body_shape_from_scope_statement_parts(
        cx,
        &scope_block.scope,
        &scope_block.instructions,
    )
}

fn render_terminal_statement_source_for_body_shape(
    cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
) -> Option<String> {
    let stmt = codegen_terminal(cx, &term_stmt.terminal)?;
    let mut rendered = String::new();
    append_rendered_terminal_statement(&mut rendered, term_stmt, &stmt);
    Some(rendered)
}

fn try_build_generated_body_shape_from_terminal_statement(
    cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
) -> Option<GeneratedBodyShape> {
    if matches!(term_stmt.terminal, ReactiveTerminal::Switch { .. }) {
        let mut probe_cx = cx.clone();
        if let Some(rendered) =
            render_terminal_statement_source_for_body_shape(&mut probe_cx, term_stmt)
        {
            let rendered_shape = analyze_generated_body_shape(&rendered);
            if !matches!(rendered_shape, GeneratedBodyShape::Unknown) {
                *cx = probe_cx;
                return Some(rendered_shape);
            }
        }
    }

    let shape = try_build_generated_body_shape_from_reactive_terminal(cx, &term_stmt.terminal)?;
    if let Some(label) = &term_stmt.label
        && !label.implicit
    {
        Some(GeneratedBodyShape::Labeled {
            label: format!("bb{}", label.id.0),
            inner: Box::new(shape),
        })
    } else {
        Some(shape)
    }
}

fn apply_direct_prefix_codegen_state(cx: &mut Context, instr: &ReactiveInstruction) -> bool {
    let mut probe_cx = cx.clone();
    if codegen_instruction_nullable(&mut probe_cx, instr).is_none() {
        if std::env::var("DEBUG_DIRECT_BODY_SHAPE_TRACE").is_ok() {
            eprintln!(
                "[DIRECT_BODY_SHAPE_TRACE] codegen_instruction_nullable_none tag={} lvalue={:?}",
                instruction_value_tag(&instr.value),
                instr.lvalue.as_ref().and_then(|place| place
                    .identifier
                    .name
                    .as_ref()
                    .map(|name| name.value()))
            );
        }
        if materialize_fusable_temp_instruction(&mut probe_cx, instr) {
            *cx = probe_cx;
            return false;
        }
        *cx = probe_cx;
        return false;
    }

    match &instr.value {
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => {
            if lvalue.place.identifier.name.is_some() {
                cx.declare(&lvalue.place.identifier);
                cx.mark_decl_runtime_emitted(lvalue.place.identifier.declaration_id);
            }
        }
        InstructionValue::StoreLocal { lvalue, .. }
        | InstructionValue::StoreContext { lvalue, .. }
            if lvalue.kind != InstructionKind::Reassign
                && lvalue.place.identifier.name.is_some() =>
        {
            cx.declare(&lvalue.place.identifier);
            cx.mark_decl_runtime_emitted(lvalue.place.identifier.declaration_id);
        }
        _ => {}
    }
    true
}

#[derive(Default)]
struct DirectMemoizedExistingReturnParts {
    bindings: Vec<GeneratedBinding>,
    assignments: Vec<GeneratedAssignment>,
    expressions: Vec<String>,
    setup_statements: Vec<String>,
    memoized_expr: Option<String>,
}

struct InlineLiteralInitScopeMatch<'a> {
    source_instr: &'a ReactiveInstruction,
    store_instr: &'a ReactiveInstruction,
    store_lvalue: &'a LValue,
}

fn match_inline_literal_init_scope<'a>(
    scope_block: &'a ReactiveScopeBlock,
    following_stmts: &'a [ReactiveStatement],
) -> Option<InlineLiteralInitScopeMatch<'a>> {
    if !scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.len() != 1
    {
        return None;
    }
    let decl = scope_block.scope.declarations.values().next()?;
    let ReactiveStatement::Instruction(source_instr) = scope_block.instructions.first()? else {
        return None;
    };
    let source_lvalue = source_instr.lvalue.as_ref()?;
    if source_lvalue.identifier.declaration_id != decl.identifier.declaration_id {
        return None;
    }
    if !matches!(
        &source_instr.value,
        InstructionValue::Primitive { .. }
            | InstructionValue::ArrayExpression { .. }
            | InstructionValue::ObjectExpression { .. }
    ) {
        return None;
    }

    let ReactiveStatement::Instruction(store_instr) = following_stmts.first()? else {
        return None;
    };
    let (store_lvalue, store_value) = match &store_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => (lvalue, value),
        _ => return None,
    };
    if store_value.identifier.declaration_id != decl.identifier.declaration_id
        || store_lvalue.place.identifier.name.is_none()
    {
        return None;
    }
    let Some(parent_scope) = &store_lvalue.place.identifier.scope else {
        return None;
    };
    if parent_scope.dependencies.is_empty() {
        return None;
    }

    Some(InlineLiteralInitScopeMatch {
        source_instr,
        store_instr,
        store_lvalue,
    })
}

fn try_build_direct_fused_ternary_source_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
) -> Option<(GeneratedBodyShape, usize)> {
    if scope_block.scope.dependencies.len() != 1
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
    {
        return None;
    }
    let decl = scope_block.scope.declarations.values().next()?;
    let mut ternary_idx: Option<usize> = None;
    let mut scope_is_consequent: Option<bool> = None;
    for (idx, stmt) in following_stmts.iter().enumerate().take(8) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if idx > 0
            && !is_ignorable_bridge_interstitial(instr)
            && !matches!(&instr.value, InstructionValue::Ternary { .. })
        {
            continue;
        }
        let lvalue = instr.lvalue.as_ref()?;
        let InstructionValue::Ternary {
            consequent,
            alternate,
            ..
        } = &instr.value
        else {
            continue;
        };
        let cons_is_scope = consequent.identifier.declaration_id == decl.identifier.declaration_id;
        let alt_is_scope = alternate.identifier.declaration_id == decl.identifier.declaration_id;
        if !cons_is_scope && !alt_is_scope {
            continue;
        }
        if lvalue.identifier.declaration_id == decl.identifier.declaration_id {
            continue;
        }
        ternary_idx = Some(idx);
        scope_is_consequent = Some(cons_is_scope);
        break;
    }
    let ternary_idx = ternary_idx?;
    let scope_is_consequent = scope_is_consequent?;
    for stmt in &following_stmts[..ternary_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            return None;
        };
        if !is_ignorable_bridge_interstitial(instr) {
            return None;
        }
        let _ = codegen_instruction_nullable(cx, instr);
    }
    let ReactiveStatement::Instruction(ternary_instr) = following_stmts.get(ternary_idx)? else {
        return None;
    };
    let ternary_lvalue = ternary_instr.lvalue.as_ref()?;
    let InstructionValue::Ternary {
        test,
        consequent,
        alternate,
        ..
    } = &ternary_instr.value
    else {
        return None;
    };
    let non_scope_branch_expr_raw = if scope_is_consequent {
        codegen_place_to_expression(cx, alternate)
    } else {
        codegen_place_to_expression(cx, consequent)
    };
    let non_scope_is_inlineable_primitive =
        is_inlineable_primitive_literal_expression(non_scope_branch_expr_raw.trim());
    if non_scope_branch_expr_raw != "null" && !non_scope_is_inlineable_primitive {
        return None;
    }
    if scope_block.instructions.is_empty() {
        return None;
    }
    let source_idx = scope_block.instructions.len() - 1;
    for prefix_stmt in &scope_block.instructions[..source_idx] {
        let ReactiveStatement::Instruction(prefix_instr) = prefix_stmt else {
            return None;
        };
        let emitted = codegen_instruction_nullable(cx, prefix_instr);
        if emitted
            .as_deref()
            .is_some_and(|stmt| !stmt.trim().is_empty())
        {
            return None;
        }
    }
    let ReactiveStatement::Instruction(source_instr) = scope_block.instructions.get(source_idx)?
    else {
        return None;
    };
    let source_lvalue = source_instr.lvalue.as_ref()?;
    if source_lvalue.identifier.declaration_id != decl.identifier.declaration_id {
        return None;
    }
    if matches!(
        &source_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    let raw_dep = &scope_block.scope.dependencies[0];
    let cond_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
    let dep_for_codegen = truncate_ref_current_dep(raw_dep, &cx.stable_ref_decls);
    let mut dep_expr = codegen_dependency(cx, &dep_for_codegen);
    let mut force_root_dep = false;
    if !scope_is_consequent && !dep_for_codegen.path.is_empty() {
        let root_expr = identifier_name_with_cx(cx, &dep_for_codegen.identifier);
        if cond_expr.contains(&format!("{}?.", root_expr)) {
            dep_expr = root_expr;
            force_root_dep = true;
        }
    }
    let cond_is_non_local = cx
        .non_local_binding_decls
        .contains(&test.identifier.declaration_id);
    let include_cond_dep = !force_root_dep
        && !cond_is_non_local
        && !is_inlineable_primitive_literal_expression(cond_expr.trim());
    let source_ev = codegen_instruction_value_ev(cx, &source_instr.value);
    let mut source_expr = source_ev.wrap_if_needed(ExprPrecedence::Conditional);
    let should_compact_source_expr = match &source_instr.value {
        InstructionValue::ObjectExpression { properties, .. } => {
            properties.iter().any(|property| {
                matches!(
                    property,
                    ObjectPropertyOrSpread::Property(ObjectProperty {
                        type_: ObjectPropertyType::Method,
                        ..
                    })
                )
            })
        }
        InstructionValue::CallExpression { .. } => true,
        _ => false,
    };
    if source_expr.contains('\n') && should_compact_source_expr && !source_expr.contains('`') {
        source_expr = compact_single_statement(&source_expr);
    }
    let consequent_expr = if scope_is_consequent {
        source_expr.clone()
    } else {
        codegen_place_with_min_prec(cx, consequent, ExprPrecedence::Conditional)
    };
    let alternate_expr = if scope_is_consequent {
        codegen_place_with_min_prec(cx, alternate, ExprPrecedence::Conditional)
    } else {
        source_expr.clone()
    };
    let rhs_expr =
        render_conditional_expression_ast(&cond_expr, &consequent_expr, &alternate_expr)?;

    let decl_name = identifier_name_with_cx(cx, &decl.identifier);
    let needs_declaration = !has_materialized_named_binding(cx, &decl.identifier);
    if needs_declaration {
        cx.mark_decl_runtime_emitted(decl.identifier.declaration_id);
    }
    cx.declare(&decl.identifier);

    let mut dep_exprs = Vec::new();
    if include_cond_dep {
        dep_exprs.push(cond_expr.clone());
    }
    dep_exprs.push(dep_expr);
    let mut shape = build_direct_existing_memoized_return_shape(
        cx,
        decl_name.clone(),
        dep_exprs,
        DirectMemoizedExistingReturnParts {
            memoized_expr: Some(rhs_expr),
            ..DirectMemoizedExistingReturnParts::default()
        },
        None,
    )?;
    if needs_declaration {
        shape = GeneratedBodyShape::PrefixedDeclarations {
            declarations: vec![GeneratedDeclaration {
                kind: ast::VariableDeclarationKind::Let,
                pattern: decl_name.clone(),
            }],
            inner: Box::new(shape),
        };
    }

    cx.set_temp_expr(
        &ternary_lvalue.identifier,
        Some(ExprValue::primary(decl_name.clone())),
    );
    let suppressed_display_idx = ternary_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(ternary_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }

    Some((shape, ternary_idx + 1))
}

fn try_build_direct_fused_zero_dep_literal_store_prefix(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
) -> Option<(GeneratedBodyShape, usize)> {
    if !cx.inline_temp_zero_dep_scope_shapes {
        return None;
    }
    let InlineLiteralInitScopeMatch {
        source_instr,
        store_lvalue,
        ..
    } = match_inline_literal_init_scope(scope_block, following_stmts)?;
    let target_ident = &store_lvalue.place.identifier;
    let target_name = identifier_name_with_cx(cx, target_ident);
    let source_expr = codegen_instruction_value_ev(cx, &source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let kind = if has_materialized_named_binding(cx, target_ident) {
        InstructionKind::Reassign
    } else {
        store_lvalue.kind
    };
    let shape = if kind != InstructionKind::Reassign {
        let kind = variable_declaration_kind(store_lvalue.kind)?;
        cx.mark_decl_runtime_emitted(target_ident.declaration_id);
        cx.declare(target_ident);
        GeneratedBodyShape::PrefixedBindings {
            bindings: vec![GeneratedBinding {
                kind,
                pattern: target_name,
                expression: source_expr,
                promote_to_function_declaration: cx
                    .function_decl_decls
                    .contains(&target_ident.declaration_id),
            }],
            inner: Box::new(GeneratedBodyShape::ExpressionStatements(vec![])),
        }
    } else {
        cx.declare(target_ident);
        GeneratedBodyShape::PrefixedAssignments {
            assignments: vec![GeneratedAssignment {
                target: target_name,
                value: source_expr,
            }],
            inner: Box::new(GeneratedBodyShape::ExpressionStatements(vec![])),
        }
    };
    Some((shape, 1))
}

fn try_build_direct_inline_zero_dep_literal_into_following_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
) -> Option<GeneratedBodyShape> {
    let (source_decl, source_instr) = zero_dep_single_decl_scope_source(scope_block)?;
    if !matches!(
        &source_instr.value,
        InstructionValue::Primitive { .. }
            | InstructionValue::ArrayExpression { .. }
            | InstructionValue::ObjectExpression { .. }
    ) {
        return None;
    }
    let source_lvalue = source_instr.lvalue.as_ref()?;

    let ReactiveStatement::Scope(next_scope) = following_stmts.first()? else {
        return None;
    };
    if next_scope.scope.dependencies.is_empty() {
        return None;
    }
    let ReactiveStatement::Instruction(first_instr) = next_scope.instructions.first()? else {
        return None;
    };
    let (store_lvalue, store_value) = match &first_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => (lvalue, value),
        _ => return None,
    };
    if store_value.identifier.declaration_id != source_decl
        || store_lvalue.place.identifier.name.is_none()
        || first_instr.lvalue.is_some()
    {
        return None;
    }
    if reactive_block_uses_declaration(&next_scope.instructions[1..], source_decl) {
        return None;
    }

    let temp_snapshot = cx.snapshot_temps();
    let source_seed_expr = codegen_instruction_value_ev(cx, &source_instr.value);
    cx.set_temp_expr(&source_lvalue.identifier, Some(source_seed_expr));
    let shape = try_build_generated_body_shape_from_reactive_block(cx, following_stmts);
    if shape.is_none() {
        cx.restore_temps(temp_snapshot);
        return None;
    }

    let suppressed_display_idx = source_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(source_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }

    shape
}

fn try_build_direct_fused_zero_dep_ternary_default_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
) -> Option<(GeneratedBodyShape, usize)> {
    if !scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.is_empty()
    {
        return None;
    }

    let decl = scope_block.scope.declarations.values().next()?;
    let source_decl_id = decl.identifier.declaration_id;
    let mut probe_cx = cx.clone();
    let mut source_instr: Option<&ReactiveInstruction> = None;
    for stmt in &scope_block.instructions {
        let ReactiveStatement::Instruction(instr) = stmt else {
            return None;
        };
        let source_expr = codegen_instruction_value_ev(&mut probe_cx, &instr.value);
        let lvalue = instr.lvalue.as_ref()?;
        probe_cx
            .temp
            .insert(lvalue.identifier.declaration_id, Some(source_expr));
        if lvalue.identifier.declaration_id == source_decl_id {
            source_instr = Some(instr);
        }
    }
    let source_instr = source_instr?;
    let source_lvalue = source_instr.lvalue.as_ref()?;
    if source_lvalue.identifier.declaration_id != source_decl_id {
        return None;
    }
    if matches!(
        &source_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    let mut source_alias_decls: HashSet<DeclarationId> = HashSet::from([source_decl_id]);
    let mut ternary_idx: Option<usize> = None;
    let mut source_is_consequent = false;
    let mut source_place: Option<Place> = None;
    let mut dep_place: Option<Place> = None;
    for (idx, stmt) in following_stmts.iter().enumerate().take(8) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if let Some(lvalue) = &instr.lvalue {
            let source_derived = match &instr.value {
                InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. } => {
                    source_alias_decls.contains(&place.identifier.declaration_id)
                }
                InstructionValue::TypeCastExpression { value, .. } => {
                    source_alias_decls.contains(&value.identifier.declaration_id)
                }
                _ => false,
            };
            if source_derived {
                source_alias_decls.insert(lvalue.identifier.declaration_id);
            }
        }
        if idx > 0
            && !is_ignorable_bridge_interstitial(instr)
            && !matches!(&instr.value, InstructionValue::Ternary { .. })
        {
            continue;
        }
        let _ = instr.lvalue.as_ref()?;
        let InstructionValue::Ternary {
            consequent,
            alternate,
            ..
        } = &instr.value
        else {
            continue;
        };
        let cons_is_source = source_alias_decls.contains(&consequent.identifier.declaration_id);
        let alt_is_source = source_alias_decls.contains(&alternate.identifier.declaration_id);
        if cons_is_source == alt_is_source {
            continue;
        }
        let candidate_dep = if cons_is_source {
            alternate
        } else {
            consequent
        };
        if candidate_dep.identifier.declaration_id == decl.identifier.declaration_id {
            continue;
        }
        let dep_expr = codegen_place_to_expression(cx, candidate_dep);
        if !is_valid_js_identifier_name(dep_expr.trim()) {
            continue;
        }
        ternary_idx = Some(idx);
        source_is_consequent = cons_is_source;
        source_place = Some(if cons_is_source {
            consequent.clone()
        } else {
            alternate.clone()
        });
        dep_place = Some(candidate_dep.clone());
        break;
    }

    let ternary_idx = ternary_idx?;
    let source_seed_expr = probe_cx
        .temp
        .get(&source_decl_id)
        .cloned()
        .flatten()
        .unwrap_or_else(|| codegen_instruction_value_ev(&mut probe_cx, &source_instr.value));
    let cx_snapshot = cx.clone();
    cx.set_temp_expr(&source_lvalue.identifier, Some(source_seed_expr));
    for stmt in &following_stmts[..ternary_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            *cx = cx_snapshot;
            return None;
        };
        let bridge_stmt = codegen_instruction_nullable(cx, instr);
        if bridge_stmt
            .as_deref()
            .is_some_and(|text| !text.trim().is_empty())
        {
            *cx = cx_snapshot;
            return None;
        }
    }

    let ReactiveStatement::Instruction(ternary_instr) = following_stmts.get(ternary_idx)? else {
        *cx = cx_snapshot;
        return None;
    };
    let ternary_lvalue = ternary_instr.lvalue.as_ref()?;
    let InstructionValue::Ternary { test, .. } = &ternary_instr.value else {
        *cx = cx_snapshot;
        return None;
    };
    let dep_place = dep_place?;
    let source_place = source_place?;

    let cond_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
    let source_expr = codegen_place_with_min_prec(cx, &source_place, ExprPrecedence::Conditional);
    let dep_expr_cond = codegen_place_with_min_prec(cx, &dep_place, ExprPrecedence::Conditional);
    let dep_expr_guard = codegen_place_to_expression(cx, &dep_place);

    let use_ternary_lvalue =
        ternary_lvalue
            .identifier
            .name
            .as_ref()
            .is_some_and(|name| match name {
                IdentifierName::Named(n) | IdentifierName::Promoted(n) => {
                    !(n.starts_with('t') && n[1..].chars().all(|ch| ch.is_ascii_digit()))
                }
            });
    let output_ident = if use_ternary_lvalue {
        &ternary_lvalue.identifier
    } else {
        &decl.identifier
    };
    let output_name = identifier_name_with_cx(cx, output_ident);
    let rhs_expr = if source_is_consequent {
        render_conditional_expression_ast(&cond_expr, &source_expr, &dep_expr_cond)
    } else {
        render_conditional_expression_ast(&cond_expr, &dep_expr_cond, &source_expr)
    }?;

    let needs_declaration = !has_materialized_named_binding(cx, output_ident);
    if needs_declaration {
        cx.mark_decl_runtime_emitted(output_ident.declaration_id);
    }
    cx.declare(output_ident);

    let mut shape = build_direct_existing_memoized_return_shape(
        cx,
        output_name.clone(),
        vec![dep_expr_guard],
        DirectMemoizedExistingReturnParts {
            memoized_expr: Some(rhs_expr),
            ..DirectMemoizedExistingReturnParts::default()
        },
        None,
    )?;
    if needs_declaration {
        shape = GeneratedBodyShape::PrefixedDeclarations {
            declarations: vec![GeneratedDeclaration {
                kind: ast::VariableDeclarationKind::Let,
                pattern: output_name.clone(),
            }],
            inner: Box::new(shape),
        };
    }

    cx.set_temp_expr(
        &ternary_lvalue.identifier,
        Some(ExprValue::primary(output_name.clone())),
    );
    cx.temp.insert(
        decl.identifier.declaration_id,
        Some(ExprValue::primary(output_name)),
    );
    let suppressed_display_idx = ternary_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(ternary_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }

    Some((shape, ternary_idx + 1))
}

fn try_build_generated_body_shape_from_reactive_scope_return(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    term_stmt: &ReactiveTerminalStatement,
) -> Option<GeneratedBodyShape> {
    if let Some(shape) = try_build_generated_early_return_scope_return(cx, scope_block, term_stmt) {
        return Some(shape);
    }
    if term_stmt.label.is_some() {
        return None;
    }
    let ReactiveTerminal::Return { value, .. } = &term_stmt.terminal else {
        return None;
    };
    let mut full_scope_body = scope_block.instructions.clone();
    full_scope_body.push(ReactiveStatement::Terminal(term_stmt.clone()));
    let mut computation_cx = cx.clone();
    computation_cx.inline_temp_zero_dep_scope_shapes = true;
    let computation_shape =
        try_build_generated_body_shape_from_reactive_block(&mut computation_cx, &full_scope_body)?;
    cx.next_cache_index = computation_cx.next_cache_index;
    let dep_exprs =
        collect_direct_scope_dependency_exprs(cx, &scope_block.scope, &scope_block.instructions)?;
    if scope_block.scope.reassignments.len() == 1 && scope_block.scope.declarations.is_empty() {
        let output_ident = &scope_block.scope.reassignments[0];
        if value.identifier.declaration_id != output_ident.declaration_id {
            return None;
        }
        let value_name = identifier_name_with_cx(cx, output_ident);
        if let Some(parts) = try_decompose_direct_memoized_existing_return_shape(
            computation_shape.clone(),
            &value_name,
        ) {
            return build_direct_existing_memoized_return_shape(
                cx,
                value_name,
                dep_exprs,
                parts,
                Some((&scope_block.scope, &scope_block.instructions)),
            );
        }
        if generated_body_shape_returned_identifier(&computation_shape) == Some(value_name.as_str())
        {
            return build_direct_computed_memoized_return_shape(
                cx,
                value_name,
                None,
                dep_exprs,
                computation_shape,
            );
        }
        return None;
    }
    if scope_block.scope.declarations.len() == 1 && scope_block.scope.reassignments.is_empty() {
        let output_decl = scope_block.scope.declarations.values().next()?;
        if value.identifier.declaration_id != output_decl.identifier.declaration_id {
            return None;
        }
        let value_name = identifier_name_with_cx(cx, &output_decl.identifier);
        if let Some(parts) = try_decompose_direct_memoized_declared_return_shape(
            computation_shape.clone(),
            &value_name,
        ) {
            return build_direct_declared_memoized_return_shape(
                cx,
                value_name,
                dep_exprs,
                parts,
                Some((&scope_block.scope, &scope_block.instructions)),
            );
        }
        if generated_body_shape_returned_identifier(&computation_shape) == Some(value_name.as_str())
        {
            return build_direct_computed_memoized_return_shape(
                cx,
                value_name,
                Some(ast::VariableDeclarationKind::Let),
                dep_exprs,
                computation_shape,
            );
        }
        return None;
    }
    None
}

fn try_build_generated_early_return_scope_return(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    term_stmt: &ReactiveTerminalStatement,
) -> Option<GeneratedBodyShape> {
    let trace = std::env::var("DEBUG_DIRECT_EARLY_RETURN_TRACE").is_ok();
    if term_stmt.label.is_some() {
        if trace {
            eprintln!("[DIRECT_EARLY_RETURN_TRACE] skip: terminal label present");
        }
        return None;
    }
    let ReactiveTerminal::Return { value, .. } = &term_stmt.terminal else {
        if trace {
            eprintln!("[DIRECT_EARLY_RETURN_TRACE] skip: terminal not return");
        }
        return None;
    };
    let early_return = scope_block.scope.early_return_value.as_ref()?;
    let dep_exprs =
        collect_direct_scope_dependency_exprs(cx, &scope_block.scope, &scope_block.instructions)?;
    let mut computation_cx = cx.clone();
    computation_cx.inline_temp_zero_dep_scope_shapes = true;
    let Some(computation_shape) = try_build_generated_body_shape_from_reactive_block(
        &mut computation_cx,
        &scope_block.instructions,
    ) else {
        if trace {
            eprintln!(
                "[DIRECT_EARLY_RETURN_TRACE] skip: inner computation shape none scope={}",
                scope_block.scope.id.0
            );
        }
        return None;
    };
    cx.next_cache_index = computation_cx.next_cache_index;
    let mut setup_statements =
        try_render_statement_sources_from_generated_body_shape(&computation_shape)?;
    setup_statements = rewrite_generated_setup_statements(setup_statements);
    if setup_statements.is_empty() {
        if trace {
            eprintln!(
                "[DIRECT_EARLY_RETURN_TRACE] skip: empty setup statements scope={}",
                scope_block.scope.id.0
            );
        }
        return None;
    }

    let mut sorted_decls: Vec<&ScopeDeclaration> =
        scope_block.scope.declarations.values().collect();
    sorted_decls.sort_by(|a, b| {
        identifier_name_static(&a.identifier)
            .cmp(&identifier_name_static(&b.identifier))
            .then_with(|| {
                a.identifier
                    .declaration_id
                    .0
                    .cmp(&b.identifier.declaration_id.0)
            })
    });
    let mut declarations = Vec::with_capacity(sorted_decls.len());
    let mut cached_values =
        Vec::with_capacity(sorted_decls.len() + scope_block.scope.reassignments.len());
    for decl in sorted_decls {
        let name = identifier_name_with_cx(cx, &decl.identifier);
        declarations.push(GeneratedDeclaration {
            kind: ast::VariableDeclarationKind::Let,
            pattern: name.clone(),
        });
        cached_values.push(GeneratedCachedValue { name, slot: 0 });
    }
    for reassignment in &scope_block.scope.reassignments {
        cached_values.push(GeneratedCachedValue {
            name: identifier_name_with_cx(cx, reassignment),
            slot: 0,
        });
    }
    if !declarations.is_empty() {
        setup_statements =
            rewrite_cached_setup_statements_for_outer_declarations(setup_statements, &declarations);
    }
    setup_statements = preserve_scope_setup_statement_blank_lines(
        cx,
        &scope_block.scope,
        &scope_block.instructions,
        &declarations,
        setup_statements,
    );

    if cached_values.is_empty() {
        if trace {
            eprintln!(
                "[DIRECT_EARLY_RETURN_TRACE] skip: no cached values scope={}",
                scope_block.scope.id.0
            );
        }
        return None;
    }

    let mut deps = Vec::with_capacity(dep_exprs.len());
    let mut outer_slots = Vec::with_capacity(dep_exprs.len() + cached_values.len());
    for dep_expr in dep_exprs {
        deps.push((cx.alloc_cache_slot(), dep_expr));
        outer_slots.push(deps.last().expect("dep inserted").0);
    }
    for cached_value in &mut cached_values {
        cached_value.slot = cx.alloc_cache_slot();
        outer_slots.push(cached_value.slot);
    }
    let setup_statements =
        rebase_nested_cache_slots_for_outer_wrapper(setup_statements, &mut outer_slots);
    let dep_count = deps.len();
    for ((dep_slot, _), slot) in deps.iter_mut().zip(outer_slots.iter().copied()) {
        *dep_slot = slot;
    }
    for (cached_value, slot) in cached_values
        .iter_mut()
        .zip(outer_slots.into_iter().skip(dep_count))
    {
        cached_value.slot = slot;
    }
    let restored_values = cached_values.clone();
    let sentinel_name = identifier_name_with_cx(cx, &early_return.value);
    if !cached_values
        .iter()
        .any(|value| value.name == sentinel_name)
    {
        if trace {
            eprintln!(
                "[DIRECT_EARLY_RETURN_TRACE] skip: sentinel {} not in cached values {:?}",
                sentinel_name, cached_values
            );
        }
        return None;
    }
    let final_return = if value.identifier.declaration_id == early_return.value.declaration_id {
        None
    } else {
        let final_return = identifier_name_with_cx(cx, &value.identifier);
        cached_values
            .iter()
            .any(|cached_value| cached_value.name == final_return)
            .then_some(final_return)
    };
    let inner = GeneratedBodyShape::MemoizedEarlyReturnSentinel {
        deps,
        setup_statements,
        cached_values,
        restored_values,
        sentinel_name,
        final_return,
        fallback_body: None,
    };
    if declarations.is_empty() {
        Some(inner)
    } else {
        Some(GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner: Box::new(inner),
        })
    }
}

fn try_decompose_direct_memoized_existing_return_shape(
    shape: GeneratedBodyShape,
    value_name: &str,
) -> Option<DirectMemoizedExistingReturnParts> {
    match shape {
        GeneratedBodyShape::ReturnIdentifier(name) if name == value_name => {
            Some(DirectMemoizedExistingReturnParts::default())
        }
        GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner,
        } if alias_name == value_name => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, &source_name)?;
            if parts.memoized_expr.is_none() {
                parts.memoized_expr = Some(source_name);
            }
            Some(parts)
        }
        GeneratedBodyShape::AliasedReturn {
            alias_name,
            source_name,
            inner,
            ..
        } if alias_name == value_name => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, &source_name)?;
            if parts.memoized_expr.is_none() {
                parts.memoized_expr = Some(source_name);
            }
            Some(parts)
        }
        GeneratedBodyShape::AssignedExpressionReturn {
            value_name: assigned_name,
            expression,
            ..
        } if assigned_name == value_name => Some(DirectMemoizedExistingReturnParts {
            memoized_expr: Some(expression),
            ..Default::default()
        }),
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, value_name)?;
            let mut prefix_statements = declarations
                .into_iter()
                .map(|declaration| render_generated_declaration_statement(&declaration))
                .collect::<Option<Vec<_>>>()?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedBindings { bindings, inner } => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, value_name)?;
            let mut prefix_statements = bindings
                .iter()
                .map(render_generated_binding_statement)
                .collect::<Option<Vec<_>>>()?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner } => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, value_name)?;
            let mut prefix_statements = assignments
                .iter()
                .map(render_generated_assignment_statement)
                .collect::<Option<Vec<_>>>()?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedExpressionStatements { expressions, inner } => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, value_name)?;
            let mut prefix_statements = expressions
                .iter()
                .map(|expression| render_generated_expression_statement(expression))
                .collect::<Option<Vec<_>>>()?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::Sequential { prefix, inner } => {
            let mut parts =
                try_decompose_direct_memoized_existing_return_shape(*inner, value_name)?;
            let mut prefix_statements =
                try_render_statement_sources_from_generated_body_shape(&prefix)?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        _ => None,
    }
}

fn collect_direct_scope_dependency_exprs(
    cx: &mut Context,
    scope: &ReactiveScope,
    _block: &[ReactiveStatement],
) -> Option<Vec<String>> {
    let sorted_deps: Vec<ReactiveScopeDependency> = scope
        .dependencies
        .iter()
        .map(|dep| truncate_ref_current_dep(dep, &cx.stable_ref_decls))
        .collect();
    let mut dep_refs: Vec<&ReactiveScopeDependency> = sorted_deps.iter().collect();
    sort_scope_dependency_refs_for_codegen(cx, &mut dep_refs);
    let mut seen = HashSet::new();
    let mut dep_exprs = Vec::new();
    for dep in dep_refs {
        let key = format_dependency_identity(dep);
        if seen.insert(key) {
            dep_exprs.push(codegen_dependency(cx, dep));
        }
    }
    Some(dep_exprs)
}

fn build_direct_existing_memoized_return_shape(
    cx: &mut Context,
    value_name: String,
    dep_exprs: Vec<String>,
    parts: DirectMemoizedExistingReturnParts,
    change_detection_scope: Option<(&ReactiveScope, &ReactiveBlock)>,
) -> Option<GeneratedBodyShape> {
    if dep_exprs.is_empty() {
        let value_slot = cx.alloc_cache_slot();
        if let Some(shape) = build_option_sensitive_memoized_return_shape(
            cx,
            OptionSensitiveMemoizedReturnShapeSpec {
                value_name: &value_name,
                declare_value_kind: None,
                deps: &[],
                zero_dep_sentinel_slot: Some(value_slot),
                value_slot,
                parts: &parts,
                change_detection_scope,
            },
        ) {
            return Some(shape);
        }
        return Some(GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
            value_name,
            value_slot,
            memoized_bindings: parts.bindings,
            memoized_assignments: parts.assignments,
            memoized_expressions: parts.expressions,
            memoized_setup_statements: parts.setup_statements,
            memoized_expr: parts.memoized_expr,
        });
    }
    if dep_exprs.len() == 1 {
        let dep_slot = cx.alloc_cache_slot();
        let value_slot = cx.alloc_cache_slot();
        let deps = vec![(dep_slot, dep_exprs[0].clone())];
        if let Some(shape) = build_option_sensitive_memoized_return_shape(
            cx,
            OptionSensitiveMemoizedReturnShapeSpec {
                value_name: &value_name,
                declare_value_kind: None,
                deps: &deps,
                zero_dep_sentinel_slot: None,
                value_slot,
                parts: &parts,
                change_detection_scope,
            },
        ) {
            return Some(shape);
        }
        return Some(GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
            value_name,
            dep_slot,
            dep_expr: dep_exprs[0].clone(),
            value_slot,
            memoized_bindings: parts.bindings,
            memoized_assignments: parts.assignments,
            memoized_expressions: parts.expressions,
            memoized_setup_statements: parts.setup_statements,
            memoized_expr: parts.memoized_expr,
        });
    }
    let mut deps = Vec::with_capacity(dep_exprs.len());
    for dep_expr in dep_exprs {
        deps.push((cx.alloc_cache_slot(), dep_expr));
    }
    let value_slot = cx.alloc_cache_slot();
    if let Some(shape) = build_option_sensitive_memoized_return_shape(
        cx,
        OptionSensitiveMemoizedReturnShapeSpec {
            value_name: &value_name,
            declare_value_kind: None,
            deps: &deps,
            zero_dep_sentinel_slot: None,
            value_slot,
            parts: &parts,
            change_detection_scope,
        },
    ) {
        return Some(shape);
    }
    Some(GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
        value_name,
        deps,
        value_slot,
        memoized_bindings: parts.bindings,
        memoized_assignments: parts.assignments,
        memoized_expressions: parts.expressions,
        memoized_setup_statements: parts.setup_statements,
        memoized_expr: parts.memoized_expr,
    })
}

fn build_direct_declared_memoized_return_shape(
    cx: &mut Context,
    value_name: String,
    dep_exprs: Vec<String>,
    parts: DirectMemoizedExistingReturnParts,
    change_detection_scope: Option<(&ReactiveScope, &ReactiveBlock)>,
) -> Option<GeneratedBodyShape> {
    let value_kind = ast::VariableDeclarationKind::Let;
    if dep_exprs.is_empty() {
        let value_slot = cx.alloc_cache_slot();
        if let Some(shape) = build_option_sensitive_memoized_return_shape(
            cx,
            OptionSensitiveMemoizedReturnShapeSpec {
                value_name: &value_name,
                declare_value_kind: Some(value_kind),
                deps: &[],
                zero_dep_sentinel_slot: Some(value_slot),
                value_slot,
                parts: &parts,
                change_detection_scope,
            },
        ) {
            return Some(shape);
        }
        return Some(GeneratedBodyShape::ZeroDependencyMemoizedReturn {
            value_name,
            value_kind,
            value_slot,
            memoized_bindings: parts.bindings,
            memoized_assignments: parts.assignments,
            memoized_expressions: parts.expressions,
            memoized_setup_statements: parts.setup_statements,
            memoized_expr: parts.memoized_expr,
        });
    }
    if dep_exprs.len() == 1 {
        let dep_slot = cx.alloc_cache_slot();
        let value_slot = cx.alloc_cache_slot();
        let deps = vec![(dep_slot, dep_exprs[0].clone())];
        if let Some(shape) = build_option_sensitive_memoized_return_shape(
            cx,
            OptionSensitiveMemoizedReturnShapeSpec {
                value_name: &value_name,
                declare_value_kind: Some(value_kind),
                deps: &deps,
                zero_dep_sentinel_slot: None,
                value_slot,
                parts: &parts,
                change_detection_scope,
            },
        ) {
            return Some(shape);
        }
        return Some(GeneratedBodyShape::SingleDependencyMemoizedReturn {
            value_name,
            value_kind,
            dep_slot,
            dep_expr: dep_exprs[0].clone(),
            value_slot,
            memoized_bindings: parts.bindings,
            memoized_assignments: parts.assignments,
            memoized_expressions: parts.expressions,
            memoized_setup_statements: parts.setup_statements,
            memoized_expr: parts.memoized_expr,
        });
    }
    let mut deps = Vec::with_capacity(dep_exprs.len());
    for dep_expr in dep_exprs {
        deps.push((cx.alloc_cache_slot(), dep_expr));
    }
    let value_slot = cx.alloc_cache_slot();
    if let Some(shape) = build_option_sensitive_memoized_return_shape(
        cx,
        OptionSensitiveMemoizedReturnShapeSpec {
            value_name: &value_name,
            declare_value_kind: Some(value_kind),
            deps: &deps,
            zero_dep_sentinel_slot: None,
            value_slot,
            parts: &parts,
            change_detection_scope,
        },
    ) {
        return Some(shape);
    }
    Some(GeneratedBodyShape::MultiDependencyMemoizedReturn {
        value_name,
        value_kind,
        deps,
        value_slot,
        memoized_bindings: parts.bindings,
        memoized_assignments: parts.assignments,
        memoized_expressions: parts.expressions,
        memoized_setup_statements: parts.setup_statements,
        memoized_expr: parts.memoized_expr,
    })
}

fn build_direct_computed_memoized_return_shape(
    cx: &mut Context,
    value_name: String,
    value_kind: Option<ast::VariableDeclarationKind>,
    dep_exprs: Vec<String>,
    computation: GeneratedBodyShape,
) -> Option<GeneratedBodyShape> {
    let mut deps = Vec::with_capacity(dep_exprs.len());
    for dep_expr in dep_exprs {
        deps.push((cx.alloc_cache_slot(), dep_expr));
    }
    let value_slot = cx.alloc_cache_slot();
    Some(GeneratedBodyShape::MemoizedComputedReturn {
        value_name,
        value_kind,
        deps,
        value_slot,
        computation: Box::new(computation),
    })
}

fn render_generated_declaration_statement(declaration: &GeneratedDeclaration) -> Option<String> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let pattern = parse_binding_pattern_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        &declaration.pattern,
    )
    .ok()?;
    let statement = ast::Statement::VariableDeclaration(builder.alloc_variable_declaration(
        SPAN,
        declaration.kind,
        builder.vec1(builder.variable_declarator(
            SPAN,
            declaration.kind,
            pattern,
            NONE,
            None,
            false,
        )),
        false,
    ));
    Some(codegen_statement_with_flow_cast_restore(&statement))
}

fn render_generated_binding_statement(binding: &GeneratedBinding) -> Option<String> {
    if binding.promote_to_function_declaration
        && let Some(statement) =
            function_expr_as_declaration(binding.pattern.trim(), &binding.expression)
    {
        return Some(statement.trim_end().to_string());
    }

    render_reactive_variable_statement_ast(
        binding.kind,
        &binding.pattern,
        Some(&binding.expression),
    )
    .map(|statement| statement.trim_end().to_string())
}

fn render_generated_assignment_statement(assignment: &GeneratedAssignment) -> Option<String> {
    render_reactive_assignment_statement_ast(&assignment.target, &assignment.value)
        .map(|statement| statement.trim_end().to_string())
}

fn render_generated_expression_statement(expression: &str) -> Option<String> {
    render_reactive_expression_statement_ast(expression)
        .map(|statement| statement.trim_end().to_string())
}

fn is_simple_generated_identifier_name(name: &str) -> bool {
    let mut chars = name.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    (first == '_' || first == '$' || first.is_ascii_alphabetic())
        && chars.all(|ch| ch == '_' || ch == '$' || ch.is_ascii_alphanumeric())
}

fn generated_body_shape_supports_guard_aliases(shape: &GeneratedBodyShape) -> bool {
    matches!(
        shape,
        GeneratedBodyShape::MemoizedCachedValues { deps, .. } if !deps.is_empty()
    ) || matches!(
        shape,
        GeneratedBodyShape::SingleDependencyMemoizedReturn { .. }
            | GeneratedBodyShape::SingleDependencyMemoizedExistingReturn { .. }
            | GeneratedBodyShape::MultiDependencyMemoizedReturn { .. }
            | GeneratedBodyShape::MultiDependencyMemoizedExistingReturn { .. }
    )
}

fn hoist_guard_alias_bindings_outside_declarations(
    shape: GeneratedBodyShape,
) -> GeneratedBodyShape {
    match shape {
        GeneratedBodyShape::Block { inner } => GeneratedBodyShape::Block {
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::Labeled { label, inner } => GeneratedBodyShape::Labeled {
            label,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::GuardedBody { test, inner } => GeneratedBodyShape::GuardedBody {
            test,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::GuardedReturnPrefix {
            test,
            consequent,
            inner,
        } => GeneratedBodyShape::GuardedReturnPrefix {
            test,
            consequent,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::ConditionalBranches {
            test,
            consequent,
            alternate,
        } => GeneratedBodyShape::ConditionalBranches {
            test,
            consequent: Box::new(hoist_guard_alias_bindings_outside_declarations(*consequent)),
            alternate: Box::new(hoist_guard_alias_bindings_outside_declarations(*alternate)),
        },
        GeneratedBodyShape::WhileLoop { test, body } => GeneratedBodyShape::WhileLoop {
            test,
            body: Box::new(hoist_guard_alias_bindings_outside_declarations(*body)),
        },
        GeneratedBodyShape::DoWhileLoop { test, body } => GeneratedBodyShape::DoWhileLoop {
            test,
            body: Box::new(hoist_guard_alias_bindings_outside_declarations(*body)),
        },
        GeneratedBodyShape::ForLoop {
            init,
            test,
            update,
            body,
        } => GeneratedBodyShape::ForLoop {
            init,
            test,
            update,
            body: Box::new(hoist_guard_alias_bindings_outside_declarations(*body)),
        },
        GeneratedBodyShape::ForInLoop { left, right, body } => GeneratedBodyShape::ForInLoop {
            left,
            right,
            body: Box::new(hoist_guard_alias_bindings_outside_declarations(*body)),
        },
        GeneratedBodyShape::ForOfLoop { left, right, body } => GeneratedBodyShape::ForOfLoop {
            left,
            right,
            body: Box::new(hoist_guard_alias_bindings_outside_declarations(*body)),
        },
        GeneratedBodyShape::TryCatch {
            catch_param,
            try_body,
            catch_body,
        } => GeneratedBodyShape::TryCatch {
            catch_param,
            try_body: Box::new(hoist_guard_alias_bindings_outside_declarations(*try_body)),
            catch_body: Box::new(hoist_guard_alias_bindings_outside_declarations(*catch_body)),
        },
        GeneratedBodyShape::WrappedReturnExpression {
            source_name,
            expression,
            inner,
        } => GeneratedBodyShape::WrappedReturnExpression {
            source_name,
            expression,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner,
        } => GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::AliasedReturn {
            alias_name,
            alias_kind,
            source_name,
            inner,
        } => GeneratedBodyShape::AliasedReturn {
            alias_name,
            alias_kind,
            source_name,
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } => {
            let inner = hoist_guard_alias_bindings_outside_declarations(*inner);
            if let GeneratedBodyShape::PrefixedBindings { bindings, inner } = inner {
                let declaration_names: Vec<String> = declarations
                    .iter()
                    .map(|declaration| declaration.pattern.clone())
                    .filter(|pattern| is_simple_generated_identifier_name(pattern))
                    .collect();
                let can_swap = !declaration_names.is_empty()
                    && !bindings.is_empty()
                    && bindings.iter().all(|binding| {
                        is_simple_generated_identifier_name(&binding.pattern)
                            && declaration_names
                                .iter()
                                .all(|name| !contains_word(&binding.expression, name))
                    })
                    && generated_body_shape_supports_guard_aliases(inner.as_ref());
                if can_swap {
                    return GeneratedBodyShape::PrefixedBindings {
                        bindings,
                        inner: Box::new(GeneratedBodyShape::PrefixedDeclarations {
                            declarations,
                            inner,
                        }),
                    };
                }
                return GeneratedBodyShape::PrefixedDeclarations {
                    declarations,
                    inner: Box::new(GeneratedBodyShape::PrefixedBindings { bindings, inner }),
                };
            }
            GeneratedBodyShape::PrefixedDeclarations {
                declarations,
                inner: Box::new(inner),
            }
        }
        GeneratedBodyShape::PrefixedBindings { bindings, inner } => {
            GeneratedBodyShape::PrefixedBindings {
                bindings,
                inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
            }
        }
        GeneratedBodyShape::PrefixedExpressionStatements { expressions, inner } => {
            GeneratedBodyShape::PrefixedExpressionStatements {
                expressions,
                inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
            }
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner } => {
            GeneratedBodyShape::PrefixedAssignments {
                assignments,
                inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
            }
        }
        GeneratedBodyShape::Sequential { prefix, inner } => GeneratedBodyShape::Sequential {
            prefix: Box::new(hoist_guard_alias_bindings_outside_declarations(*prefix)),
            inner: Box::new(hoist_guard_alias_bindings_outside_declarations(*inner)),
        },
        other => other,
    }
}

fn apply_generated_body_shape_cache_binding_name(
    shape: GeneratedBodyShape,
    cache_binding_name: &str,
) -> GeneratedBodyShape {
    if cache_binding_name == "$" {
        return shape;
    }

    fn apply_cache_binding_name_in_expression(
        expression: String,
        cache_binding_name: &str,
    ) -> String {
        expression.replace("$[", &format!("{cache_binding_name}["))
    }

    fn apply_cache_binding_name_in_statement_source(
        statement_source: String,
        cache_binding_name: &str,
    ) -> String {
        statement_source.replace("$[", &format!("{cache_binding_name}["))
    }

    fn apply_bindings(
        bindings: Vec<GeneratedBinding>,
        cache_binding_name: &str,
    ) -> Vec<GeneratedBinding> {
        bindings
            .into_iter()
            .map(|binding| GeneratedBinding {
                expression: apply_cache_binding_name_in_expression(
                    binding.expression,
                    cache_binding_name,
                ),
                ..binding
            })
            .collect()
    }

    fn apply_assignments(
        assignments: Vec<GeneratedAssignment>,
        cache_binding_name: &str,
    ) -> Vec<GeneratedAssignment> {
        assignments
            .into_iter()
            .map(|assignment| GeneratedAssignment {
                target: apply_cache_binding_name_in_expression(
                    assignment.target,
                    cache_binding_name,
                ),
                value: apply_cache_binding_name_in_expression(assignment.value, cache_binding_name),
            })
            .collect()
    }

    match shape {
        GeneratedBodyShape::Unknown => GeneratedBodyShape::Unknown,
        GeneratedBodyShape::Block { inner } => GeneratedBodyShape::Block {
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::Labeled { label, inner } => GeneratedBodyShape::Labeled {
            label,
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::Switch {
            discriminant,
            cases,
        } => GeneratedBodyShape::Switch {
            discriminant: apply_cache_binding_name_in_expression(discriminant, cache_binding_name),
            cases: cases
                .into_iter()
                .map(|case| GeneratedSwitchCase {
                    test: case.test.map(|test| {
                        apply_cache_binding_name_in_expression(test, cache_binding_name)
                    }),
                    consequent: apply_generated_body_shape_cache_binding_name(
                        case.consequent,
                        cache_binding_name,
                    ),
                })
                .collect(),
        },
        GeneratedBodyShape::DebuggerStatements(count) => {
            GeneratedBodyShape::DebuggerStatements(count)
        }
        GeneratedBodyShape::ExpressionStatements(expressions) => {
            GeneratedBodyShape::ExpressionStatements(
                expressions
                    .into_iter()
                    .map(|expression| {
                        apply_cache_binding_name_in_expression(expression, cache_binding_name)
                    })
                    .collect(),
            )
        }
        GeneratedBodyShape::AssignmentStatements(assignments) => {
            GeneratedBodyShape::AssignmentStatements(apply_assignments(
                assignments,
                cache_binding_name,
            ))
        }
        GeneratedBodyShape::GuardedBody { test, inner } => GeneratedBodyShape::GuardedBody {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::GuardedExpressionStatements { test, expressions } => {
            GeneratedBodyShape::GuardedExpressionStatements {
                test: apply_cache_binding_name_in_expression(test, cache_binding_name),
                expressions: expressions
                    .into_iter()
                    .map(|expression| {
                        apply_cache_binding_name_in_expression(expression, cache_binding_name)
                    })
                    .collect(),
            }
        }
        GeneratedBodyShape::GuardedReturnPrefix {
            test,
            consequent,
            inner,
        } => GeneratedBodyShape::GuardedReturnPrefix {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            consequent: consequent.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::ConditionalBranches {
            test,
            consequent,
            alternate,
        } => GeneratedBodyShape::ConditionalBranches {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            consequent: Box::new(apply_generated_body_shape_cache_binding_name(
                *consequent,
                cache_binding_name,
            )),
            alternate: Box::new(apply_generated_body_shape_cache_binding_name(
                *alternate,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::GuardedAssignments { test, assignments } => {
            GeneratedBodyShape::GuardedAssignments {
                test: apply_cache_binding_name_in_expression(test, cache_binding_name),
                assignments: apply_assignments(assignments, cache_binding_name),
            }
        }
        GeneratedBodyShape::WhileLoop { test, body } => GeneratedBodyShape::WhileLoop {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            body: Box::new(apply_generated_body_shape_cache_binding_name(
                *body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::DoWhileLoop { test, body } => GeneratedBodyShape::DoWhileLoop {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            body: Box::new(apply_generated_body_shape_cache_binding_name(
                *body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::ForLoop {
            init,
            test,
            update,
            body,
        } => GeneratedBodyShape::ForLoop {
            init: init
                .map(|source| apply_cache_binding_name_in_expression(source, cache_binding_name)),
            test: test
                .map(|source| apply_cache_binding_name_in_expression(source, cache_binding_name)),
            update: update
                .map(|source| apply_cache_binding_name_in_expression(source, cache_binding_name)),
            body: Box::new(apply_generated_body_shape_cache_binding_name(
                *body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::ForInLoop { left, right, body } => GeneratedBodyShape::ForInLoop {
            left,
            right: apply_cache_binding_name_in_expression(right, cache_binding_name),
            body: Box::new(apply_generated_body_shape_cache_binding_name(
                *body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::ForOfLoop { left, right, body } => GeneratedBodyShape::ForOfLoop {
            left,
            right: apply_cache_binding_name_in_expression(right, cache_binding_name),
            body: Box::new(apply_generated_body_shape_cache_binding_name(
                *body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::GuardedAssignmentExpressions {
            test,
            assignments,
            expressions,
        } => GeneratedBodyShape::GuardedAssignmentExpressions {
            test: apply_cache_binding_name_in_expression(test, cache_binding_name),
            assignments: apply_assignments(assignments, cache_binding_name),
            expressions: expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
        },
        GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
            sentinel_slot,
            setup_statements,
            cached_values,
            restored_values,
        } => GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
            sentinel_slot,
            setup_statements: setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            cached_values,
            restored_values,
        },
        GeneratedBodyShape::MemoizedCachedValues {
            deps,
            setup_statements,
            cached_values,
            restored_values,
        } => GeneratedBodyShape::MemoizedCachedValues {
            deps: deps
                .into_iter()
                .map(|(slot, expression)| {
                    (
                        slot,
                        apply_cache_binding_name_in_expression(expression, cache_binding_name),
                    )
                })
                .collect(),
            setup_statements: setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            cached_values,
            restored_values,
        },
        GeneratedBodyShape::MemoizedEarlyReturnSentinel {
            deps,
            setup_statements,
            cached_values,
            restored_values,
            sentinel_name,
            final_return,
            fallback_body,
        } => GeneratedBodyShape::MemoizedEarlyReturnSentinel {
            deps: deps
                .into_iter()
                .map(|(slot, expression)| {
                    (
                        slot,
                        apply_cache_binding_name_in_expression(expression, cache_binding_name),
                    )
                })
                .collect(),
            setup_statements: setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            cached_values,
            restored_values,
            sentinel_name: apply_cache_binding_name_in_expression(
                sentinel_name,
                cache_binding_name,
            ),
            final_return: final_return.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
            fallback_body: fallback_body.map(|body| {
                Box::new(apply_generated_body_shape_cache_binding_name(
                    *body,
                    cache_binding_name,
                ))
            }),
        },
        GeneratedBodyShape::TryCatch {
            catch_param,
            try_body,
            catch_body,
        } => GeneratedBodyShape::TryCatch {
            catch_param,
            try_body: Box::new(apply_generated_body_shape_cache_binding_name(
                *try_body,
                cache_binding_name,
            )),
            catch_body: Box::new(apply_generated_body_shape_cache_binding_name(
                *catch_body,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::Break(label) => GeneratedBodyShape::Break(label),
        GeneratedBodyShape::Continue(label) => GeneratedBodyShape::Continue(label),
        GeneratedBodyShape::ReturnVoid => GeneratedBodyShape::ReturnVoid,
        GeneratedBodyShape::ReturnIdentifier(name) => GeneratedBodyShape::ReturnIdentifier(
            apply_cache_binding_name_in_expression(name, cache_binding_name),
        ),
        GeneratedBodyShape::ReturnExpression(expression) => GeneratedBodyShape::ReturnExpression(
            apply_cache_binding_name_in_expression(expression, cache_binding_name),
        ),
        GeneratedBodyShape::ThrowExpression(expression) => GeneratedBodyShape::ThrowExpression(
            apply_cache_binding_name_in_expression(expression, cache_binding_name),
        ),
        GeneratedBodyShape::BoundExpressionReturn {
            value_name,
            value_kind,
            expression,
        } => GeneratedBodyShape::BoundExpressionReturn {
            value_name,
            value_kind,
            expression: apply_cache_binding_name_in_expression(expression, cache_binding_name),
        },
        GeneratedBodyShape::AssignedExpressionReturn {
            value_name,
            value_kind,
            expression,
        } => GeneratedBodyShape::AssignedExpressionReturn {
            value_name,
            value_kind,
            expression: apply_cache_binding_name_in_expression(expression, cache_binding_name),
        },
        GeneratedBodyShape::ZeroDependencyMemoizedReturn {
            value_name,
            value_kind,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::ZeroDependencyMemoizedReturn {
            value_name,
            value_kind,
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
            value_name,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
            value_name,
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::SingleDependencyMemoizedReturn {
            value_name,
            value_kind,
            dep_slot,
            dep_expr,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::SingleDependencyMemoizedReturn {
            value_name,
            value_kind,
            dep_slot,
            dep_expr: apply_cache_binding_name_in_expression(dep_expr, cache_binding_name),
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
            value_name,
            dep_slot,
            dep_expr,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
            value_name,
            dep_slot,
            dep_expr: apply_cache_binding_name_in_expression(dep_expr, cache_binding_name),
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::MultiDependencyMemoizedReturn {
            value_name,
            value_kind,
            deps,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::MultiDependencyMemoizedReturn {
            value_name,
            value_kind,
            deps: deps
                .into_iter()
                .map(|(slot, expression)| {
                    (
                        slot,
                        apply_cache_binding_name_in_expression(expression, cache_binding_name),
                    )
                })
                .collect(),
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
            value_name,
            deps,
            value_slot,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_setup_statements,
            memoized_expr,
        } => GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
            value_name,
            deps: deps
                .into_iter()
                .map(|(slot, expression)| {
                    (
                        slot,
                        apply_cache_binding_name_in_expression(expression, cache_binding_name),
                    )
                })
                .collect(),
            value_slot,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_setup_statements: memoized_setup_statements
                .into_iter()
                .map(|source| {
                    apply_cache_binding_name_in_statement_source(source, cache_binding_name)
                })
                .collect(),
            memoized_expr: memoized_expr.map(|expression| {
                apply_cache_binding_name_in_expression(expression, cache_binding_name)
            }),
        },
        GeneratedBodyShape::MemoizedComputedReturn {
            value_name,
            value_kind,
            deps,
            value_slot,
            computation,
        } => GeneratedBodyShape::MemoizedComputedReturn {
            value_name,
            value_kind,
            deps: deps
                .into_iter()
                .map(|(slot, expression)| {
                    (
                        slot,
                        apply_cache_binding_name_in_expression(expression, cache_binding_name),
                    )
                })
                .collect(),
            value_slot,
            computation: Box::new(apply_generated_body_shape_cache_binding_name(
                *computation,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::SingleSlotMemoizedReturn {
            value_name,
            value_kind,
            temp_name,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_expr,
        } => GeneratedBodyShape::SingleSlotMemoizedReturn {
            value_name,
            value_kind,
            temp_name,
            memoized_bindings: apply_bindings(memoized_bindings, cache_binding_name),
            memoized_assignments: apply_assignments(memoized_assignments, cache_binding_name),
            memoized_expressions: memoized_expressions
                .into_iter()
                .map(|expression| {
                    apply_cache_binding_name_in_expression(expression, cache_binding_name)
                })
                .collect(),
            memoized_expr: apply_cache_binding_name_in_expression(
                memoized_expr,
                cache_binding_name,
            ),
        },
        GeneratedBodyShape::WrappedReturnExpression {
            source_name,
            expression,
            inner,
        } => GeneratedBodyShape::WrappedReturnExpression {
            source_name: apply_cache_binding_name_in_expression(source_name, cache_binding_name),
            expression: apply_cache_binding_name_in_expression(expression, cache_binding_name),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner,
        } => GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name: apply_cache_binding_name_in_expression(source_name, cache_binding_name),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::AliasedReturn {
            alias_name,
            alias_kind,
            source_name,
            inner,
        } => GeneratedBodyShape::AliasedReturn {
            alias_name,
            alias_kind,
            source_name: apply_cache_binding_name_in_expression(source_name, cache_binding_name),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } => GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
        GeneratedBodyShape::PrefixedBindings { bindings, inner } => {
            GeneratedBodyShape::PrefixedBindings {
                bindings: apply_bindings(bindings, cache_binding_name),
                inner: Box::new(apply_generated_body_shape_cache_binding_name(
                    *inner,
                    cache_binding_name,
                )),
            }
        }
        GeneratedBodyShape::PrefixedExpressionStatements { expressions, inner } => {
            GeneratedBodyShape::PrefixedExpressionStatements {
                expressions: expressions
                    .into_iter()
                    .map(|expression| {
                        apply_cache_binding_name_in_expression(expression, cache_binding_name)
                    })
                    .collect(),
                inner: Box::new(apply_generated_body_shape_cache_binding_name(
                    *inner,
                    cache_binding_name,
                )),
            }
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner } => {
            GeneratedBodyShape::PrefixedAssignments {
                assignments: apply_assignments(assignments, cache_binding_name),
                inner: Box::new(apply_generated_body_shape_cache_binding_name(
                    *inner,
                    cache_binding_name,
                )),
            }
        }
        GeneratedBodyShape::Sequential { prefix, inner } => GeneratedBodyShape::Sequential {
            prefix: Box::new(apply_generated_body_shape_cache_binding_name(
                *prefix,
                cache_binding_name,
            )),
            inner: Box::new(apply_generated_body_shape_cache_binding_name(
                *inner,
                cache_binding_name,
            )),
        },
    }
}

fn analyze_rendered_generated_body_shape_source(source: &str) -> Option<GeneratedBodyShape> {
    let shape = fully_canonicalize_generated_body_shape(analyze_generated_body_shape(source));
    (!matches!(shape, GeneratedBodyShape::Unknown)).then_some(shape)
}

fn push_indented_source_lines(lines: &mut Vec<String>, source: &str, indent: usize) {
    let padding = " ".repeat(indent);
    for line in source.lines() {
        lines.push(format!("{padding}{line}"));
    }
}

fn push_indented_statement_sources(lines: &mut Vec<String>, sources: &[String], indent: usize) {
    for source in sources {
        push_indented_source_lines(lines, source, indent);
    }
}

fn render_memo_guard_test_source(
    cx: &mut Context,
    deps: &[(u32, String)],
    zero_dep_sentinel_slot: Option<u32>,
) -> Option<(Vec<String>, String)> {
    let cache_binding_name = cx.synthesize_name("$");
    if deps.is_empty() {
        let sentinel_slot = zero_dep_sentinel_slot?;
        let mut test = render_cache_slot_comparison_expression_ast(
            &cache_binding_name,
            sentinel_slot,
            BinaryOperator::StrictEq,
            &render_symbol_for_call_expression_source(MEMO_CACHE_SENTINEL),
        )?;
        if cx.disable_memoization_for_debugging {
            test = render_logical_expression_ast(&test, LogicalOperator::Or, "true")?;
        }
        return Some((Vec::new(), test));
    }

    let mut guard_prefix = Vec::new();
    let mut guard_terms = Vec::with_capacity(deps.len());
    for (slot, dep_expr) in deps {
        let comparison = render_cache_slot_comparison_expression_ast(
            &cache_binding_name,
            *slot,
            BinaryOperator::StrictNotEq,
            dep_expr,
        )?;
        if cx.enable_change_variable_codegen {
            let change_name = cx.synthesize_name(&format!("c_{}", slot));
            guard_prefix.push(
                render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Const,
                    &change_name,
                    Some(&comparison),
                )?
                .trim_end()
                .to_string(),
            );
            guard_terms.push(change_name);
        } else {
            guard_terms.push(comparison);
        }
    }

    let mut test = render_logical_chain_expression_ast(&guard_terms, LogicalOperator::Or)?;
    if cx.disable_memoization_for_debugging {
        test = render_logical_expression_ast(&test, LogicalOperator::Or, "true")?;
    }
    Some((guard_prefix, test))
}

fn render_cached_value_store_sources(
    cached_values: &[GeneratedCachedValue],
    cache_binding_name: &str,
) -> Option<Vec<String>> {
    let mut stores = Vec::with_capacity(cached_values.len());
    for value in cached_values {
        stores.push(
            render_cache_slot_store_statement_ast(cache_binding_name, value.slot, &value.name)?
                .trim_end()
                .to_string(),
        );
    }
    Some(stores)
}

fn render_cached_value_restore_sources(
    restored_values: &[GeneratedCachedValue],
    cache_binding_name: &str,
) -> Option<Vec<String>> {
    let mut restores = Vec::with_capacity(restored_values.len());
    for value in restored_values {
        restores.push(
            render_cache_slot_load_assignment_statement_ast(
                &value.name,
                cache_binding_name,
                value.slot,
            )?
            .trim_end()
            .to_string(),
        );
    }
    Some(restores)
}

fn render_dependency_store_sources(
    deps: &[(u32, String)],
    cache_binding_name: &str,
) -> Option<Vec<String>> {
    let mut stores = Vec::with_capacity(deps.len());
    for (slot, dep_expr) in deps {
        stores.push(
            render_cache_slot_store_statement_ast(cache_binding_name, *slot, dep_expr)?
                .trim_end()
                .to_string(),
        );
    }
    Some(stores)
}

fn render_direct_memoized_setup_sources(
    value_name: &str,
    parts: &DirectMemoizedExistingReturnParts,
) -> Option<Vec<String>> {
    let mut statements = Vec::new();
    for binding in &parts.bindings {
        statements.push(render_generated_binding_statement(binding)?);
    }
    for assignment in &parts.assignments {
        statements.push(render_generated_assignment_statement(assignment)?);
    }
    for expression in &parts.expressions {
        statements.push(render_generated_expression_statement(expression)?);
    }
    statements.extend(parts.setup_statements.iter().cloned());
    if let Some(memoized_expr) = parts.memoized_expr.as_ref() {
        statements.push(
            render_reactive_assignment_statement_ast(value_name, memoized_expr)?
                .trim_end()
                .to_string(),
        );
    }
    Some(statements)
}

fn render_structural_check_call_source(
    old_value: String,
    new_value: String,
    name: &str,
    function_name: &str,
    phase: &str,
    scope_loc: &str,
) -> Option<String> {
    render_generated_expression_statement(&render_call_expression_from_rendered_args_ast(
        "$structuralCheck",
        &[
            old_value,
            new_value,
            format!("\"{}\"", escape_string(name)),
            format!("\"{}\"", escape_string(function_name)),
            format!("\"{}\"", phase),
            format!("\"{}\"", escape_string(scope_loc)),
        ],
        false,
    )?)
}

struct OptionSensitiveCachedValuesShapeSpec<'a> {
    scope: &'a ReactiveScope,
    instructions: &'a ReactiveBlock,
    deps: &'a [(u32, String)],
    zero_dep_sentinel_slot: Option<u32>,
    setup_statements: &'a [String],
    cached_values: &'a [GeneratedCachedValue],
    restored_values: &'a [GeneratedCachedValue],
}

fn build_option_sensitive_cached_values_shape(
    cx: &mut Context,
    spec: OptionSensitiveCachedValuesShapeSpec<'_>,
) -> Option<GeneratedBodyShape> {
    let debug = std::env::var("DEBUG_DIRECT_OPTION_SHAPE").is_ok();
    let needs_option_sensitive_shape = (cx.enable_change_detection_for_debugging
        && !spec.deps.is_empty())
        || cx.disable_memoization_for_debugging
        || (cx.enable_change_variable_codegen && !spec.deps.is_empty());
    if !needs_option_sensitive_shape {
        return None;
    }

    let cache_binding_name = cx.synthesize_name("$");
    let (guard_prefix, test) =
        render_memo_guard_test_source(cx, spec.deps, spec.zero_dep_sentinel_slot)?;
    let dep_store_sources = render_dependency_store_sources(spec.deps, &cache_binding_name)?;
    let cached_value_store_sources =
        render_cached_value_store_sources(spec.cached_values, &cache_binding_name)?;
    let restored_sources =
        render_cached_value_restore_sources(spec.restored_values, &cache_binding_name)?;
    let mut lines = guard_prefix;

    if cx.enable_change_detection_for_debugging && !spec.deps.is_empty() {
        let scope_loc = format_change_detection_scope_loc(spec.scope, spec.instructions);
        let condition_name = cx.synthesize_name("condition");
        lines.push("{".to_string());
        push_indented_statement_sources(&mut lines, spec.setup_statements, 2);
        lines.push(format!("  let {condition_name} = {test};"));
        lines.push(format!("  if (!{condition_name}) {{"));
        for value in spec.restored_values {
            let old_name = cx.synthesize_name(&format!("old${}", value.name));
            lines.push(format!(
                "    let {old_name} = {};",
                render_cache_slot_access_expression_ast(&cache_binding_name, value.slot)?
            ));
            lines.push(format!(
                "    {}",
                render_structural_check_call_source(
                    old_name,
                    value.name.clone(),
                    &value.name,
                    &cx.function_name,
                    "cached",
                    &scope_loc,
                )?
            ));
        }
        lines.push("  }".to_string());
        push_indented_statement_sources(&mut lines, &dep_store_sources, 2);
        push_indented_statement_sources(&mut lines, &cached_value_store_sources, 2);
        lines.push(format!("  if ({condition_name}) {{"));
        push_indented_statement_sources(&mut lines, spec.setup_statements, 4);
        for value in spec.cached_values {
            let cached_access =
                render_cache_slot_access_expression_ast(&cache_binding_name, value.slot)?;
            lines.push(format!(
                "    {}",
                render_structural_check_call_source(
                    cached_access.clone(),
                    value.name.clone(),
                    &value.name,
                    &cx.function_name,
                    "recomputed",
                    &scope_loc,
                )?
            ));
            lines.push(format!("    {} = {};", value.name, cached_access));
        }
        lines.push("  }".to_string());
        lines.push("}".to_string());
    } else {
        lines.push(format!("if ({test}) {{"));
        push_indented_statement_sources(&mut lines, spec.setup_statements, 2);
        push_indented_statement_sources(&mut lines, &dep_store_sources, 2);
        push_indented_statement_sources(&mut lines, &cached_value_store_sources, 2);
        lines.push("} else {".to_string());
        push_indented_statement_sources(&mut lines, &restored_sources, 2);
        lines.push("}".to_string());
    }

    let source = lines.join("\n");
    let analyzed = analyze_rendered_generated_body_shape_source(&source);
    if debug && analyzed.is_none() {
        eprintln!(
            "[DIRECT_OPTION_SHAPE] cached-values fn={} deps={:?} sentinel={:?} source=\n{}",
            cx.function_name, spec.deps, spec.zero_dep_sentinel_slot, source
        );
    }
    analyzed
}

struct OptionSensitiveMemoizedReturnShapeSpec<'a> {
    value_name: &'a str,
    declare_value_kind: Option<ast::VariableDeclarationKind>,
    deps: &'a [(u32, String)],
    zero_dep_sentinel_slot: Option<u32>,
    value_slot: u32,
    parts: &'a DirectMemoizedExistingReturnParts,
    change_detection_scope: Option<(&'a ReactiveScope, &'a ReactiveBlock)>,
}

fn build_option_sensitive_memoized_return_shape(
    cx: &mut Context,
    spec: OptionSensitiveMemoizedReturnShapeSpec<'_>,
) -> Option<GeneratedBodyShape> {
    let debug = std::env::var("DEBUG_DIRECT_OPTION_SHAPE").is_ok();
    let needs_change_detection_shape = cx.enable_change_detection_for_debugging
        && !spec.deps.is_empty()
        && spec.change_detection_scope.is_some();
    let needs_option_sensitive_shape = needs_change_detection_shape
        || cx.disable_memoization_for_debugging
        || (cx.enable_change_variable_codegen && !spec.deps.is_empty());
    if !needs_option_sensitive_shape {
        return None;
    }

    let cache_binding_name = cx.synthesize_name("$");
    let (guard_prefix, test) =
        render_memo_guard_test_source(cx, spec.deps, spec.zero_dep_sentinel_slot)?;
    let setup_sources = render_direct_memoized_setup_sources(spec.value_name, spec.parts)?;
    let dep_store_sources = render_dependency_store_sources(spec.deps, &cache_binding_name)?;
    let restore_source = render_cache_slot_load_assignment_statement_ast(
        spec.value_name,
        &cache_binding_name,
        spec.value_slot,
    )?
    .trim_end()
    .to_string();
    let value_store_source = render_cache_slot_store_statement_ast(
        &cache_binding_name,
        spec.value_slot,
        spec.value_name,
    )?
    .trim_end()
    .to_string();

    let mut lines = guard_prefix;
    if let Some(value_kind) = spec.declare_value_kind {
        lines.push(render_generated_declaration_statement(
            &GeneratedDeclaration {
                kind: value_kind,
                pattern: spec.value_name.to_string(),
            },
        )?);
    }

    if needs_change_detection_shape {
        let (scope, instructions) = spec.change_detection_scope?;
        let scope_loc = format_change_detection_scope_loc(scope, instructions);
        let condition_name = cx.synthesize_name("condition");
        lines.push("{".to_string());
        push_indented_statement_sources(&mut lines, &setup_sources, 2);
        lines.push(format!("  let {condition_name} = {test};"));
        lines.push(format!("  if (!{condition_name}) {{"));
        let old_name = cx.synthesize_name(&format!("old${}", spec.value_name));
        lines.push(format!(
            "    let {old_name} = {};",
            render_cache_slot_access_expression_ast(&cache_binding_name, spec.value_slot)?
        ));
        lines.push(format!(
            "    {}",
            render_structural_check_call_source(
                old_name,
                spec.value_name.to_string(),
                spec.value_name,
                &cx.function_name,
                "cached",
                &scope_loc,
            )?
        ));
        lines.push("  }".to_string());
        push_indented_statement_sources(&mut lines, &dep_store_sources, 2);
        push_indented_source_lines(&mut lines, &value_store_source, 2);
        lines.push(format!("  if ({condition_name}) {{"));
        push_indented_statement_sources(&mut lines, &setup_sources, 4);
        let cached_access =
            render_cache_slot_access_expression_ast(&cache_binding_name, spec.value_slot)?;
        lines.push(format!(
            "    {}",
            render_structural_check_call_source(
                cached_access.clone(),
                spec.value_name.to_string(),
                spec.value_name,
                &cx.function_name,
                "recomputed",
                &scope_loc,
            )?
        ));
        lines.push(format!("    {} = {cached_access};", spec.value_name));
        lines.push("  }".to_string());
        lines.push("}".to_string());
    } else {
        lines.push(format!("if ({test}) {{"));
        push_indented_statement_sources(&mut lines, &setup_sources, 2);
        push_indented_statement_sources(&mut lines, &dep_store_sources, 2);
        push_indented_source_lines(&mut lines, &value_store_source, 2);
        lines.push("} else {".to_string());
        push_indented_source_lines(&mut lines, &restore_source, 2);
        lines.push("}".to_string());
    }
    lines.push(format!("return {};", spec.value_name));

    let source = lines.join("\n");
    let analyzed = analyze_rendered_generated_body_shape_source(&source);
    if debug && analyzed.is_none() {
        eprintln!(
            "[DIRECT_OPTION_SHAPE] return fn={} value={} deps={:?} sentinel={:?} source=\n{}",
            cx.function_name, spec.value_name, spec.deps, spec.zero_dep_sentinel_slot, source
        );
    }
    analyzed
}

fn try_decompose_direct_memoized_declared_return_shape(
    shape: GeneratedBodyShape,
    value_name: &str,
) -> Option<DirectMemoizedExistingReturnParts> {
    match shape {
        GeneratedBodyShape::ReturnIdentifier(name) if name == value_name => {
            Some(DirectMemoizedExistingReturnParts::default())
        }
        GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner,
        } if alias_name == value_name => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, &source_name)?;
            if parts.memoized_expr.is_none() {
                parts.memoized_expr = Some(source_name);
            }
            Some(parts)
        }
        GeneratedBodyShape::AliasedReturn {
            alias_name,
            source_name,
            inner,
            ..
        } if alias_name == value_name => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, &source_name)?;
            if parts.memoized_expr.is_none() {
                parts.memoized_expr = Some(source_name);
            }
            Some(parts)
        }
        GeneratedBodyShape::AssignedExpressionReturn {
            value_name: assigned_name,
            expression,
            ..
        } if assigned_name == value_name => Some(DirectMemoizedExistingReturnParts {
            memoized_expr: Some(expression),
            ..Default::default()
        }),
        GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, value_name)?;
            let mut prefix_statements = Vec::new();
            for declaration in declarations {
                if declaration.pattern == value_name {
                    continue;
                }
                prefix_statements.push(render_generated_declaration_statement(&declaration)?);
            }
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedBindings { bindings, inner } => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, value_name)?;
            let mut prefix_statements = Vec::new();
            for binding in bindings {
                if binding.pattern == value_name {
                    if parts.memoized_expr.is_some() {
                        return None;
                    }
                    parts.memoized_expr = Some(binding.expression);
                } else {
                    prefix_statements.push(render_generated_binding_statement(&binding)?);
                }
            }
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedAssignments { assignments, inner } => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, value_name)?;
            let mut prefix_statements = Vec::new();
            for assignment in assignments {
                if assignment.target == value_name {
                    if parts.memoized_expr.is_some() {
                        return None;
                    }
                    parts.memoized_expr = Some(assignment.value);
                } else {
                    prefix_statements.push(render_generated_assignment_statement(&assignment)?);
                }
            }
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::PrefixedExpressionStatements { expressions, inner } => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, value_name)?;
            let mut prefix_statements = expressions
                .iter()
                .map(|expression| render_generated_expression_statement(expression))
                .collect::<Option<Vec<_>>>()?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        GeneratedBodyShape::Sequential { prefix, inner } => {
            let mut parts =
                try_decompose_direct_memoized_declared_return_shape(*inner, value_name)?;
            let mut prefix_statements =
                try_render_statement_sources_from_generated_body_shape(&prefix)?;
            prefix_statements.extend(parts.setup_statements);
            parts.setup_statements = prefix_statements;
            Some(parts)
        }
        _ => None,
    }
}

fn can_inline_direct_scope_shape(scope: &ReactiveScope) -> bool {
    scope.dependencies.is_empty()
        && scope.declarations.is_empty()
        && scope.reassignments.is_empty()
        && scope.merged_id.is_none()
        && scope.early_return_value.is_none()
}

fn can_inline_direct_pruned_scope_shape(scope: &ReactiveScope) -> bool {
    scope.merged_id.is_none() && scope.early_return_value.is_none()
}

fn try_wrap_generated_body_shape_with_instruction_prefix(
    cx: &mut Context,
    instr: &ReactiveInstruction,
    inner: GeneratedBodyShape,
) -> Option<GeneratedBodyShape> {
    let shape = match &instr.value {
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => {
            let kind =
                variable_declaration_kind(lvalue.kind).unwrap_or(ast::VariableDeclarationKind::Let);
            let pattern = identifier_name_with_cx(cx, &lvalue.place.identifier);
            if kind == ast::VariableDeclarationKind::Let
                && let Some(expression) = crate::optimization::dead_code_elimination::preserved_top_level_let_initializer_for_decl(lvalue.place.identifier.declaration_id)
            {
                Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind,
                        pattern,
                        expression,
                        promote_to_function_declaration: false,
                    }],
                    inner: Box::new(inner),
                })
            } else {
                Some(GeneratedBodyShape::PrefixedDeclarations {
                    declarations: vec![GeneratedDeclaration { kind, pattern }],
                    inner: Box::new(inner),
                })
            }
        }
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => match lvalue.kind {
            InstructionKind::Const
            | InstructionKind::Let
            | InstructionKind::Catch
            | InstructionKind::HoistedConst
            | InstructionKind::HoistedLet => {
                let pattern = identifier_name_with_cx(cx, &lvalue.place.identifier);
                let expression = codegen_place_to_expression(cx, value);
                Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind: variable_declaration_kind(lvalue.kind)?,
                        pattern,
                        expression,
                        promote_to_function_declaration: cx
                            .function_decl_decls
                            .contains(&lvalue.place.identifier.declaration_id),
                    }],
                    inner: Box::new(inner),
                })
            }
            InstructionKind::Reassign => {
                let target = identifier_name_with_cx(cx, &lvalue.place.identifier);
                let value = codegen_place_to_expression(cx, value);
                Some(GeneratedBodyShape::PrefixedAssignments {
                    assignments: vec![GeneratedAssignment { target, value }],
                    inner: Box::new(inner),
                })
            }
            InstructionKind::Function => {
                let pattern = identifier_name_with_cx(cx, &lvalue.place.identifier);
                let expression = codegen_place_to_expression(cx, value);
                Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind: ast::VariableDeclarationKind::Const,
                        pattern,
                        expression,
                        promote_to_function_declaration: true,
                    }],
                    inner: Box::new(inner),
                })
            }
            InstructionKind::HoistedFunction => {
                let pattern = identifier_name_with_cx(cx, &lvalue.place.identifier);
                let expression = codegen_place_to_expression(cx, value);
                Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind: ast::VariableDeclarationKind::Const,
                        pattern,
                        expression,
                        promote_to_function_declaration: cx
                            .function_decl_decls
                            .contains(&lvalue.place.identifier.declaration_id),
                    }],
                    inner: Box::new(inner),
                })
            }
        },
        InstructionValue::Destructure { lvalue, value, .. } => {
            let pattern = codegen_pattern(cx, &lvalue.pattern);
            let expression = codegen_place_to_expression(cx, value);
            let declaration_kind =
                reactive_destructure_declaration_kind(cx, lvalue.kind, &lvalue.pattern);
            match lvalue.kind {
                InstructionKind::Reassign => Some(GeneratedBodyShape::PrefixedAssignments {
                    assignments: vec![GeneratedAssignment {
                        target: pattern,
                        value: expression,
                    }],
                    inner: Box::new(inner),
                }),
                _ => Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind: declaration_kind,
                        pattern,
                        expression,
                        promote_to_function_declaration: false,
                    }],
                    inner: Box::new(inner),
                }),
            }
        }
        _ => rendered_single_statement_prefix(
            codegen_instruction_nullable(cx, instr)?.as_str(),
            inner,
        ),
    };
    if shape.is_none() && std::env::var("DEBUG_DIRECT_BODY_SHAPE_TRACE").is_ok() {
        let rendered = codegen_instruction_nullable(cx, instr).unwrap_or_default();
        eprintln!(
            "[DIRECT_BODY_SHAPE_TRACE] wrap_prefix_none tag={} lvalue={:?} rendered={}",
            instruction_value_tag(&instr.value),
            instr.lvalue.as_ref().and_then(|place| place
                .identifier
                .name
                .as_ref()
                .map(|name| name.value())),
            rendered.replace('\n', "\\n"),
        );
    }
    shape
}

fn rendered_single_statement_prefix(
    rendered: &str,
    inner: GeneratedBodyShape,
) -> Option<GeneratedBodyShape> {
    let allocator = Allocator::default();
    let statements = parse_statement_list_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        rendered,
    )
    .ok()?;
    let [statement] = statements.as_slice() else {
        return None;
    };
    match statement {
        ast::Statement::VariableDeclaration(declaration) => {
            if declaration.declarations.len() != 1 {
                return None;
            }
            let declarator = &declaration.declarations[0];
            let pattern = codegen_binding_pattern_with_flow_cast_restore(&declarator.id);
            if let Some(init) = declarator.init.as_ref() {
                let expression = strip_top_level_parenthesized_expression(
                    codegen_expression_with_flow_cast_restore(init),
                );
                Some(GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![GeneratedBinding {
                        kind: declaration.kind,
                        pattern,
                        expression,
                        promote_to_function_declaration: false,
                    }],
                    inner: Box::new(inner),
                })
            } else {
                Some(GeneratedBodyShape::PrefixedDeclarations {
                    declarations: vec![GeneratedDeclaration {
                        kind: declaration.kind,
                        pattern,
                    }],
                    inner: Box::new(inner),
                })
            }
        }
        ast::Statement::ExpressionStatement(expr_stmt) => {
            if let ast::Expression::AssignmentExpression(assignment) =
                expr_stmt.expression.without_parentheses()
                && assignment.operator == AssignmentOperator::Assign
            {
                return Some(GeneratedBodyShape::PrefixedAssignments {
                    assignments: vec![GeneratedAssignment {
                        target: codegen_assignment_target_with_flow_cast_restore(&assignment.left),
                        value: codegen_expression_with_flow_cast_restore(&assignment.right),
                    }],
                    inner: Box::new(inner),
                });
            }
            Some(GeneratedBodyShape::PrefixedExpressionStatements {
                expressions: vec![codegen_expression_with_flow_cast_restore(
                    &expr_stmt.expression,
                )],
                inner: Box::new(inner),
            })
        }
        ast::Statement::DebuggerStatement(_) => Some(GeneratedBodyShape::Sequential {
            prefix: Box::new(GeneratedBodyShape::DebuggerStatements(1)),
            inner: Box::new(inner),
        }),
        _ => {
            let analyzed =
                fully_canonicalize_generated_body_shape(analyze_generated_body_shape(rendered));
            if matches!(analyzed, GeneratedBodyShape::Unknown) {
                None
            } else if generated_body_shape_is_empty(&analyzed) {
                Some(inner)
            } else {
                Some(GeneratedBodyShape::Sequential {
                    prefix: Box::new(analyzed),
                    inner: Box::new(inner),
                })
            }
        }
    }
}

fn variable_declaration_kind(kind: InstructionKind) -> Option<ast::VariableDeclarationKind> {
    match kind {
        InstructionKind::Const | InstructionKind::HoistedConst => {
            Some(ast::VariableDeclarationKind::Const)
        }
        InstructionKind::Let | InstructionKind::Catch | InstructionKind::HoistedLet => {
            Some(ast::VariableDeclarationKind::Let)
        }
        InstructionKind::Reassign => None,
        InstructionKind::Function | InstructionKind::HoistedFunction => None,
    }
}

fn try_build_generated_body_shape_from_reactive_terminal(
    cx: &mut Context,
    terminal: &ReactiveTerminal,
) -> Option<GeneratedBodyShape> {
    match terminal {
        ReactiveTerminal::Break {
            target,
            target_kind,
            ..
        } => match target_kind {
            ReactiveTerminalTargetKind::Implicit => {
                Some(GeneratedBodyShape::ExpressionStatements(vec![]))
            }
            ReactiveTerminalTargetKind::Unlabeled => Some(GeneratedBodyShape::Break(None)),
            ReactiveTerminalTargetKind::Labeled => {
                Some(GeneratedBodyShape::Break(Some(format!("bb{}", target.0))))
            }
        },
        ReactiveTerminal::Continue {
            target,
            target_kind,
            ..
        } => match target_kind {
            ReactiveTerminalTargetKind::Implicit => {
                Some(GeneratedBodyShape::ExpressionStatements(vec![]))
            }
            ReactiveTerminalTargetKind::Unlabeled => Some(GeneratedBodyShape::Continue(None)),
            ReactiveTerminalTargetKind::Labeled => Some(GeneratedBodyShape::Continue(Some(
                format!("bb{}", target.0),
            ))),
        },
        ReactiveTerminal::Return { value, .. } => {
            let expr = codegen_place_to_expression(cx, value);
            if expr == "undefined" {
                Some(GeneratedBodyShape::ReturnVoid)
            } else if is_simple_generated_identifier(&expr) {
                Some(GeneratedBodyShape::ReturnIdentifier(expr))
            } else {
                Some(GeneratedBodyShape::ReturnExpression(expr))
            }
        }
        ReactiveTerminal::Throw { value, .. } => {
            let expr = codegen_place_to_expression(cx, value);
            Some(GeneratedBodyShape::ThrowExpression(expr))
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            let test = codegen_place_to_expression(cx, test);
            let mut consequent_cx = cx.clone();
            let consequent = Box::new(try_build_generated_body_shape_from_reactive_block(
                &mut consequent_cx,
                consequent,
            )?);
            if let Some(alternate) = alternate {
                // Branch-local temp names can be reused across mutually exclusive arms,
                // but memo slots still need to stay globally unique.
                cx.next_cache_index = consequent_cx.next_cache_index;
                let mut alternate_cx = cx.clone();
                let alternate = Box::new(try_build_generated_body_shape_from_reactive_block(
                    &mut alternate_cx,
                    alternate,
                )?);
                cx.next_cache_index = alternate_cx.next_cache_index;
                Some(GeneratedBodyShape::ConditionalBranches {
                    test,
                    consequent,
                    alternate,
                })
            } else {
                cx.next_cache_index = consequent_cx.next_cache_index;
                Some(GeneratedBodyShape::GuardedBody {
                    test,
                    inner: consequent,
                })
            }
        }
        ReactiveTerminal::Switch { test, cases, .. } => {
            let discriminant = codegen_place_to_expression(cx, test);
            let mut generated_cases = Vec::with_capacity(cases.len());
            for case in cases {
                let consequent = match &case.block {
                    Some(block) => {
                        let mut case_cx = cx.clone();
                        let inner = try_build_generated_body_shape_from_reactive_block(
                            &mut case_cx,
                            block,
                        )?;
                        // Keep branch-local temps isolated, but memo slots must
                        // remain globally unique across switch arms to match
                        // upstream cache layout.
                        cx.next_cache_index = case_cx.next_cache_index;
                        if matches!(&inner, GeneratedBodyShape::ExpressionStatements(expressions) if expressions.is_empty())
                        {
                            inner
                        } else {
                            GeneratedBodyShape::Block {
                                inner: Box::new(inner),
                            }
                        }
                    }
                    None => GeneratedBodyShape::ExpressionStatements(vec![]),
                };
                generated_cases.push(GeneratedSwitchCase {
                    test: case
                        .test
                        .as_ref()
                        .map(|test| codegen_place_to_expression(cx, test)),
                    consequent,
                });
            }
            Some(GeneratedBodyShape::Switch {
                discriminant,
                cases: generated_cases,
            })
        }
        ReactiveTerminal::DoWhile {
            loop_block, test, ..
        } => Some(GeneratedBodyShape::DoWhileLoop {
            test: codegen_place_to_expression(cx, test),
            body: Box::new(try_build_generated_body_shape_from_reactive_block(
                cx, loop_block,
            )?),
        }),
        ReactiveTerminal::While {
            test, loop_block, ..
        } => Some(GeneratedBodyShape::WhileLoop {
            test: codegen_place_to_expression(cx, test),
            body: Box::new(try_build_generated_body_shape_from_reactive_block(
                cx, loop_block,
            )?),
        }),
        ReactiveTerminal::For {
            init,
            test,
            update,
            update_value,
            loop_block,
            ..
        } => {
            let mut init_code = codegen_for_init(cx, init);
            let test_expr = codegen_place_to_expression(cx, test);
            let update_code = update
                .as_ref()
                .map(|block| codegen_for_update(cx, block, update_value.as_deref()))
                .unwrap_or_default();
            if let Some(filled_init) =
                maybe_fill_for_header_initializer_from_update(&init_code, &update_code)
            {
                init_code = filled_init;
            }
            Some(GeneratedBodyShape::ForLoop {
                init: (!init_code.is_empty()).then_some(init_code),
                test: Some(test_expr),
                update: (!update_code.is_empty()).then_some(update_code),
                body: Box::new(try_build_generated_body_shape_from_reactive_block(
                    cx, loop_block,
                )?),
            })
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            let init_out = codegen_block_no_reset(cx, init);
            let (kind, lval, collection_place) = extract_for_in_of_header_from_init(cx, init);
            let collection_expr = if let Some(place) = collection_place {
                codegen_place_to_expression(cx, &place)
            } else if test.identifier.id.0 == 0 {
                let rendered_init = init_out.trim().trim_end_matches(';').to_string();
                if rendered_init.is_empty() {
                    codegen_place_to_expression(cx, test)
                } else {
                    rendered_init
                }
            } else {
                codegen_place_to_expression(cx, test)
            };
            Some(GeneratedBodyShape::ForOfLoop {
                left: format!("{kind} {lval}"),
                right: collection_expr,
                body: Box::new(try_build_generated_body_shape_from_reactive_block(
                    cx, loop_block,
                )?),
            })
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            let init_out = codegen_block_no_reset(cx, init);
            let (kind, lval, collection_place) = extract_for_in_of_header_from_init(cx, init);
            let collection_expr = if let Some(place) = collection_place {
                codegen_place_to_expression(cx, &place)
            } else {
                init_out.trim().trim_end_matches(';').to_string()
            };
            Some(GeneratedBodyShape::ForInLoop {
                left: format!("{kind} {lval}"),
                right: collection_expr,
                body: Box::new(try_build_generated_body_shape_from_reactive_block(
                    cx, loop_block,
                )?),
            })
        }
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => Some(GeneratedBodyShape::TryCatch {
            catch_param: handler_binding
                .as_ref()
                .map(|binding| identifier_name_with_cx(cx, &binding.identifier)),
            try_body: Box::new(try_build_generated_body_shape_from_reactive_block(
                cx, block,
            )?),
            catch_body: Box::new(try_build_generated_body_shape_from_reactive_block(
                cx, handler,
            )?),
        }),
        ReactiveTerminal::Label { block, .. } => {
            try_build_generated_body_shape_from_reactive_block(cx, block)
        }
    }
}

pub(crate) fn analyze_generated_body_shape(body: &str) -> GeneratedBodyShape {
    GENERATED_BODY_SHAPE_CACHE.with(|cache| cache.borrow_mut().clear());
    analyze_generated_body_shape_impl(body, true)
}

fn analyze_generated_body_shape_impl(body: &str, allow_sequential: bool) -> GeneratedBodyShape {
    let cache_key = (allow_sequential, body.to_string());
    if let Some(shape) =
        GENERATED_BODY_SHAPE_CACHE.with(|cache| cache.borrow().get(&cache_key).cloned())
    {
        return shape;
    }

    let shape = analyze_generated_body_shape_uncached(body, allow_sequential, &HashMap::new());
    GENERATED_BODY_SHAPE_CACHE.with(|cache| {
        cache.borrow_mut().insert(cache_key, shape.clone());
    });
    shape
}

fn analyze_generated_body_shape_impl_with_guard_aliases(
    body: &str,
    allow_sequential: bool,
    guard_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
) -> GeneratedBodyShape {
    if guard_aliases.is_empty() {
        analyze_generated_body_shape_impl(body, allow_sequential)
    } else {
        analyze_generated_body_shape_uncached(body, allow_sequential, guard_aliases)
    }
}

fn analyze_generated_body_shape_uncached(
    body: &str,
    allow_sequential: bool,
    guard_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
) -> GeneratedBodyShape {
    fn shape_returned_identifier(shape: &GeneratedBodyShape) -> Option<&str> {
        generated_body_shape_returned_identifier(shape)
    }

    fn cached_values_prefix_contains_name(prefix_shape: &GeneratedBodyShape, name: &str) -> bool {
        match prefix_shape {
            GeneratedBodyShape::ZeroDependencyMemoizedCachedValues { cached_values, .. }
            | GeneratedBodyShape::MemoizedCachedValues { cached_values, .. } => cached_values
                .iter()
                .any(|cached_value| cached_value.name == name),
            _ => false,
        }
    }

    fn cached_values_prefix_len(prefix_shape: &GeneratedBodyShape) -> usize {
        match prefix_shape {
            GeneratedBodyShape::ZeroDependencyMemoizedCachedValues { cached_values, .. }
            | GeneratedBodyShape::MemoizedCachedValues { cached_values, .. } => cached_values.len(),
            _ => 0,
        }
    }

    fn can_follow_cached_values_intermediate_prefix(shape: &GeneratedBodyShape) -> bool {
        matches!(
            shape,
            GeneratedBodyShape::Block { .. }
                | GeneratedBodyShape::Labeled { .. }
                | GeneratedBodyShape::Switch { .. }
                | GeneratedBodyShape::DebuggerStatements(_)
                | GeneratedBodyShape::GuardedBody { .. }
                | GeneratedBodyShape::GuardedExpressionStatements { .. }
                | GeneratedBodyShape::GuardedReturnPrefix { .. }
                | GeneratedBodyShape::ConditionalBranches { .. }
                | GeneratedBodyShape::GuardedAssignments { .. }
                | GeneratedBodyShape::WhileLoop { .. }
                | GeneratedBodyShape::DoWhileLoop { .. }
                | GeneratedBodyShape::ForLoop { .. }
                | GeneratedBodyShape::ForInLoop { .. }
                | GeneratedBodyShape::ForOfLoop { .. }
                | GeneratedBodyShape::GuardedAssignmentExpressions { .. }
                | GeneratedBodyShape::ZeroDependencyMemoizedCachedValues { .. }
                | GeneratedBodyShape::MemoizedCachedValues { .. }
                | GeneratedBodyShape::MemoizedEarlyReturnSentinel { .. }
                | GeneratedBodyShape::TryCatch { .. }
        )
    }

    fn can_follow_cached_values_prefix(
        prefix_shape: &GeneratedBodyShape,
        shape: &GeneratedBodyShape,
    ) -> bool {
        match shape {
            GeneratedBodyShape::Unknown => false,
            GeneratedBodyShape::Block { inner }
            | GeneratedBodyShape::Labeled { inner, .. }
            | GeneratedBodyShape::GuardedReturnPrefix { inner, .. }
            | GeneratedBodyShape::PrefixedDeclarations { inner, .. }
            | GeneratedBodyShape::PrefixedBindings { inner, .. }
            | GeneratedBodyShape::PrefixedExpressionStatements { inner, .. }
            | GeneratedBodyShape::PrefixedAssignments { inner, .. }
            | GeneratedBodyShape::GuardedBody { inner, .. } => {
                can_follow_cached_values_prefix(prefix_shape, inner)
            }
            GeneratedBodyShape::ConditionalBranches {
                consequent,
                alternate,
                ..
            } => {
                can_follow_cached_values_prefix(prefix_shape, consequent)
                    && can_follow_cached_values_prefix(prefix_shape, alternate)
            }
            GeneratedBodyShape::Sequential { prefix, inner } => {
                can_follow_cached_values_intermediate_prefix(prefix)
                    && can_follow_cached_values_prefix(prefix_shape, inner)
            }
            GeneratedBodyShape::ReturnIdentifier(name) => {
                !cached_values_prefix_contains_name(prefix_shape, name)
                    || cached_values_prefix_len(prefix_shape) > 1
            }
            GeneratedBodyShape::ReturnVoid
            | GeneratedBodyShape::ReturnExpression(_)
            | GeneratedBodyShape::ThrowExpression(_)
            | GeneratedBodyShape::Break(_)
            | GeneratedBodyShape::Continue(_)
            | GeneratedBodyShape::DebuggerStatements(_)
            | GeneratedBodyShape::ExpressionStatements(_)
            | GeneratedBodyShape::AssignmentStatements(_)
            | GeneratedBodyShape::GuardedExpressionStatements { .. }
            | GeneratedBodyShape::GuardedAssignments { .. }
            | GeneratedBodyShape::GuardedAssignmentExpressions { .. } => true,
            GeneratedBodyShape::ZeroDependencyMemoizedReturn { .. }
            | GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn { .. }
            | GeneratedBodyShape::SingleDependencyMemoizedReturn { .. }
            | GeneratedBodyShape::SingleDependencyMemoizedExistingReturn { .. }
            | GeneratedBodyShape::MultiDependencyMemoizedReturn { .. }
            | GeneratedBodyShape::MultiDependencyMemoizedExistingReturn { .. }
            | GeneratedBodyShape::MemoizedComputedReturn { .. }
            | GeneratedBodyShape::SingleSlotMemoizedReturn { .. } => true,
            GeneratedBodyShape::MemoizedEarlyReturnSentinel { .. } => true,
            GeneratedBodyShape::BoundExpressionReturn { .. }
            | GeneratedBodyShape::AssignedExpressionReturn { .. }
            | GeneratedBodyShape::WrappedReturnExpression { .. }
            | GeneratedBodyShape::AssignedAliasReturn { .. }
            | GeneratedBodyShape::AliasedReturn { .. } => false,
            GeneratedBodyShape::WhileLoop { .. }
            | GeneratedBodyShape::DoWhileLoop { .. }
            | GeneratedBodyShape::ForLoop { .. }
            | GeneratedBodyShape::ForInLoop { .. }
            | GeneratedBodyShape::ForOfLoop { .. }
            | GeneratedBodyShape::ZeroDependencyMemoizedCachedValues { .. }
            | GeneratedBodyShape::MemoizedCachedValues { .. }
            | GeneratedBodyShape::Switch { .. }
            | GeneratedBodyShape::TryCatch { .. } => true,
        }
    }

    fn binding_identifier_name(pattern: &ast::BindingPattern<'_>) -> Option<String> {
        match pattern {
            ast::BindingPattern::BindingIdentifier(identifier) => Some(identifier.name.to_string()),
            _ => None,
        }
    }

    fn expression_identifier_name<'a>(expression: &'a ast::Expression<'a>) -> Option<&'a str> {
        match expression.without_parentheses() {
            ast::Expression::Identifier(identifier) => Some(identifier.name.as_str()),
            _ => None,
        }
    }

    fn expression_is_identifier(expression: &ast::Expression<'_>, name: &str) -> bool {
        expression_identifier_name(expression).is_some_and(|identifier| identifier == name)
    }

    fn expression_numeric_slot(expression: &ast::Expression<'_>) -> Option<u32> {
        let ast::Expression::NumericLiteral(number) = expression.without_parentheses() else {
            return None;
        };
        let value = number.value;
        if value.fract() != 0.0 || value < 0.0 || value > u32::MAX as f64 {
            return None;
        }
        Some(value as u32)
    }

    fn expression_cache_access<'a>(expression: &'a ast::Expression<'a>) -> Option<(&'a str, u32)> {
        let ast::Expression::ComputedMemberExpression(member) = expression.without_parentheses()
        else {
            return None;
        };
        if member.optional {
            return None;
        }
        let ast::Expression::Identifier(object) = member.object.without_parentheses() else {
            return None;
        };
        Some((
            object.name.as_str(),
            expression_numeric_slot(&member.expression)?,
        ))
    }

    fn expression_is_symbol_for(expression: &ast::Expression<'_>, sentinel: &str) -> bool {
        let ast::Expression::CallExpression(call) = expression.without_parentheses() else {
            return false;
        };
        if call.optional || call.arguments.len() != 1 {
            return false;
        }
        let ast::Expression::StaticMemberExpression(member) = call.callee.without_parentheses()
        else {
            return false;
        };
        if member.optional || member.property.name != "for" {
            return false;
        }
        if !expression_is_identifier(&member.object, "Symbol") {
            return false;
        }
        let argument = call.arguments[0].to_expression();
        let ast::Expression::StringLiteral(literal) = argument.without_parentheses() else {
            return false;
        };
        literal.value.as_str() == sentinel
    }

    fn collect_dependency_guards(
        expression: &ast::Expression<'_>,
        guard_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
    ) -> Option<Vec<GeneratedDependencyGuard>> {
        match expression.without_parentheses() {
            ast::Expression::LogicalExpression(logical)
                if logical.operator == AstLogicalOperator::Or =>
            {
                let mut guards = collect_dependency_guards(&logical.left, guard_aliases)?;
                guards.extend(collect_dependency_guards(&logical.right, guard_aliases)?);
                Some(guards)
            }
            ast::Expression::BinaryExpression(binary)
                if binary.operator == AstBinaryOperator::StrictInequality =>
            {
                let (cache_var, dep_slot) = expression_cache_access(&binary.left)?;
                Some(vec![GeneratedDependencyGuard {
                    cache_var: cache_var.to_string(),
                    dep_slot,
                    dep_expr: codegen_expression_with_flow_cast_restore(&binary.right),
                }])
            }
            ast::Expression::Identifier(identifier) => {
                guard_aliases.get(identifier.name.as_str()).cloned()
            }
            _ => None,
        }
    }

    fn collect_guard_alias_bindings(
        statements: &[ast::Statement<'_>],
        parent_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
    ) -> HashMap<String, Vec<GeneratedDependencyGuard>> {
        let mut aliases = parent_aliases.clone();
        for statement in statements {
            let ast::Statement::VariableDeclaration(declaration) = statement else {
                continue;
            };
            if declaration.declarations.len() != 1 {
                continue;
            }
            let declarator = &declaration.declarations[0];
            let Some(init) = declarator.init.as_ref() else {
                continue;
            };
            let Some(binding_name) = binding_identifier_name(&declarator.id) else {
                continue;
            };
            let Some(guards) = collect_dependency_guards(init, &aliases) else {
                continue;
            };
            aliases.insert(binding_name, guards);
        }
        aliases
    }

    fn assignment_target_identifier_name<'a>(
        target: &'a ast::AssignmentTarget<'a>,
    ) -> Option<&'a str> {
        match target {
            ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) => {
                Some(identifier.name.as_str())
            }
            _ => None,
        }
    }

    fn assignment_target_cache_access<'a>(
        target: &'a ast::AssignmentTarget<'a>,
    ) -> Option<(&'a str, u32)> {
        match target {
            ast::AssignmentTarget::ComputedMemberExpression(member) if !member.optional => {
                let ast::Expression::Identifier(object) = member.object.without_parentheses()
                else {
                    return None;
                };
                Some((
                    object.name.as_str(),
                    expression_numeric_slot(&member.expression)?,
                ))
            }
            _ => None,
        }
    }

    fn assignment_statement_parts<'a>(
        statement: &'a ast::Statement<'a>,
    ) -> Option<(&'a ast::AssignmentTarget<'a>, &'a ast::Expression<'a>)> {
        let ast::Statement::ExpressionStatement(expression_statement) = statement else {
            return None;
        };
        let ast::Expression::AssignmentExpression(assignment) =
            expression_statement.expression.without_parentheses()
        else {
            return None;
        };
        if assignment.operator != AssignmentOperator::Assign {
            return None;
        }
        Some((&assignment.left, &assignment.right))
    }

    fn statement_assigns_identifier_to_expression<'a>(
        statement: &'a ast::Statement<'a>,
        identifier: &str,
    ) -> Option<&'a ast::Expression<'a>> {
        let (target, value) = assignment_statement_parts(statement)?;
        (assignment_target_identifier_name(target)? == identifier).then_some(value)
    }

    fn statement_assigns_cache_slot_from_identifier(
        statement: &ast::Statement<'_>,
        cache_var: &str,
        slot: u32,
        identifier: &str,
    ) -> bool {
        let Some((target, value)) = assignment_statement_parts(statement) else {
            return false;
        };
        assignment_target_cache_access(target).is_some_and(|(name, index)| {
            name == cache_var && index == slot && expression_is_identifier(value, identifier)
        })
    }

    fn statement_assigns_identifier_from_cache_slot(
        statement: &ast::Statement<'_>,
        identifier: &str,
        cache_var: &str,
        slot: u32,
    ) -> bool {
        let Some((target, value)) = assignment_statement_parts(statement) else {
            return false;
        };
        assignment_target_identifier_name(target) == Some(identifier)
            && expression_cache_access(value)
                .is_some_and(|(name, index)| name == cache_var && index == slot)
    }

    fn statement_returns_identifier(statement: &ast::Statement<'_>, identifier: &str) -> bool {
        let ast::Statement::ReturnStatement(return_statement) = statement else {
            return false;
        };
        return_statement
            .argument
            .as_ref()
            .is_some_and(|argument| expression_is_identifier(argument, identifier))
    }

    fn statement_returns_identifier_name(statement: &ast::Statement<'_>) -> Option<String> {
        let ast::Statement::ReturnStatement(return_statement) = statement else {
            return None;
        };
        let argument = return_statement.argument.as_ref()?;
        expression_identifier_name(argument).map(str::to_string)
    }

    fn sentinel_guard_return_name(statement: &ast::Statement<'_>) -> Option<String> {
        let ast::Statement::IfStatement(if_statement) = statement else {
            return None;
        };
        if if_statement.alternate.is_some() {
            return None;
        }
        let ast::Expression::BinaryExpression(test) = if_statement.test.without_parentheses()
        else {
            return None;
        };
        if test.operator != AstBinaryOperator::StrictInequality {
            return None;
        }
        if !expression_is_symbol_for(&test.right, EARLY_RETURN_SENTINEL) {
            return None;
        }
        let sentinel_name = expression_identifier_name(&test.left)?.to_string();
        let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent else {
            return None;
        };
        if consequent_block.body.len() != 1
            || !statement_returns_identifier(&consequent_block.body[0], &sentinel_name)
        {
            return None;
        }
        Some(sentinel_name)
    }

    fn extract_return_argument<'a>(
        statement: &'a ast::Statement<'a>,
    ) -> Option<Option<&'a ast::Expression<'a>>> {
        match statement {
            ast::Statement::ReturnStatement(return_statement) => {
                Some(return_statement.argument.as_ref())
            }
            ast::Statement::BlockStatement(block) if block.body.len() == 1 => {
                extract_return_argument(&block.body[0])
            }
            _ => None,
        }
    }

    fn cache_prologue_binding_name(statement: &ast::Statement<'_>) -> Option<String> {
        let ast::Statement::VariableDeclaration(declaration) = statement else {
            return None;
        };
        if declaration.kind != ast::VariableDeclarationKind::Const
            || declaration.declarations.len() != 1
        {
            return None;
        }
        let declarator = &declaration.declarations[0];
        let cache_name = binding_identifier_name(&declarator.id)?;
        let init = declarator.init.as_ref()?;
        let ast::Expression::CallExpression(call) = init.without_parentheses() else {
            return None;
        };
        if call.optional || call.arguments.len() != 1 {
            return None;
        }
        if !expression_is_identifier(&call.callee, "_c") {
            return None;
        }
        let size = call.arguments[0].to_expression();
        (expression_numeric_slot(size) == Some(1)).then_some(cache_name)
    }

    fn collect_leading_initialized_bindings(
        statements: &[ast::Statement<'_>],
    ) -> (Vec<GeneratedBinding>, usize) {
        let mut bindings = Vec::new();
        let mut prefix_len = 0usize;
        for statement in statements {
            let ast::Statement::VariableDeclaration(declaration) = statement else {
                break;
            };
            if declaration.declarations.len() != 1 {
                break;
            }
            let declarator = &declaration.declarations[0];
            let Some(init) = declarator.init.as_ref() else {
                break;
            };
            bindings.push(GeneratedBinding {
                kind: declaration.kind,
                pattern: codegen_binding_pattern_with_flow_cast_restore(&declarator.id),
                expression: strip_top_level_parenthesized_expression(
                    codegen_expression_with_flow_cast_restore(init),
                ),
                promote_to_function_declaration: false,
            });
            prefix_len += 1;
        }
        (bindings, prefix_len)
    }

    fn collect_leading_side_effect_assignments(
        statements: &[ast::Statement<'_>],
        terminal_identifier: &str,
    ) -> (Vec<GeneratedAssignment>, usize) {
        let mut assignments = Vec::new();
        let mut prefix_len = 0usize;
        for statement in statements {
            let Some((target, value)) = assignment_statement_parts(statement) else {
                break;
            };
            if assignment_target_identifier_name(target) == Some(terminal_identifier)
                || assignment_target_cache_access(target).is_some()
            {
                break;
            }
            assignments.push(GeneratedAssignment {
                target: codegen_assignment_target_with_flow_cast_restore(target),
                value: codegen_expression_with_flow_cast_restore(value),
            });
            prefix_len += 1;
        }
        (assignments, prefix_len)
    }

    fn collect_leading_expression_statements(
        statements: &[ast::Statement<'_>],
    ) -> (Vec<String>, usize) {
        let mut expressions = Vec::new();
        let mut prefix_len = 0usize;
        for statement in statements {
            let ast::Statement::ExpressionStatement(expression_statement) = statement else {
                break;
            };
            if matches!(
                expression_statement.expression.without_parentheses(),
                ast::Expression::AssignmentExpression(_)
            ) {
                break;
            }
            expressions.push(codegen_expression_with_flow_cast_restore(
                &expression_statement.expression,
            ));
            prefix_len += 1;
        }
        (expressions, prefix_len)
    }

    fn collect_cached_value_stores(
        statements: &[ast::Statement<'_>],
    ) -> Option<Vec<GeneratedCachedValue>> {
        let mut values = Vec::with_capacity(statements.len());
        for statement in statements {
            let (target, value) = assignment_statement_parts(statement)?;
            let (cache_name, slot) = assignment_target_cache_access(target)?;
            let name = expression_identifier_name(value)?.to_string();
            if cache_name != "$" {
                // Analysis only runs on rendered bodies, which always use `$`.
                // Keep this strict so malformed matches do not masquerade as shapes.
                return None;
            }
            values.push(GeneratedCachedValue { name, slot });
        }
        Some(values)
    }

    fn collect_cached_value_restores(
        statements: &[ast::Statement<'_>],
    ) -> Option<Vec<GeneratedCachedValue>> {
        let mut values = Vec::with_capacity(statements.len());
        for statement in statements {
            let (target, value) = assignment_statement_parts(statement)?;
            let name = assignment_target_identifier_name(target)?.to_string();
            let (cache_name, slot) = expression_cache_access(value)?;
            if cache_name != "$" {
                return None;
            }
            values.push(GeneratedCachedValue { name, slot });
        }
        Some(values)
    }

    fn cached_value_sets_match(
        stored_values: &[GeneratedCachedValue],
        restored_values: &[GeneratedCachedValue],
    ) -> bool {
        let mut stored = stored_values
            .iter()
            .map(|value| (value.slot, value.name.as_str()))
            .collect::<Vec<_>>();
        let mut restored = restored_values
            .iter()
            .map(|value| (value.slot, value.name.as_str()))
            .collect::<Vec<_>>();
        stored.sort_unstable();
        restored.sort_unstable();
        stored == restored
    }

    fn collect_assignments(
        statements: &[ast::Statement<'_>],
        allow_cache_targets: bool,
    ) -> (Vec<GeneratedAssignment>, usize) {
        let mut assignments = Vec::new();
        let mut prefix_len = 0usize;
        for statement in statements {
            let Some((target, value)) = assignment_statement_parts(statement) else {
                break;
            };
            if !allow_cache_targets && assignment_target_cache_access(target).is_some() {
                break;
            }
            assignments.push(GeneratedAssignment {
                target: codegen_assignment_target_with_flow_cast_restore(target),
                value: codegen_expression_with_flow_cast_restore(value),
            });
            prefix_len += 1;
        }
        (assignments, prefix_len)
    }

    fn collect_non_cache_assignments(
        statements: &[ast::Statement<'_>],
    ) -> (Vec<GeneratedAssignment>, usize) {
        collect_assignments(statements, false)
    }

    fn collect_candidate_return_identifiers(statements: &[ast::Statement<'_>]) -> Vec<String> {
        let mut candidates = Vec::new();
        for statement in statements.iter().rev() {
            match statement {
                ast::Statement::VariableDeclaration(declaration)
                    if declaration.declarations.len() == 1 =>
                {
                    if let Some(name) = binding_identifier_name(&declaration.declarations[0].id)
                        && !candidates.contains(&name)
                    {
                        candidates.push(name);
                    }
                }
                ast::Statement::ExpressionStatement(_) => {
                    if let Some((target, _)) = assignment_statement_parts(statement)
                        && let Some(name) = assignment_target_identifier_name(target)
                    {
                        let name = name.to_string();
                        if !candidates.contains(&name) {
                            candidates.push(name);
                        }
                    }
                }
                ast::Statement::ReturnStatement(return_statement) => {
                    if let Some(argument) = return_statement.argument.as_ref()
                        && let Some(name) = expression_identifier_name(argument)
                    {
                        let name = name.to_string();
                        if !candidates.contains(&name) {
                            candidates.push(name);
                        }
                    }
                }
                _ => {}
            }
        }
        candidates
    }

    fn collect_leading_uninitialized_declarations(
        statements: &[ast::Statement<'_>],
    ) -> (Vec<GeneratedDeclaration>, usize) {
        let mut declarations = Vec::new();
        let mut prefix_len = 0usize;
        for statement in statements {
            let ast::Statement::VariableDeclaration(declaration) = statement else {
                break;
            };
            if declaration.declarations.len() != 1 {
                break;
            }
            let declarator = &declaration.declarations[0];
            if declarator.init.is_some() {
                break;
            }
            declarations.push(GeneratedDeclaration {
                kind: declaration.kind,
                pattern: codegen_binding_pattern_with_flow_cast_restore(&declarator.id),
            });
            prefix_len += 1;
        }
        (declarations, prefix_len)
    }

    fn count_leading_initialized_bindings(statements: &[ast::Statement<'_>]) -> usize {
        let mut prefix_len = 0usize;
        for statement in statements {
            let ast::Statement::VariableDeclaration(declaration) = statement else {
                break;
            };
            if declaration.declarations.len() != 1 {
                break;
            }
            let declarator = &declaration.declarations[0];
            if declarator.init.is_none() {
                break;
            }
            prefix_len += 1;
        }
        prefix_len
    }

    fn can_start_sequential_suffix(statement: &ast::Statement<'_>) -> bool {
        matches!(
            statement,
            ast::Statement::VariableDeclaration(_)
                | ast::Statement::ExpressionStatement(_)
                | ast::Statement::DebuggerStatement(_)
                | ast::Statement::ReturnStatement(_)
                | ast::Statement::IfStatement(_)
                | ast::Statement::TryStatement(_)
                | ast::Statement::WhileStatement(_)
                | ast::Statement::DoWhileStatement(_)
                | ast::Statement::ForStatement(_)
                | ast::Statement::ForInStatement(_)
                | ast::Statement::ForOfStatement(_)
                | ast::Statement::ThrowStatement(_)
                | ast::Statement::BreakStatement(_)
                | ast::Statement::ContinueStatement(_)
        )
    }

    fn collect_sequential_split_indices(statements: &[ast::Statement<'_>]) -> Vec<usize> {
        let binding_prefix_len = count_leading_initialized_bindings(statements);
        let mut candidates = Vec::new();
        let can_be_structured_prefix = |statement: &ast::Statement<'_>| {
            matches!(
                statement,
                ast::Statement::BlockStatement(_)
                    | ast::Statement::LabeledStatement(_)
                    | ast::Statement::SwitchStatement(_)
                    | ast::Statement::DebuggerStatement(_)
            )
        };
        if statements.len() >= 2
            && matches!(statements.first(), Some(ast::Statement::IfStatement(_)))
            && statements.get(1).is_some_and(can_start_sequential_suffix)
        {
            candidates.push(1);
        }
        if statements.len() >= 2
            && statements.first().is_some_and(can_be_structured_prefix)
            && statements.get(1).is_some_and(can_start_sequential_suffix)
        {
            candidates.push(1);
        }
        if statements.len() >= 3
            && matches!(statements.first(), Some(ast::Statement::IfStatement(_)))
            && matches!(statements.get(1), Some(ast::Statement::IfStatement(_)))
            && statements.get(2).is_some_and(can_start_sequential_suffix)
        {
            candidates.push(2);
        }
        if binding_prefix_len + 1 < statements.len()
            && matches!(
                statements.get(binding_prefix_len),
                Some(ast::Statement::IfStatement(_))
            )
            && statements
                .get(binding_prefix_len + 1)
                .is_some_and(can_start_sequential_suffix)
        {
            candidates.push(binding_prefix_len + 1);
        }
        if binding_prefix_len + 1 < statements.len()
            && statements
                .get(binding_prefix_len)
                .is_some_and(can_be_structured_prefix)
            && statements
                .get(binding_prefix_len + 1)
                .is_some_and(can_start_sequential_suffix)
        {
            candidates.push(binding_prefix_len + 1);
        }
        if binding_prefix_len + 2 < statements.len()
            && matches!(
                statements.get(binding_prefix_len),
                Some(ast::Statement::IfStatement(_))
            )
            && matches!(
                statements.get(binding_prefix_len + 1),
                Some(ast::Statement::IfStatement(_))
            )
            && statements
                .get(binding_prefix_len + 2)
                .is_some_and(can_start_sequential_suffix)
        {
            candidates.push(binding_prefix_len + 2);
        }
        if statements.len() >= 2
            && matches!(
                statements.first(),
                Some(ast::Statement::ExpressionStatement(_))
            )
            && statements.get(1).is_some_and(can_start_sequential_suffix)
        {
            candidates.push(1);
        }
        if binding_prefix_len + 1 < statements.len()
            && matches!(
                statements.get(binding_prefix_len),
                Some(ast::Statement::ExpressionStatement(_))
            )
            && statements
                .get(binding_prefix_len + 1)
                .is_some_and(can_start_sequential_suffix)
        {
            candidates.push(binding_prefix_len + 1);
        }
        if binding_prefix_len + 2 < statements.len()
            && matches!(
                statements.get(binding_prefix_len),
                Some(ast::Statement::VariableDeclaration(_))
            )
            && matches!(
                statements.get(binding_prefix_len + 1),
                Some(ast::Statement::IfStatement(_))
            )
        {
            candidates.push(binding_prefix_len + 2);
        }
        if binding_prefix_len + 3 < statements.len()
            && matches!(
                statements.get(binding_prefix_len),
                Some(ast::Statement::VariableDeclaration(_))
            )
            && matches!(
                statements.get(binding_prefix_len + 1),
                Some(ast::Statement::IfStatement(_))
            )
            && matches!(
                statements.get(binding_prefix_len + 2),
                Some(ast::Statement::VariableDeclaration(_))
            )
        {
            candidates.push(binding_prefix_len + 3);
        }
        if matches!(
            statements.first(),
            Some(ast::Statement::ExpressionStatement(_))
        ) && matches!(
            statements.get(1),
            Some(ast::Statement::VariableDeclaration(_))
        ) {
            candidates.push(1);
        }
        candidates.sort_unstable();
        candidates.dedup();
        candidates
    }

    fn is_memoization_guard_test(
        test: &ast::Expression<'_>,
        guard_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
    ) -> bool {
        if let ast::Expression::BinaryExpression(binary) = test.without_parentheses()
            && binary.operator == AstBinaryOperator::StrictEquality
            && expression_cache_access(&binary.left).is_some()
            && expression_is_symbol_for(&binary.right, MEMO_CACHE_SENTINEL)
        {
            return true;
        }
        collect_dependency_guards(test, guard_aliases).is_some()
    }

    fn statement_shape(
        statement: &ast::Statement<'_>,
        guard_aliases: &HashMap<String, Vec<GeneratedDependencyGuard>>,
    ) -> GeneratedBodyShape {
        match statement {
            ast::Statement::BlockStatement(block) => {
                let source = codegen_statements_with_flow_cast_restore(&block.body);
                analyze_generated_body_shape_impl_with_guard_aliases(&source, true, guard_aliases)
            }
            _ => {
                let source = codegen_statement_with_flow_cast_restore(statement);
                analyze_generated_body_shape_impl_with_guard_aliases(&source, true, guard_aliases)
            }
        }
    }

    fn collect_statement_sources_from_body_slice(
        body_source: &str,
        body_offset: usize,
        statements: &[ast::Statement<'_>],
    ) -> Vec<String> {
        let mut collected = Vec::with_capacity(statements.len());
        let mut previous_end: Option<usize> = None;
        for statement in statements {
            let Some(start) = (statement.span().start as usize).checked_sub(body_offset) else {
                return statements
                    .iter()
                    .map(codegen_statement_with_flow_cast_restore)
                    .collect();
            };
            let Some(end) = (statement.span().end as usize).checked_sub(body_offset) else {
                return statements
                    .iter()
                    .map(codegen_statement_with_flow_cast_restore)
                    .collect();
            };
            if end > body_source.len() || start > end {
                return statements
                    .iter()
                    .map(codegen_statement_with_flow_cast_restore)
                    .collect();
            }

            let mut statement_source = body_source[start..end].trim().to_string();
            if let Some(previous_end) = previous_end {
                let between = &body_source[previous_end..start];
                if between.chars().filter(|&ch| ch == '\n').count() >= 2 {
                    statement_source = add_statement_blank_line_marker(statement_source);
                }
            }
            collected.push(statement_source);
            previous_end = Some(end);
        }
        collected
    }

    for source_type in [
        SourceType::mjs().with_jsx(true),
        SourceType::ts().with_jsx(true),
        SourceType::tsx(),
    ] {
        let allocator = Allocator::default();
        let Ok((body_offset, function_body)) = parse_function_body_for_ast_codegen_with_offset(
            &allocator,
            source_type,
            false,
            false,
            body,
        ) else {
            continue;
        };
        let statements = &function_body.statements;

        if statements.is_empty() {
            return GeneratedBodyShape::ExpressionStatements(Vec::new());
        }

        if let [ast::Statement::DebuggerStatement(_)] = statements.as_slice() {
            return GeneratedBodyShape::DebuggerStatements(1);
        }

        if statements.len() >= 2
            && matches!(
                statements.first(),
                Some(ast::Statement::DebuggerStatement(_))
            )
        {
            let suffix_source = codegen_statements_with_flow_cast_restore(&statements[1..]);
            let suffix_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if !matches!(suffix_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::Sequential {
                    prefix: Box::new(GeneratedBodyShape::DebuggerStatements(1)),
                    inner: Box::new(suffix_shape),
                };
            }
        }

        if let [ast::Statement::BlockStatement(block)] = statements.as_slice() {
            let inner_source = codegen_statements_with_flow_cast_restore(&block.body);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &inner_source,
                true,
                guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::Block {
                    inner: Box::new(inner_shape),
                };
            }
        }

        if statements.len() >= 2
            && let Some(ast::Statement::BlockStatement(block)) = statements.first()
        {
            let inner_source = codegen_statements_with_flow_cast_restore(&block.body);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &inner_source,
                true,
                guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                let suffix_source = codegen_statements_with_flow_cast_restore(&statements[1..]);
                let suffix_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &suffix_source,
                    true,
                    guard_aliases,
                );
                if !matches!(suffix_shape, GeneratedBodyShape::Unknown) {
                    return GeneratedBodyShape::Sequential {
                        prefix: Box::new(GeneratedBodyShape::Block {
                            inner: Box::new(inner_shape),
                        }),
                        inner: Box::new(suffix_shape),
                    };
                }
            }
        }

        if let [ast::Statement::LabeledStatement(labeled)] = statements.as_slice() {
            let inner_shape = statement_shape(&labeled.body, guard_aliases);
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::Labeled {
                    label: labeled.label.name.to_string(),
                    inner: Box::new(inner_shape),
                };
            }
        }

        if let [ast::Statement::SwitchStatement(switch_statement)] = statements.as_slice() {
            let mut cases = Vec::with_capacity(switch_statement.cases.len());
            let mut all_structured = true;
            for case in &switch_statement.cases {
                let consequent = if case.consequent.is_empty() {
                    GeneratedBodyShape::ExpressionStatements(Vec::new())
                } else {
                    let consequent_source =
                        codegen_statements_with_flow_cast_restore(&case.consequent);
                    analyze_generated_body_shape_impl_with_guard_aliases(
                        &consequent_source,
                        true,
                        guard_aliases,
                    )
                };
                if matches!(consequent, GeneratedBodyShape::Unknown) {
                    all_structured = false;
                    break;
                }
                cases.push(GeneratedSwitchCase {
                    test: case
                        .test
                        .as_ref()
                        .map(codegen_expression_with_flow_cast_restore),
                    consequent,
                });
            }
            if all_structured {
                return GeneratedBodyShape::Switch {
                    discriminant: codegen_expression_with_flow_cast_restore(
                        &switch_statement.discriminant,
                    ),
                    cases,
                };
            }
        }

        if statements.len() >= 2
            && let Some(ast::Statement::IfStatement(if_statement)) = statements.first()
            && if_statement.alternate.is_none()
            && let Some(consequent_argument) = extract_return_argument(&if_statement.consequent)
        {
            let suffix_source = codegen_statements_with_flow_cast_restore(&statements[1..]);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::GuardedReturnPrefix {
                    test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                    consequent: consequent_argument.map(codegen_expression_with_flow_cast_restore),
                    inner: Box::new(inner_shape),
                };
            }
        }

        if let [ast::Statement::IfStatement(if_statement)] = statements.as_slice()
            && if_statement.alternate.is_none()
            && let Some(consequent_argument) = extract_return_argument(&if_statement.consequent)
        {
            return GeneratedBodyShape::GuardedReturnPrefix {
                test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                consequent: consequent_argument.map(codegen_expression_with_flow_cast_restore),
                inner: Box::new(GeneratedBodyShape::ExpressionStatements(Vec::new())),
            };
        }

        if let [ast::Statement::IfStatement(if_statement)] = statements.as_slice()
            && let Some(alternate) = if_statement.alternate.as_ref()
            && !is_memoization_guard_test(&if_statement.test, guard_aliases)
        {
            let consequent_shape = statement_shape(&if_statement.consequent, guard_aliases);
            if !matches!(consequent_shape, GeneratedBodyShape::Unknown) {
                let alternate_shape = statement_shape(alternate, guard_aliases);
                if !matches!(alternate_shape, GeneratedBodyShape::Unknown) {
                    return GeneratedBodyShape::ConditionalBranches {
                        test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                        consequent: Box::new(consequent_shape),
                        alternate: Box::new(alternate_shape),
                    };
                }
            }
        }

        if let [ast::Statement::WhileStatement(while_statement)] = statements.as_slice() {
            let body_shape = statement_shape(&while_statement.body, guard_aliases);
            if !matches!(body_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::WhileLoop {
                    test: codegen_expression_with_flow_cast_restore(&while_statement.test),
                    body: Box::new(body_shape),
                };
            }
        }

        if let [ast::Statement::DoWhileStatement(do_while_statement)] = statements.as_slice() {
            let body_shape = statement_shape(&do_while_statement.body, guard_aliases);
            if !matches!(body_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::DoWhileLoop {
                    test: codegen_expression_with_flow_cast_restore(&do_while_statement.test),
                    body: Box::new(body_shape),
                };
            }
        }

        if let [ast::Statement::ForStatement(for_statement)] = statements.as_slice() {
            let body_shape = statement_shape(&for_statement.body, guard_aliases);
            if !matches!(body_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::ForLoop {
                    init: for_statement
                        .init
                        .as_ref()
                        .map(codegen_for_statement_init_with_oxc),
                    test: for_statement
                        .test
                        .as_ref()
                        .map(codegen_expression_with_flow_cast_restore),
                    update: for_statement
                        .update
                        .as_ref()
                        .map(codegen_expression_with_flow_cast_restore),
                    body: Box::new(body_shape),
                };
            }
        }

        if let [ast::Statement::ForInStatement(for_statement)] = statements.as_slice() {
            let body_shape = statement_shape(&for_statement.body, guard_aliases);
            if !matches!(body_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::ForInLoop {
                    left: codegen_for_statement_left_with_oxc(&for_statement.left),
                    right: codegen_expression_with_flow_cast_restore(&for_statement.right),
                    body: Box::new(body_shape),
                };
            }
        }

        if let [ast::Statement::ForOfStatement(for_statement)] = statements.as_slice() {
            let body_shape = statement_shape(&for_statement.body, guard_aliases);
            if !matches!(body_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::ForOfLoop {
                    left: codegen_for_statement_left_with_oxc(&for_statement.left),
                    right: codegen_expression_with_flow_cast_restore(&for_statement.right),
                    body: Box::new(body_shape),
                };
            }
        }

        if statements.len() >= 2
            && let Some(ast::Statement::VariableDeclaration(alias_decl)) =
                statements.get(statements.len() - 2)
            && alias_decl.declarations.len() == 1
        {
            let alias_decl = &alias_decl.declarations[0];
            if let Some(alias_name) = binding_identifier_name(&alias_decl.id)
                && let Some(init) = alias_decl.init.as_ref()
                && let Some(source_name) = expression_identifier_name(init).map(str::to_string)
                && let ast::Statement::ReturnStatement(return_stmt) =
                    &statements[statements.len() - 1]
                && return_stmt
                    .argument
                    .as_ref()
                    .is_some_and(|argument| expression_is_identifier(argument, &alias_name))
            {
                let prefix_source =
                    codegen_statements_with_flow_cast_restore(&statements[..statements.len() - 2]);
                let inner_shape = {
                    let direct_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                        &prefix_source,
                        true,
                        guard_aliases,
                    );
                    if shape_returned_identifier(&direct_shape)
                        .is_some_and(|name| name == source_name)
                    {
                        direct_shape
                    } else {
                        let synthetic_return = format!("{prefix_source}\nreturn {source_name};");
                        analyze_generated_body_shape_impl_with_guard_aliases(
                            &synthetic_return,
                            true,
                            guard_aliases,
                        )
                    }
                };
                if shape_returned_identifier(&inner_shape).is_some_and(|name| name == source_name) {
                    return GeneratedBodyShape::AliasedReturn {
                        alias_name,
                        alias_kind: alias_decl.kind,
                        source_name,
                        inner: Box::new(inner_shape),
                    };
                }
            }
        }

        if statements.len() >= 2
            && let Some(ast::Statement::ReturnStatement(return_stmt)) = statements.last()
            && let Some(return_argument) = return_stmt.argument.as_ref()
            && let Some(alias_name) =
                expression_identifier_name(return_argument).map(str::to_string)
            && let Some((target, value)) =
                assignment_statement_parts(&statements[statements.len() - 2])
            && assignment_target_identifier_name(target) == Some(alias_name.as_str())
            && let Some(source_name) = expression_identifier_name(value).map(str::to_string)
        {
            let prefix_source =
                codegen_statements_with_flow_cast_restore(&statements[..statements.len() - 2]);
            let inner_shape = {
                let direct_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &prefix_source,
                    true,
                    guard_aliases,
                );
                if shape_returned_identifier(&direct_shape).is_some_and(|name| name == source_name)
                {
                    direct_shape
                } else {
                    let synthetic_return = format!("{prefix_source}\nreturn {source_name};");
                    analyze_generated_body_shape_impl_with_guard_aliases(
                        &synthetic_return,
                        true,
                        guard_aliases,
                    )
                }
            };
            if shape_returned_identifier(&inner_shape).is_some_and(|name| name == source_name) {
                return GeneratedBodyShape::AssignedAliasReturn {
                    alias_name,
                    source_name,
                    inner: Box::new(inner_shape),
                };
            }
        }

        if let [ast::Statement::ReturnStatement(return_stmt)] = statements.as_slice() {
            return match return_stmt.argument.as_ref() {
                None => GeneratedBodyShape::ReturnVoid,
                Some(argument) => match argument.without_parentheses() {
                    ast::Expression::Identifier(identifier) => {
                        GeneratedBodyShape::ReturnIdentifier(identifier.name.to_string())
                    }
                    _ => GeneratedBodyShape::ReturnExpression(
                        codegen_expression_with_flow_cast_restore(argument),
                    ),
                },
            };
        }

        if let [ast::Statement::ThrowStatement(throw_stmt)] = statements.as_slice() {
            return GeneratedBodyShape::ThrowExpression(codegen_expression_with_flow_cast_restore(
                &throw_stmt.argument,
            ));
        }

        if let [ast::Statement::BreakStatement(break_stmt)] = statements.as_slice() {
            return GeneratedBodyShape::Break(
                break_stmt
                    .label
                    .as_ref()
                    .map(|label| label.name.to_string()),
            );
        }

        if let [ast::Statement::ContinueStatement(continue_stmt)] = statements.as_slice() {
            return GeneratedBodyShape::Continue(
                continue_stmt
                    .label
                    .as_ref()
                    .map(|label| label.name.to_string()),
            );
        }

        if statements.len() >= 2
            && let Some(ast::Statement::IfStatement(if_statement)) = statements.first()
            && let Some(alternate) = if_statement.alternate.as_ref()
            && let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent
            && let ast::Statement::BlockStatement(alternate_block) = alternate
            && let Some(sentinel_name) = sentinel_guard_return_name(&statements[1])
        {
            let (final_return, fallback_body) = if statements.len() == 2 {
                (None, None)
            } else if statements.len() == 3 {
                if let Some(final_return) = statement_returns_identifier_name(&statements[2]) {
                    (Some(final_return), None)
                } else {
                    let tail_source = codegen_statements_with_flow_cast_restore(&statements[2..]);
                    let tail_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                        &tail_source,
                        true,
                        guard_aliases,
                    );
                    if matches!(tail_shape, GeneratedBodyShape::Unknown) {
                        continue;
                    }
                    (None, Some(Box::new(tail_shape)))
                }
            } else {
                let tail_source = codegen_statements_with_flow_cast_restore(&statements[2..]);
                let tail_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &tail_source,
                    true,
                    guard_aliases,
                );
                if matches!(tail_shape, GeneratedBodyShape::Unknown) {
                    continue;
                }
                (None, Some(Box::new(tail_shape)))
            };
            let Some(dependency_guards) =
                collect_dependency_guards(&if_statement.test, guard_aliases)
            else {
                continue;
            };
            let Some(restored_values) = collect_cached_value_restores(&alternate_block.body) else {
                continue;
            };
            if restored_values.is_empty()
                || !restored_values
                    .iter()
                    .any(|value| value.name == sentinel_name)
            {
                continue;
            }
            let dep_len = dependency_guards.len();
            let cache_len = restored_values.len();
            if consequent_block.body.len() <= dep_len + cache_len {
                continue;
            }
            let dep_base = consequent_block.body.len() - (dep_len + cache_len);
            let cache_base = consequent_block.body.len() - cache_len;
            let Some(cached_values) =
                collect_cached_value_stores(&consequent_block.body[cache_base..])
            else {
                continue;
            };
            if !cached_value_sets_match(&cached_values, &restored_values) {
                continue;
            }
            let mut deps = Vec::with_capacity(dependency_guards.len());
            let mut guards_match = true;
            for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                let Some((dep_target, dep_value)) =
                    assignment_statement_parts(&consequent_block.body[dep_base + index])
                else {
                    guards_match = false;
                    break;
                };
                if assignment_target_cache_access(dep_target)
                    != Some((
                        dependency_guard.cache_var.as_str(),
                        dependency_guard.dep_slot,
                    ))
                    || codegen_expression_with_flow_cast_restore(dep_value)
                        != dependency_guard.dep_expr
                {
                    guards_match = false;
                    break;
                }
                deps.push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
            }
            if !guards_match {
                continue;
            }
            let setup_statements = collect_statement_sources_from_body_slice(
                body,
                body_offset,
                &consequent_block.body[..dep_base],
            );
            if setup_statements.is_empty() {
                continue;
            }
            return GeneratedBodyShape::MemoizedEarlyReturnSentinel {
                deps,
                setup_statements,
                cached_values,
                restored_values,
                sentinel_name,
                final_return,
                fallback_body,
            };
        }

        if let [ast::Statement::IfStatement(if_statement)] = statements.as_slice()
            && let Some(alternate) = if_statement.alternate.as_ref()
            && let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent
            && let ast::Statement::BlockStatement(alternate_block) = alternate
        {
            if let ast::Expression::BinaryExpression(test) = if_statement.test.without_parentheses()
                && test.operator == AstBinaryOperator::StrictEquality
                && let Some((cache_var, sentinel_slot)) = expression_cache_access(&test.left)
                && cache_var == "$"
                && expression_is_symbol_for(&test.right, MEMO_CACHE_SENTINEL)
            {
                let Some(restored_values) = collect_cached_value_restores(&alternate_block.body)
                else {
                    continue;
                };
                if restored_values.is_empty()
                    || consequent_block.body.len() <= restored_values.len()
                {
                    continue;
                }
                let cache_base = consequent_block.body.len() - restored_values.len();
                let Some(cached_values) =
                    collect_cached_value_stores(&consequent_block.body[cache_base..])
                else {
                    continue;
                };
                if !cached_value_sets_match(&cached_values, &restored_values)
                    || !cached_values
                        .iter()
                        .any(|value| value.slot == sentinel_slot)
                {
                    continue;
                }
                let setup_statements = collect_statement_sources_from_body_slice(
                    body,
                    body_offset,
                    &consequent_block.body[..cache_base],
                );
                if setup_statements.is_empty() {
                    continue;
                }
                return GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
                    sentinel_slot,
                    setup_statements,
                    cached_values,
                    restored_values,
                };
            }

            let Some(dependency_guards) =
                collect_dependency_guards(&if_statement.test, guard_aliases)
            else {
                continue;
            };
            let Some(restored_values) = collect_cached_value_restores(&alternate_block.body) else {
                continue;
            };
            if restored_values.is_empty() {
                continue;
            }
            let dep_len = dependency_guards.len();
            let cache_len = restored_values.len();
            if consequent_block.body.len() <= dep_len + cache_len {
                continue;
            }
            let dep_base = consequent_block.body.len() - (dep_len + cache_len);
            let cache_base = consequent_block.body.len() - cache_len;
            let Some(cached_values) =
                collect_cached_value_stores(&consequent_block.body[cache_base..])
            else {
                continue;
            };
            if !cached_value_sets_match(&cached_values, &restored_values) {
                continue;
            }
            let mut deps = Vec::with_capacity(dependency_guards.len());
            let mut guards_match = true;
            for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                let Some((dep_target, dep_value)) =
                    assignment_statement_parts(&consequent_block.body[dep_base + index])
                else {
                    guards_match = false;
                    break;
                };
                if assignment_target_cache_access(dep_target)
                    != Some((
                        dependency_guard.cache_var.as_str(),
                        dependency_guard.dep_slot,
                    ))
                    || codegen_expression_with_flow_cast_restore(dep_value)
                        != dependency_guard.dep_expr
                {
                    guards_match = false;
                    break;
                }
                deps.push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
            }
            if !guards_match {
                continue;
            }
            let setup_statements = collect_statement_sources_from_body_slice(
                body,
                body_offset,
                &consequent_block.body[..dep_base],
            );
            if setup_statements.is_empty() {
                continue;
            }
            return GeneratedBodyShape::MemoizedCachedValues {
                deps,
                setup_statements,
                cached_values,
                restored_values,
            };
        }

        if let [ast::Statement::TryStatement(try_statement)] = statements.as_slice()
            && try_statement.finalizer.is_none()
            && let Some(handler) = try_statement.handler.as_ref()
        {
            let try_source = codegen_statements_with_flow_cast_restore(&try_statement.block.body);
            let try_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &try_source,
                true,
                guard_aliases,
            );
            if matches!(try_shape, GeneratedBodyShape::Unknown) {
                continue;
            }
            let catch_source = codegen_statements_with_flow_cast_restore(&handler.body.body);
            let catch_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &catch_source,
                true,
                guard_aliases,
            );
            if matches!(catch_shape, GeneratedBodyShape::Unknown) {
                continue;
            }
            let catch_param = handler
                .param
                .as_ref()
                .and_then(|param| binding_identifier_name(&param.pattern));
            return GeneratedBodyShape::TryCatch {
                catch_param,
                try_body: Box::new(try_shape),
                catch_body: Box::new(catch_shape),
            };
        }

        let (terminal_expressions, expression_len) =
            collect_leading_expression_statements(statements);
        if expression_len == statements.len() && !terminal_expressions.is_empty() {
            return GeneratedBodyShape::ExpressionStatements(terminal_expressions);
        }

        let (terminal_assignments, assignment_len) = collect_assignments(statements, true);
        if assignment_len == statements.len() && !terminal_assignments.is_empty() {
            return GeneratedBodyShape::AssignmentStatements(terminal_assignments);
        }

        if let [ast::Statement::IfStatement(if_statement)] = statements.as_slice()
            && if_statement.alternate.is_none()
            && let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent
        {
            let (expressions, expression_len) =
                collect_leading_expression_statements(&consequent_block.body);
            if expression_len == consequent_block.body.len() && !expressions.is_empty() {
                return GeneratedBodyShape::GuardedExpressionStatements {
                    test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                    expressions,
                };
            }
            let (assignments, assignment_len) =
                collect_non_cache_assignments(&consequent_block.body);
            if assignment_len == consequent_block.body.len() && !assignments.is_empty() {
                return GeneratedBodyShape::GuardedAssignments {
                    test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                    assignments,
                };
            }
            if assignment_len > 0 && assignment_len < consequent_block.body.len() {
                let (expressions, expression_len) =
                    collect_leading_expression_statements(&consequent_block.body[assignment_len..]);
                if assignment_len + expression_len == consequent_block.body.len()
                    && !assignments.is_empty()
                    && !expressions.is_empty()
                {
                    return GeneratedBodyShape::GuardedAssignmentExpressions {
                        test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                        assignments,
                        expressions,
                    };
                }
            }
        }

        if let [ast::Statement::IfStatement(if_statement)] = statements.as_slice()
            && if_statement.alternate.is_none()
        {
            let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent else {
                continue;
            };
            let consequent_shape = if consequent_block.body.is_empty() {
                GeneratedBodyShape::ExpressionStatements(Vec::new())
            } else {
                let consequent_source =
                    codegen_statements_with_flow_cast_restore(&consequent_block.body);
                analyze_generated_body_shape_impl_with_guard_aliases(
                    &consequent_source,
                    true,
                    guard_aliases,
                )
            };
            if !matches!(consequent_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::GuardedBody {
                    test: codegen_expression_with_flow_cast_restore(&if_statement.test),
                    inner: Box::new(consequent_shape),
                };
            }
        }

        if statements.len() >= 2
            && let Some(ast::Statement::ReturnStatement(return_stmt)) = statements.last()
            && let Some(argument) = return_stmt.argument.as_ref()
            && !matches!(
                argument.without_parentheses(),
                ast::Expression::Identifier(_)
            )
        {
            let wrapped_expression = codegen_expression_with_flow_cast_restore(argument);
            let prefix_source =
                codegen_statements_with_flow_cast_restore(&statements[..statements.len() - 1]);
            for candidate_name in
                collect_candidate_return_identifiers(&statements[..statements.len() - 1])
            {
                if !contains_identifier_token(&wrapped_expression, &candidate_name) {
                    continue;
                }
                let synthetic_return = format!("{prefix_source}\nreturn {candidate_name};");
                let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &synthetic_return,
                    true,
                    guard_aliases,
                );
                if shape_returned_identifier(&inner_shape)
                    .is_some_and(|name| name == candidate_name)
                {
                    return GeneratedBodyShape::WrappedReturnExpression {
                        source_name: candidate_name,
                        expression: wrapped_expression,
                        inner: Box::new(inner_shape),
                    };
                }
            }
        }

        let (prefixed_bindings, prefix_len) = collect_leading_initialized_bindings(statements);
        if prefix_len > 0 && prefix_len < statements.len() {
            let suffix_source =
                codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
            let prefixed_guard_aliases =
                collect_guard_alias_bindings(&statements[..prefix_len], guard_aliases);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                &prefixed_guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::PrefixedBindings {
                    bindings: prefixed_bindings,
                    inner: Box::new(inner_shape),
                };
            }
        }

        let (prefixed_declarations, max_prefix_len) =
            collect_leading_uninitialized_declarations(statements);
        if max_prefix_len > 0 && max_prefix_len < statements.len() {
            for prefix_len in (1..=max_prefix_len).rev() {
                let suffix_source =
                    codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
                let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &suffix_source,
                    true,
                    guard_aliases,
                );
                if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                    return GeneratedBodyShape::PrefixedDeclarations {
                        declarations: prefixed_declarations[..prefix_len].to_vec(),
                        inner: Box::new(inner_shape),
                    };
                }
            }
        }

        let (prefixed_expressions, prefix_len) = collect_leading_expression_statements(statements);
        if prefix_len > 0 && prefix_len < statements.len() && statements.len() <= 6 {
            let suffix_source =
                codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::PrefixedExpressionStatements {
                    expressions: prefixed_expressions,
                    inner: Box::new(inner_shape),
                };
            }
        }

        let (prefixed_assignments, prefix_len) = collect_assignments(statements, true);
        if prefix_len > 0 && prefix_len < statements.len() {
            let suffix_source =
                codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                return GeneratedBodyShape::PrefixedAssignments {
                    assignments: prefixed_assignments,
                    inner: Box::new(inner_shape),
                };
            }
        }

        for terminal_identifier in collect_candidate_return_identifiers(statements) {
            let (prefixed_assignments, prefix_len) =
                collect_leading_side_effect_assignments(statements, &terminal_identifier);
            if prefix_len == 0 || prefix_len >= statements.len() {
                continue;
            }
            let suffix_source =
                codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if shape_returned_identifier(&inner_shape)
                .is_some_and(|name| name == terminal_identifier)
            {
                return GeneratedBodyShape::PrefixedAssignments {
                    assignments: prefixed_assignments,
                    inner: Box::new(inner_shape),
                };
            }
        }

        if statements.len() == 2
            && let Some(ast::Statement::VariableDeclaration(declaration)) = statements.first()
        {
            if declaration.declarations.len() != 1 {
                continue;
            }
            let declarator = &declaration.declarations[0];
            let Some(value_name) = binding_identifier_name(&declarator.id) else {
                continue;
            };
            let Some(init) = declarator.init.as_ref() else {
                continue;
            };
            if statement_returns_identifier(&statements[1], &value_name) {
                return GeneratedBodyShape::BoundExpressionReturn {
                    value_name,
                    value_kind: declaration.kind,
                    expression: codegen_expression_with_flow_cast_restore(init),
                };
            }
        }

        if statements.len() >= 2 {
            let prefix_shape = statement_shape(&statements[0], guard_aliases);
            let allow_prefix_sequence = matches!(
                prefix_shape,
                GeneratedBodyShape::Block { .. }
                    | GeneratedBodyShape::Labeled { .. }
                    | GeneratedBodyShape::Switch { .. }
                    | GeneratedBodyShape::GuardedBody { .. }
                    | GeneratedBodyShape::GuardedExpressionStatements { .. }
                    | GeneratedBodyShape::GuardedReturnPrefix { .. }
                    | GeneratedBodyShape::ConditionalBranches { .. }
                    | GeneratedBodyShape::GuardedAssignments { .. }
                    | GeneratedBodyShape::WhileLoop { .. }
                    | GeneratedBodyShape::DoWhileLoop { .. }
                    | GeneratedBodyShape::ForLoop { .. }
                    | GeneratedBodyShape::ForInLoop { .. }
                    | GeneratedBodyShape::ForOfLoop { .. }
                    | GeneratedBodyShape::GuardedAssignmentExpressions { .. }
                    | GeneratedBodyShape::TryCatch { .. }
            );
            let allow_cached_values_prefix = matches!(
                prefix_shape,
                GeneratedBodyShape::ZeroDependencyMemoizedCachedValues { .. }
                    | GeneratedBodyShape::MemoizedCachedValues { .. }
            );
            if allow_prefix_sequence || allow_cached_values_prefix {
                let suffix_source = codegen_statements_with_flow_cast_restore(&statements[1..]);
                let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &suffix_source,
                    true,
                    guard_aliases,
                );
                let can_sequence = if allow_cached_values_prefix {
                    can_follow_cached_values_prefix(&prefix_shape, &inner_shape)
                } else {
                    true
                };
                if can_sequence && !matches!(inner_shape, GeneratedBodyShape::Unknown) {
                    return GeneratedBodyShape::Sequential {
                        prefix: Box::new(prefix_shape),
                        inner: Box::new(inner_shape),
                    };
                }
            }
        }

        if statements.len() == 2 {
            let Some(ast::Statement::IfStatement(if_statement)) = statements.first() else {
                continue;
            };
            let Some(Some(return_argument)) = extract_return_argument(&statements[1]) else {
                continue;
            };
            let Some(value_name) = expression_identifier_name(return_argument).map(str::to_string)
            else {
                continue;
            };
            let Some(alternate) = if_statement.alternate.as_ref() else {
                continue;
            };
            let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent else {
                continue;
            };
            let ast::Statement::BlockStatement(alternate_block) = alternate else {
                continue;
            };
            if alternate_block.body.len() != 1 {
                continue;
            }
            let binary_test = match if_statement.test.without_parentheses() {
                ast::Expression::BinaryExpression(test) => Some(test),
                _ => None,
            };
            if let Some(test) = binary_test
                && test.operator == AstBinaryOperator::StrictEquality
                && let Some((cache_var, value_slot)) = expression_cache_access(&test.left)
                && expression_is_symbol_for(&test.right, MEMO_CACHE_SENTINEL)
            {
                let (memoized_bindings, binding_prefix_len) =
                    collect_leading_initialized_bindings(&consequent_block.body);
                let (memoized_assignments, assignment_prefix_len) =
                    collect_leading_side_effect_assignments(
                        &consequent_block.body[binding_prefix_len..],
                        &value_name,
                    );
                let (memoized_expressions, expression_prefix_len) =
                    collect_leading_expression_statements(
                        &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                    );
                let setup_len = binding_prefix_len + assignment_prefix_len + expression_prefix_len;
                if consequent_block.body.len() == setup_len + 2 {
                    let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                        &consequent_block.body[setup_len],
                        &value_name,
                    )
                    .map(codegen_expression_with_flow_cast_restore) else {
                        continue;
                    };
                    if !statement_assigns_cache_slot_from_identifier(
                        &consequent_block.body[setup_len + 1],
                        cache_var,
                        value_slot,
                        &value_name,
                    ) || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    ) || !statement_returns_identifier(&statements[1], &value_name)
                    {
                        continue;
                    }
                    return GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
                        value_name,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements: vec![],
                        memoized_expr: Some(memoized_expr),
                    };
                }
                if consequent_block.body.len() == setup_len + 1 {
                    if !statement_assigns_cache_slot_from_identifier(
                        &consequent_block.body[setup_len],
                        cache_var,
                        value_slot,
                        &value_name,
                    ) || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    ) || !statement_returns_identifier(&statements[1], &value_name)
                    {
                        continue;
                    }
                    return GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
                        value_name,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements: vec![],
                        memoized_expr: None,
                    };
                }
                let Some(last_statement) = consequent_block.body.last() else {
                    continue;
                };
                if !statement_assigns_cache_slot_from_identifier(
                    last_statement,
                    cache_var,
                    value_slot,
                    &value_name,
                ) || !statement_assigns_identifier_from_cache_slot(
                    &alternate_block.body[0],
                    &value_name,
                    cache_var,
                    value_slot,
                ) || !statement_returns_identifier(&statements[1], &value_name)
                    || consequent_block.body.len() <= setup_len + 1
                {
                    continue;
                }
                let memoized_setup_statements = collect_statement_sources_from_body_slice(
                    body,
                    body_offset,
                    &consequent_block.body[setup_len..consequent_block.body.len() - 1],
                );
                if memoized_setup_statements.is_empty() {
                    continue;
                }
                return GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
                    value_name,
                    value_slot,
                    memoized_bindings,
                    memoized_assignments,
                    memoized_expressions,
                    memoized_setup_statements,
                    memoized_expr: None,
                };
            }
            if let Some(dependency_guards) =
                collect_dependency_guards(&if_statement.test, guard_aliases)
                && dependency_guards.len() >= 2
            {
                let (memoized_bindings, binding_prefix_len) =
                    collect_leading_initialized_bindings(&consequent_block.body);
                let (memoized_assignments, assignment_prefix_len) =
                    collect_leading_side_effect_assignments(
                        &consequent_block.body[binding_prefix_len..],
                        &value_name,
                    );
                let (memoized_expressions, expression_prefix_len) =
                    collect_leading_expression_statements(
                        &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                    );
                let setup_len = binding_prefix_len + assignment_prefix_len + expression_prefix_len;
                let Some(cache_var) = dependency_guards
                    .first()
                    .map(|guard| guard.cache_var.as_str())
                else {
                    continue;
                };
                if consequent_block.body.len() == setup_len + dependency_guards.len() + 2
                    && let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                        &consequent_block.body[setup_len],
                        &value_name,
                    )
                    .map(codegen_expression_with_flow_cast_restore)
                {
                    let mut dep_pairs: Vec<(u32, String)> =
                        Vec::with_capacity(dependency_guards.len());
                    let mut guards_match = true;
                    for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                        let Some((dep_target, dep_value)) = assignment_statement_parts(
                            &consequent_block.body[setup_len + index + 1],
                        ) else {
                            guards_match = false;
                            break;
                        };
                        if assignment_target_cache_access(dep_target)
                            != Some((
                                dependency_guard.cache_var.as_str(),
                                dependency_guard.dep_slot,
                            ))
                            || codegen_expression_with_flow_cast_restore(dep_value)
                                != dependency_guard.dep_expr
                        {
                            guards_match = false;
                            break;
                        }
                        dep_pairs
                            .push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
                    }
                    if !guards_match {
                        continue;
                    }
                    let Some((value_target, value_value)) = assignment_statement_parts(
                        &consequent_block.body[setup_len + dependency_guards.len() + 1],
                    ) else {
                        continue;
                    };
                    let Some((assigned_cache_var, value_slot)) =
                        assignment_target_cache_access(value_target)
                    else {
                        continue;
                    };
                    if assigned_cache_var != cache_var
                        || !expression_is_identifier(value_value, &value_name)
                        || !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        )
                        || !statement_returns_identifier(&statements[1], &value_name)
                    {
                        continue;
                    }
                    return GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                        value_name,
                        deps: dep_pairs,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements: vec![],
                        memoized_expr: Some(memoized_expr),
                    };
                }
                if consequent_block.body.len() == setup_len + dependency_guards.len() + 1 {
                    let mut dep_pairs: Vec<(u32, String)> =
                        Vec::with_capacity(dependency_guards.len());
                    let mut guards_match = true;
                    for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                        let Some((dep_target, dep_value)) =
                            assignment_statement_parts(&consequent_block.body[setup_len + index])
                        else {
                            guards_match = false;
                            break;
                        };
                        if assignment_target_cache_access(dep_target)
                            != Some((
                                dependency_guard.cache_var.as_str(),
                                dependency_guard.dep_slot,
                            ))
                            || codegen_expression_with_flow_cast_restore(dep_value)
                                != dependency_guard.dep_expr
                        {
                            guards_match = false;
                            break;
                        }
                        dep_pairs
                            .push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
                    }
                    if !guards_match {
                        continue;
                    }
                    let Some((value_target, value_value)) = assignment_statement_parts(
                        &consequent_block.body[setup_len + dependency_guards.len()],
                    ) else {
                        continue;
                    };
                    let Some((assigned_cache_var, value_slot)) =
                        assignment_target_cache_access(value_target)
                    else {
                        continue;
                    };
                    if assigned_cache_var != cache_var
                        || !expression_is_identifier(value_value, &value_name)
                        || !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        )
                        || !statement_returns_identifier(&statements[1], &value_name)
                    {
                        continue;
                    }
                    return GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                        value_name,
                        deps: dep_pairs,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements: vec![],
                        memoized_expr: None,
                    };
                }

                if consequent_block.body.len() <= setup_len + dependency_guards.len() + 1 {
                    continue;
                }
                let mut dep_pairs: Vec<(u32, String)> = Vec::with_capacity(dependency_guards.len());
                let mut guards_match = true;
                let dep_base = consequent_block.body.len() - (dependency_guards.len() + 1);
                for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                    let Some((dep_target, dep_value)) =
                        assignment_statement_parts(&consequent_block.body[dep_base + index])
                    else {
                        guards_match = false;
                        break;
                    };
                    if assignment_target_cache_access(dep_target)
                        != Some((
                            dependency_guard.cache_var.as_str(),
                            dependency_guard.dep_slot,
                        ))
                        || codegen_expression_with_flow_cast_restore(dep_value)
                            != dependency_guard.dep_expr
                    {
                        guards_match = false;
                        break;
                    }
                    dep_pairs.push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
                }
                if !guards_match {
                    continue;
                }
                let Some((value_target, value_value)) =
                    assignment_statement_parts(consequent_block.body.last().unwrap())
                else {
                    continue;
                };
                let Some((assigned_cache_var, value_slot)) =
                    assignment_target_cache_access(value_target)
                else {
                    continue;
                };
                if assigned_cache_var != cache_var
                    || !expression_is_identifier(value_value, &value_name)
                    || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    )
                    || !statement_returns_identifier(&statements[1], &value_name)
                    || dep_base <= setup_len
                {
                    continue;
                }
                let memoized_setup_statements = collect_statement_sources_from_body_slice(
                    body,
                    body_offset,
                    &consequent_block.body[setup_len..dep_base],
                );
                if memoized_setup_statements.is_empty() {
                    continue;
                }
                return GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                    value_name,
                    deps: dep_pairs,
                    value_slot,
                    memoized_bindings,
                    memoized_assignments,
                    memoized_expressions,
                    memoized_setup_statements,
                    memoized_expr: None,
                };
            }

            let Some(dependency_guard) =
                collect_dependency_guards(&if_statement.test, guard_aliases).and_then(|guards| {
                    (guards.len() == 1)
                        .then(|| guards.into_iter().next())
                        .flatten()
                })
            else {
                continue;
            };
            let (memoized_bindings, binding_prefix_len) =
                collect_leading_initialized_bindings(&consequent_block.body);
            let (memoized_assignments, assignment_prefix_len) =
                collect_leading_side_effect_assignments(
                    &consequent_block.body[binding_prefix_len..],
                    &value_name,
                );
            let (memoized_expressions, expression_prefix_len) =
                collect_leading_expression_statements(
                    &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                );
            let setup_len = binding_prefix_len + assignment_prefix_len + expression_prefix_len;
            let cache_var = dependency_guard.cache_var.as_str();
            let dep_slot = dependency_guard.dep_slot;
            let dep_expr = dependency_guard.dep_expr;
            if consequent_block.body.len() == setup_len + 3
                && let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                    &consequent_block.body[setup_len],
                    &value_name,
                )
                .map(codegen_expression_with_flow_cast_restore)
            {
                let Some((dep_target, dep_value)) =
                    assignment_statement_parts(&consequent_block.body[setup_len + 1])
                else {
                    continue;
                };
                if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                    || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
                {
                    continue;
                }
                let Some((value_target, value_value)) =
                    assignment_statement_parts(&consequent_block.body[setup_len + 2])
                else {
                    continue;
                };
                let Some((assigned_cache_var, value_slot)) =
                    assignment_target_cache_access(value_target)
                else {
                    continue;
                };
                if assigned_cache_var != cache_var
                    || !expression_is_identifier(value_value, &value_name)
                    || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    )
                    || !statement_returns_identifier(&statements[1], &value_name)
                {
                    continue;
                }
                return GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
                    value_name,
                    dep_slot,
                    dep_expr,
                    value_slot,
                    memoized_bindings,
                    memoized_assignments,
                    memoized_expressions,
                    memoized_setup_statements: vec![],
                    memoized_expr: Some(memoized_expr),
                };
            }
            if consequent_block.body.len() == setup_len + 2 {
                let Some((dep_target, dep_value)) =
                    assignment_statement_parts(&consequent_block.body[setup_len])
                else {
                    continue;
                };
                if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                    || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
                {
                    continue;
                }
                let Some((value_target, value_value)) =
                    assignment_statement_parts(&consequent_block.body[setup_len + 1])
                else {
                    continue;
                };
                let Some((assigned_cache_var, value_slot)) =
                    assignment_target_cache_access(value_target)
                else {
                    continue;
                };
                if assigned_cache_var != cache_var
                    || !expression_is_identifier(value_value, &value_name)
                    || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    )
                    || !statement_returns_identifier(&statements[1], &value_name)
                {
                    continue;
                }
                return GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
                    value_name,
                    dep_slot,
                    dep_expr,
                    value_slot,
                    memoized_bindings,
                    memoized_assignments,
                    memoized_expressions,
                    memoized_setup_statements: vec![],
                    memoized_expr: None,
                };
            }

            if consequent_block.body.len() <= setup_len + 2 {
                continue;
            }
            let dep_base = consequent_block.body.len() - 2;
            let Some((dep_target, dep_value)) =
                assignment_statement_parts(&consequent_block.body[dep_base])
            else {
                continue;
            };
            if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
            {
                continue;
            }
            let Some((value_target, value_value)) = consequent_block
                .body
                .last()
                .and_then(assignment_statement_parts)
            else {
                continue;
            };
            let Some((assigned_cache_var, value_slot)) =
                assignment_target_cache_access(value_target)
            else {
                continue;
            };
            if assigned_cache_var != cache_var
                || !expression_is_identifier(value_value, &value_name)
                || !statement_assigns_identifier_from_cache_slot(
                    &alternate_block.body[0],
                    &value_name,
                    cache_var,
                    value_slot,
                )
                || !statement_returns_identifier(&statements[1], &value_name)
                || dep_base <= setup_len
            {
                continue;
            }
            let memoized_setup_statements = collect_statement_sources_from_body_slice(
                body,
                body_offset,
                &consequent_block.body[setup_len..dep_base],
            );
            if memoized_setup_statements.is_empty() {
                continue;
            }
            return GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
                value_name,
                dep_slot,
                dep_expr,
                value_slot,
                memoized_bindings,
                memoized_assignments,
                memoized_expressions,
                memoized_setup_statements,
                memoized_expr: None,
            };
        }

        if statements.len() == 3 {
            let Some(ast::Statement::VariableDeclaration(value_decl)) = statements.first() else {
                continue;
            };
            if value_decl.declarations.len() != 1 {
                continue;
            }
            let value_decl = &value_decl.declarations[0];
            let Some(value_name) = binding_identifier_name(&value_decl.id) else {
                continue;
            };
            if let Some(init) = value_decl.init.as_ref()
                && statement_returns_identifier(&statements[2], &value_name)
                && let Some(assigned_expr) =
                    statement_assigns_identifier_to_expression(&statements[1], &value_name)
                && codegen_expression_with_flow_cast_restore(assigned_expr)
                    == codegen_expression_with_flow_cast_restore(init)
            {
                return GeneratedBodyShape::BoundExpressionReturn {
                    value_name,
                    value_kind: value_decl.kind,
                    expression: codegen_expression_with_flow_cast_restore(init),
                };
            }
            if value_decl.init.is_none() {
                if let Some(assigned_expr) =
                    statement_assigns_identifier_to_expression(&statements[1], &value_name)
                    && statement_returns_identifier(&statements[2], &value_name)
                {
                    return GeneratedBodyShape::AssignedExpressionReturn {
                        value_name,
                        value_kind: value_decl.kind,
                        expression: codegen_expression_with_flow_cast_restore(assigned_expr),
                    };
                }
                let Some(ast::Statement::IfStatement(if_statement)) = statements.get(1) else {
                    continue;
                };
                let Some(alternate) = if_statement.alternate.as_ref() else {
                    continue;
                };
                let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent
                else {
                    continue;
                };
                let ast::Statement::BlockStatement(alternate_block) = alternate else {
                    continue;
                };
                if alternate_block.body.len() != 1 {
                    continue;
                }
                if !statement_returns_identifier(&statements[2], &value_name) {
                    let tail_shape = statement_shape(&statements[2], guard_aliases);
                    if !matches!(tail_shape, GeneratedBodyShape::Unknown) {
                        let prefix_source =
                            codegen_statements_with_flow_cast_restore(&statements[..2]);
                        let synthetic_return = format!("{prefix_source}\nreturn {value_name};");
                        let prefix_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                            &synthetic_return,
                            false,
                            guard_aliases,
                        );
                        if shape_returned_identifier(&prefix_shape)
                            .is_some_and(|name| name == value_name)
                        {
                            return GeneratedBodyShape::Sequential {
                                prefix: Box::new(prefix_shape),
                                inner: Box::new(tail_shape),
                            };
                        }
                    }
                }
                let binary_test = match if_statement.test.without_parentheses() {
                    ast::Expression::BinaryExpression(test) => Some(test),
                    _ => None,
                };
                if let Some(test) = binary_test
                    && test.operator == AstBinaryOperator::StrictEquality
                    && let Some((cache_var, value_slot)) = expression_cache_access(&test.left)
                    && expression_is_symbol_for(&test.right, MEMO_CACHE_SENTINEL)
                {
                    let (memoized_bindings, binding_prefix_len) =
                        collect_leading_initialized_bindings(&consequent_block.body);
                    let (memoized_assignments, assignment_prefix_len) =
                        collect_leading_side_effect_assignments(
                            &consequent_block.body[binding_prefix_len..],
                            &value_name,
                        );
                    let (memoized_expressions, expression_prefix_len) =
                        collect_leading_expression_statements(
                            &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                        );
                    let setup_len =
                        binding_prefix_len + assignment_prefix_len + expression_prefix_len;
                    if consequent_block.body.len() == setup_len + 2 {
                        let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                            &consequent_block.body[setup_len],
                            &value_name,
                        )
                        .map(codegen_expression_with_flow_cast_restore) else {
                            continue;
                        };
                        if !statement_assigns_cache_slot_from_identifier(
                            &consequent_block.body[setup_len + 1],
                            cache_var,
                            value_slot,
                            &value_name,
                        ) || !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        ) || !statement_returns_identifier(&statements[2], &value_name)
                        {
                            continue;
                        }
                        return GeneratedBodyShape::ZeroDependencyMemoizedReturn {
                            value_name,
                            value_kind: value_decl.kind,
                            value_slot,
                            memoized_bindings,
                            memoized_assignments,
                            memoized_expressions,
                            memoized_setup_statements: vec![],
                            memoized_expr: Some(memoized_expr),
                        };
                    }
                    let Some(last_statement) = consequent_block.body.last() else {
                        continue;
                    };
                    if !statement_assigns_cache_slot_from_identifier(
                        last_statement,
                        cache_var,
                        value_slot,
                        &value_name,
                    ) || !statement_assigns_identifier_from_cache_slot(
                        &alternate_block.body[0],
                        &value_name,
                        cache_var,
                        value_slot,
                    ) || !statement_returns_identifier(&statements[2], &value_name)
                        || consequent_block.body.len() <= setup_len + 1
                    {
                        continue;
                    }
                    let memoized_setup_statements = collect_statement_sources_from_body_slice(
                        body,
                        body_offset,
                        &consequent_block.body[setup_len..consequent_block.body.len() - 1],
                    );
                    if memoized_setup_statements.is_empty() {
                        continue;
                    }
                    return GeneratedBodyShape::ZeroDependencyMemoizedReturn {
                        value_name,
                        value_kind: value_decl.kind,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements,
                        memoized_expr: None,
                    };
                }
                if let Some(dependency_guards) =
                    collect_dependency_guards(&if_statement.test, guard_aliases)
                    && dependency_guards.len() >= 2
                {
                    let (memoized_bindings, binding_prefix_len) =
                        collect_leading_initialized_bindings(&consequent_block.body);
                    let (memoized_assignments, assignment_prefix_len) =
                        collect_leading_side_effect_assignments(
                            &consequent_block.body[binding_prefix_len..],
                            &value_name,
                        );
                    let (memoized_expressions, expression_prefix_len) =
                        collect_leading_expression_statements(
                            &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                        );
                    let setup_len =
                        binding_prefix_len + assignment_prefix_len + expression_prefix_len;
                    let Some(cache_var) = dependency_guards
                        .first()
                        .map(|guard| guard.cache_var.as_str())
                    else {
                        continue;
                    };
                    if consequent_block.body.len() == setup_len + dependency_guards.len() + 2
                        && let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                            &consequent_block.body[setup_len],
                            &value_name,
                        )
                        .map(codegen_expression_with_flow_cast_restore)
                    {
                        let mut dep_pairs: Vec<(u32, String)> =
                            Vec::with_capacity(dependency_guards.len());
                        let mut guards_match = true;
                        for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                            let Some((dep_target, dep_value)) = assignment_statement_parts(
                                &consequent_block.body[setup_len + index + 1],
                            ) else {
                                guards_match = false;
                                break;
                            };
                            if assignment_target_cache_access(dep_target)
                                != Some((
                                    dependency_guard.cache_var.as_str(),
                                    dependency_guard.dep_slot,
                                ))
                                || codegen_expression_with_flow_cast_restore(dep_value)
                                    != dependency_guard.dep_expr
                            {
                                guards_match = false;
                                break;
                            }
                            dep_pairs.push((
                                dependency_guard.dep_slot,
                                dependency_guard.dep_expr.clone(),
                            ));
                        }
                        if !guards_match {
                            continue;
                        }
                        let Some((value_target, value_value)) = assignment_statement_parts(
                            &consequent_block.body[setup_len + dependency_guards.len() + 1],
                        ) else {
                            continue;
                        };
                        let Some((assigned_cache_var, value_slot)) =
                            assignment_target_cache_access(value_target)
                        else {
                            continue;
                        };
                        if assigned_cache_var != cache_var
                            || !expression_is_identifier(value_value, &value_name)
                            || !statement_assigns_identifier_from_cache_slot(
                                &alternate_block.body[0],
                                &value_name,
                                cache_var,
                                value_slot,
                            )
                            || !statement_returns_identifier(&statements[2], &value_name)
                        {
                            continue;
                        }
                        return GeneratedBodyShape::MultiDependencyMemoizedReturn {
                            value_name,
                            value_kind: value_decl.kind,
                            deps: dep_pairs,
                            value_slot,
                            memoized_bindings,
                            memoized_assignments,
                            memoized_expressions,
                            memoized_setup_statements: vec![],
                            memoized_expr: Some(memoized_expr),
                        };
                    }
                    if consequent_block.body.len() == setup_len + dependency_guards.len() + 1 {
                        let mut dep_pairs: Vec<(u32, String)> =
                            Vec::with_capacity(dependency_guards.len());
                        let mut guards_match = true;
                        for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                            let Some((dep_target, dep_value)) = assignment_statement_parts(
                                &consequent_block.body[setup_len + index],
                            ) else {
                                guards_match = false;
                                break;
                            };
                            if assignment_target_cache_access(dep_target)
                                != Some((
                                    dependency_guard.cache_var.as_str(),
                                    dependency_guard.dep_slot,
                                ))
                                || codegen_expression_with_flow_cast_restore(dep_value)
                                    != dependency_guard.dep_expr
                            {
                                guards_match = false;
                                break;
                            }
                            dep_pairs.push((
                                dependency_guard.dep_slot,
                                dependency_guard.dep_expr.clone(),
                            ));
                        }
                        if !guards_match {
                            continue;
                        }
                        let Some((value_target, value_value)) = assignment_statement_parts(
                            &consequent_block.body[setup_len + dependency_guards.len()],
                        ) else {
                            continue;
                        };
                        let Some((assigned_cache_var, value_slot)) =
                            assignment_target_cache_access(value_target)
                        else {
                            continue;
                        };
                        if assigned_cache_var != cache_var
                            || !expression_is_identifier(value_value, &value_name)
                            || !statement_assigns_identifier_from_cache_slot(
                                &alternate_block.body[0],
                                &value_name,
                                cache_var,
                                value_slot,
                            )
                            || !statement_returns_identifier(&statements[2], &value_name)
                        {
                            continue;
                        }
                        return GeneratedBodyShape::MultiDependencyMemoizedReturn {
                            value_name,
                            value_kind: value_decl.kind,
                            deps: dep_pairs,
                            value_slot,
                            memoized_bindings,
                            memoized_assignments,
                            memoized_expressions,
                            memoized_setup_statements: vec![],
                            memoized_expr: None,
                        };
                    }

                    if consequent_block.body.len() <= setup_len + dependency_guards.len() + 1 {
                        continue;
                    }
                    let mut dep_pairs: Vec<(u32, String)> =
                        Vec::with_capacity(dependency_guards.len());
                    let mut guards_match = true;
                    let dep_base = consequent_block.body.len() - (dependency_guards.len() + 1);
                    for (index, dependency_guard) in dependency_guards.iter().enumerate() {
                        let Some((dep_target, dep_value)) =
                            assignment_statement_parts(&consequent_block.body[dep_base + index])
                        else {
                            guards_match = false;
                            break;
                        };
                        if assignment_target_cache_access(dep_target)
                            != Some((
                                dependency_guard.cache_var.as_str(),
                                dependency_guard.dep_slot,
                            ))
                            || codegen_expression_with_flow_cast_restore(dep_value)
                                != dependency_guard.dep_expr
                        {
                            guards_match = false;
                            break;
                        }
                        dep_pairs
                            .push((dependency_guard.dep_slot, dependency_guard.dep_expr.clone()));
                    }
                    if !guards_match {
                        continue;
                    }
                    let Some((value_target, value_value)) =
                        assignment_statement_parts(consequent_block.body.last().unwrap())
                    else {
                        continue;
                    };
                    let Some((assigned_cache_var, value_slot)) =
                        assignment_target_cache_access(value_target)
                    else {
                        continue;
                    };
                    if assigned_cache_var != cache_var
                        || !expression_is_identifier(value_value, &value_name)
                        || !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        )
                        || !statement_returns_identifier(&statements[2], &value_name)
                        || dep_base <= setup_len
                    {
                        continue;
                    }
                    let memoized_setup_statements = collect_statement_sources_from_body_slice(
                        body,
                        body_offset,
                        &consequent_block.body[setup_len..dep_base],
                    );
                    if memoized_setup_statements.is_empty() {
                        continue;
                    }
                    return GeneratedBodyShape::MultiDependencyMemoizedReturn {
                        value_name,
                        value_kind: value_decl.kind,
                        deps: dep_pairs,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements,
                        memoized_expr: None,
                    };
                }

                if let Some(dependency_guard) =
                    collect_dependency_guards(&if_statement.test, guard_aliases).and_then(
                        |guards| {
                            (guards.len() == 1)
                                .then(|| guards.into_iter().next())
                                .flatten()
                        },
                    )
                {
                    let (memoized_bindings, binding_prefix_len) =
                        collect_leading_initialized_bindings(&consequent_block.body);
                    let (memoized_assignments, assignment_prefix_len) =
                        collect_leading_side_effect_assignments(
                            &consequent_block.body[binding_prefix_len..],
                            &value_name,
                        );
                    let (memoized_expressions, expression_prefix_len) =
                        collect_leading_expression_statements(
                            &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
                        );
                    let setup_len =
                        binding_prefix_len + assignment_prefix_len + expression_prefix_len;
                    let cache_var = dependency_guard.cache_var.as_str();
                    let dep_slot = dependency_guard.dep_slot;
                    let dep_expr = dependency_guard.dep_expr;
                    if consequent_block.body.len() == setup_len + 3
                        && let Some(memoized_expr) = statement_assigns_identifier_to_expression(
                            &consequent_block.body[setup_len],
                            &value_name,
                        )
                        .map(codegen_expression_with_flow_cast_restore)
                    {
                        let Some((dep_target, dep_value)) =
                            assignment_statement_parts(&consequent_block.body[setup_len + 1])
                        else {
                            continue;
                        };
                        if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                            || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
                        {
                            continue;
                        }
                        let Some((value_target, value_value)) =
                            assignment_statement_parts(&consequent_block.body[setup_len + 2])
                        else {
                            continue;
                        };
                        let Some((assigned_cache_var, value_slot)) =
                            assignment_target_cache_access(value_target)
                        else {
                            continue;
                        };
                        if assigned_cache_var != cache_var
                            || !expression_is_identifier(value_value, &value_name)
                        {
                            continue;
                        }
                        if !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        ) || !statement_returns_identifier(&statements[2], &value_name)
                        {
                            continue;
                        }
                        return GeneratedBodyShape::SingleDependencyMemoizedReturn {
                            value_name,
                            value_kind: value_decl.kind,
                            dep_slot,
                            dep_expr,
                            value_slot,
                            memoized_bindings,
                            memoized_assignments,
                            memoized_expressions,
                            memoized_setup_statements: vec![],
                            memoized_expr: Some(memoized_expr),
                        };
                    }
                    if consequent_block.body.len() == setup_len + 2 {
                        let Some((dep_target, dep_value)) =
                            assignment_statement_parts(&consequent_block.body[setup_len])
                        else {
                            continue;
                        };
                        if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                            || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
                        {
                            continue;
                        }
                        let Some((value_target, value_value)) =
                            assignment_statement_parts(&consequent_block.body[setup_len + 1])
                        else {
                            continue;
                        };
                        let Some((assigned_cache_var, value_slot)) =
                            assignment_target_cache_access(value_target)
                        else {
                            continue;
                        };
                        if assigned_cache_var != cache_var
                            || !expression_is_identifier(value_value, &value_name)
                            || !statement_assigns_identifier_from_cache_slot(
                                &alternate_block.body[0],
                                &value_name,
                                cache_var,
                                value_slot,
                            )
                            || !statement_returns_identifier(&statements[2], &value_name)
                        {
                            continue;
                        }
                        return GeneratedBodyShape::SingleDependencyMemoizedReturn {
                            value_name,
                            value_kind: value_decl.kind,
                            dep_slot,
                            dep_expr,
                            value_slot,
                            memoized_bindings,
                            memoized_assignments,
                            memoized_expressions,
                            memoized_setup_statements: vec![],
                            memoized_expr: None,
                        };
                    }

                    if consequent_block.body.len() <= setup_len + 2 {
                        continue;
                    }
                    let dep_base = consequent_block.body.len() - 2;
                    let Some((dep_target, dep_value)) =
                        assignment_statement_parts(&consequent_block.body[dep_base])
                    else {
                        continue;
                    };
                    if assignment_target_cache_access(dep_target) != Some((cache_var, dep_slot))
                        || codegen_expression_with_flow_cast_restore(dep_value) != dep_expr
                    {
                        continue;
                    }
                    let Some((value_target, value_value)) = consequent_block
                        .body
                        .last()
                        .and_then(assignment_statement_parts)
                    else {
                        continue;
                    };
                    let Some((assigned_cache_var, value_slot)) =
                        assignment_target_cache_access(value_target)
                    else {
                        continue;
                    };
                    if assigned_cache_var != cache_var
                        || !expression_is_identifier(value_value, &value_name)
                        || !statement_assigns_identifier_from_cache_slot(
                            &alternate_block.body[0],
                            &value_name,
                            cache_var,
                            value_slot,
                        )
                        || !statement_returns_identifier(&statements[2], &value_name)
                        || dep_base <= setup_len
                    {
                        continue;
                    }
                    let memoized_setup_statements = collect_statement_sources_from_body_slice(
                        body,
                        body_offset,
                        &consequent_block.body[setup_len..dep_base],
                    );
                    if memoized_setup_statements.is_empty() {
                        continue;
                    }
                    return GeneratedBodyShape::SingleDependencyMemoizedReturn {
                        value_name,
                        value_kind: value_decl.kind,
                        dep_slot,
                        dep_expr,
                        value_slot,
                        memoized_bindings,
                        memoized_assignments,
                        memoized_expressions,
                        memoized_setup_statements,
                        memoized_expr: None,
                    };
                }
            }
        }

        for terminal_identifier in collect_candidate_return_identifiers(statements) {
            let (prefixed_assignments, prefix_len) =
                collect_leading_side_effect_assignments(statements, &terminal_identifier);
            if prefix_len == 0 || prefix_len >= statements.len() {
                continue;
            }
            let suffix_source =
                codegen_statements_with_flow_cast_restore(&statements[prefix_len..]);
            let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                &suffix_source,
                true,
                guard_aliases,
            );
            if shape_returned_identifier(&inner_shape)
                .is_some_and(|name| name == terminal_identifier)
            {
                return GeneratedBodyShape::PrefixedAssignments {
                    assignments: prefixed_assignments,
                    inner: Box::new(inner_shape),
                };
            }
        }

        if allow_sequential && (2..=48).contains(&statements.len()) {
            for split_index in collect_sequential_split_indices(statements) {
                let prefixed_guard_aliases =
                    collect_guard_alias_bindings(&statements[..split_index], guard_aliases);
                let suffix_source =
                    codegen_statements_with_flow_cast_restore(&statements[split_index..]);
                let inner_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                    &suffix_source,
                    true,
                    &prefixed_guard_aliases,
                );
                if matches!(inner_shape, GeneratedBodyShape::Unknown) {
                    continue;
                }

                let prefix_source =
                    codegen_statements_with_flow_cast_restore(&statements[..split_index]);
                let prefix_shape = {
                    if split_index == 1 {
                        let direct_shape = statement_shape(&statements[0], guard_aliases);
                        (!matches!(direct_shape, GeneratedBodyShape::Unknown))
                            .then_some(direct_shape)
                    } else {
                        let synthetic_shape =
                            collect_candidate_return_identifiers(&statements[..split_index])
                                .into_iter()
                                .find_map(|candidate_name| {
                                    let synthetic_return =
                                        format!("{prefix_source}\nreturn {candidate_name};");
                                    let synthetic_shape =
                                        analyze_generated_body_shape_impl_with_guard_aliases(
                                            &synthetic_return,
                                            false,
                                            guard_aliases,
                                        );
                                    shape_returned_identifier(&synthetic_shape)
                                        .is_some_and(|name| name == candidate_name)
                                        .then_some(synthetic_shape)
                                });
                        synthetic_shape.or_else(|| {
                            let direct_shape = analyze_generated_body_shape_impl_with_guard_aliases(
                                &prefix_source,
                                false,
                                guard_aliases,
                            );
                            (!matches!(direct_shape, GeneratedBodyShape::Unknown))
                                .then_some(direct_shape)
                        })
                    }
                };
                if let Some(prefix_shape) = prefix_shape {
                    return GeneratedBodyShape::Sequential {
                        prefix: Box::new(prefix_shape),
                        inner: Box::new(inner_shape),
                    };
                }
            }
        }

        if statements.len() != 5 {
            continue;
        }
        let Some(cache_var) = cache_prologue_binding_name(&statements[0]) else {
            continue;
        };
        let Some(ast::Statement::VariableDeclaration(memo_decl)) = statements.get(1) else {
            continue;
        };
        if memo_decl.kind != ast::VariableDeclarationKind::Let || memo_decl.declarations.len() != 1
        {
            continue;
        }
        let memo_decl = &memo_decl.declarations[0];
        if memo_decl.init.is_some() {
            continue;
        }
        let Some(memo_var) = binding_identifier_name(&memo_decl.id) else {
            continue;
        };

        let Some(ast::Statement::IfStatement(if_statement)) = statements.get(2) else {
            continue;
        };
        let ast::Expression::BinaryExpression(test) = if_statement.test.without_parentheses()
        else {
            continue;
        };
        if test.operator != AstBinaryOperator::StrictEquality
            || expression_cache_access(&test.left) != Some((cache_var.as_str(), 0))
            || !expression_is_symbol_for(&test.right, MEMO_CACHE_SENTINEL)
        {
            continue;
        }
        let Some(alternate) = if_statement.alternate.as_ref() else {
            continue;
        };
        let ast::Statement::BlockStatement(consequent_block) = &if_statement.consequent else {
            continue;
        };
        let ast::Statement::BlockStatement(alternate_block) = alternate else {
            continue;
        };
        let (memoized_bindings, binding_prefix_len) =
            collect_leading_initialized_bindings(&consequent_block.body);
        let (memoized_assignments, assignment_prefix_len) = collect_leading_side_effect_assignments(
            &consequent_block.body[binding_prefix_len..],
            &memo_var,
        );
        let (memoized_expressions, expression_prefix_len) = collect_leading_expression_statements(
            &consequent_block.body[binding_prefix_len + assignment_prefix_len..],
        );
        let setup_len = binding_prefix_len + assignment_prefix_len + expression_prefix_len;
        if consequent_block.body.len() != setup_len + 2 || alternate_block.body.len() != 1 {
            continue;
        }

        let Some(memoized_expr) = statement_assigns_identifier_to_expression(
            &consequent_block.body[setup_len],
            &memo_var,
        )
        .map(codegen_expression_with_flow_cast_restore) else {
            continue;
        };
        if !statement_assigns_cache_slot_from_identifier(
            &consequent_block.body[setup_len + 1],
            &cache_var,
            0,
            &memo_var,
        ) {
            continue;
        }
        if !statement_assigns_identifier_from_cache_slot(
            &alternate_block.body[0],
            &memo_var,
            &cache_var,
            0,
        ) {
            continue;
        }

        let Some(ast::Statement::VariableDeclaration(value_decl)) = statements.get(3) else {
            continue;
        };
        if value_decl.declarations.len() != 1 {
            continue;
        }
        let value_decl = &value_decl.declarations[0];
        let Some(value_name) = binding_identifier_name(&value_decl.id) else {
            continue;
        };
        if !matches!(
            value_decl.kind,
            ast::VariableDeclarationKind::Let | ast::VariableDeclarationKind::Const
        ) {
            continue;
        }
        let Some(init) = value_decl.init.as_ref() else {
            continue;
        };
        let ast::Expression::ConditionalExpression(conditional) = init.without_parentheses() else {
            continue;
        };
        let ast::Expression::BinaryExpression(test) = conditional.test.without_parentheses() else {
            continue;
        };
        if test.operator != AstBinaryOperator::StrictEquality
            || !expression_is_identifier(&test.right, "undefined")
            || !expression_is_identifier(&conditional.consequent, &memo_var)
        {
            continue;
        }
        let Some(temp_name) = expression_identifier_name(&test.left).map(str::to_string) else {
            continue;
        };
        if !expression_is_identifier(&conditional.alternate, &temp_name) {
            continue;
        }

        if !statement_returns_identifier(&statements[4], &value_name) {
            continue;
        }

        return GeneratedBodyShape::SingleSlotMemoizedReturn {
            value_name,
            value_kind: value_decl.kind,
            temp_name,
            memoized_bindings,
            memoized_assignments,
            memoized_expressions,
            memoized_expr,
        };
    }
    GeneratedBodyShape::Unknown
}

fn strip_trailing_bare_return(body: &str, is_async: bool, is_generator: bool) -> String {
    let allocator = Allocator::default();
    if let Ok((wrapper_prefix_len, parsed_body)) = parse_function_body_for_ast_codegen_with_offset(
        &allocator,
        SourceType::mjs().with_jsx(true),
        is_async,
        is_generator,
        body,
    ) && let Some(ast::Statement::ReturnStatement(return_statement)) =
        parsed_body.statements.last()
        && return_statement.argument.is_none()
    {
        let start = return_statement.span.start as usize - wrapper_prefix_len;
        let mut stripped = body[..start].trim_end().to_string();
        stripped.push('\n');
        return stripped;
    }

    let trimmed = body.trim_end();
    if let Some(prefix) = trimmed.strip_suffix("return;") {
        let mut stripped = prefix.to_string();
        stripped.push('\n');
        stripped
    } else {
        body.to_string()
    }
}

fn prune_unused_const_literal_decls(body: &str, is_async: bool, is_generator: bool) -> String {
    let allocator = Allocator::default();
    if let Ok((wrapper_prefix_len, parsed_body)) = parse_function_body_for_ast_codegen_with_offset(
        &allocator,
        SourceType::mjs().with_jsx(true),
        is_async,
        is_generator,
        body,
    ) {
        let removable: HashSet<usize> = parsed_body
            .statements
            .iter()
            .enumerate()
            .filter_map(|(idx, statement)| {
                let name = const_literal_decl_identifier(statement)?;
                let used_elsewhere = parsed_body.statements.iter().enumerate().any(
                    |(other_idx, other_statement)| {
                        other_idx != idx
                            && statement_references_identifier(other_statement, name.as_str())
                    },
                );
                (!used_elsewhere).then_some(idx)
            })
            .collect();
        if removable.is_empty() {
            return body.to_string();
        }

        let mut out = String::with_capacity(body.len());
        let mut cursor = 0usize;
        for (idx, statement) in parsed_body.statements.iter().enumerate() {
            if !removable.contains(&idx) {
                continue;
            }
            let start = statement.span().start as usize - wrapper_prefix_len;
            let end = parsed_body
                .statements
                .get(idx + 1)
                .map(|next| next.span().start as usize - wrapper_prefix_len)
                .unwrap_or(body.len());
            out.push_str(&body[cursor..start]);
            cursor = end;
        }
        out.push_str(&body[cursor..]);
        return out;
    }

    prune_unused_const_literal_decls_line_fallback(body)
}

fn prune_unused_const_literal_decls_line_fallback(body: &str) -> String {
    let lines: Vec<&str> = body.lines().collect();
    if lines.is_empty() {
        return body.to_string();
    }

    let mut in_multiline_for_header = vec![false; lines.len()];
    let mut for_header_start: Option<usize> = None;
    for (idx, line) in lines.iter().enumerate() {
        let trimmed = line.trim();
        if let Some(start) = for_header_start {
            if trimmed == ") {" || trimmed == ")" || trimmed.starts_with(") {") {
                for slot in in_multiline_for_header.iter_mut().take(idx + 1).skip(start) {
                    *slot = true;
                }
                for_header_start = None;
            }
            continue;
        }
        if trimmed == "for (" || trimmed.ends_with("for (") {
            for_header_start = Some(idx);
        }
    }

    let mut candidates: HashMap<usize, String> = HashMap::new();
    for (idx, line) in lines.iter().enumerate() {
        if in_multiline_for_header[idx] {
            continue;
        }
        let trimmed = line.trim();
        let Some((name, rhs)) = parse_const_literal_decl(trimmed) else {
            continue;
        };
        if is_inlineable_primitive_literal_expression(&rhs) {
            candidates.insert(idx, name);
        }
    }
    if candidates.is_empty() {
        return body.to_string();
    }

    let mut keep = vec![true; lines.len()];
    for (idx, name) in candidates {
        let used_elsewhere = lines
            .iter()
            .enumerate()
            .any(|(other, line)| other != idx && contains_identifier_token(line, &name));
        if !used_elsewhere {
            keep[idx] = false;
        }
    }

    let mut out = String::new();
    for (idx, line) in lines.iter().enumerate() {
        if keep[idx] {
            out.push_str(line);
            out.push('\n');
        }
    }
    out
}

fn const_literal_decl_identifier(statement: &ast::Statement<'_>) -> Option<String> {
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if declaration.kind != ast::VariableDeclarationKind::Const
        || declaration.declarations.len() != 1
    {
        return None;
    }
    let declarator = &declaration.declarations[0];
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    let init = declarator.init.as_ref()?;
    expression_is_inlineable_primitive_literal(init).then(|| identifier.name.to_string())
}

fn parse_const_literal_decl(line: &str) -> Option<(String, String)> {
    let allocator = Allocator::default();
    let statement =
        parse_single_statement_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), line)
            .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    let declaration = declaration.unbox();
    if declaration.kind != ast::VariableDeclarationKind::Const
        || declaration.declarations.len() != 1
    {
        return None;
    }
    let declarator = declaration.declarations.into_iter().next()?;
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    let init = declarator.init.as_ref()?;
    Some((
        identifier.name.to_string(),
        codegen_expression_with_flow_cast_restore(init),
    ))
}

fn contains_identifier_token(haystack: &str, needle: &str) -> bool {
    if needle.is_empty() {
        return false;
    }
    if let Some(found) = rendered_source_references_identifier(haystack, needle) {
        return found;
    }
    let mut start = 0usize;
    while let Some(found) = haystack[start..].find(needle) {
        let idx = start + found;
        let before_ok = if idx == 0 {
            true
        } else {
            !is_simple_identifier_char(haystack.as_bytes()[idx - 1] as char)
        };
        let end = idx + needle.len();
        let after_ok = if end >= haystack.len() {
            true
        } else {
            !is_simple_identifier_char(haystack.as_bytes()[end] as char)
        };
        if before_ok && after_ok {
            return true;
        }
        start = end;
    }
    false
}

fn rendered_source_references_identifier(source: &str, ident: &str) -> Option<bool> {
    let trimmed = source.trim();
    if trimmed.is_empty() {
        return Some(false);
    }
    let allocator = Allocator::default();
    if let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) {
        let mut detector = IdentifierReferenceDetector {
            ident,
            found: false,
        };
        detector.visit_expression(&expression);
        return Some(detector.found);
    }
    let body = parse_function_body_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        false,
        false,
        trimmed,
    )
    .ok()?;
    let mut detector = IdentifierReferenceDetector {
        ident,
        found: false,
    };
    for statement in &body.statements {
        detector.visit_statement(statement);
        if detector.found {
            return Some(true);
        }
    }
    Some(false)
}

fn statement_references_identifier(statement: &ast::Statement<'_>, ident: &str) -> bool {
    let mut detector = IdentifierReferenceDetector {
        ident,
        found: false,
    };
    detector.visit_statement(statement);
    detector.found
}

struct IdentifierReferenceDetector<'ident> {
    ident: &'ident str,
    found: bool,
}

impl<'a> Visit<'a> for IdentifierReferenceDetector<'_> {
    fn visit_identifier_reference(&mut self, it: &ast::IdentifierReference<'a>) {
        if it.name == self.ident {
            self.found = true;
        }
    }
}

fn contains_base_identifier_token(haystack: &str, needle: &str) -> bool {
    if needle.is_empty() {
        return false;
    }
    if let Some(found) = rendered_source_references_identifier(haystack, needle) {
        return found;
    }
    let mut start = 0usize;
    while let Some(found) = haystack[start..].find(needle) {
        let idx = start + found;
        let before_ok = if idx == 0 {
            true
        } else {
            let prev = haystack.as_bytes()[idx - 1] as char;
            prev != '.' && !is_simple_identifier_char(prev)
        };
        let end = idx + needle.len();
        let after_ok = if end >= haystack.len() {
            true
        } else {
            !is_simple_identifier_char(haystack.as_bytes()[end] as char)
        };
        if before_ok && after_ok {
            return true;
        }
        start = end;
    }
    false
}

fn is_simple_identifier_char(ch: char) -> bool {
    ch == '_' || ch == '$' || ch.is_ascii_alphanumeric()
}

fn build_hook_guard_call_expression_ast(builder: AstBuilder, mode: u8) -> ast::Expression {
    builder.expression_call(
        SPAN,
        builder.expression_identifier(SPAN, builder.ident(HOOK_GUARD_IDENT)),
        NONE,
        builder.vec1(ast::Argument::from(builder.expression_numeric_literal(
            SPAN,
            mode as f64,
            None,
            NumberBase::Decimal,
        ))),
        false,
    )
}

fn build_hook_guard_call_statement_ast(builder: AstBuilder, mode: u8) -> ast::Statement {
    builder.statement_expression(SPAN, build_hook_guard_call_expression_ast(builder, mode))
}

#[cfg(test)]
fn render_hook_guarded_block_ast(body: &str, before: u8, after: u8) -> Option<String> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut guarded_body = builder.vec1(build_hook_guard_call_statement_ast(builder, before));
    guarded_body.extend(
        parse_statement_list_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), body)
            .ok()?,
    );
    let statement = builder.statement_try(
        SPAN,
        builder.alloc_block_statement(SPAN, guarded_body),
        Option::<oxc_allocator::Box<'_, ast::CatchClause<'_>>>::None,
        Some(builder.alloc_block_statement(
            SPAN,
            builder.vec1(build_hook_guard_call_statement_ast(builder, after)),
        )),
    );
    Some(format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ))
}

fn render_hook_guarded_call_expression_ast(call_expr: &str) -> Option<String> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut try_body = builder.vec1(build_hook_guard_call_statement_ast(
        builder,
        HOOK_GUARD_ALLOW,
    ));
    try_body.push(
        builder.statement_return(
            SPAN,
            Some(
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    call_expr,
                )
                .ok()?,
            ),
        ),
    );
    let try_statement = builder.statement_try(
        SPAN,
        builder.alloc_block_statement(SPAN, try_body),
        Option::<oxc_allocator::Box<'_, ast::CatchClause<'_>>>::None,
        Some(builder.alloc_block_statement(
            SPAN,
            builder.vec1(build_hook_guard_call_statement_ast(
                builder,
                HOOK_GUARD_DISALLOW,
            )),
        )),
    );
    let function = builder.expression_function(
        SPAN,
        ast::FunctionType::FunctionExpression,
        None,
        false,
        false,
        false,
        NONE,
        NONE,
        builder.alloc(builder.formal_parameters(
            SPAN,
            ast::FormalParameterKind::FormalParameter,
            builder.vec(),
            Option::<oxc_allocator::Box<'_, ast::FormalParameterRest<'_>>>::None,
        )),
        NONE,
        Some(builder.alloc(builder.function_body(
            SPAN,
            builder.vec(),
            builder.vec1(try_statement),
        ))),
    );
    let expression = builder.expression_call(SPAN, function, NONE, builder.vec(), false);
    Some(strip_optional_chain_receiver_parens(
        strip_top_level_parenthesized_expression(codegen_expression_with_flow_cast_restore(
            &expression,
        )),
    ))
}

fn guard_hook_call_expression(cx: &mut Context, call_expr: String) -> String {
    cx.emitted_hook_guards = true;
    render_hook_guarded_call_expression_ast(&call_expr)
        .expect("generated hook-guarded call should parse")
}

fn set_codegen_error_once(cx: &mut Context, reason: &str, message: String) {
    if cx.codegen_error.is_some() {
        return;
    }
    cx.codegen_error = Some(CompilerError::Bail(BailOut {
        reason: reason.to_string(),
        diagnostics: vec![CompilerDiagnostic {
            severity: DiagnosticSeverity::Invariant,
            message,
        }],
    }));
}

fn set_const_declaration_expression_error(cx: &mut Context, kind: InstructionKind) {
    let message = if kind == InstructionKind::Let || kind == InstructionKind::HoistedLet {
        "this is const".to_string()
    } else {
        format!("this is {:?}", kind)
    };
    set_codegen_error_once(
        cx,
        "Const declaration cannot be referenced as an expression",
        message,
    );
}

fn set_function_declaration_expression_error(cx: &mut Context, kind: InstructionKind) {
    set_codegen_error_once(
        cx,
        "Function declaration cannot be referenced as an expression",
        format!("this is {:?}", kind),
    );
}

fn adopt_codegen_error(cx: &mut Context, child_error: Option<CompilerError>) {
    if cx.codegen_error.is_none() {
        cx.codegen_error = child_error;
    }
}

fn collect_child_context_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut captured = HashSet::new();
    collect_child_context_declarations_in_block(block, &mut captured);
    captured
}

fn collect_mutable_child_context_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut captured = HashSet::new();
    collect_mutable_child_context_declarations_in_block(block, &mut captured);
    captured
}

fn collect_child_context_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::FunctionExpression { lowered_func, .. }
                | InstructionValue::ObjectMethod { lowered_func, .. } => {
                    for place in &lowered_func.func.context {
                        out.insert(place.identifier.declaration_id);
                    }
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                collect_child_context_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_child_context_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_child_context_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_child_context_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_child_context_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_child_context_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_child_context_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_child_context_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_child_context_declarations_in_block(block, out);
            collect_child_context_declarations_in_block(handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_mutable_child_context_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::FunctionExpression { lowered_func, .. }
                | InstructionValue::ObjectMethod { lowered_func, .. } => {
                    let mut child_reassigned = HashSet::new();
                    collect_reassigned_decl_ids_in_hir_function(
                        &lowered_func.func,
                        &mut child_reassigned,
                    );
                    for place in &lowered_func.func.context {
                        if child_reassigned.contains(&place.identifier.declaration_id) {
                            out.insert(place.identifier.declaration_id);
                        }
                    }
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                collect_mutable_child_context_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_mutable_child_context_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_mutable_child_context_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_reassigned_decl_ids_in_hir_function(
    func: &HIRFunction,
    out: &mut HashSet<DeclarationId>,
) {
    for (_, block) in &func.body.blocks {
        for instr in &block.instructions {
            match &instr.value {
                InstructionValue::StoreLocal { lvalue, .. }
                | InstructionValue::StoreContext { lvalue, .. } => {
                    if lvalue.kind == InstructionKind::Reassign {
                        out.insert(lvalue.place.identifier.declaration_id);
                    }
                }
                InstructionValue::PrefixUpdate { lvalue, .. }
                | InstructionValue::PostfixUpdate { lvalue, .. } => {
                    out.insert(lvalue.identifier.declaration_id);
                }
                InstructionValue::FunctionExpression { lowered_func, .. }
                | InstructionValue::ObjectMethod { lowered_func, .. } => {
                    collect_reassigned_decl_ids_in_hir_function(&lowered_func.func, out);
                }
                _ => {}
            }
        }
    }
}

fn collect_mutable_child_context_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_mutable_child_context_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_mutable_child_context_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_mutable_child_context_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_mutable_child_context_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_mutable_child_context_declarations_in_block(block, out);
            collect_mutable_child_context_declarations_in_block(handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_reassigned_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut reassigned = HashSet::new();
    collect_reassigned_declarations_in_block(block, &mut reassigned);
    reassigned
}

fn collect_mutable_destructure_sources(
    block: &ReactiveBlock,
    reassigned: &HashSet<DeclarationId>,
) -> HashSet<DeclarationId> {
    let mut destructure_edges: Vec<(DeclarationId, Vec<DeclarationId>)> = Vec::new();
    let mut assignment_edges: Vec<(DeclarationId, DeclarationId)> = Vec::new();
    collect_mutable_destructure_edges_in_block(
        block,
        &mut destructure_edges,
        &mut assignment_edges,
    );

    let mut mutable_sources = reassigned.clone();
    collect_update_expression_declarations_in_block(block, &mut mutable_sources);
    let mut changed = true;
    while changed {
        changed = false;

        for (source, target) in &assignment_edges {
            if mutable_sources.contains(target) && mutable_sources.insert(*source) {
                changed = true;
            }
        }

        for (source, operands) in &destructure_edges {
            if operands
                .iter()
                .any(|operand| mutable_sources.contains(operand))
                && mutable_sources.insert(*source)
            {
                changed = true;
            }
        }
    }

    mutable_sources
}

fn collect_update_expression_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    let mut temp_sources = HashMap::new();
    collect_update_expression_declarations_in_block_with_temps(block, out, &mut temp_sources);
}

fn collect_update_expression_declarations_in_block_with_temps(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
    temp_sources: &mut HashMap<DeclarationId, DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. } => {
                    if let Some(lvalue) = &instr.lvalue {
                        temp_sources.insert(
                            lvalue.identifier.declaration_id,
                            resolve_update_source_decl_id(place, temp_sources),
                        );
                    }
                }
                InstructionValue::TypeCastExpression { value, .. } => {
                    if let Some(lvalue) = &instr.lvalue {
                        temp_sources.insert(
                            lvalue.identifier.declaration_id,
                            resolve_update_source_decl_id(value, temp_sources),
                        );
                    }
                }
                InstructionValue::PrefixUpdate { value, .. }
                | InstructionValue::PostfixUpdate { value, .. } => {
                    out.insert(resolve_update_source_decl_id(value, temp_sources));
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                let mut nested_temp_sources = temp_sources.clone();
                collect_update_expression_declarations_in_block_with_temps(
                    &scope.instructions,
                    out,
                    &mut nested_temp_sources,
                );
            }
            ReactiveStatement::PrunedScope(scope) => {
                let mut nested_temp_sources = temp_sources.clone();
                collect_update_expression_declarations_in_block_with_temps(
                    &scope.instructions,
                    out,
                    &mut nested_temp_sources,
                );
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_update_expression_declarations_in_terminal(
                    &term_stmt.terminal,
                    out,
                    temp_sources,
                );
            }
        }
    }
}

fn resolve_update_source_decl_id(
    place: &Place,
    temp_sources: &HashMap<DeclarationId, DeclarationId>,
) -> DeclarationId {
    temp_sources
        .get(&place.identifier.declaration_id)
        .copied()
        .unwrap_or(place.identifier.declaration_id)
}

fn collect_update_expression_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
    temp_sources: &HashMap<DeclarationId, DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            let mut consequent_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                consequent,
                out,
                &mut consequent_temp_sources,
            );
            if let Some(alt) = alternate {
                let mut alternate_temp_sources = temp_sources.clone();
                collect_update_expression_declarations_in_block_with_temps(
                    alt,
                    out,
                    &mut alternate_temp_sources,
                );
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    let mut case_temp_sources = temp_sources.clone();
                    collect_update_expression_declarations_in_block_with_temps(
                        block,
                        out,
                        &mut case_temp_sources,
                    );
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            let mut init_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                init,
                out,
                &mut init_temp_sources,
            );
            if let Some(update) = update {
                let mut update_temp_sources = temp_sources.clone();
                collect_update_expression_declarations_in_block_with_temps(
                    update,
                    out,
                    &mut update_temp_sources,
                );
            }
            let mut loop_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                loop_block,
                out,
                &mut loop_temp_sources,
            );
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            let mut init_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                init,
                out,
                &mut init_temp_sources,
            );
            let mut loop_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                loop_block,
                out,
                &mut loop_temp_sources,
            );
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            let mut loop_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                loop_block,
                out,
                &mut loop_temp_sources,
            );
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            let mut block_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                block,
                out,
                &mut block_temp_sources,
            );
            let mut handler_temp_sources = temp_sources.clone();
            collect_update_expression_declarations_in_block_with_temps(
                handler,
                out,
                &mut handler_temp_sources,
            );
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_mutable_destructure_edges_in_block(
    block: &ReactiveBlock,
    destructure_edges: &mut Vec<(DeclarationId, Vec<DeclarationId>)>,
    assignment_edges: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::Destructure { lvalue, value, .. } => {
                    destructure_edges.push((
                        value.identifier.declaration_id,
                        pattern_operands(&lvalue.pattern)
                            .into_iter()
                            .map(|place| place.identifier.declaration_id)
                            .collect(),
                    ));
                }
                InstructionValue::StoreLocal { lvalue, value, .. }
                | InstructionValue::StoreContext { lvalue, value, .. } => {
                    assignment_edges.push((
                        value.identifier.declaration_id,
                        lvalue.place.identifier.declaration_id,
                    ));
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                collect_mutable_destructure_edges_in_block(
                    &scope.instructions,
                    destructure_edges,
                    assignment_edges,
                );
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_mutable_destructure_edges_in_block(
                    &scope.instructions,
                    destructure_edges,
                    assignment_edges,
                );
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_mutable_destructure_edges_in_terminal(
                    &term_stmt.terminal,
                    destructure_edges,
                    assignment_edges,
                );
            }
        }
    }
}

fn collect_mutable_destructure_edges_in_terminal(
    terminal: &ReactiveTerminal,
    destructure_edges: &mut Vec<(DeclarationId, Vec<DeclarationId>)>,
    assignment_edges: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_mutable_destructure_edges_in_block(
                consequent,
                destructure_edges,
                assignment_edges,
            );
            if let Some(alt) = alternate {
                collect_mutable_destructure_edges_in_block(
                    alt,
                    destructure_edges,
                    assignment_edges,
                );
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_mutable_destructure_edges_in_block(
                        block,
                        destructure_edges,
                        assignment_edges,
                    );
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_mutable_destructure_edges_in_block(init, destructure_edges, assignment_edges);
            if let Some(update) = update {
                collect_mutable_destructure_edges_in_block(
                    update,
                    destructure_edges,
                    assignment_edges,
                );
            }
            collect_mutable_destructure_edges_in_block(
                loop_block,
                destructure_edges,
                assignment_edges,
            );
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_mutable_destructure_edges_in_block(init, destructure_edges, assignment_edges);
            collect_mutable_destructure_edges_in_block(
                loop_block,
                destructure_edges,
                assignment_edges,
            );
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_mutable_destructure_edges_in_block(
                loop_block,
                destructure_edges,
                assignment_edges,
            );
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_mutable_destructure_edges_in_block(block, destructure_edges, assignment_edges);
            collect_mutable_destructure_edges_in_block(
                handler,
                destructure_edges,
                assignment_edges,
            );
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_elidable_null_initializer_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut reassigning_scope_ids: HashMap<DeclarationId, HashSet<ScopeId>> = HashMap::new();
    collect_reassigning_scope_ids_in_block(block, &mut reassigning_scope_ids);
    if reassigning_scope_ids.is_empty() {
        return HashSet::new();
    }

    let mut required_initializers = HashSet::new();
    let mut active_scope_ids = Vec::new();
    collect_reads_outside_reassigning_scopes_in_block(
        block,
        &reassigning_scope_ids,
        &mut active_scope_ids,
        &mut required_initializers,
    );

    reassigning_scope_ids
        .into_keys()
        .filter(|decl_id| !required_initializers.contains(decl_id))
        .collect()
}

fn collect_reassigning_scope_ids_in_block(
    block: &ReactiveBlock,
    out: &mut HashMap<DeclarationId, HashSet<ScopeId>>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(_) => {}
            ReactiveStatement::Scope(scope) => {
                for reassignment in &scope.scope.reassignments {
                    out.entry(reassignment.declaration_id)
                        .or_default()
                        .insert(scope.scope.id);
                }
                collect_reassigning_scope_ids_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                for reassignment in &scope.scope.reassignments {
                    out.entry(reassignment.declaration_id)
                        .or_default()
                        .insert(scope.scope.id);
                }
                collect_reassigning_scope_ids_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_reassigning_scope_ids_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_reassigning_scope_ids_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashMap<DeclarationId, HashSet<ScopeId>>,
) {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => {}
        ReactiveTerminal::Return { .. } | ReactiveTerminal::Throw { .. } => {}
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_reassigning_scope_ids_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. } => {
            collect_reassigning_scope_ids_in_block(loop_block, out);
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_reassigning_scope_ids_in_block(init, out);
            if let Some(update) = update {
                collect_reassigning_scope_ids_in_block(update, out);
            }
            collect_reassigning_scope_ids_in_block(loop_block, out);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_reassigning_scope_ids_in_block(init, out);
            collect_reassigning_scope_ids_in_block(loop_block, out);
        }
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_reassigning_scope_ids_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_reassigning_scope_ids_in_block(alt, out);
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_reassigning_scope_ids_in_block(block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_reassigning_scope_ids_in_block(block, out);
            collect_reassigning_scope_ids_in_block(handler, out);
        }
    }
}

fn collect_reads_outside_reassigning_scopes_in_block(
    block: &ReactiveBlock,
    reassigning_scope_ids: &HashMap<DeclarationId, HashSet<ScopeId>>,
    active_scope_ids: &mut Vec<ScopeId>,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                visitors::for_each_instruction_value_operand(&instr.value, |place| {
                    mark_initializer_required_if_read_outside_reassigning_scope(
                        place.identifier.declaration_id,
                        reassigning_scope_ids,
                        active_scope_ids,
                        out,
                    );
                });
            }
            ReactiveStatement::Scope(scope) => {
                active_scope_ids.push(scope.scope.id);
                collect_reads_outside_reassigning_scopes_in_block(
                    &scope.instructions,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
                active_scope_ids.pop();
            }
            ReactiveStatement::PrunedScope(scope) => {
                active_scope_ids.push(scope.scope.id);
                collect_reads_outside_reassigning_scopes_in_block(
                    &scope.instructions,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
                active_scope_ids.pop();
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_reads_outside_reassigning_scopes_in_terminal(
                    &term_stmt.terminal,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
            }
        }
    }
}

fn collect_reads_outside_reassigning_scopes_in_terminal(
    terminal: &ReactiveTerminal,
    reassigning_scope_ids: &HashMap<DeclarationId, HashSet<ScopeId>>,
    active_scope_ids: &mut Vec<ScopeId>,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => {}
        ReactiveTerminal::Return { value, .. } | ReactiveTerminal::Throw { value, .. } => {
            mark_initializer_required_if_read_outside_reassigning_scope(
                value.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::Switch { test, cases, .. } => {
            mark_initializer_required_if_read_outside_reassigning_scope(
                test.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            for case in cases {
                if let Some(test) = &case.test {
                    mark_initializer_required_if_read_outside_reassigning_scope(
                        test.identifier.declaration_id,
                        reassigning_scope_ids,
                        active_scope_ids,
                        out,
                    );
                }
                if let Some(block) = &case.block {
                    collect_reads_outside_reassigning_scopes_in_block(
                        block,
                        reassigning_scope_ids,
                        active_scope_ids,
                        out,
                    );
                }
            }
        }
        ReactiveTerminal::DoWhile {
            loop_block, test, ..
        }
        | ReactiveTerminal::While {
            test, loop_block, ..
        } => {
            mark_initializer_required_if_read_outside_reassigning_scope(
                test.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            collect_reads_outside_reassigning_scopes_in_block(
                loop_block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            loop_block,
            ..
        } => {
            collect_reads_outside_reassigning_scopes_in_block(
                init,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            mark_initializer_required_if_read_outside_reassigning_scope(
                test.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            if let Some(update) = update {
                collect_reads_outside_reassigning_scopes_in_block(
                    update,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
            }
            collect_reads_outside_reassigning_scopes_in_block(
                loop_block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            collect_reads_outside_reassigning_scopes_in_block(
                init,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            mark_initializer_required_if_read_outside_reassigning_scope(
                test.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            collect_reads_outside_reassigning_scopes_in_block(
                loop_block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_reads_outside_reassigning_scopes_in_block(
                init,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            collect_reads_outside_reassigning_scopes_in_block(
                loop_block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            mark_initializer_required_if_read_outside_reassigning_scope(
                test.identifier.declaration_id,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            collect_reads_outside_reassigning_scopes_in_block(
                consequent,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            if let Some(alt) = alternate {
                collect_reads_outside_reassigning_scopes_in_block(
                    alt,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_reads_outside_reassigning_scopes_in_block(
                block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => {
            if let Some(binding) = handler_binding {
                mark_initializer_required_if_read_outside_reassigning_scope(
                    binding.identifier.declaration_id,
                    reassigning_scope_ids,
                    active_scope_ids,
                    out,
                );
            }
            collect_reads_outside_reassigning_scopes_in_block(
                block,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
            collect_reads_outside_reassigning_scopes_in_block(
                handler,
                reassigning_scope_ids,
                active_scope_ids,
                out,
            );
        }
    }
}

fn mark_initializer_required_if_read_outside_reassigning_scope(
    decl_id: DeclarationId,
    reassigning_scope_ids: &HashMap<DeclarationId, HashSet<ScopeId>>,
    active_scope_ids: &[ScopeId],
    out: &mut HashSet<DeclarationId>,
) {
    let Some(scope_ids) = reassigning_scope_ids.get(&decl_id) else {
        return;
    };
    if active_scope_ids
        .iter()
        .any(|active_scope_id| scope_ids.contains(active_scope_id))
    {
        return;
    }
    out.insert(decl_id);
}

fn collect_reassigned_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::StoreLocal { lvalue, .. }
                | InstructionValue::StoreContext { lvalue, .. } => {
                    if lvalue.kind == InstructionKind::Reassign {
                        out.insert(lvalue.place.identifier.declaration_id);
                    }
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                collect_reassigned_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_reassigned_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_reassigned_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_reassigned_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_reassigned_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_reassigned_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_reassigned_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_reassigned_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_reassigned_declarations_in_block(block, out);
            collect_reassigned_declarations_in_block(handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_read_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut reads = HashSet::new();
    collect_read_declarations_in_block(block, &mut reads);
    reads
}

fn collect_direct_read_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut reads = HashSet::new();
    collect_direct_read_declarations_in_block(block, &mut reads);
    reads
}

fn collect_scope_dependency_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut deps = HashSet::new();
    collect_scope_dependency_declarations_in_block(block, &mut deps);
    deps
}

fn collect_scope_dependency_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(_) => {}
            ReactiveStatement::Scope(scope) => {
                for dep in &scope.scope.dependencies {
                    out.insert(dep.identifier.declaration_id);
                }
                collect_scope_dependency_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                for dep in &scope.scope.dependencies {
                    out.insert(dep.identifier.declaration_id);
                }
                collect_scope_dependency_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_scope_dependency_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_scope_dependency_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => {}
        ReactiveTerminal::Return { .. } | ReactiveTerminal::Throw { .. } => {}
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_scope_dependency_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. } => {
            collect_scope_dependency_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_scope_dependency_declarations_in_block(init, out);
            if let Some(update) = update {
                collect_scope_dependency_declarations_in_block(update, out);
            }
            collect_scope_dependency_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_scope_dependency_declarations_in_block(init, out);
            collect_scope_dependency_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_scope_dependency_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_scope_dependency_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_scope_dependency_declarations_in_block(block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_scope_dependency_declarations_in_block(block, out);
            collect_scope_dependency_declarations_in_block(handler, out);
        }
    }
}

fn collect_non_local_binding_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut direct_non_local = HashSet::new();
    let mut aliases: Vec<(DeclarationId, DeclarationId)> = Vec::new();
    collect_non_local_binding_declarations_in_block(block, &mut direct_non_local, &mut aliases);

    // Propagate non-local origin through lowered alias loads before memo guard
    // generation. This keeps dep filtering stable even when upstream-style
    // expression fusion removes explicit LoadGlobal emissions.
    let mut propagated = direct_non_local;
    let mut changed = true;
    while changed {
        changed = false;
        for (target, source) in &aliases {
            if propagated.contains(source) && propagated.insert(*target) {
                changed = true;
            }
        }
    }
    propagated
}

fn collect_non_local_binding_declarations_in_block(
    block: &ReactiveBlock,
    direct_non_local: &mut HashSet<DeclarationId>,
    aliases: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                let Some(lvalue) = &instr.lvalue else {
                    continue;
                };
                match &instr.value {
                    InstructionValue::LoadGlobal { .. } => {
                        direct_non_local.insert(lvalue.identifier.declaration_id);
                    }
                    InstructionValue::LoadLocal { place, .. }
                    | InstructionValue::LoadContext { place, .. } => {
                        aliases.push((
                            lvalue.identifier.declaration_id,
                            place.identifier.declaration_id,
                        ));
                    }
                    InstructionValue::TypeCastExpression { value, .. } => {
                        aliases.push((
                            lvalue.identifier.declaration_id,
                            value.identifier.declaration_id,
                        ));
                    }
                    _ => {}
                }
            }
            ReactiveStatement::Scope(scope) => {
                collect_non_local_binding_declarations_in_block(
                    &scope.instructions,
                    direct_non_local,
                    aliases,
                );
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_non_local_binding_declarations_in_block(
                    &scope.instructions,
                    direct_non_local,
                    aliases,
                );
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_non_local_binding_declarations_in_terminal(
                    &term_stmt.terminal,
                    direct_non_local,
                    aliases,
                );
            }
        }
    }
}

fn collect_non_local_binding_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    direct_non_local: &mut HashSet<DeclarationId>,
    aliases: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_non_local_binding_declarations_in_block(consequent, direct_non_local, aliases);
            if let Some(alt) = alternate {
                collect_non_local_binding_declarations_in_block(alt, direct_non_local, aliases);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_non_local_binding_declarations_in_block(
                        block,
                        direct_non_local,
                        aliases,
                    );
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_non_local_binding_declarations_in_block(init, direct_non_local, aliases);
            if let Some(update_block) = update {
                collect_non_local_binding_declarations_in_block(
                    update_block,
                    direct_non_local,
                    aliases,
                );
            }
            collect_non_local_binding_declarations_in_block(loop_block, direct_non_local, aliases);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_non_local_binding_declarations_in_block(init, direct_non_local, aliases);
            collect_non_local_binding_declarations_in_block(loop_block, direct_non_local, aliases);
        }
        ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_non_local_binding_declarations_in_block(loop_block, direct_non_local, aliases);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_non_local_binding_declarations_in_block(block, direct_non_local, aliases);
            collect_non_local_binding_declarations_in_block(handler, direct_non_local, aliases);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_function_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut function_expr_decl_captures = HashMap::new();
    collect_function_expression_declaration_metadata_in_block(
        block,
        &mut function_expr_decl_captures,
    );

    let mut function_decls = HashSet::new();
    collect_function_declarations_in_block(
        block,
        &function_expr_decl_captures,
        &mut function_decls,
    );
    function_decls
}

fn collect_function_expression_declaration_metadata_in_block(
    block: &ReactiveBlock,
    out: &mut HashMap<DeclarationId, HashSet<DeclarationId>>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if let InstructionValue::FunctionExpression {
                    expr_type,
                    lowered_func,
                    ..
                } = &instr.value
                    && *expr_type == FunctionExpressionType::FunctionDeclaration
                    && let Some(lvalue) = &instr.lvalue
                {
                    let captures = lowered_func
                        .func
                        .context
                        .iter()
                        .map(|place| place.identifier.declaration_id)
                        .collect::<HashSet<_>>();
                    out.insert(lvalue.identifier.declaration_id, captures);
                }
            }
            ReactiveStatement::Scope(scope) => {
                collect_function_expression_declaration_metadata_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_function_expression_declaration_metadata_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_function_expression_declaration_metadata_in_terminal(
                    &term_stmt.terminal,
                    out,
                );
            }
        }
    }
}

fn collect_function_expression_declaration_metadata_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashMap<DeclarationId, HashSet<DeclarationId>>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_function_expression_declaration_metadata_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_function_expression_declaration_metadata_in_block(alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_function_expression_declaration_metadata_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_function_expression_declaration_metadata_in_block(init, out);
            if let Some(update_block) = update {
                collect_function_expression_declaration_metadata_in_block(update_block, out);
            }
            collect_function_expression_declaration_metadata_in_block(loop_block, out);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_function_expression_declaration_metadata_in_block(init, out);
            collect_function_expression_declaration_metadata_in_block(loop_block, out);
        }
        ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_function_expression_declaration_metadata_in_block(loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_function_expression_declaration_metadata_in_block(block, out);
            collect_function_expression_declaration_metadata_in_block(handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_function_declarations_in_block(
    block: &ReactiveBlock,
    function_expr_decl_captures: &HashMap<DeclarationId, HashSet<DeclarationId>>,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::DeclareLocal { lvalue, .. }
                | InstructionValue::DeclareContext { lvalue, .. } => {
                    if lvalue.kind == InstructionKind::Function {
                        out.insert(lvalue.place.identifier.declaration_id);
                    }
                }
                InstructionValue::StoreLocal { lvalue, value, .. }
                | InstructionValue::StoreContext { lvalue, value, .. } => {
                    if lvalue.place.identifier.name.is_some()
                        && function_expr_decl_captures
                            .get(&value.identifier.declaration_id)
                            .is_some_and(|captures| {
                                captures.contains(&lvalue.place.identifier.declaration_id)
                            })
                    {
                        out.insert(lvalue.place.identifier.declaration_id);
                    }
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope) => {
                collect_function_declarations_in_block(
                    &scope.instructions,
                    function_expr_decl_captures,
                    out,
                );
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_function_declarations_in_block(
                    &scope.instructions,
                    function_expr_decl_captures,
                    out,
                );
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_function_declarations_in_terminal(
                    &term_stmt.terminal,
                    function_expr_decl_captures,
                    out,
                );
            }
        }
    }
}

fn collect_function_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    function_expr_decl_captures: &HashMap<DeclarationId, HashSet<DeclarationId>>,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_function_declarations_in_block(consequent, function_expr_decl_captures, out);
            if let Some(alt) = alternate {
                collect_function_declarations_in_block(alt, function_expr_decl_captures, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_function_declarations_in_block(block, function_expr_decl_captures, out);
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_function_declarations_in_block(init, function_expr_decl_captures, out);
            if let Some(update_block) = update {
                collect_function_declarations_in_block(
                    update_block,
                    function_expr_decl_captures,
                    out,
                );
            }
            collect_function_declarations_in_block(loop_block, function_expr_decl_captures, out);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_function_declarations_in_block(init, function_expr_decl_captures, out);
            collect_function_declarations_in_block(loop_block, function_expr_decl_captures, out);
        }
        ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_function_declarations_in_block(loop_block, function_expr_decl_captures, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_function_declarations_in_block(block, function_expr_decl_captures, out);
            collect_function_declarations_in_block(handler, function_expr_decl_captures, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_preferred_declaration_names(block: &ReactiveBlock) -> HashMap<DeclarationId, String> {
    let mut names = HashMap::new();
    collect_preferred_declaration_names_in_block(block, &mut names);
    names
}

fn collect_fire_binding_declarations(block: &ReactiveBlock) -> Vec<DeclarationId> {
    let mut ordered = Vec::new();
    let mut seen = HashSet::new();
    collect_fire_binding_declarations_in_block(block, &mut ordered, &mut seen);
    ordered
}

fn collect_fire_binding_declarations_in_block(
    block: &ReactiveBlock,
    ordered: &mut Vec<DeclarationId>,
    seen: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if let Some(lvalue) = &instr.lvalue
                    && is_fire_binding_identifier(&lvalue.identifier)
                    && seen.insert(lvalue.identifier.declaration_id)
                {
                    ordered.push(lvalue.identifier.declaration_id);
                }
            }
            ReactiveStatement::Scope(scope) => {
                collect_fire_binding_declarations_in_block(&scope.instructions, ordered, seen);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_fire_binding_declarations_in_block(&scope.instructions, ordered, seen);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_fire_binding_declarations_in_terminal(&term_stmt.terminal, ordered, seen);
            }
        }
    }
}

fn collect_fire_binding_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    ordered: &mut Vec<DeclarationId>,
    seen: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_fire_binding_declarations_in_block(consequent, ordered, seen);
            if let Some(alt) = alternate {
                collect_fire_binding_declarations_in_block(alt, ordered, seen);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_fire_binding_declarations_in_block(block, ordered, seen);
                }
            }
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_fire_binding_declarations_in_block(init, ordered, seen);
            if let Some(update_block) = update {
                collect_fire_binding_declarations_in_block(update_block, ordered, seen);
            }
            collect_fire_binding_declarations_in_block(loop_block, ordered, seen);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_fire_binding_declarations_in_block(init, ordered, seen);
            collect_fire_binding_declarations_in_block(loop_block, ordered, seen);
        }
        ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_fire_binding_declarations_in_block(loop_block, ordered, seen);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_fire_binding_declarations_in_block(block, ordered, seen);
            collect_fire_binding_declarations_in_block(handler, ordered, seen);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn is_fire_binding_identifier(identifier: &Identifier) -> bool {
    matches!(
        &identifier.type_,
        Type::Function {
            shape_id: Some(shape_id),
            ..
        } if shape_id == "BuiltInFireFunction"
    )
}

fn remember_preferred_identifier_name(
    names: &mut HashMap<DeclarationId, String>,
    identifier: &Identifier,
) {
    let Some(name) = identifier.name.as_ref() else {
        return;
    };
    names
        .entry(identifier.declaration_id)
        .or_insert_with(|| name.value().to_string());
}

fn collect_preferred_declaration_names_in_block(
    block: &ReactiveBlock,
    names: &mut HashMap<DeclarationId, String>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if let Some(lvalue) = &instr.lvalue {
                    remember_preferred_identifier_name(names, &lvalue.identifier);
                }
            }
            ReactiveStatement::Scope(scope) => {
                collect_preferred_declaration_names_in_block(&scope.instructions, names);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_preferred_declaration_names_in_block(&scope.instructions, names);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_preferred_declaration_names_in_terminal(&term_stmt.terminal, names);
            }
        }
    }
}

fn collect_preferred_declaration_names_in_terminal(
    terminal: &ReactiveTerminal,
    names: &mut HashMap<DeclarationId, String>,
) {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => {}
        ReactiveTerminal::Return { value, .. } | ReactiveTerminal::Throw { value, .. } => {
            remember_preferred_identifier_name(names, &value.identifier);
        }
        ReactiveTerminal::Switch { test, cases, .. } => {
            remember_preferred_identifier_name(names, &test.identifier);
            for case in cases {
                if let Some(test) = &case.test {
                    remember_preferred_identifier_name(names, &test.identifier);
                }
                if let Some(block) = &case.block {
                    collect_preferred_declaration_names_in_block(block, names);
                }
            }
        }
        ReactiveTerminal::DoWhile {
            loop_block, test, ..
        }
        | ReactiveTerminal::While {
            test, loop_block, ..
        } => {
            remember_preferred_identifier_name(names, &test.identifier);
            collect_preferred_declaration_names_in_block(loop_block, names);
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            loop_block,
            ..
        } => {
            collect_preferred_declaration_names_in_block(init, names);
            remember_preferred_identifier_name(names, &test.identifier);
            if let Some(update) = update {
                collect_preferred_declaration_names_in_block(update, names);
            }
            collect_preferred_declaration_names_in_block(loop_block, names);
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            collect_preferred_declaration_names_in_block(init, names);
            remember_preferred_identifier_name(names, &test.identifier);
            collect_preferred_declaration_names_in_block(loop_block, names);
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_preferred_declaration_names_in_block(init, names);
            collect_preferred_declaration_names_in_block(loop_block, names);
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            remember_preferred_identifier_name(names, &test.identifier);
            collect_preferred_declaration_names_in_block(consequent, names);
            if let Some(alt) = alternate {
                collect_preferred_declaration_names_in_block(alt, names);
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_preferred_declaration_names_in_block(block, names);
        }
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => {
            if let Some(binding) = handler_binding {
                remember_preferred_identifier_name(names, &binding.identifier);
            }
            collect_preferred_declaration_names_in_block(block, names);
            collect_preferred_declaration_names_in_block(handler, names);
        }
    }
}

fn collect_read_declarations_in_block(block: &ReactiveBlock, out: &mut HashSet<DeclarationId>) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                visitors::for_each_instruction_value_operand(&instr.value, |place| {
                    out.insert(place.identifier.declaration_id);
                });
            }
            ReactiveStatement::Scope(scope) => {
                collect_read_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_read_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_read_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_direct_read_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::FunctionExpression { .. }
                | InstructionValue::ObjectMethod { .. } => {}
                value => {
                    visitors::for_each_instruction_value_operand(value, |place| {
                        out.insert(place.identifier.declaration_id);
                    });
                }
            },
            ReactiveStatement::Scope(scope) => {
                collect_direct_read_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_direct_read_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_read_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_read_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => {}
        ReactiveTerminal::Return { value, .. } | ReactiveTerminal::Throw { value, .. } => {
            out.insert(value.identifier.declaration_id);
        }
        ReactiveTerminal::Switch { test, cases, .. } => {
            out.insert(test.identifier.declaration_id);
            for case in cases {
                if let Some(test) = &case.test {
                    out.insert(test.identifier.declaration_id);
                }
                if let Some(block) = &case.block {
                    collect_read_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::DoWhile {
            loop_block, test, ..
        }
        | ReactiveTerminal::While {
            test, loop_block, ..
        } => {
            out.insert(test.identifier.declaration_id);
            collect_read_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            loop_block,
            ..
        } => {
            collect_read_declarations_in_block(init, out);
            out.insert(test.identifier.declaration_id);
            if let Some(update) = update {
                collect_read_declarations_in_block(update, out);
            }
            collect_read_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            collect_read_declarations_in_block(init, out);
            out.insert(test.identifier.declaration_id);
            collect_read_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_read_declarations_in_block(init, out);
            collect_read_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            out.insert(test.identifier.declaration_id);
            collect_read_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_read_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_read_declarations_in_block(block, out);
        }
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => {
            if let Some(binding) = handler_binding {
                out.insert(binding.identifier.declaration_id);
            }
            collect_read_declarations_in_block(block, out);
            collect_read_declarations_in_block(handler, out);
        }
    }
}

fn collect_manual_memo_root_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut roots = HashSet::new();
    collect_manual_memo_root_declarations_in_block(block, &mut roots);
    roots
}

fn collect_manual_memo_root_declarations_in_block(
    block: &ReactiveBlock,
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if let InstructionValue::StartMemoize { deps, .. } = &instr.value
                    && let Some(deps) = deps
                {
                    for dep in deps {
                        if let ManualMemoRoot::NamedLocal(place) = &dep.root {
                            out.insert(place.identifier.declaration_id);
                        }
                    }
                }
            }
            ReactiveStatement::Scope(scope) => {
                collect_manual_memo_root_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_manual_memo_root_declarations_in_block(&scope.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_manual_memo_root_declarations_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_manual_memo_root_declarations_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_manual_memo_root_declarations_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. } => {
            collect_manual_memo_root_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_manual_memo_root_declarations_in_block(init, out);
            if let Some(update) = update {
                collect_manual_memo_root_declarations_in_block(update, out);
            }
            collect_manual_memo_root_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_manual_memo_root_declarations_in_block(init, out);
            collect_manual_memo_root_declarations_in_block(loop_block, out);
        }
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_manual_memo_root_declarations_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_manual_memo_root_declarations_in_block(alt, out);
            }
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_manual_memo_root_declarations_in_block(block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_manual_memo_root_declarations_in_block(block, out);
            collect_manual_memo_root_declarations_in_block(handler, out);
        }
    }
}

fn collect_jsx_only_component_tag_declarations(block: &ReactiveBlock) -> HashSet<DeclarationId> {
    let mut jsx_component_reads = HashSet::new();
    let mut non_jsx_reads = HashSet::new();
    collect_jsx_tag_usage_in_block(block, &mut jsx_component_reads, &mut non_jsx_reads);
    jsx_component_reads.retain(|decl_id| !non_jsx_reads.contains(decl_id));
    jsx_component_reads
}

fn collect_jsx_tag_usage_in_block(
    block: &ReactiveBlock,
    jsx_component_reads: &mut HashSet<DeclarationId>,
    non_jsx_reads: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::JsxExpression {
                    tag,
                    props,
                    children,
                    ..
                } => {
                    if let JsxTag::Component(place) = tag {
                        jsx_component_reads.insert(place.identifier.declaration_id);
                    }
                    for prop in props {
                        match prop {
                            JsxAttribute::Attribute { place, .. }
                            | JsxAttribute::SpreadAttribute { argument: place } => {
                                non_jsx_reads.insert(place.identifier.declaration_id);
                            }
                        }
                    }
                    if let Some(children) = children {
                        for child in children {
                            non_jsx_reads.insert(child.identifier.declaration_id);
                        }
                    }
                }
                _ => {
                    visitors::for_each_instruction_value_operand(&instr.value, |place| {
                        non_jsx_reads.insert(place.identifier.declaration_id);
                    });
                }
            },
            ReactiveStatement::Scope(scope) => {
                collect_jsx_tag_usage_in_block(
                    &scope.instructions,
                    jsx_component_reads,
                    non_jsx_reads,
                );
            }
            ReactiveStatement::PrunedScope(scope) => {
                collect_jsx_tag_usage_in_block(
                    &scope.instructions,
                    jsx_component_reads,
                    non_jsx_reads,
                );
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_read_declarations_in_terminal(&term_stmt.terminal, non_jsx_reads);
            }
        }
    }
}

/// Generate a block of statements, resetting temporaries afterward.
fn codegen_block(cx: &mut Context, block: &[ReactiveStatement]) -> String {
    let temp_snapshot = cx.snapshot_temps();
    cx.block_scope_output_names.push(HashSet::new());
    cx.block_scope_declared_temp_names.push(HashSet::new());
    let result = codegen_block_no_reset(cx, block);
    let _ = cx.block_scope_declared_temp_names.pop();
    let _ = cx.block_scope_output_names.pop();
    cx.restore_temps(temp_snapshot);
    result
}

/// Generate a block of statements without resetting temporaries.
/// Used for sequence expressions where the final value references earlier temps.
fn codegen_block_no_reset(cx: &mut Context, block: &[ReactiveStatement]) -> String {
    codegen_block_no_reset_with_options(cx, block, false)
}

fn codegen_block_no_reset_with_options(
    cx: &mut Context,
    block: &[ReactiveStatement],
    allow_top_level_zero_dep_literal_inline: bool,
) -> String {
    #[derive(Clone)]
    struct PendingSequenceExpr {
        exprs: Vec<String>,
        loc: SourceLocation,
    }

    fn source_loc_line_range(loc: &SourceLocation) -> Option<(u32, u32)> {
        match loc {
            SourceLocation::Source(range) => Some((range.start.line, range.end.line)),
            SourceLocation::Generated => None,
        }
    }

    fn maybe_insert_source_line_gap(
        output: &mut String,
        last_source_end_line: &mut Option<u32>,
        current_loc: Option<&SourceLocation>,
    ) {
        let Some(current_loc) = current_loc else {
            return;
        };
        let Some((current_start_line, _)) = source_loc_line_range(current_loc) else {
            return;
        };
        let Some(previous_end_line) = *last_source_end_line else {
            return;
        };
        if current_start_line > previous_end_line + 1 && !output.ends_with("\n\n") {
            if !output.ends_with('\n') {
                output.push('\n');
            }
            output.push('\n');
        }
    }

    fn should_insert_blank_line_after_function_assignment(stmt: &str) -> bool {
        let trimmed = stmt.trim();
        if !trimmed.contains('\n') {
            return false;
        }
        let allocator = Allocator::default();
        let statement = match parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            trimmed,
        ) {
            Ok(statement) => statement,
            Err(_) => return false,
        };
        let ast::Statement::VariableDeclaration(declaration) = statement else {
            return false;
        };
        if declaration.declarations.len() != 1 {
            return false;
        }
        let Some(init) = declaration
            .declarations
            .first()
            .and_then(|declarator| declarator.init.as_ref())
        else {
            return false;
        };
        matches!(
            init.without_parentheses(),
            ast::Expression::FunctionExpression(_) | ast::Expression::ArrowFunctionExpression(_)
        )
    }

    fn append_statement_with_source_gap(
        output: &mut String,
        stmt: &str,
        current_loc: Option<&SourceLocation>,
        last_source_end_line: &mut Option<u32>,
    ) {
        maybe_insert_source_line_gap(output, last_source_end_line, current_loc);
        output.push_str(stmt);
        if !stmt.ends_with('\n') {
            output.push('\n');
        }
        if should_insert_blank_line_after_function_assignment(stmt) && !output.ends_with("\n\n") {
            output.push('\n');
        }
        if let Some(current_loc) = current_loc
            && let Some((_, current_end_line)) = source_loc_line_range(current_loc)
        {
            *last_source_end_line = Some(current_end_line);
        }
    }

    fn is_simple_identifier(name: &str) -> bool {
        let mut chars = name.chars();
        let Some(first) = chars.next() else {
            return false;
        };
        if !(first == '_' || first == '$' || first.is_ascii_alphabetic()) {
            return false;
        }
        chars.all(|ch| ch == '_' || ch == '$' || ch.is_ascii_alphanumeric())
    }

    fn parse_uninitialized_declaration_name(stmt: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        let ast::Statement::VariableDeclaration(declaration) = statement else {
            return None;
        };
        if declaration.declarations.len() != 1 {
            return None;
        }
        let declarator = declaration.declarations.first()?;
        if declarator.init.is_some() {
            return None;
        }
        let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
            return None;
        };
        Some(identifier.name.to_string())
    }

    fn parse_simple_assignment(stmt: &str) -> Option<(String, String)> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        )
        .ok()?;
        match statement {
            ast::Statement::VariableDeclaration(declaration) => {
                if declaration.declarations.len() != 1 {
                    return None;
                }
                let declarator = declaration.declarations.first()?;
                let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
                    return None;
                };
                let init = declarator.init.as_ref()?;
                Some((
                    identifier.name.to_string(),
                    codegen_expression_with_flow_cast_restore(init),
                ))
            }
            ast::Statement::ExpressionStatement(expression_statement) => {
                let ast::Expression::AssignmentExpression(assignment) =
                    expression_statement.expression.without_parentheses()
                else {
                    return None;
                };
                if assignment.operator != AssignmentOperator::Assign {
                    return None;
                }
                let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) =
                    &assignment.left
                else {
                    return None;
                };
                Some((
                    identifier.name.to_string(),
                    codegen_expression_with_flow_cast_restore(&assignment.right),
                ))
            }
            _ => None,
        }
    }

    fn statement_is_variable_declaration(stmt: &str) -> bool {
        let allocator = Allocator::default();
        matches!(
            parse_single_statement_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                stmt.trim(),
            ),
            Ok(ast::Statement::VariableDeclaration(_))
        )
    }

    enum NextEmittedStatement {
        PushOnTarget,
        TerminalIf { multiline_source: bool },
        Other,
    }

    fn next_emitted_statement_for_spacing(
        cx: &Context,
        block: &[ReactiveStatement],
        start_idx: usize,
        assignment_target_name: Option<&str>,
    ) -> Option<NextEmittedStatement> {
        let debug = std::env::var("DEBUG_STRUCTURAL_GAP").is_ok();
        fn resolve_place_simple_identifier(cx: &Context, place: &Place) -> Option<String> {
            if let Some(name) = resolve_place_name(cx, place)
                && is_simple_identifier(&name)
            {
                return Some(name);
            }
            cx.temp
                .get(&place.identifier.declaration_id)
                .and_then(|value| value.as_ref())
                .and_then(|value| {
                    let expr = value.expr.trim();
                    if is_simple_identifier(expr) {
                        Some(expr.to_string())
                    } else {
                        None
                    }
                })
        }

        fn is_push_method_property(cx: &Context, property: &Place) -> bool {
            if let Some(name) = resolve_place_name(cx, property)
                && (name == "push" || name.ends_with(".push") || name.ends_with("?.push"))
            {
                return true;
            }
            cx.temp
                .get(&property.identifier.declaration_id)
                .and_then(|value| value.as_ref())
                .is_some_and(|value| {
                    let expr = value.expr.trim();
                    expr == "\"push\"" || expr == "'push'" || expr == "push"
                })
        }

        let mut cursor = start_idx;
        while let Some(stmt) = block.get(cursor) {
            match stmt {
                ReactiveStatement::Instruction(instr) => {
                    if let Some(target_name) = assignment_target_name
                        && let InstructionValue::MethodCall {
                            receiver, property, ..
                        } = &instr.value
                    {
                        let receiver_name = resolve_place_simple_identifier(cx, receiver);
                        let property_name = resolve_place_name(cx, property);
                        let property_temp = cx
                            .temp
                            .get(&property.identifier.declaration_id)
                            .and_then(|value| value.as_ref())
                            .map(|value| value.expr.clone());
                        let property_is_push = is_push_method_property(cx, property);
                        if debug {
                            eprintln!(
                                "[STRUCT_GAP] lookahead methodcall idx={} receiver={:?} target={} prop_name={:?} prop_temp={:?} push={}",
                                cursor,
                                receiver_name,
                                target_name,
                                property_name,
                                property_temp,
                                property_is_push
                            );
                        }
                        if receiver_name
                            .as_deref()
                            .is_some_and(|name| name == target_name)
                            && property_is_push
                        {
                            return Some(NextEmittedStatement::PushOnTarget);
                        }
                    }
                    if instr.lvalue.is_none() {
                        if debug {
                            eprintln!(
                                "[STRUCT_GAP] lookahead stop idx={} kind={} lvalue-none",
                                cursor,
                                instruction_value_tag(&instr.value)
                            );
                        }
                        return Some(NextEmittedStatement::Other);
                    }
                    if debug {
                        eprintln!(
                            "[STRUCT_GAP] lookahead continue idx={} kind={} lvalue-some",
                            cursor,
                            instruction_value_tag(&instr.value)
                        );
                    }
                }
                ReactiveStatement::Terminal(term_stmt) => {
                    if let ReactiveTerminal::If { loc, .. } = &term_stmt.terminal {
                        let multiline_source = matches!(loc, SourceLocation::Source(range) if range.end.line > range.start.line);
                        if debug {
                            eprintln!(
                                "[STRUCT_GAP] lookahead terminal-if idx={} multiline_source={}",
                                cursor, multiline_source
                            );
                        }
                        return Some(NextEmittedStatement::TerminalIf { multiline_source });
                    }
                    if debug {
                        eprintln!("[STRUCT_GAP] lookahead terminal-other idx={}", cursor);
                    }
                    return Some(NextEmittedStatement::Other);
                }
                ReactiveStatement::Scope(_) | ReactiveStatement::PrunedScope(_) => {
                    if debug {
                        eprintln!("[STRUCT_GAP] lookahead stop idx={} scope", cursor);
                    }
                    return None;
                }
            }
            cursor += 1;
        }
        None
    }

    fn should_insert_structural_blank_after_instruction(
        cx: &Context,
        block: &[ReactiveStatement],
        idx: usize,
        stmt: &str,
        current_loc: Option<&SourceLocation>,
    ) -> bool {
        let debug = std::env::var("DEBUG_STRUCTURAL_GAP").is_ok();
        let is_generated = matches!(current_loc, Some(SourceLocation::Generated));
        let source_span_lines = match current_loc {
            Some(SourceLocation::Source(range)) => Some((range.start.line, range.end.line)),
            _ => None,
        };
        let is_multiline_source =
            source_span_lines.is_some_and(|(start_line, end_line)| end_line > start_line);
        let uninitialized_decl = if matches!(current_loc, Some(SourceLocation::Generated)) {
            parse_uninitialized_declaration_name(stmt)
        } else {
            None
        };
        let assignment = parse_simple_assignment(stmt);
        if uninitialized_decl.is_none() && assignment.is_none() {
            if debug {
                eprintln!(
                    "[STRUCT_GAP] idx={} skip: not candidate stmt={:?}",
                    idx,
                    stmt.trim()
                );
            }
            return false;
        }

        let assignment_target_name = assignment.as_ref().map(|(name, _)| name.as_str());
        let next_stmt =
            next_emitted_statement_for_spacing(cx, block, idx + 1, assignment_target_name);
        if debug {
            eprintln!(
                "[STRUCT_GAP] idx={} stmt={:?} loc={:?} uninit={:?} assign={:?} next={}",
                idx,
                stmt.trim(),
                source_span_lines,
                uninitialized_decl,
                assignment,
                match &next_stmt {
                    Some(NextEmittedStatement::PushOnTarget) => "push",
                    Some(NextEmittedStatement::TerminalIf {
                        multiline_source: true,
                    }) => {
                        "if(multiline)"
                    }
                    Some(NextEmittedStatement::TerminalIf {
                        multiline_source: false,
                    }) => {
                        "if(singleline)"
                    }
                    Some(NextEmittedStatement::Other) => "other",
                    None => "none",
                }
            );
        }
        if uninitialized_decl
            .as_deref()
            .is_some_and(|name| matches!(name.strip_prefix('t'), Some(rest) if !rest.is_empty() && rest.chars().all(|ch| ch.is_ascii_digit())))
            && matches!(
                next_stmt,
                Some(NextEmittedStatement::TerminalIf {
                    multiline_source: true
                })
            )
        {
            if debug {
                eprintln!("[STRUCT_GAP] idx={} decision: blank-after-uninit-if", idx);
            }
            return true;
        }

        if !(is_generated || is_multiline_source) {
            if debug {
                eprintln!(
                    "[STRUCT_GAP] idx={} decision: single-line source assignment, skip",
                    idx
                );
            }
            return false;
        }
        let is_declaration_assignment = statement_is_variable_declaration(stmt);
        if is_declaration_assignment {
            if debug {
                eprintln!(
                    "[STRUCT_GAP] idx={} decision: declaration assignment, skip",
                    idx
                );
            }
            return false;
        }
        let Some((name, rhs)) = assignment else {
            return false;
        };
        let rhs_is_iife_like = rendered_expr_is_array_seed_like(&rhs);
        if !rhs_is_iife_like {
            return false;
        }
        if !matches!(next_stmt, Some(NextEmittedStatement::PushOnTarget)) {
            return false;
        }
        // Keep this narrow: only direct identifier assignments.
        let result = is_simple_identifier(&name);
        if debug {
            eprintln!(
                "[STRUCT_GAP] idx={} decision: blank-after-assignment-push name={} rhs={} result={}",
                idx, name, rhs, result
            );
        }
        result
    }

    fn flush_pending_sequence_expr(
        output: &mut String,
        pending: &mut Option<PendingSequenceExpr>,
        last_source_end_line: &mut Option<u32>,
    ) {
        if let Some(pending_expr) = pending.take() {
            for expr in pending_expr.exprs {
                append_statement_with_source_gap(
                    output,
                    &render_reactive_expression_statement_ast(&expr)
                        .expect("pending sequence expression should stay on AST path"),
                    Some(&pending_expr.loc),
                    last_source_end_line,
                );
            }
        }
    }

    fn is_assignment_like_sequence_expr(expr: &str) -> bool {
        fn is_assignment_like(expression: &ast::Expression<'_>) -> bool {
            match expression {
                ast::Expression::AssignmentExpression(_) => true,
                ast::Expression::ParenthesizedExpression(parenthesized) => {
                    is_assignment_like(&parenthesized.expression)
                }
                _ => false,
            }
        }

        let allocator = Allocator::default();
        parse_rendered_expression_ast(&allocator, expr)
            .as_ref()
            .is_some_and(is_assignment_like)
    }

    fn wrap_sequence_expr_item(expr: &str) -> String {
        let trimmed = expr.trim();
        if is_assignment_like_sequence_expr(trimmed)
            && !(trimmed.starts_with('(') && trimmed.ends_with(')'))
        {
            format!("({trimmed})")
        } else {
            trimmed.to_string()
        }
    }

    fn render_pending_sequence_prefix(pending: &PendingSequenceExpr) -> Option<String> {
        if pending.exprs.is_empty() {
            return None;
        }
        let mut rendered = Vec::with_capacity(pending.exprs.len());
        for expr in &pending.exprs {
            rendered.push(wrap_sequence_expr_item(expr));
        }
        Some(rendered.join(", "))
    }

    fn extract_simple_expression_statement(stmt: &str) -> Option<String> {
        let trimmed = stmt.trim();
        if trimmed.is_empty() || !trimmed.ends_with(';') || trimmed.contains('\n') {
            return None;
        }
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            trimmed,
        )
        .ok()?;
        let ast::Statement::ExpressionStatement(expression_statement) = statement else {
            return None;
        };
        Some(codegen_expression_with_flow_cast_restore(
            &expression_statement.expression,
        ))
    }

    fn source_locs_are_sequence_adjacent(
        prefix: &SourceLocation,
        current: &SourceLocation,
    ) -> bool {
        let (SourceLocation::Source(prefix), SourceLocation::Source(current)) = (prefix, current)
        else {
            return false;
        };
        if prefix.end.line != current.start.line || current.start.column < prefix.end.column {
            return false;
        }
        current.start.column - prefix.end.column <= 3
    }

    fn source_locs_are_sequence_compatible(
        prefix: &SourceLocation,
        current: &SourceLocation,
    ) -> bool {
        if source_locs_are_sequence_adjacent(prefix, current) {
            return true;
        }
        let (SourceLocation::Source(prefix), SourceLocation::Source(current)) = (prefix, current)
        else {
            return false;
        };
        prefix.start.line == current.start.line
            && current.start.column <= prefix.start.column
            && current.end.column >= prefix.end.column
    }

    fn combine_assignment_statement_with_sequence_prefix(
        stmt: &str,
        prefix_expr: &str,
    ) -> Option<String> {
        let trimmed = stmt.trim();
        if trimmed.is_empty() || !trimmed.ends_with(';') || trimmed.contains('\n') {
            return None;
        }
        let allocator = Allocator::default();
        let builder = AstBuilder::new(&allocator);
        let prefix_expression = parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            prefix_expr.trim(),
        )
        .ok()?;
        let mut statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            trimmed,
        )
        .ok()?;

        match &mut statement {
            ast::Statement::VariableDeclaration(declaration) => {
                if declaration.declarations.len() != 1 {
                    return None;
                }
                let declarator = declaration.declarations.first_mut()?;
                let init = declarator.init.as_ref()?.clone_in(&allocator);
                declarator.init = Some(builder.expression_sequence(
                    SPAN,
                    builder.vec_from_iter([prefix_expression.clone_in(&allocator), init]),
                ));
            }
            ast::Statement::ExpressionStatement(expression_statement) => {
                let ast::Expression::AssignmentExpression(assignment) =
                    &mut expression_statement.expression
                else {
                    return None;
                };
                let rhs = assignment.right.clone_in(&allocator);
                assignment.right = builder.expression_sequence(
                    SPAN,
                    builder.vec_from_iter([prefix_expression.clone_in(&allocator), rhs]),
                );
            }
            _ => return None,
        }

        let mut rendered = codegen_statement_with_flow_cast_restore(&statement);
        rendered.push('\n');
        Some(rendered)
    }

    fn maybe_combine_instruction_with_pending_sequence(
        cx: &mut Context,
        instr: &ReactiveInstruction,
        stmt: &str,
        pending: &PendingSequenceExpr,
    ) -> Option<String> {
        let prefix_expr = render_pending_sequence_prefix(pending)?;
        match &instr.value {
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => {
                let lvalue = instr.lvalue.as_ref()?;
                if lvalue.identifier.name.is_none()
                    || place.identifier.name.is_some()
                    || !source_locs_are_sequence_adjacent(&pending.loc, &place.loc)
                {
                    return None;
                }
                combine_assignment_statement_with_sequence_prefix(stmt, &prefix_expr)
            }
            InstructionValue::StoreLocal { value, .. }
            | InstructionValue::StoreContext { value, .. } => {
                if instr.lvalue.is_some()
                    || value.identifier.name.is_some()
                    || !source_locs_are_sequence_compatible(&pending.loc, &value.loc)
                {
                    return None;
                }
                combine_assignment_statement_with_sequence_prefix(stmt, &prefix_expr)
            }
            InstructionValue::LogicalExpression {
                operator,
                left,
                right,
                ..
            } => {
                if instr.lvalue.is_some()
                    || !source_locs_are_sequence_compatible(&pending.loc, &left.loc)
                {
                    return None;
                }
                let logical_prec = logical_operator_precedence(operator);
                let left_expr = codegen_logical_operand(cx, left, logical_prec);
                let right_expr = codegen_logical_operand(cx, right, logical_prec);
                let combined_left = render_sequence_expression_ast(&pending.exprs, &left_expr)
                    .expect("pending logical sequence should stay on AST path");
                render_reactive_expression_statement_ast(
                    &render_logical_expression_ast(&combined_left, *operator, &right_expr)
                        .expect("pending logical expression should stay on AST path"),
                )
            }
            _ => None,
        }
    }

    fn maybe_codegen_while_with_pending_sequence(
        cx: &mut Context,
        terminal: &ReactiveTerminal,
        pending: &PendingSequenceExpr,
    ) -> Option<String> {
        let ReactiveTerminal::While {
            test, loop_block, ..
        } = terminal
        else {
            return None;
        };
        if test.identifier.name.is_some()
            || !source_locs_are_sequence_compatible(&pending.loc, &test.loc)
        {
            if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                eprintln!(
                    "[CODEGEN_EXPR] skip-while-sequence pending_loc={:?} test_loc={:?} test_name={:?}",
                    pending.loc, test.loc, test.identifier.name
                );
            }
            return None;
        }
        let test_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Assignment);
        let pending_expr = render_pending_sequence_prefix(pending)?;
        if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
            eprintln!(
                "[CODEGEN_EXPR] fuse-while-sequence pending={} test_expr={}",
                pending_expr, test_expr
            );
        }
        let body = codegen_block(cx, loop_block);
        render_reactive_while_statement_ast(&format!("({}, {})", pending_expr, test_expr), &body)
    }

    fn sequence_seed_loc(instr: &ReactiveInstruction) -> &SourceLocation {
        match &instr.value {
            InstructionValue::StoreLocal { value, .. }
            | InstructionValue::StoreContext { value, .. } => &value.loc,
            _ => &instr.loc,
        }
    }

    fn is_reassign_store_without_outer_lvalue(instr: &ReactiveInstruction) -> bool {
        if instr.lvalue.is_some() {
            return false;
        }
        match &instr.value {
            InstructionValue::StoreLocal { lvalue, .. }
            | InstructionValue::StoreContext { lvalue, .. } => {
                lvalue.kind == InstructionKind::Reassign && lvalue.place.identifier.name.is_some()
            }
            _ => false,
        }
    }

    fn instruction_source_loc_for_spacing<'a>(
        cx: &'a Context,
        instr: &'a ReactiveInstruction,
    ) -> &'a SourceLocation {
        match &instr.value {
            InstructionValue::StoreLocal { value, .. }
            | InstructionValue::StoreContext { value, .. } => {
                if let Some(Some(expr_value)) = cx.temp.get(&value.identifier.declaration_id) {
                    let expr = expr_value.expr.trim_start();
                    if rendered_expr_is_function_like(expr) {
                        return &instr.loc;
                    }
                }
                &value.loc
            }
            _ => &instr.loc,
        }
    }

    fn is_sequence_chainable_loc(seed: &SourceLocation, current: &SourceLocation) -> bool {
        let (SourceLocation::Source(seed), SourceLocation::Source(current)) = (seed, current)
        else {
            return false;
        };
        seed.start.line == current.start.line
            && (current.start.column >= seed.start.column
                || source_locs_are_sequence_compatible(
                    &SourceLocation::Source(seed.clone()),
                    &SourceLocation::Source(current.clone()),
                ))
    }

    fn instruction_extends_pending_sequence(
        instr: &ReactiveInstruction,
        pending: &PendingSequenceExpr,
    ) -> bool {
        if instr.lvalue.is_some() {
            return false;
        }
        match &instr.value {
            InstructionValue::StoreLocal { value, .. }
            | InstructionValue::StoreContext { value, .. } => {
                is_reassign_store_without_outer_lvalue(instr)
                    && value.identifier.name.is_none()
                    && is_sequence_chainable_loc(&pending.loc, &value.loc)
            }
            InstructionValue::PostfixUpdate { .. } | InstructionValue::PrefixUpdate { .. } => {
                is_sequence_chainable_loc(&pending.loc, &instr.loc)
            }
            _ => false,
        }
    }

    fn has_following_sequence_tail_assignment_pattern(
        block: &[ReactiveStatement],
        start: usize,
    ) -> bool {
        let ReactiveStatement::Instruction(start_instr) = &block[start] else {
            return false;
        };
        if !is_reassign_store_without_outer_lvalue(start_instr) {
            return false;
        }
        let seed_loc = sequence_seed_loc(start_instr);
        let mut saw_intermediate = false;
        let end = (start + 24).min(block.len());
        for stmt in block.iter().take(end).skip(start + 1) {
            let ReactiveStatement::Instruction(instr) = stmt else {
                break;
            };
            if instr.lvalue.is_some() {
                continue;
            }
            let is_candidate = matches!(
                instr.value,
                InstructionValue::PostfixUpdate { .. }
                    | InstructionValue::PrefixUpdate { .. }
                    | InstructionValue::StoreLocal { .. }
                    | InstructionValue::StoreContext { .. }
            );
            if !is_candidate {
                break;
            }
            match &instr.value {
                InstructionValue::StoreLocal { value, .. }
                | InstructionValue::StoreContext { value, .. } => {
                    if !is_reassign_store_without_outer_lvalue(instr)
                        || value.identifier.name.is_some()
                        || !is_sequence_chainable_loc(seed_loc, &value.loc)
                    {
                        break;
                    }
                    if saw_intermediate && source_locs_are_sequence_compatible(seed_loc, &value.loc)
                    {
                        return true;
                    }
                    saw_intermediate = true;
                }
                InstructionValue::PostfixUpdate { .. } | InstructionValue::PrefixUpdate { .. } => {
                    if !is_sequence_chainable_loc(seed_loc, &instr.loc) {
                        break;
                    }
                    saw_intermediate = true;
                }
                _ => break,
            }
        }
        false
    }

    fn single_call_expression_loc_in_block(block: &[ReactiveStatement]) -> Option<SourceLocation> {
        let mut call_loc: Option<SourceLocation> = None;
        for stmt in block {
            let ReactiveStatement::Instruction(instr) = stmt else {
                return None;
            };
            if instr.lvalue.is_none()
                && matches!(
                    instr.value,
                    InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. }
                )
            {
                if call_loc.is_some() {
                    return None;
                }
                call_loc = Some(instr.loc.clone());
            }
        }
        call_loc
    }

    fn has_following_call_temp_load_pattern(block: &[ReactiveStatement], start: usize) -> bool {
        let mut call_temp_decl: Option<DeclarationId> = None;
        let end = (start + 8).min(block.len());
        for stmt in block.iter().take(end).skip(start + 1) {
            let ReactiveStatement::Instruction(instr) = stmt else {
                break;
            };
            if let Some(call_decl) = call_temp_decl {
                match &instr.value {
                    InstructionValue::LoadLocal { place, .. }
                    | InstructionValue::LoadContext { place, .. } => {
                        if place.identifier.declaration_id == call_decl
                            && let Some(lvalue) = &instr.lvalue
                            && lvalue.identifier.name.is_some()
                        {
                            return true;
                        }
                    }
                    _ => {}
                }
                if matches!(
                    instr.value,
                    InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. }
                ) {
                    break;
                }
                continue;
            }
            if matches!(
                instr.value,
                InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. }
            ) {
                let Some(lvalue) = &instr.lvalue else {
                    return false;
                };
                if lvalue.identifier.name.is_some() {
                    return false;
                }
                call_temp_decl = Some(lvalue.identifier.declaration_id);
            }
        }
        false
    }

    fn has_following_sequence_combine_target(
        block: &[ReactiveStatement],
        start: usize,
        seed_loc: &SourceLocation,
    ) -> bool {
        let end = (start + 8).min(block.len());
        for stmt in block.iter().take(end).skip(start + 1) {
            let ReactiveStatement::Instruction(instr) = stmt else {
                break;
            };
            match &instr.value {
                InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. } => {
                    if let Some(lvalue) = &instr.lvalue {
                        if lvalue.identifier.name.is_some() {
                            return place.identifier.name.is_none()
                                && source_locs_are_sequence_adjacent(seed_loc, &place.loc);
                        }
                        continue;
                    }
                    break;
                }
                InstructionValue::StoreLocal { value, .. }
                | InstructionValue::StoreContext { value, .. } => {
                    return instr.lvalue.is_none()
                        && value.identifier.name.is_none()
                        && source_locs_are_sequence_compatible(seed_loc, &value.loc);
                }
                InstructionValue::LogicalExpression { left, .. } => {
                    return instr.lvalue.is_none()
                        && source_locs_are_sequence_compatible(seed_loc, &left.loc);
                }
                InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. } => {
                    return false;
                }
                _ => {
                    if instr
                        .lvalue
                        .as_ref()
                        .is_some_and(|lvalue| lvalue.identifier.name.is_none())
                    {
                        continue;
                    }
                    return false;
                }
            }
        }
        false
    }

    fn has_following_while_test_sequence_pattern(
        block: &[ReactiveStatement],
        start: usize,
        seed_loc: &SourceLocation,
    ) -> bool {
        let end = (start + 12).min(block.len());
        for stmt in block.iter().take(end).skip(start + 1) {
            match stmt {
                ReactiveStatement::Instruction(instr) => {
                    // Any named write means we're no longer in an expression-only chain.
                    if instr
                        .lvalue
                        .as_ref()
                        .and_then(|lvalue| lvalue.identifier.name.as_ref())
                        .is_some()
                    {
                        return false;
                    }
                }
                ReactiveStatement::Terminal(term_stmt) => {
                    if let ReactiveTerminal::While { test, .. } = &term_stmt.terminal {
                        return test.identifier.name.is_none()
                            && source_locs_are_sequence_compatible(seed_loc, &test.loc);
                    }
                    return false;
                }
                ReactiveStatement::Scope(_) | ReactiveStatement::PrunedScope(_) => return false,
            }
        }
        false
    }

    fn maybe_emit_unused_temp_named_load_statement(
        cx: &mut Context,
        block: &[ReactiveStatement],
        idx: usize,
        instr: &ReactiveInstruction,
    ) -> Option<String> {
        let expr = unused_temp_named_load_expression(cx, &block[idx + 1..], instr)?;
        render_reactive_expression_statement_ast(&expr)
    }

    fn maybe_codegen_store_context_with_value_tail(
        cx: &mut Context,
        block: &[ReactiveStatement],
        idx: usize,
        instr: &ReactiveInstruction,
    ) -> Option<String> {
        if instr.lvalue.is_some() {
            return None;
        }
        let InstructionValue::StoreContext { lvalue, value, .. } = &instr.value else {
            return None;
        };
        if lvalue.kind != InstructionKind::Reassign || lvalue.place.identifier.name.is_none() {
            return None;
        }
        let target = identifier_name_with_cx(cx, &lvalue.place.identifier);
        let rhs_expr = codegen_place_to_expression(cx, value);
        if !contains_base_identifier_token(&rhs_expr, &target)
            || !rendered_expr_contains_logical_or(&rhs_expr)
        {
            return None;
        }
        let ReactiveStatement::Instruction(next_instr) = block.get(idx + 1)? else {
            return None;
        };
        let Some(next_lvalue) = &next_instr.lvalue else {
            return None;
        };
        if next_lvalue.identifier.name.is_some() {
            return None;
        }
        let InstructionValue::Primitive {
            value: PrimitiveValue::Undefined,
            ..
        } = &next_instr.value
        else {
            return None;
        };
        let mut stmt = codegen_instruction_nullable(cx, instr)?;
        stmt.push_str(&render_reactive_expression_statement_ast(&target)?);
        Some(stmt)
    }

    let mut output = String::new();
    let mut last_source_end_line: Option<u32> = None;
    let mut pending_sequence_expr: Option<PendingSequenceExpr> = None;
    let mut i = 0usize;
    let debug_scope_bridge = std::env::var("DEBUG_SCOPE_BRIDGE").is_ok();
    let debug_codegen_trace = std::env::var("DEBUG_CODEGEN_TRACE").is_ok();
    while i < block.len() {
        if let Some(consumed) =
            maybe_codegen_fused_pruned_scope_prefix_into_following_stmt(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }

        if let Some(consumed) =
            maybe_codegen_fused_method_call_eval_order(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }

        if let Some(consumed) =
            maybe_codegen_fused_method_call_destructure_assignment(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) = maybe_codegen_fused_nullish_self_reassign(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) = maybe_codegen_fused_named_test_dual_reassign_scope_ternary_return(
            cx,
            block,
            i,
            &mut output,
        ) {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_named_test_scope_decl_ternary_statement(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_named_test_reassign_then_ternary_branch(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_reassign_then_ternary_branch(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_reassign_temp_load_then_ternary(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_reassign_stmt_into_following_null(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_reassign_stmt_into_following_logical(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_temp_load_into_following_stmt(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_named_temp_ternary_statement(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }
        if let Some(consumed) =
            maybe_codegen_fused_named_temp_logical_expression(cx, block, i, &mut output)
        {
            last_source_end_line = None;
            i += consumed;
            continue;
        }

        if debug_scope_bridge && let ReactiveStatement::Terminal(term_stmt) = &block[i] {
            let label_desc = match &term_stmt.label {
                None => "none".to_string(),
                Some(label) => format!("some(implicit={})", label.implicit),
            };
            let label_ok = term_stmt
                .label
                .as_ref()
                .map(|label| label.implicit)
                .unwrap_or(true);
            let terminal_loc = match &term_stmt.terminal {
                ReactiveTerminal::If { loc, .. }
                | ReactiveTerminal::Switch { loc, .. }
                | ReactiveTerminal::DoWhile { loc, .. }
                | ReactiveTerminal::While { loc, .. }
                | ReactiveTerminal::For { loc, .. }
                | ReactiveTerminal::ForOf { loc, .. }
                | ReactiveTerminal::ForIn { loc, .. }
                | ReactiveTerminal::Try { loc, .. }
                | ReactiveTerminal::Label { loc, .. }
                | ReactiveTerminal::Break { loc, .. }
                | ReactiveTerminal::Continue { loc, .. }
                | ReactiveTerminal::Return { loc, .. }
                | ReactiveTerminal::Throw { loc, .. } => match loc {
                    SourceLocation::Source(range) => {
                        format!(
                            "{}:{}-{}:{}",
                            range.start.line, range.start.column, range.end.line, range.end.column
                        )
                    }
                    SourceLocation::Generated => "generated".to_string(),
                },
            };
            eprintln!(
                "[SCOPE_BRIDGE] block_idx={} label={} label_ok={} next_is_scope={} terminal_loc={}",
                i,
                label_desc,
                label_ok,
                matches!(block.get(i + 1), Some(ReactiveStatement::Scope(_))),
                terminal_loc
            );
            for (lookahead, stmt) in block
                .iter()
                .enumerate()
                .take((i + 6).min(block.len()))
                .skip(i + 1)
            {
                let desc = match stmt {
                    ReactiveStatement::Instruction(instr) => {
                        let value_kind = match &instr.value {
                            InstructionValue::DeclareLocal { .. } => "DeclareLocal",
                            InstructionValue::DeclareContext { .. } => "DeclareContext",
                            InstructionValue::StoreLocal { .. } => "StoreLocal",
                            InstructionValue::StoreContext { .. } => "StoreContext",
                            InstructionValue::StartMemoize { .. } => "StartMemoize",
                            InstructionValue::FinishMemoize { .. } => "FinishMemoize",
                            _ => "InstructionOther",
                        };
                        format!("Instruction({value_kind}) value={:?}", instr.value)
                    }
                    ReactiveStatement::Scope(_) => "Scope".to_string(),
                    ReactiveStatement::PrunedScope(_) => "PrunedScope".to_string(),
                    ReactiveStatement::Terminal(_) => "Terminal".to_string(),
                };
                eprintln!("[SCOPE_BRIDGE]   lookahead idx={} {}", lookahead, desc);
            }
        }
        // Synthesize a cache guard for control-flow merged reassignments when
        // the next scope depends on that reassigned variable.
        if std::env::var("ENABLE_SCOPE_BRIDGE").is_ok()
            && !cx.disable_memoization_features
            && let ReactiveStatement::Terminal(term_stmt) = &block[i]
            && term_stmt
                .label
                .as_ref()
                .map(|label| label.implicit)
                .unwrap_or(true)
            && let Some((test_place, target_ident)) =
                memoizable_if_reassignment_scope_bridge(&term_stmt.terminal, &block[i + 1..])
            && let Some(if_stmt) = codegen_terminal(cx, &term_stmt.terminal)
        {
            let allocator = Allocator::default();
            let builder = AstBuilder::new(&allocator);
            let cache_var = cx.synthesize_name("$");
            let dep_expr = codegen_place_to_expression(cx, test_place);
            let dep_slot = cx.alloc_cache_slot();
            let value_slot = cx.alloc_cache_slot();
            let target_name = identifier_name_with_cx(cx, &target_ident);
            let mut consequent = parse_statement_list_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &if_stmt,
            )
            .expect("scope bridge terminal should stay on AST path");
            consequent.push(build_computed_member_assignment_statement_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    dep_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &dep_expr,
                )
                .expect("scope bridge dependency store should stay on AST path"),
            ));
            consequent.push(build_computed_member_assignment_statement_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    value_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
                builder.expression_identifier(SPAN, builder.ident(&target_name)),
            ));
            let alternate =
                builder.vec1(build_identifier_assignment_statement_ast_with_expression(
                    builder,
                    &target_name,
                    build_computed_member_expression_ast(
                        builder,
                        &cache_var,
                        builder.expression_numeric_literal(
                            SPAN,
                            value_slot as f64,
                            None,
                            NumberBase::Decimal,
                        ),
                    ),
                ));
            let statement = builder.statement_if(
                SPAN,
                builder.expression_binary(
                    SPAN,
                    build_computed_member_expression_ast(
                        builder,
                        &cache_var,
                        builder.expression_numeric_literal(
                            SPAN,
                            dep_slot as f64,
                            None,
                            NumberBase::Decimal,
                        ),
                    ),
                    AstBinaryOperator::StrictInequality,
                    parse_expression_for_ast_codegen(
                        &allocator,
                        SourceType::mjs().with_jsx(true),
                        &dep_expr,
                    )
                    .expect("scope bridge guard should stay on AST path"),
                ),
                builder.statement_block(SPAN, consequent),
                Some(builder.statement_block(SPAN, alternate)),
            );
            output.push_str(&format!(
                "{}\n",
                codegen_statement_with_flow_cast_restore(&statement)
            ));
            last_source_end_line = None;
            i += 1;
            continue;
        }

        let item = &block[i];
        match item {
            ReactiveStatement::Instruction(instr) => {
                if debug_codegen_trace {
                    let lvalue_decl = instr
                        .lvalue
                        .as_ref()
                        .map(|lvalue| lvalue.identifier.declaration_id.0);
                    let lvalue_name = instr
                        .lvalue
                        .as_ref()
                        .and_then(|lvalue| lvalue.identifier.name.as_ref())
                        .map(IdentifierName::value)
                        .unwrap_or("<none>");
                    eprintln!(
                        "[CODEGEN_TRACE] idx={} instr#{} kind={} lvalue_decl={:?} lvalue_name={}",
                        i,
                        instr.id.0,
                        instruction_value_tag(&instr.value),
                        lvalue_decl,
                        lvalue_name
                    );
                }
                if maybe_defer_inlineable_ternary_into_following_scope(
                    cx,
                    instr,
                    &block[..i],
                    &block[i + 1..],
                ) {
                    if debug_codegen_trace {
                        eprintln!(
                            "[CODEGEN_TRACE] idx={} instr#{} emitted=<deferred-inline-ternary>",
                            i, instr.id.0
                        );
                    }
                    i += 1;
                    continue;
                }
                if let Some(stmt) = maybe_emit_unused_temp_named_load_statement(cx, block, i, instr)
                {
                    let spacing_loc = instruction_source_loc_for_spacing(cx, instr).clone();
                    flush_pending_sequence_expr(
                        &mut output,
                        &mut pending_sequence_expr,
                        &mut last_source_end_line,
                    );
                    append_statement_with_source_gap(
                        &mut output,
                        &stmt,
                        Some(&spacing_loc),
                        &mut last_source_end_line,
                    );
                    if should_insert_structural_blank_after_instruction(
                        cx,
                        block,
                        i,
                        &stmt,
                        Some(&spacing_loc),
                    ) && !output.ends_with("\n\n")
                    {
                        output.push('\n');
                    }
                    i += 1;
                    continue;
                }
                if let Some(stmt) = maybe_codegen_store_context_with_value_tail(cx, block, i, instr)
                {
                    let spacing_loc = instruction_source_loc_for_spacing(cx, instr).clone();
                    flush_pending_sequence_expr(
                        &mut output,
                        &mut pending_sequence_expr,
                        &mut last_source_end_line,
                    );
                    append_statement_with_source_gap(
                        &mut output,
                        &stmt,
                        Some(&spacing_loc),
                        &mut last_source_end_line,
                    );
                    if should_insert_structural_blank_after_instruction(
                        cx,
                        block,
                        i,
                        &stmt,
                        Some(&spacing_loc),
                    ) && !output.ends_with("\n\n")
                    {
                        output.push('\n');
                    }
                    i += 1;
                    continue;
                }
                if let Some(pending) = &pending_sequence_expr
                    && let Some(stmt) = codegen_instruction_nullable(cx, instr)
                {
                    if debug_codegen_trace {
                        eprintln!(
                            "[CODEGEN_TRACE] idx={} instr#{} emitted={:?}",
                            i, instr.id.0, stmt
                        );
                    }
                    if let Some(combined) =
                        maybe_combine_instruction_with_pending_sequence(cx, instr, &stmt, pending)
                        && !has_following_sequence_tail_assignment_pattern(block, i)
                    {
                        let spacing_loc = instruction_source_loc_for_spacing(cx, instr).clone();
                        append_statement_with_source_gap(
                            &mut output,
                            &combined,
                            Some(&spacing_loc),
                            &mut last_source_end_line,
                        );
                        if should_insert_structural_blank_after_instruction(
                            cx,
                            block,
                            i,
                            &combined,
                            Some(&spacing_loc),
                        ) && !output.ends_with("\n\n")
                        {
                            output.push('\n');
                        }
                        pending_sequence_expr = None;
                        i += 1;
                        continue;
                    }
                    if let Some(expr) = extract_simple_expression_statement(&stmt)
                        && instruction_extends_pending_sequence(instr, pending)
                    {
                        if let Some(pending_mut) = pending_sequence_expr.as_mut() {
                            pending_mut.exprs.push(expr);
                        }
                        i += 1;
                        continue;
                    }
                    flush_pending_sequence_expr(
                        &mut output,
                        &mut pending_sequence_expr,
                        &mut last_source_end_line,
                    );
                    let spacing_loc = instruction_source_loc_for_spacing(cx, instr).clone();
                    append_statement_with_source_gap(
                        &mut output,
                        &stmt,
                        Some(&spacing_loc),
                        &mut last_source_end_line,
                    );
                    if should_insert_structural_blank_after_instruction(
                        cx,
                        block,
                        i,
                        &stmt,
                        Some(&spacing_loc),
                    ) && !output.ends_with("\n\n")
                    {
                        output.push('\n');
                    }
                    i += 1;
                    continue;
                }

                if let Some(stmt) = codegen_instruction_nullable(cx, instr) {
                    if debug_codegen_trace {
                        eprintln!(
                            "[CODEGEN_TRACE] idx={} instr#{} emitted={:?}",
                            i, instr.id.0, stmt
                        );
                    }
                    let starts_from_reassign_store = instr.lvalue.is_none()
                        && matches!(
                            instr.value,
                            InstructionValue::StoreLocal {
                                lvalue: LValue {
                                    kind: InstructionKind::Reassign,
                                    ..
                                },
                                ..
                            } | InstructionValue::StoreContext {
                                lvalue: LValue {
                                    kind: InstructionKind::Reassign,
                                    ..
                                },
                                ..
                            }
                        );
                    let starts_from_side_effect_call = instr.lvalue.is_none()
                        && matches!(
                            instr.value,
                            InstructionValue::CallExpression { .. }
                                | InstructionValue::MethodCall { .. }
                        );
                    let seed_loc = sequence_seed_loc(instr);
                    let has_sequence_tail =
                        has_following_sequence_tail_assignment_pattern(block, i);
                    let has_call_temp_load = has_following_call_temp_load_pattern(block, i);
                    let has_sequence_combine_target =
                        has_following_sequence_combine_target(block, i, seed_loc);
                    let has_while_test_tail =
                        has_following_while_test_sequence_pattern(block, i, seed_loc);
                    if (starts_from_reassign_store || starts_from_side_effect_call)
                        && (has_call_temp_load
                            || has_sequence_tail
                            || has_sequence_combine_target
                            || has_while_test_tail)
                        && let Some(expr) = extract_simple_expression_statement(&stmt)
                    {
                        flush_pending_sequence_expr(
                            &mut output,
                            &mut pending_sequence_expr,
                            &mut last_source_end_line,
                        );
                        pending_sequence_expr = Some(PendingSequenceExpr {
                            exprs: vec![expr],
                            loc: seed_loc.clone(),
                        });
                        i += 1;
                        continue;
                    }
                    flush_pending_sequence_expr(
                        &mut output,
                        &mut pending_sequence_expr,
                        &mut last_source_end_line,
                    );
                    let spacing_loc = instruction_source_loc_for_spacing(cx, instr).clone();
                    append_statement_with_source_gap(
                        &mut output,
                        &stmt,
                        Some(&spacing_loc),
                        &mut last_source_end_line,
                    );
                    if should_insert_structural_blank_after_instruction(
                        cx,
                        block,
                        i,
                        &stmt,
                        Some(&spacing_loc),
                    ) && !output.ends_with("\n\n")
                    {
                        output.push('\n');
                    }
                } else if debug_codegen_trace {
                    eprintln!(
                        "[CODEGEN_TRACE] idx={} instr#{} emitted=<none>",
                        i, instr.id.0
                    );
                }
            }
            ReactiveStatement::PrunedScope(pruned) => {
                flush_pending_sequence_expr(
                    &mut output,
                    &mut pending_sequence_expr,
                    &mut last_source_end_line,
                );
                // Pruned scopes: emit instructions without memoization
                let inner = codegen_block_no_reset(cx, &pruned.instructions);
                if let Some(expr) = extract_simple_expression_statement(&inner)
                    && let Some(loc) = single_call_expression_loc_in_block(&pruned.instructions)
                {
                    pending_sequence_expr = Some(PendingSequenceExpr {
                        exprs: vec![expr],
                        loc,
                    });
                } else {
                    output.push_str(&inner);
                    last_source_end_line = None;
                }
            }
            ReactiveStatement::Scope(scope_block) => {
                flush_pending_sequence_expr(
                    &mut output,
                    &mut pending_sequence_expr,
                    &mut last_source_end_line,
                );
                maybe_emit_reused_optional_dependency_reads(
                    cx,
                    &mut output,
                    &scope_block.scope,
                    &block[i + 1..],
                );
                if let Some(scope_dependencies) =
                    cx.scope_dependency_overrides.remove(&scope_block.scope.id)
                {
                    let mut overridden_scope = scope_block.scope.clone();
                    overridden_scope.dependencies = scope_dependencies;
                    codegen_reactive_scope(
                        cx,
                        &mut output,
                        &overridden_scope,
                        &scope_block.instructions,
                    );
                    last_source_end_line = None;
                    i += 1;
                    continue;
                }
                if cx.disable_memoization_features {
                    let inner = codegen_block_no_reset(cx, &scope_block.instructions);
                    output.push_str(&inner);
                    last_source_end_line = None;
                    i += 1;
                    continue;
                }
                if should_inline_zero_dep_global_zero_arg_call_scope(
                    cx,
                    scope_block,
                    &block[..i],
                    &block[i + 1..],
                ) {
                    let inner = codegen_block_no_reset(cx, &scope_block.instructions);
                    output.push_str(&inner);
                    last_source_end_line = None;
                    i += 1;
                    continue;
                }
                if allow_top_level_zero_dep_literal_inline
                    && let Some(consumed_following) = maybe_codegen_inline_literal_init_scope(
                        cx,
                        scope_block,
                        &block[i + 1..],
                        &mut output,
                    )
                {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) = maybe_codegen_fused_ternary_source_scope(
                    cx,
                    scope_block,
                    &block[i + 1..],
                    &mut output,
                ) {
                    // Consumed this scope and the matched following statements.
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) =
                    maybe_codegen_inline_zero_dep_literal_into_following_scope(
                        cx,
                        scope_block,
                        &block[i + 1..],
                        &mut output,
                    )
                {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) =
                    maybe_codegen_fused_dual_zero_dep_literal_ternary_scope(
                        cx,
                        scope_block,
                        &block[i + 1..],
                        &mut output,
                    )
                {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) = maybe_codegen_fused_zero_dep_literal_store_scope(
                    cx,
                    scope_block,
                    &block[i + 1..],
                    &mut output,
                ) {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                // Upstream does not fuse a zero-dep seed scope directly into a following
                // dep-guarded scope; it emits distinct memoization guards/slots for each scope.
                // Keep this path disabled for strict output parity.
                if let Some(consumed_following) =
                    maybe_codegen_fused_zero_dep_sequence_logical_scope(
                        cx,
                        scope_block,
                        &block[i + 1..],
                        &mut output,
                    )
                {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) = maybe_codegen_fused_zero_dep_ternary_default_scope(
                    cx,
                    scope_block,
                    &block[i + 1..],
                    &mut output,
                ) {
                    // Consumed this scope and the matched following statements.
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) = maybe_codegen_fused_callback_reassign_scope(
                    cx,
                    scope_block,
                    &block[i + 1..],
                    &mut output,
                ) {
                    // Consumed this scope and the matched following statements.
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(consumed_following) =
                    maybe_codegen_fused_effect_callback_empty_array_scope(
                        cx,
                        scope_block,
                        &block[i + 1..],
                        &mut output,
                    )
                {
                    last_source_end_line = None;
                    i += 1 + consumed_following;
                    continue;
                }
                if let Some(filtered_deps) = filtered_effect_callback_deps_for_explicit_empty_array(
                    cx,
                    scope_block,
                    &block[i + 1..],
                ) {
                    let mut overridden_scope = scope_block.scope.clone();
                    overridden_scope.dependencies = filtered_deps;
                    codegen_reactive_scope(
                        cx,
                        &mut output,
                        &overridden_scope,
                        &scope_block.instructions,
                    );
                    last_source_end_line = None;
                    i += 1;
                    continue;
                }
                let temp_snapshot = cx.snapshot_temps();
                // Bridge a following return by synthesizing an output when this scope
                // has no explicit outputs (no declarations or reassignments).
                // This enables sentinel-based caching for zero-dep scopes that
                // compute values consumed by an immediate `return`.
                if scope_block.scope.declarations.is_empty()
                    && scope_block.scope.reassignments.is_empty()
                    && let Some(ReactiveStatement::Terminal(term_stmt)) = block.get(i + 1)
                    && let ReactiveTerminal::Return { value, .. } = &term_stmt.terminal
                {
                    // Clone the scope and treat the return value as a reassignment output,
                    // so sentinel-based caching uses it as the first output slot.
                    let mut scope_clone = scope_block.scope.clone();
                    // Avoid duplicates just in case.
                    if !scope_clone
                        .reassignments
                        .iter()
                        .any(|id| id.id == value.identifier.id)
                    {
                        scope_clone.reassignments.push(value.identifier.clone());
                    }
                    codegen_reactive_scope(
                        cx,
                        &mut output,
                        &scope_clone,
                        &scope_block.instructions,
                    );
                    last_source_end_line = None;
                    cx.restore_temps(temp_snapshot);
                    // Proceed to emit the following return as usual in the next loop iteration.
                    i += 1;
                    continue;
                }
                codegen_reactive_scope(
                    cx,
                    &mut output,
                    &scope_block.scope,
                    &scope_block.instructions,
                );
                last_source_end_line = None;
                cx.restore_temps(temp_snapshot);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                if let Some(pending) = &pending_sequence_expr
                    && let Some(stmt) =
                        maybe_codegen_while_with_pending_sequence(cx, &term_stmt.terminal, pending)
                {
                    append_rendered_terminal_statement(&mut output, term_stmt, &stmt);
                    pending_sequence_expr = None;
                    last_source_end_line = None;
                    i += 1;
                    continue;
                }
                flush_pending_sequence_expr(
                    &mut output,
                    &mut pending_sequence_expr,
                    &mut last_source_end_line,
                );
                if let Some((rewritten, consumed_following)) =
                    maybe_codegen_inverted_labeled_if_fallthrough(cx, term_stmt, block, i)
                {
                    output.push_str(&rewritten);
                    last_source_end_line = None;
                    if !output.ends_with('\n') {
                        output.push('\n');
                    }
                    i += consumed_following + 1;
                    continue;
                }
                if let Some(consumed_following) =
                    maybe_codegen_labeled_if_adjacent_block(cx, term_stmt, block, i, &mut output)
                {
                    last_source_end_line = None;
                    i += consumed_following + 1;
                    continue;
                }
                if let Some(stmt) = codegen_terminal(cx, &term_stmt.terminal) {
                    let insert_blank_after_labeled_if =
                        should_insert_blank_after_labeled_if(term_stmt, block, i);
                    let insert_blank_after_try =
                        should_insert_blank_after_try_call_followup(cx, term_stmt, block, i);
                    let insert_blank_after_breaking_if =
                        should_insert_blank_after_if_trailing_labeled_break(
                            cx, term_stmt, block, i,
                        );
                    append_rendered_terminal_statement(&mut output, term_stmt, &stmt);
                    last_source_end_line = None;
                    if (insert_blank_after_labeled_if
                        || insert_blank_after_try
                        || insert_blank_after_breaking_if)
                        && !output.ends_with("\n\n")
                    {
                        output.push('\n');
                    }
                }
            }
        }
        i += 1;
    }
    flush_pending_sequence_expr(
        &mut output,
        &mut pending_sequence_expr,
        &mut last_source_end_line,
    );
    output
}

fn split_trailing_break(block: &[ReactiveStatement]) -> Option<(BlockId, &[ReactiveStatement])> {
    if block.is_empty() {
        return None;
    }
    let last = block.last()?;
    let ReactiveStatement::Terminal(ReactiveTerminalStatement {
        terminal: ReactiveTerminal::Break { target, .. },
        ..
    }) = last
    else {
        return None;
    };
    Some((*target, &block[..block.len() - 1]))
}

fn maybe_codegen_inverted_labeled_if_fallthrough(
    cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
    block: &[ReactiveStatement],
    idx: usize,
) -> Option<(String, usize)> {
    let debug = std::env::var("DEBUG_LABEL_FALLTHROUGH").is_ok();
    macro_rules! bail {
        ($reason:expr) => {{
            if debug {
                eprintln!("[LABEL_FALLTHROUGH] skip: {}", $reason);
            }
            return None;
        }};
    }

    let Some(label) = &term_stmt.label else {
        bail!("no-label");
    };
    if label.implicit {
        bail!("implicit-label");
    }

    let ReactiveTerminal::If {
        test,
        consequent,
        alternate,
        ..
    } = &term_stmt.terminal
    else {
        bail!("non-if-terminal");
    };
    if alternate.is_some() {
        bail!("has-alternate");
    }

    let Some((cons_target, cons_prefix)) = split_trailing_break(consequent) else {
        bail!("consequent-no-trailing-break");
    };
    // Only apply to outer-target break inversion patterns.
    if cons_target == label.id {
        bail!("consequent-target-is-self");
    }
    if cons_prefix.is_empty() || !cons_prefix.iter().all(is_instruction_statement) {
        bail!("consequent-not-instruction-only");
    }

    if idx + 1 >= block.len() {
        bail!("no-following");
    }
    let following = &block[idx + 1..];
    let mut consumed_following = None;
    for take in 1..=following.len() {
        let slice = &following[..take];
        if let Some((target, _)) = split_trailing_break(slice)
            && target == cons_target
        {
            consumed_following = Some(take);
            break;
        }
    }
    let Some(consumed_following) = consumed_following else {
        bail!("no-following-slice-with-matching-break");
    };
    let fallthrough_block = &following[..consumed_following];
    let Some((fallthrough_target, fallthrough_prefix)) = split_trailing_break(fallthrough_block)
    else {
        bail!("fallthrough-no-trailing-break");
    };
    if fallthrough_target != cons_target
        || fallthrough_prefix.is_empty()
        || !fallthrough_prefix.iter().all(is_instruction_statement)
    {
        bail!("fallthrough-shape-mismatch");
    }

    let test_expr = codegen_place_to_expression(cx, test);
    let fallthrough_code = codegen_block(cx, fallthrough_prefix);
    let consequent_code = codegen_block(cx, cons_prefix);
    // Only rewrite very simple one-statement branches.
    if count_non_empty_lines(&fallthrough_code) != 1 || count_non_empty_lines(&consequent_code) != 1
    {
        bail!("branch-codes-not-single-statement");
    }
    // Guard against over-eager rewrites (e.g. call expressions) that diverge
    // from upstream output shape in non-inversion fixtures.
    if !is_simple_assignment_line(&fallthrough_code) || !is_simple_assignment_line(&consequent_code)
    {
        bail!("branch-codes-not-simple-assignment");
    }
    if debug {
        eprintln!(
            "[LABEL_FALLTHROUGH] apply: label=bb{} implicit={} target=bb{} test={} fallthrough={:?} consequent={:?}",
            label.id.0, label.implicit, cons_target.0, test_expr, fallthrough_code, consequent_code
        );
    }

    let label_name = format!("bb{}", label.id.0);
    let target_label = format!("bb{}", cons_target.0);
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let labeled_if = builder.statement_labeled(
        SPAN,
        builder.label_identifier(SPAN, builder.atom(&label_name)),
        builder.statement_if(
            SPAN,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &test_expr,
            )
            .ok()?,
            builder.statement_block(
                SPAN,
                builder.vec1(builder.statement_break(
                    SPAN,
                    Some(builder.label_identifier(SPAN, builder.atom(&label_name))),
                )),
            ),
            None,
        ),
    );
    let mut rewritten = format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&labeled_if)
    );
    rewritten.push_str(&fallthrough_code);
    rewritten.push_str(&render_reactive_break_statement_ast(Some(&target_label))?);
    rewritten.push_str(&consequent_code);
    Some((rewritten, consumed_following))
}

fn is_instruction_statement(stmt: &ReactiveStatement) -> bool {
    matches!(stmt, ReactiveStatement::Instruction(_))
}

fn count_non_empty_lines(code: &str) -> usize {
    code.lines().filter(|line| !line.trim().is_empty()).count()
}

fn is_simple_assignment_line(code: &str) -> bool {
    let allocator = Allocator::default();
    let Ok(statement) =
        parse_single_statement_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), code)
    else {
        return false;
    };
    matches!(
        statement,
        ast::Statement::ExpressionStatement(expression_statement)
            if matches!(
                expression_statement.expression.without_parentheses(),
                ast::Expression::AssignmentExpression(_)
            )
    )
}

fn emit_labeled_statement(output: &mut String, label_id: BlockId, stmt: &str) {
    // If no control transfer references this label in rendered statement,
    // skip emitting it (parity with upstream label pruning pass).
    if !statement_references_label(stmt, label_id) {
        output.push_str(stmt);
        return;
    }

    let trimmed = stmt.trim_start();
    if trimmed.is_empty() {
        output.push_str(&format!("bb{}:\n", label_id.0));
        return;
    }
    let own_label_prefix = format!("bb{}:", label_id.0);
    if trimmed.starts_with(&own_label_prefix) {
        output.push_str(trimmed);
        if !trimmed.ends_with('\n') {
            output.push('\n');
        }
        return;
    }
    let label = format!("bb{}", label_id.0);
    let needs_block_wrapper = labeled_statement_needs_block_wrapper(trimmed);
    let rendered = render_reactive_labeled_statement_ast(&label, trimmed, needs_block_wrapper)
        .expect("generated labeled statement should parse");
    output.push_str(&rendered);
}

fn statement_references_label(stmt: &str, label_id: BlockId) -> bool {
    let label = format!("bb{}", label_id.0);
    rendered_statement_references_label(stmt, &label)
}

fn append_rendered_terminal_statement(
    output: &mut String,
    term_stmt: &ReactiveTerminalStatement,
    stmt: &str,
) {
    if let Some(label) = &term_stmt.label
        && !label.implicit
    {
        emit_labeled_statement(output, label.id, stmt);
    } else {
        output.push_str(stmt);
    }

    if !output.ends_with('\n') {
        output.push('\n');
    }
}

fn maybe_codegen_labeled_if_adjacent_block(
    cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
    block: &[ReactiveStatement],
    idx: usize,
    output: &mut String,
) -> Option<usize> {
    let debug = std::env::var("DEBUG_LABEL_ADJ").is_ok();
    macro_rules! bail {
        ($reason:expr) => {{
            if debug {
                eprintln!("[LABEL_ADJ] skip: {}", $reason);
            }
            return None;
        }};
    }

    let label = term_stmt.label.as_ref()?;
    if label.implicit {
        bail!("implicit-label");
    }
    let ReactiveTerminal::If {
        consequent,
        alternate,
        loc,
        ..
    } = &term_stmt.terminal
    else {
        bail!("non-if");
    };
    let SourceLocation::Source(range) = loc else {
        bail!("generated-loc");
    };
    let term_start_line = range.start.line;
    let term_end_line = range.end.line;

    let branch_breaks_to_label = |branch: &[ReactiveStatement]| {
        split_trailing_break(branch)
            .map(|(target, prefix)| target == label.id && prefix.is_empty())
            .unwrap_or(false)
    };
    let consequent_breaks_to_label = branch_breaks_to_label(consequent);
    let alternate_breaks_to_label = alternate
        .as_ref()
        .map(|branch| branch_breaks_to_label(branch))
        .unwrap_or(false);
    if !consequent_breaks_to_label && !alternate_breaks_to_label {
        bail!("no-self-break-branch");
    }

    // Collect the first concrete source statement after this terminal.
    let mut consumed_following = 0usize;
    let mut first_following_line = None;
    let mut following_stmt = String::new();
    while let Some(ReactiveStatement::Instruction(instr)) = block.get(idx + 1 + consumed_following)
    {
        let Some(line) = reactive_instruction_start_line(instr) else {
            break;
        };
        if let Some(first_line) = first_following_line {
            if line != first_line {
                break;
            }
        } else {
            first_following_line = Some(line);
        }
        if let Some(stmt) = codegen_instruction_nullable(cx, instr) {
            following_stmt.push_str(&stmt);
            if !stmt.ends_with('\n') {
                following_stmt.push('\n');
            }
        }
        consumed_following += 1;
    }
    let Some(following_line) = first_following_line else {
        bail!("no-following-instruction");
    };
    // When the next statement starts on the immediately following source line,
    // upstream keeps it inside the labeled block.
    if following_line != term_end_line + 1 {
        bail!(format!(
            "following-line-mismatch term_end={} follow={}",
            term_end_line, following_line
        ));
    }
    if following_stmt.trim().is_empty() {
        bail!("following-stmt-empty");
    }
    if rendered_statement_is_cache_store(&following_stmt) {
        bail!("following-is-cache-store");
    }

    let mut prefix_stmt = None;
    let allow_prefix_lift = consequent_breaks_to_label && alternate.is_none();
    if allow_prefix_lift
        && term_start_line > 1
        && idx > 0
        && let Some(ReactiveStatement::Instruction(prev_instr)) = block.get(idx - 1)
        && reactive_instruction_start_line(prev_instr)
            .is_some_and(|line| line == term_start_line || line + 1 == term_start_line)
    {
        prefix_stmt = pop_last_simple_statement_line(output);
        if debug {
            eprintln!(
                "[LABEL_ADJ] prefix-candidate idx={} prev_line={} term_start={} popped={}",
                idx,
                reactive_instruction_start_line(prev_instr).unwrap_or_default(),
                term_start_line,
                prefix_stmt.is_some()
            );
        }
    } else if debug {
        let prev_line = if idx > 0 {
            match block.get(idx - 1) {
                Some(ReactiveStatement::Instruction(prev_instr)) => {
                    reactive_instruction_start_line(prev_instr).unwrap_or_default()
                }
                _ => 0,
            }
        } else {
            0
        };
        eprintln!(
            "[LABEL_ADJ] prefix-skip idx={} prev_line={} term_start={} allow_prefix={}",
            idx, prev_line, term_start_line, allow_prefix_lift
        );
    }

    let Some(if_stmt) = codegen_terminal(cx, &term_stmt.terminal) else {
        bail!("codegen-terminal-none");
    };
    let label_name = format!("bb{}", label.id.0);
    let had_prefix_stmt = prefix_stmt.is_some();
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut rewritten_body = builder.vec();
    if let Some(prefix) = prefix_stmt {
        rewritten_body.extend(
            parse_statement_list_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                prefix.trim(),
            )
            .ok()?,
        );
    }
    rewritten_body.extend(
        parse_statement_list_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            if_stmt.trim_end(),
        )
        .ok()?,
    );
    rewritten_body.extend(
        parse_statement_list_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            following_stmt.trim_end(),
        )
        .ok()?,
    );
    let rewritten = format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&builder.statement_labeled(
            SPAN,
            builder.label_identifier(SPAN, builder.atom(&label_name)),
            builder.statement_block(SPAN, rewritten_body),
        ))
    );
    let next_is_cache_store =
        next_emitted_statement_is_cache_store(cx, block, idx + 1 + consumed_following);
    if matches!(next_is_cache_store, Some(false)) {
        output.push_str(&rewritten);
        output.push('\n');
    } else {
        output.push_str(&rewritten);
    }
    if debug {
        eprintln!(
            "[LABEL_ADJ] apply: label=bb{} consumed={} prefix={} term={}..{} next_cache={:?}",
            label.id.0,
            consumed_following,
            had_prefix_stmt,
            term_start_line,
            term_end_line,
            next_is_cache_store
        );
    }
    Some(consumed_following)
}

fn reactive_instruction_start_line(instr: &ReactiveInstruction) -> Option<u32> {
    match &instr.loc {
        SourceLocation::Source(range) => Some(range.start.line),
        SourceLocation::Generated => None,
    }
}

fn reactive_terminal_start_line(terminal: &ReactiveTerminal) -> Option<u32> {
    let loc = match terminal {
        ReactiveTerminal::Break { loc, .. }
        | ReactiveTerminal::Continue { loc, .. }
        | ReactiveTerminal::Return { loc, .. }
        | ReactiveTerminal::Throw { loc, .. }
        | ReactiveTerminal::Switch { loc, .. }
        | ReactiveTerminal::DoWhile { loc, .. }
        | ReactiveTerminal::While { loc, .. }
        | ReactiveTerminal::For { loc, .. }
        | ReactiveTerminal::ForOf { loc, .. }
        | ReactiveTerminal::ForIn { loc, .. }
        | ReactiveTerminal::If { loc, .. }
        | ReactiveTerminal::Label { loc, .. }
        | ReactiveTerminal::Try { loc, .. } => loc,
    };
    match loc {
        SourceLocation::Source(range) => Some(range.start.line),
        SourceLocation::Generated => None,
    }
}

fn pop_last_simple_statement_line(output: &mut String) -> Option<String> {
    let mut end = output.len();
    while end > 0 && output.as_bytes()[end - 1] == b'\n' {
        end -= 1;
    }
    if end == 0 {
        return None;
    }
    let start = output[..end].rfind('\n').map_or(0, |idx| idx + 1);
    let line = &output[start..end];
    let trimmed = line.trim();
    if trimmed.is_empty() || !trimmed.ends_with(';') || !is_literal_init_assignment_line(trimmed) {
        return None;
    }
    let trimmed_owned = trimmed.to_string();
    output.truncate(start);
    Some(trimmed_owned)
}

fn is_literal_init_assignment_line(line: &str) -> bool {
    let trimmed = line.trim();
    if rendered_statement_is_cache_store(trimmed) {
        return false;
    }
    let allocator = Allocator::default();
    let Ok(statement) = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        trimmed,
    ) else {
        return false;
    };
    match statement {
        ast::Statement::VariableDeclaration(declaration) => declaration
            .unbox()
            .declarations
            .into_iter()
            .next()
            .and_then(|declarator| declarator.init)
            .is_some_and(|init| is_empty_array_or_object_literal_expression(&init)),
        ast::Statement::ExpressionStatement(statement) => match statement.unbox().expression {
            ast::Expression::AssignmentExpression(assignment) => {
                is_empty_array_or_object_literal_expression(&assignment.right)
            }
            _ => false,
        },
        ast::Statement::BreakStatement(_)
        | ast::Statement::ContinueStatement(_)
        | ast::Statement::LabeledStatement(_) => false,
        _ => false,
    }
}

fn is_empty_array_or_object_literal_expression(expression: &ast::Expression<'_>) -> bool {
    match expression.without_parentheses() {
        ast::Expression::ArrayExpression(array) => array.elements.is_empty(),
        ast::Expression::ObjectExpression(object) => object.properties.is_empty(),
        _ => false,
    }
}

fn rendered_expr_is_empty_array_literal(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    matches!(
        expression.without_parentheses(),
        ast::Expression::ArrayExpression(array) if array.elements.is_empty()
    )
}

fn rendered_expr_root_identifier_name(expr: &str) -> Option<String> {
    fn root_identifier_name<'a>(expression: &'a ast::Expression<'a>) -> Option<String> {
        match expression.without_parentheses() {
            ast::Expression::Identifier(identifier) => Some(identifier.name.to_string()),
            ast::Expression::StaticMemberExpression(member) => root_identifier_name(&member.object),
            ast::Expression::ComputedMemberExpression(member) => {
                root_identifier_name(&member.object)
            }
            ast::Expression::ChainExpression(chain) => match &chain.expression {
                ast::ChainElement::StaticMemberExpression(member) => {
                    root_identifier_name(&member.object)
                }
                ast::ChainElement::ComputedMemberExpression(member) => {
                    root_identifier_name(&member.object)
                }
                ast::ChainElement::CallExpression(call) => root_identifier_name(&call.callee),
                _ => None,
            },
            _ => None,
        }
    }

    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return None;
    }
    let allocator = Allocator::default();
    let expression = parse_rendered_expression_ast(&allocator, trimmed)?;
    root_identifier_name(&expression)
}

fn rendered_expr_contains_assignment_to_target(expr: &str, target: &str, rhs_expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };

    struct TargetAssignmentDetector<'a> {
        target: &'a str,
        rhs_expr: &'a str,
        found: bool,
    }

    impl<'a> Visit<'a> for TargetAssignmentDetector<'_> {
        fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
            if self.found {
                return;
            }
            if let ast::Expression::AssignmentExpression(assignment) =
                expression.without_parentheses()
                && assignment.operator == AssignmentOperator::Assign
                && let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) =
                    &assignment.left
                && identifier.name == self.target
                && codegen_expression_with_flow_cast_restore(&assignment.right) == self.rhs_expr
            {
                self.found = true;
                return;
            }
            walk::walk_expression(self, expression);
        }
    }

    let mut detector = TargetAssignmentDetector {
        target,
        rhs_expr,
        found: false,
    };
    detector.visit_expression(&expression);
    detector.found
}

fn rendered_expr_contains_push_call_on_target(expr: &str, target: &str) -> bool {
    fn callee_is_push_on_target(callee: &ast::Expression<'_>, target: &str) -> bool {
        match callee.without_parentheses() {
            ast::Expression::StaticMemberExpression(member) => {
                member.property.name == "push"
                    && matches!(
                        member.object.without_parentheses(),
                        ast::Expression::Identifier(identifier) if identifier.name == target
                    )
            }
            _ => false,
        }
    }

    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };

    struct PushCallDetector<'a> {
        target: &'a str,
        found: bool,
    }

    impl<'a> Visit<'a> for PushCallDetector<'_> {
        fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
            if self.found {
                return;
            }
            let is_match = match expression.without_parentheses() {
                ast::Expression::CallExpression(call) => {
                    callee_is_push_on_target(&call.callee, self.target)
                }
                ast::Expression::ChainExpression(chain) => match &chain.expression {
                    ast::ChainElement::CallExpression(call) => {
                        callee_is_push_on_target(&call.callee, self.target)
                    }
                    _ => false,
                },
                _ => false,
            };
            if is_match {
                self.found = true;
                return;
            }
            walk::walk_expression(self, expression);
        }
    }

    let mut detector = PushCallDetector {
        target,
        found: false,
    };
    detector.visit_expression(&expression);
    detector.found
}

fn rendered_statement_is_push_call_on_target(stmt: &str, target: &str) -> bool {
    let trimmed = stmt.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Ok(statement) = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        trimmed,
    ) else {
        return false;
    };
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return false;
    };
    rendered_expr_contains_push_call_on_target(
        &codegen_expression_with_flow_cast_restore(&expression_statement.expression),
        target,
    )
}

fn next_emitted_statement_is_cache_store(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start_idx: usize,
) -> Option<bool> {
    preview_next_emitted_statement(cx, block, start_idx)
        .as_deref()
        .map(rendered_statement_is_cache_store)
}

fn preview_next_emitted_statement(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start_idx: usize,
) -> Option<String> {
    let debug = std::env::var("DEBUG_LABEL_ADJ").is_ok();
    let temp_snapshot = cx.snapshot_temps();
    let mut idx = start_idx;
    let mut first_stmt = None;
    while let Some(stmt) = block.get(idx) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if let Some(code) = codegen_instruction_nullable(cx, instr) {
            first_stmt = Some(code);
            break;
        }
        idx += 1;
    }
    cx.restore_temps(temp_snapshot);
    if debug {
        eprintln!(
            "[LABEL_ADJ] next-preview idx={} stmt={:?}",
            start_idx, first_stmt
        );
    }
    first_stmt
}

fn rendered_statement_is_cache_store(stmt: &str) -> bool {
    let trimmed = stmt.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Ok(statement) = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        trimmed,
    ) else {
        return false;
    };
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return false;
    };
    let ast::Expression::AssignmentExpression(assignment) =
        expression_statement.expression.without_parentheses()
    else {
        return false;
    };
    matches!(
        &assignment.left,
        ast::AssignmentTarget::ComputedMemberExpression(member)
            if matches!(
                member.object.without_parentheses(),
                ast::Expression::Identifier(identifier) if identifier.name == "$"
            )
    )
}

fn rendered_statement_references_label(stmt: &str, label: &str) -> bool {
    fn statement_references_label_ast(statement: &ast::Statement<'_>, label: &str) -> bool {
        match statement {
            ast::Statement::BreakStatement(break_statement) => break_statement
                .label
                .as_ref()
                .is_some_and(|identifier| identifier.name == label),
            ast::Statement::ContinueStatement(continue_statement) => continue_statement
                .label
                .as_ref()
                .is_some_and(|identifier| identifier.name == label),
            ast::Statement::BlockStatement(block) => block
                .body
                .iter()
                .any(|statement| statement_references_label_ast(statement, label)),
            ast::Statement::IfStatement(if_statement) => {
                statement_references_label_ast(&if_statement.consequent, label)
                    || if_statement
                        .alternate
                        .as_ref()
                        .is_some_and(|statement| statement_references_label_ast(statement, label))
            }
            ast::Statement::LabeledStatement(labeled) => {
                statement_references_label_ast(&labeled.body, label)
            }
            ast::Statement::ForStatement(for_statement) => {
                statement_references_label_ast(&for_statement.body, label)
            }
            ast::Statement::ForInStatement(for_statement) => {
                statement_references_label_ast(&for_statement.body, label)
            }
            ast::Statement::ForOfStatement(for_statement) => {
                statement_references_label_ast(&for_statement.body, label)
            }
            ast::Statement::WhileStatement(while_statement) => {
                statement_references_label_ast(&while_statement.body, label)
            }
            ast::Statement::DoWhileStatement(do_while_statement) => {
                statement_references_label_ast(&do_while_statement.body, label)
            }
            ast::Statement::WithStatement(with_statement) => {
                statement_references_label_ast(&with_statement.body, label)
            }
            ast::Statement::SwitchStatement(switch_statement) => switch_statement
                .cases
                .iter()
                .flat_map(|case| case.consequent.iter())
                .any(|statement| statement_references_label_ast(statement, label)),
            ast::Statement::TryStatement(try_statement) => {
                try_statement
                    .block
                    .body
                    .iter()
                    .any(|statement| statement_references_label_ast(statement, label))
                    || try_statement.handler.as_ref().is_some_and(|handler| {
                        handler
                            .body
                            .body
                            .iter()
                            .any(|statement| statement_references_label_ast(statement, label))
                    })
                    || try_statement.finalizer.as_ref().is_some_and(|finalizer| {
                        finalizer
                            .body
                            .iter()
                            .any(|statement| statement_references_label_ast(statement, label))
                    })
            }
            _ => false,
        }
    }

    let trimmed = stmt.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Ok(statements) =
        parse_statement_list_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), trimmed)
    else {
        return false;
    };
    statements
        .iter()
        .any(|statement| statement_references_label_ast(statement, label))
}

fn should_insert_blank_after_labeled_if(
    term_stmt: &ReactiveTerminalStatement,
    block: &[ReactiveStatement],
    idx: usize,
) -> bool {
    let Some(label) = term_stmt.label.as_ref() else {
        return false;
    };
    if label.implicit {
        return false;
    }
    let ReactiveTerminal::If {
        consequent,
        alternate,
        loc,
        ..
    } = &term_stmt.terminal
    else {
        return false;
    };
    if alternate.is_some() {
        return false;
    }
    let SourceLocation::Source(range) = loc else {
        return false;
    };
    let Some((target, prefix)) = split_trailing_break(consequent) else {
        return false;
    };
    if target != label.id || !prefix.is_empty() {
        return false;
    }
    let term_end_line = range.end.line;
    let mut cursor = idx + 1;
    while let Some(stmt) = block.get(cursor) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            return false;
        };
        if let Some(next_line) = reactive_instruction_start_line(instr) {
            return next_line >= term_end_line + 2;
        }
        cursor += 1;
    }
    false
}

fn should_insert_blank_after_try_call_followup(
    _cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
    block: &[ReactiveStatement],
    idx: usize,
) -> bool {
    let debug = std::env::var("DEBUG_TRY_SPACE").is_ok();
    let ReactiveTerminal::Try { handler, loc, .. } = &term_stmt.terminal else {
        if debug {
            eprintln!("[TRY_SPACE] skip: non-try");
        }
        return false;
    };
    let SourceLocation::Source(range) = loc else {
        if debug {
            eprintln!("[TRY_SPACE] skip: generated-loc");
        }
        return false;
    };
    let mut cursor = idx + 1;
    let mut next_line = None;
    while let Some(stmt) = block.get(cursor) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if let Some(line) = reactive_instruction_start_line(instr) {
            next_line = Some(line);
            break;
        }
        cursor += 1;
    }
    let Some(next_line) = next_line else {
        if debug {
            eprintln!("[TRY_SPACE] skip: no-following-source-line");
        }
        return false;
    };
    if next_line != range.end.line + 1 {
        if debug {
            eprintln!(
                "[TRY_SPACE] skip: line-gap term_end={} next_line={}",
                range.end.line, next_line
            );
        }
        return false;
    }
    let mut cursor = idx + 1;
    let mut is_call = false;
    while let Some(stmt) = block.get(cursor) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        let Some(line) = reactive_instruction_start_line(instr) else {
            cursor += 1;
            continue;
        };
        if line != next_line {
            break;
        }
        if matches!(
            &instr.value,
            InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. }
        ) {
            is_call = true;
            break;
        }
        cursor += 1;
    }
    if debug {
        eprintln!(
            "[TRY_SPACE] decision: term={}..{} next_line={} call={} handler_len={}",
            range.start.line,
            range.end.line,
            next_line,
            is_call,
            handler.len()
        );
    }
    is_call
}

fn should_insert_blank_after_if_trailing_labeled_break(
    cx: &mut Context,
    term_stmt: &ReactiveTerminalStatement,
    block: &[ReactiveStatement],
    idx: usize,
) -> bool {
    let debug = std::env::var("DEBUG_IF_BREAK_SPACE").is_ok();
    let ReactiveTerminal::If {
        consequent,
        alternate,
        ..
    } = &term_stmt.terminal
    else {
        return false;
    };
    let breaks_in_consequent = branch_has_trailing_labeled_break(consequent);
    let breaks_in_alternate = alternate
        .as_ref()
        .is_some_and(|branch| branch_has_trailing_labeled_break(branch));
    if !breaks_in_consequent && !breaks_in_alternate {
        if debug {
            eprintln!("[IF_BREAK_SPACE] skip: no trailing labeled break");
        }
        return false;
    }
    if debug {
        eprintln!(
            "[IF_BREAK_SPACE] candidate: idx={} break_cons={} break_alt={}",
            idx, breaks_in_consequent, breaks_in_alternate
        );
    }
    let mut cursor = idx + 1;
    let mut saw_source_instruction = false;
    while let Some(stmt) = block.get(cursor) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            if saw_source_instruction
                && matches!(
                    stmt,
                    ReactiveStatement::Terminal(ReactiveTerminalStatement {
                        terminal: ReactiveTerminal::If { .. },
                        ..
                    })
                )
            {
                if debug {
                    eprintln!(
                        "[IF_BREAK_SPACE] decision: insert before following terminal-if at cursor={}",
                        cursor
                    );
                }
                return true;
            }
            if debug {
                let kind = match stmt {
                    ReactiveStatement::Terminal(term_stmt) => match &term_stmt.terminal {
                        ReactiveTerminal::If { .. } => "terminal-if",
                        ReactiveTerminal::Switch { .. } => "terminal-switch",
                        ReactiveTerminal::Try { .. } => "terminal-try",
                        ReactiveTerminal::Return { .. } => "terminal-return",
                        ReactiveTerminal::Break { .. } => "terminal-break",
                        ReactiveTerminal::Continue { .. } => "terminal-continue",
                        ReactiveTerminal::Throw { .. } => "terminal-throw",
                        ReactiveTerminal::DoWhile { .. } => "terminal-do-while",
                        ReactiveTerminal::For { .. } => "terminal-for",
                        ReactiveTerminal::ForOf { .. } => "terminal-for-of",
                        ReactiveTerminal::ForIn { .. } => "terminal-for-in",
                        ReactiveTerminal::While { .. } => "terminal-while",
                        ReactiveTerminal::Label { .. } => "terminal-label",
                    },
                    ReactiveStatement::Scope(_) => "scope",
                    ReactiveStatement::PrunedScope(_) => "pruned-scope",
                    ReactiveStatement::Instruction(_) => "instruction",
                };
                eprintln!(
                    "[IF_BREAK_SPACE] stop: non-instruction at cursor={} kind={}",
                    cursor, kind
                );
            }
            return false;
        };
        if reactive_instruction_start_line(instr).is_none() {
            if debug {
                eprintln!("[IF_BREAK_SPACE] skip: no source line at cursor={}", cursor);
            }
            cursor += 1;
            continue;
        }
        saw_source_instruction = true;
        let temp_snapshot = cx.snapshot_temps();
        let next_stmt = codegen_instruction_nullable(cx, instr);
        cx.restore_temps(temp_snapshot);
        let Some(next_stmt) = next_stmt else {
            if debug {
                eprintln!(
                    "[IF_BREAK_SPACE] skip: instruction emitted none at cursor={}",
                    cursor
                );
            }
            cursor += 1;
            continue;
        };
        let trimmed = next_stmt.trim_start();
        let should_insert = !statement_is_variable_declaration_global(trimmed);
        if debug {
            eprintln!(
                "[IF_BREAK_SPACE] decision: cursor={} stmt={:?} insert={}",
                cursor,
                trimmed.lines().next().unwrap_or(trimmed),
                should_insert
            );
        }
        return should_insert;
    }
    if debug {
        eprintln!("[IF_BREAK_SPACE] stop: end of block");
    }
    false
}

fn branch_has_trailing_labeled_break(branch: &[ReactiveStatement]) -> bool {
    matches!(
        branch.last(),
        Some(ReactiveStatement::Terminal(ReactiveTerminalStatement {
            terminal: ReactiveTerminal::Break {
                target_kind: ReactiveTerminalTargetKind::Labeled,
                ..
            },
            ..
        }))
    )
}

fn labeled_statement_needs_block_wrapper(stmt: &str) -> bool {
    let Some(first_stmt_end) = first_top_level_statement_end(stmt) else {
        return false;
    };
    has_non_trivia_after(stmt, first_stmt_end)
}

fn first_top_level_statement_end(code: &str) -> Option<usize> {
    #[derive(Clone, Copy, PartialEq, Eq)]
    enum ScanState {
        Normal,
        SingleQuote,
        DoubleQuote,
        TemplateQuote,
        LineComment,
        BlockComment,
    }

    let bytes = code.as_bytes();
    let mut i = 0usize;
    let mut paren = 0u32;
    let mut bracket = 0u32;
    let mut brace = 0u32;
    let mut state = ScanState::Normal;
    let mut escaped = false;

    while i < bytes.len() {
        let b = bytes[i];
        match state {
            ScanState::LineComment => {
                if b == b'\n' {
                    state = ScanState::Normal;
                }
                i += 1;
                continue;
            }
            ScanState::BlockComment => {
                if b == b'*' && bytes.get(i + 1) == Some(&b'/') {
                    state = ScanState::Normal;
                    i += 2;
                } else {
                    i += 1;
                }
                continue;
            }
            ScanState::SingleQuote => {
                if escaped {
                    escaped = false;
                } else if b == b'\\' {
                    escaped = true;
                } else if b == b'\'' {
                    state = ScanState::Normal;
                }
                i += 1;
                continue;
            }
            ScanState::DoubleQuote => {
                if escaped {
                    escaped = false;
                } else if b == b'\\' {
                    escaped = true;
                } else if b == b'"' {
                    state = ScanState::Normal;
                }
                i += 1;
                continue;
            }
            ScanState::TemplateQuote => {
                if escaped {
                    escaped = false;
                } else if b == b'\\' {
                    escaped = true;
                } else if b == b'`' {
                    state = ScanState::Normal;
                }
                i += 1;
                continue;
            }
            ScanState::Normal => {}
        }

        if b == b'/' && bytes.get(i + 1) == Some(&b'/') {
            state = ScanState::LineComment;
            i += 2;
            continue;
        }
        if b == b'/' && bytes.get(i + 1) == Some(&b'*') {
            state = ScanState::BlockComment;
            i += 2;
            continue;
        }
        if b == b'\'' {
            state = ScanState::SingleQuote;
            i += 1;
            continue;
        }
        if b == b'"' {
            state = ScanState::DoubleQuote;
            i += 1;
            continue;
        }
        if b == b'`' {
            state = ScanState::TemplateQuote;
            i += 1;
            continue;
        }

        match b {
            b'(' => paren += 1,
            b')' => paren = paren.saturating_sub(1),
            b'[' => bracket += 1,
            b']' => bracket = bracket.saturating_sub(1),
            b'{' => brace += 1,
            b'}' => {
                brace = brace.saturating_sub(1);
                if paren == 0 && bracket == 0 && brace == 0 {
                    let end = i + 1;
                    if let Some(next) = next_non_trivia_index(code, end)
                        && (slice_starts_with_keyword(code, next, "else")
                            || slice_starts_with_keyword(code, next, "catch")
                            || slice_starts_with_keyword(code, next, "finally")
                            || slice_starts_with_keyword(code, next, "while"))
                    {
                        i += 1;
                        continue;
                    }
                    return Some(end);
                }
            }
            b';' => {
                if paren == 0 && bracket == 0 && brace == 0 {
                    return Some(i + 1);
                }
            }
            _ => {}
        }
        i += 1;
    }

    None
}

fn has_non_trivia_after(code: &str, start: usize) -> bool {
    next_non_trivia_index(code, start).is_some()
}

fn next_non_trivia_index(code: &str, start: usize) -> Option<usize> {
    let bytes = code.as_bytes();
    let mut i = start;
    while i < bytes.len() {
        let b = bytes[i];
        if b.is_ascii_whitespace() {
            i += 1;
            continue;
        }
        if b == b'/' && bytes.get(i + 1) == Some(&b'/') {
            i += 2;
            while i < bytes.len() && bytes[i] != b'\n' {
                i += 1;
            }
            continue;
        }
        if b == b'/' && bytes.get(i + 1) == Some(&b'*') {
            i += 2;
            while i + 1 < bytes.len() && !(bytes[i] == b'*' && bytes[i + 1] == b'/') {
                i += 1;
            }
            if i + 1 < bytes.len() {
                i += 2;
            }
            continue;
        }
        return Some(i);
    }
    None
}

fn slice_starts_with_keyword(code: &str, start: usize, kw: &str) -> bool {
    let rest = &code[start..];
    if !rest.starts_with(kw) {
        return false;
    }
    let after = rest[kw.len()..].chars().next();
    after.is_none_or(|ch| !(ch == '_' || ch == '$' || ch.is_ascii_alphanumeric()))
}

fn maybe_emit_reused_optional_dependency_reads(
    cx: &mut Context,
    output: &mut String,
    scope: &ReactiveScope,
    following_stmts: &[ReactiveStatement],
) {
    let mut current_deps: Vec<ReactiveScopeDependency> = scope
        .dependencies
        .iter()
        .map(|dep| truncate_ref_current_dep(dep, &cx.stable_ref_decls))
        .collect();
    sort_scope_dependencies_for_codegen(cx, &mut current_deps);

    let mut seen_current: HashSet<String> = HashSet::new();
    let mut optional_deps: Vec<ReactiveScopeDependency> = Vec::new();
    for dep in current_deps {
        if !dep.path.iter().any(|entry| entry.optional) {
            continue;
        }
        let key = format_dependency_name(&dep);
        if seen_current.insert(key) {
            optional_deps.push(dep);
        }
    }
    if optional_deps.is_empty() {
        return;
    }

    let optional_keys: HashSet<String> = optional_deps.iter().map(format_dependency_name).collect();
    let mut reused_by_later_scope = false;
    for stmt in following_stmts {
        let maybe_scope = match stmt {
            ReactiveStatement::Scope(scope_block) => Some(&scope_block.scope),
            ReactiveStatement::PrunedScope(scope_block) => Some(&scope_block.scope),
            _ => None,
        };
        let Some(next_scope) = maybe_scope else {
            continue;
        };
        if next_scope.dependencies.iter().any(|dep| {
            let dep = truncate_ref_current_dep(dep, &cx.stable_ref_decls);
            optional_keys.contains(&format_dependency_name(&dep))
        }) {
            reused_by_later_scope = true;
            break;
        }
    }
    if !reused_by_later_scope {
        return;
    }

    for dep in optional_deps {
        let dep_expr = codegen_dependency(cx, &dep);
        if rendered_expr_contains_optional_chain(&dep_expr)
            && cx.emitted_optional_dep_reads.insert(dep_expr.clone())
        {
            output.push_str(
                &render_reactive_expression_statement_ast(&dep_expr)
                    .expect("optional dependency read should stay on AST path"),
            );
        }
    }
}

fn maybe_codegen_fused_nullish_self_reassign(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    let first_lvalue = first_instr.lvalue.as_ref()?;
    if first_lvalue.identifier.name.is_none() || !cx.has_declared(&first_lvalue.identifier) {
        return None;
    }
    if matches!(
        first_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    let mut cursor = start + 1;
    let (second_lvalue, right_place) = loop {
        let ReactiveStatement::Instruction(instr) = block.get(cursor)? else {
            return None;
        };
        if let InstructionValue::LogicalExpression {
            operator,
            left,
            right,
            ..
        } = &instr.value
        {
            if *operator != LogicalOperator::NullishCoalescing {
                return None;
            }
            let second_lvalue = instr.lvalue.as_ref()?;
            if left.identifier.declaration_id != first_lvalue.identifier.declaration_id {
                return None;
            }
            break (second_lvalue, right);
        }

        if !is_fusable_inline_temp_instruction(instr)
            || !materialize_fusable_temp_instruction(cx, instr)
        {
            return None;
        }
        cursor += 1;
    };

    let lhs = codegen_instruction_value_ev(cx, &first_instr.value)
        .wrap_if_needed(ExprPrecedence::NullishCoalescing);
    let rhs = codegen_place_with_min_prec(cx, right_place, ExprPrecedence::NullishCoalescing);
    let fused_expr = render_logical_expression_ast(&lhs, LogicalOperator::NullishCoalescing, &rhs)?;

    if first_lvalue.identifier.name.is_none() {
        let ev = ExprValue::new(fused_expr, ExprPrecedence::NullishCoalescing);
        cx.temp
            .insert(first_lvalue.identifier.declaration_id, Some(ev.clone()));
        if second_lvalue.identifier.declaration_id != first_lvalue.identifier.declaration_id {
            cx.temp
                .insert(second_lvalue.identifier.declaration_id, Some(ev));
        }
    } else {
        let name = identifier_name_with_cx(cx, &first_lvalue.identifier);
        if cx.has_declared(&first_lvalue.identifier) {
            output.push_str(&render_reactive_assignment_statement_ast(
                &name,
                &fused_expr,
            )?);
        } else {
            cx.declare(&first_lvalue.identifier);
            output.push_str(&render_reactive_variable_statement_ast(
                ast::VariableDeclarationKind::Const,
                &name,
                Some(&fused_expr),
            )?);
        }
        if second_lvalue.identifier.id != first_lvalue.identifier.id {
            cx.set_temp_expr(&second_lvalue.identifier, Some(ExprValue::primary(name)));
        }
    }

    Some(cursor - start + 1)
}

fn split_top_level_statement_chunks_global(code: &str) -> Option<Vec<String>> {
    let mut chunks = Vec::new();
    let mut start = 0usize;
    let mut paren_depth = 0usize;
    let mut bracket_depth = 0usize;
    let mut brace_depth = 0usize;
    let mut in_single_quote = false;
    let mut in_double_quote = false;
    let mut escape = false;
    let mut line_comment = false;
    let mut block_comment = false;
    let mut template_stack: Vec<usize> = Vec::new();
    let mut chars = code.char_indices().peekable();

    while let Some((idx, ch)) = chars.next() {
        if line_comment {
            if ch == '\n' {
                line_comment = false;
            }
            continue;
        }

        if block_comment {
            if ch == '*' && chars.peek().is_some_and(|(_, next)| *next == '/') {
                chars.next();
                block_comment = false;
            }
            continue;
        }

        if in_single_quote {
            if escape {
                escape = false;
            } else if ch == '\\' {
                escape = true;
            } else if ch == '\'' {
                in_single_quote = false;
            }
            continue;
        }

        if in_double_quote {
            if escape {
                escape = false;
            } else if ch == '\\' {
                escape = true;
            } else if ch == '"' {
                in_double_quote = false;
            }
            continue;
        }

        if let Some(template_expr_depth) = template_stack.last_mut() {
            if *template_expr_depth == 0 {
                if escape {
                    escape = false;
                    continue;
                }
                match ch {
                    '\\' => escape = true,
                    '`' => {
                        template_stack.pop();
                    }
                    '$' if chars.peek().is_some_and(|(_, next)| *next == '{') => {
                        chars.next();
                        *template_expr_depth = 1;
                    }
                    _ => {}
                }
                continue;
            }

            match ch {
                '/' if chars.peek().is_some_and(|(_, next)| *next == '/') => {
                    chars.next();
                    line_comment = true;
                }
                '/' if chars.peek().is_some_and(|(_, next)| *next == '*') => {
                    chars.next();
                    block_comment = true;
                }
                '\'' => in_single_quote = true,
                '"' => in_double_quote = true,
                '`' => template_stack.push(0),
                '{' => *template_expr_depth += 1,
                '}' => {
                    *template_expr_depth = template_expr_depth.saturating_sub(1);
                }
                _ => {}
            }
            continue;
        }

        match ch {
            '/' if chars.peek().is_some_and(|(_, next)| *next == '/') => {
                chars.next();
                line_comment = true;
            }
            '/' if chars.peek().is_some_and(|(_, next)| *next == '*') => {
                chars.next();
                block_comment = true;
            }
            '\'' => in_single_quote = true,
            '"' => in_double_quote = true,
            '`' => template_stack.push(0),
            '(' => paren_depth += 1,
            ')' => paren_depth = paren_depth.saturating_sub(1),
            '[' => bracket_depth += 1,
            ']' => bracket_depth = bracket_depth.saturating_sub(1),
            '{' => brace_depth += 1,
            '}' => brace_depth = brace_depth.saturating_sub(1),
            ';' if paren_depth == 0 && bracket_depth == 0 && brace_depth == 0 => {
                let chunk = code[start..=idx].trim();
                if !chunk.is_empty() {
                    chunks.push(chunk.to_string());
                }
                start = idx + 1;
            }
            _ => {}
        }
    }

    if in_single_quote
        || in_double_quote
        || line_comment
        || block_comment
        || !template_stack.is_empty()
        || paren_depth != 0
        || bracket_depth != 0
        || brace_depth != 0
    {
        return None;
    }

    if !code[start..].trim().is_empty() {
        return None;
    }

    if chunks.is_empty() {
        None
    } else {
        Some(chunks)
    }
}

fn statement_is_variable_declaration_global(stmt: &str) -> bool {
    let allocator = Allocator::default();
    matches!(
        parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            stmt.trim(),
        ),
        Ok(ast::Statement::VariableDeclaration(_))
    )
}

fn assignment_expression_rhs_global(expr: &str) -> Option<String> {
    let allocator = Allocator::default();
    let expression = parse_rendered_expression_ast(&allocator, expr)?;
    let ast::Expression::AssignmentExpression(assignment) = expression.without_parentheses() else {
        return None;
    };
    if assignment.operator != AssignmentOperator::Assign {
        return None;
    }
    Some(codegen_expression_with_flow_cast_restore(&assignment.right))
}

fn extract_simple_expression_statement_global(stmt: &str) -> Option<String> {
    let chunks = split_top_level_statement_chunks_global(stmt)?;
    let [chunk] = chunks.as_slice() else {
        return None;
    };
    let allocator = Allocator::default();
    let statement =
        parse_single_statement_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), chunk)
            .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    Some(codegen_expression_with_flow_cast_restore(
        &expression_statement.expression,
    ))
}

fn extract_initializer_rhs_global(stmt: &str) -> Option<String> {
    let chunks = split_top_level_statement_chunks_global(stmt)?;
    let [chunk] = chunks.as_slice() else {
        return None;
    };
    let allocator = Allocator::default();
    let statement =
        parse_single_statement_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), chunk)
            .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if declaration.declarations.len() != 1 {
        return None;
    }
    let declarator = declaration.declarations.first()?;
    let init = declarator.init.as_ref()?;
    Some(codegen_expression_with_flow_cast_restore(init))
}

fn normalize_fusion_match_text(text: &str) -> String {
    let mut normalized = String::with_capacity(text.len());
    let mut prev_was_whitespace = false;

    for ch in text.chars() {
        if ch.is_whitespace() {
            if !prev_was_whitespace {
                normalized.push(' ');
                prev_was_whitespace = true;
            }
        } else {
            normalized.push(ch);
            prev_was_whitespace = false;
        }
    }

    normalized.trim().to_string()
}

fn contains_all_bridge_exprs_normalized(text: &str, bridge_exprs: &[String]) -> bool {
    let normalized_text = normalize_fusion_match_text(text);
    bridge_exprs.iter().all(|bridge_expr| {
        let normalized_expr = normalize_fusion_match_text(bridge_expr);
        normalized_text.contains(&normalized_expr)
    })
}

fn is_assignment_like_sequence_expr_global(expr: &str) -> bool {
    fn is_assignment_like(expression: &ast::Expression<'_>) -> bool {
        match expression {
            ast::Expression::AssignmentExpression(_) => true,
            ast::Expression::ParenthesizedExpression(parenthesized) => {
                is_assignment_like(&parenthesized.expression)
            }
            _ => false,
        }
    }

    let allocator = Allocator::default();
    parse_rendered_expression_ast(&allocator, expr)
        .as_ref()
        .is_some_and(is_assignment_like)
}

fn wrap_sequence_expr_item_global(expr: &str) -> String {
    let trimmed = expr.trim();
    if is_assignment_like_sequence_expr_global(trimmed)
        && !(trimmed.starts_with('(') && trimmed.ends_with(')'))
    {
        format!("({trimmed})")
    } else {
        trimmed.to_string()
    }
}

fn parse_uninitialized_declaration_name(line: &str) -> Option<String> {
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if declaration.declarations.len() != 1 {
        return None;
    }
    let declarator = declaration.declarations.first()?;
    if declarator.init.is_some() {
        return None;
    }
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    Some(identifier.name.to_string())
}

fn parse_named_const_assignment_line(line: &str) -> Option<(String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if declaration.kind != ast::VariableDeclarationKind::Const
        || declaration.declarations.len() != 1
    {
        return None;
    }
    let declarator = declaration.declarations.first()?;
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    let init = declarator.init.as_ref()?;
    Some((
        indent,
        identifier.name.to_string(),
        codegen_expression_with_flow_cast_restore(init),
    ))
}

fn parse_named_temp_binding_line(line: &str) -> Option<(String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if !matches!(
        declaration.kind,
        ast::VariableDeclarationKind::Const | ast::VariableDeclarationKind::Let
    ) || declaration.declarations.len() != 1
    {
        return None;
    }
    let declarator = declaration.declarations.first()?;
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    let init = declarator.init.as_ref()?;
    Some((
        indent,
        identifier.name.to_string(),
        codegen_expression_with_flow_cast_restore(init),
    ))
}

fn parse_assignment_statement_line(line: &str) -> Option<(String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    let ast::Expression::AssignmentExpression(assignment) =
        expression_statement.expression.without_parentheses()
    else {
        return None;
    };
    if assignment.operator != AssignmentOperator::Assign {
        return None;
    }
    let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) = &assignment.left else {
        return None;
    };
    Some((
        indent,
        identifier.name.to_string(),
        codegen_expression_with_flow_cast_restore(&assignment.right),
    ))
}

fn parse_assignment_statement_source_line(line: &str) -> Option<(String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    let ast::Expression::AssignmentExpression(assignment) =
        expression_statement.expression.without_parentheses()
    else {
        return None;
    };
    if assignment.operator != AssignmentOperator::Assign {
        return None;
    }
    Some((
        indent,
        codegen_assignment_target_with_flow_cast_restore(&assignment.left),
        codegen_expression_with_flow_cast_restore(&assignment.right),
    ))
}

fn parse_computed_member_assignment_line(line: &str) -> Option<(String, String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    let ast::Expression::AssignmentExpression(assignment) =
        expression_statement.expression.without_parentheses()
    else {
        return None;
    };
    if assignment.operator != AssignmentOperator::Assign {
        return None;
    }
    let ast::AssignmentTarget::ComputedMemberExpression(member) = &assignment.left else {
        return None;
    };
    Some((
        indent,
        codegen_expression_with_flow_cast_restore(&member.object),
        codegen_expression_with_flow_cast_restore(&member.expression),
        codegen_expression_with_flow_cast_restore(&assignment.right),
    ))
}

fn parse_ternary_statement_line(line: &str) -> Option<(String, String, String, String)> {
    let indent_len = line.len().saturating_sub(line.trim_start().len());
    let indent = line[..indent_len].to_string();
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        line.trim(),
    )
    .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    let ast::Expression::ConditionalExpression(conditional) =
        expression_statement.expression.without_parentheses()
    else {
        return None;
    };
    Some((
        indent,
        codegen_expression_with_flow_cast_restore(&conditional.test),
        codegen_expression_with_flow_cast_restore(&conditional.consequent),
        codegen_expression_with_flow_cast_restore(&conditional.alternate),
    ))
}

fn rewrite_named_test_reassign_ternary_in_scope_computation(computation: &str) -> String {
    let had_trailing_newline = computation.ends_with('\n');
    let lines: Vec<String> = computation
        .trim_end_matches('\n')
        .split('\n')
        .map(|line| line.to_string())
        .collect();
    if lines.is_empty() {
        return computation.to_string();
    }

    let mut out: Vec<String> = Vec::with_capacity(lines.len());
    let mut i = 0usize;
    while i < lines.len() {
        if i + 3 < lines.len()
            && let Some((indent, test_name, test_expr)) =
                parse_named_const_assignment_line(&lines[i])
            && is_codegen_temp_name(&test_name)
            && let Some((_, temp_name, consequent_expr)) =
                parse_assignment_statement_line(&lines[i + 1])
            && is_codegen_temp_name(&temp_name)
            && let Some((_, assign_target, assign_rhs)) =
                parse_assignment_statement_line(&lines[i + 2])
            && let Some((_, ternary_test, ternary_consequent, ternary_alternate)) =
                parse_ternary_statement_line(&lines[i + 3])
            && ternary_test == test_name
            && ternary_consequent == temp_name
            && contains_identifier_token(&ternary_alternate, &assign_target)
            && rendered_expr_is_empty_array_literal(&assign_rhs)
            && rendered_expr_root_identifier_name(&test_expr).as_deref() == Some("props")
            && rendered_expr_contains_assignment_to_target(&consequent_expr, &assign_target, "[]")
            && rendered_expr_contains_push_call_on_target(&consequent_expr, &assign_target)
            && rendered_expr_contains_push_call_on_target(&ternary_alternate, &assign_target)
            && i > 0
            && rendered_statement_is_push_call_on_target(&lines[i - 1], &assign_target)
        {
            let assign_expr = render_assignment_expression_ast(&assign_target, &assign_rhs)
                .expect("prop push ternary assignment should stay on AST path");
            let alternate_expr = render_sequence_expression_ast(&[assign_expr], &ternary_alternate)
                .expect("prop push ternary alternate should stay on AST path");
            let rewritten_expr =
                render_conditional_expression_ast(&test_expr, &consequent_expr, &alternate_expr)
                    .expect("prop push ternary should stay on AST path");
            out.push(
                render_indented_expression_statement_ast(&indent, &rewritten_expr)
                    .expect("prop push ternary statement should stay on AST path")
                    .trim_end_matches('\n')
                    .to_string(),
            );
            i += 4;
            continue;
        }
        out.push(lines[i].clone());
        i += 1;
    }

    let mut rewritten = out.join("\n");
    if had_trailing_newline {
        rewritten.push('\n');
    }
    rewritten
}

fn rendered_expr_is_array_reset_literal(expr: &str) -> bool {
    if rendered_expr_is_empty_array_literal(expr) {
        return true;
    }

    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    matches!(
        expression.without_parentheses(),
        ast::Expression::ArrayExpression(array)
            if array.elements.len() == 1
                && matches!(
                    array.elements.first(),
                    Some(ast::ArrayExpressionElement::ArrayExpression(inner))
                        if inner.elements.is_empty()
                )
    )
}

fn rewrite_named_test_sequence_ternary_in_scope_computation(computation: &str) -> String {
    let had_trailing_newline = computation.ends_with('\n');
    let mut lines: Vec<String> = computation
        .trim_end_matches('\n')
        .split('\n')
        .map(|line| line.to_string())
        .collect();
    if lines.is_empty() {
        return computation.to_string();
    }

    let mut keep = vec![true; lines.len()];
    for ternary_idx in 0..lines.len() {
        let Some((indent, ternary_test, ternary_consequent, ternary_alternate)) =
            parse_ternary_statement_line(&lines[ternary_idx])
        else {
            continue;
        };
        if !is_codegen_temp_name(&ternary_test) {
            continue;
        }

        let mut binding: Option<(usize, String)> = None;
        for idx in (0..ternary_idx).rev() {
            if !keep[idx] {
                continue;
            }
            if let Some((binding_indent, binding_name, binding_expr)) =
                parse_named_const_assignment_line(&lines[idx])
                && binding_indent == indent
                && binding_name == ternary_test
            {
                binding = Some((idx, binding_expr));
                break;
            }
            if contains_identifier_token(&lines[idx], &ternary_test) {
                break;
            }
        }
        let Some((binding_idx, test_expr)) = binding else {
            continue;
        };

        if ternary_idx >= 3
            && keep[ternary_idx - 3]
            && keep[ternary_idx - 2]
            && keep[ternary_idx - 1]
            && let Some((assign1_indent, assign1_target, assign1_rhs)) =
                parse_assignment_statement_source_line(&lines[ternary_idx - 3])
            && assign1_indent == indent
            && rendered_expr_is_array_reset_literal(&assign1_rhs)
            && let Some((binding_indent, binding_name, consequent_expr)) =
                parse_named_temp_binding_line(&lines[ternary_idx - 2])
            && binding_indent == indent
            && is_codegen_temp_name(&binding_name)
            && let Some((assign2_indent, assign2_target, assign2_rhs)) =
                parse_assignment_statement_source_line(&lines[ternary_idx - 1])
            && assign2_indent == indent
            && rendered_expr_is_array_reset_literal(&assign2_rhs)
            && ternary_consequent == binding_name
        {
            let assign1_names =
                collect_identifier_tokens_from_generated_expression(&assign1_target);
            let assign2_names =
                collect_identifier_tokens_from_generated_expression(&assign2_target);
            let same_targets = !assign1_names.is_empty()
                && !assign2_names.is_empty()
                && assign1_names == assign2_names;
            let test_uses_target = assign1_names
                .iter()
                .any(|target| contains_identifier_token(&test_expr, target));
            let consequent_uses_target = assign1_names
                .iter()
                .any(|target| contains_identifier_token(&consequent_expr, target));
            let alternate_uses_target = assign2_names
                .iter()
                .any(|target| contains_identifier_token(&ternary_alternate, target));
            if same_targets && !test_uses_target && consequent_uses_target && alternate_uses_target
            {
                let assign1_expr = lines[ternary_idx - 3]
                    .trim()
                    .trim_end_matches(';')
                    .to_string();
                let assign2_expr = lines[ternary_idx - 1]
                    .trim()
                    .trim_end_matches(';')
                    .to_string();
                if let Some(consequent_branch) = render_sequence_expression_ast(
                    std::slice::from_ref(&assign1_expr),
                    &consequent_expr,
                ) && let Some(alternate_branch) = render_sequence_expression_ast(
                    std::slice::from_ref(&assign2_expr),
                    &ternary_alternate,
                ) && let Some(rewritten_expr) = render_conditional_expression_ast(
                    &test_expr,
                    &consequent_branch,
                    &alternate_branch,
                ) && let Some(statement) =
                    render_indented_expression_statement_ast(&indent, &rewritten_expr)
                {
                    keep[binding_idx] = false;
                    keep[ternary_idx - 3] = false;
                    keep[ternary_idx - 2] = false;
                    keep[ternary_idx - 1] = false;
                    lines[ternary_idx] = statement.trim_end_matches('\n').to_string();
                    continue;
                }
            }
        }

        if ternary_idx >= 1
            && keep[ternary_idx - 1]
            && let Some((assign_indent, assign_target, assign_rhs)) =
                parse_assignment_statement_source_line(&lines[ternary_idx - 1])
            && assign_indent == indent
            && rendered_expr_is_array_reset_literal(&assign_rhs)
        {
            let assign_target_names =
                collect_identifier_tokens_from_generated_expression(&assign_target);
            let test_uses_target = assign_target_names
                .iter()
                .any(|target| contains_identifier_token(&test_expr, target));
            let consequent_uses_target = assign_target_names
                .iter()
                .any(|target| contains_identifier_token(&ternary_consequent, target));
            let alternate_uses_target = assign_target_names
                .iter()
                .any(|target| contains_identifier_token(&ternary_alternate, target));
            let non_sequence_branch = if consequent_uses_target && !alternate_uses_target {
                Some(&ternary_alternate)
            } else if alternate_uses_target && !consequent_uses_target {
                Some(&ternary_consequent)
            } else {
                None
            };
            if !assign_target_names.is_empty()
                && !test_uses_target
                && non_sequence_branch
                    .is_some_and(|branch| is_inlineable_primitive_literal_expression(branch.trim()))
            {
                let assign_expr = lines[ternary_idx - 1]
                    .trim()
                    .trim_end_matches(';')
                    .to_string();
                let consequent = if consequent_uses_target {
                    let Some(expr) = render_sequence_expression_ast(
                        std::slice::from_ref(&assign_expr),
                        &ternary_consequent,
                    ) else {
                        continue;
                    };
                    expr
                } else {
                    ternary_consequent
                };
                let alternate = if alternate_uses_target {
                    let Some(expr) = render_sequence_expression_ast(
                        std::slice::from_ref(&assign_expr),
                        &ternary_alternate,
                    ) else {
                        continue;
                    };
                    expr
                } else {
                    ternary_alternate
                };
                if let Some(rewritten_expr) =
                    render_conditional_expression_ast(&test_expr, &consequent, &alternate)
                    && let Some(statement) =
                        render_indented_expression_statement_ast(&indent, &rewritten_expr)
                {
                    keep[binding_idx] = false;
                    keep[ternary_idx - 1] = false;
                    lines[ternary_idx] = statement.trim_end_matches('\n').to_string();
                }
            }
        }
    }

    let mut rewritten = lines
        .into_iter()
        .zip(keep)
        .filter_map(|(line, keep)| keep.then_some(line))
        .collect::<Vec<_>>()
        .join("\n");
    if had_trailing_newline {
        rewritten.push('\n');
    }
    rewritten
}

fn rewrite_named_temp_ternary_in_scope_computation(computation: &str) -> String {
    let had_trailing_newline = computation.ends_with('\n');
    let lines: Vec<String> = computation
        .trim_end_matches('\n')
        .split('\n')
        .map(|line| line.to_string())
        .collect();
    if lines.is_empty() {
        return computation.to_string();
    }

    let mut out: Vec<String> = Vec::with_capacity(lines.len());
    let mut i = 0usize;
    while i < lines.len() {
        let Some((indent, first_name, first_expr)) = parse_named_temp_binding_line(&lines[i])
        else {
            out.push(lines[i].clone());
            i += 1;
            continue;
        };
        if !is_codegen_temp_name(&first_name) {
            out.push(lines[i].clone());
            i += 1;
            continue;
        }

        let mut bindings: HashMap<String, String> = HashMap::new();
        bindings.insert(first_name, first_expr);
        let mut j = i + 1;
        while j < lines.len() {
            let Some((next_indent, name, expr)) = parse_named_temp_binding_line(&lines[j]) else {
                break;
            };
            if next_indent != indent || !is_codegen_temp_name(&name) {
                break;
            }
            bindings.insert(name, expr);
            j += 1;
        }

        let Some((ternary_indent, test, consequent, alternate)) = lines
            .get(j)
            .and_then(|line| parse_ternary_statement_line(line))
        else {
            out.push(lines[i].clone());
            i += 1;
            continue;
        };
        if ternary_indent != indent {
            out.push(lines[i].clone());
            i += 1;
            continue;
        }

        let rewritten_test = bindings.get(&test).cloned().unwrap_or_else(|| test.clone());
        let rewritten_consequent = bindings
            .get(&consequent)
            .cloned()
            .unwrap_or_else(|| consequent.clone());
        let rewritten_alternate = bindings
            .get(&alternate)
            .cloned()
            .unwrap_or_else(|| alternate.clone());
        let changed = rewritten_test != test
            || rewritten_consequent != consequent
            || rewritten_alternate != alternate;
        if !changed {
            out.push(lines[i].clone());
            i += 1;
            continue;
        }

        let rewritten_expr = render_conditional_expression_ast(
            &rewritten_test,
            &rewritten_consequent,
            &rewritten_alternate,
        )
        .expect("named temp ternary should stay on AST path");
        out.push(
            render_indented_expression_statement_ast(&indent, &rewritten_expr)
                .expect("named temp ternary statement should stay on AST path")
                .trim_end_matches('\n')
                .to_string(),
        );
        i = j + 1;
    }

    let mut rewritten = out.join("\n");
    if had_trailing_newline {
        rewritten.push('\n');
    }
    rewritten
}

struct DualReassignScopeBranch {
    decl_id: DeclarationId,
    dep_expr: String,
    branch_expr: String,
    reassign_ident: Identifier,
    reassign_name: String,
}

fn parse_dual_reassign_scope_branch(
    cx: &Context,
    scope_block: &ReactiveScopeBlock,
) -> Option<DualReassignScopeBranch> {
    macro_rules! skip {
        ($($arg:tt)*) => {{
            debug_codegen_expr(
                "fused-dual-reassign-branch-parse-skip",
                format!("scope={} {}", scope_block.scope.id.0, format!($($arg)*)),
            );
            return None;
        }};
    }
    if scope_block.scope.dependencies.len() != 1
        || scope_block.scope.reassignments.len() != 1
        || scope_block.scope.declarations.len() != 1
    {
        skip!(
            "shape deps={} reassignments={} decls={}",
            scope_block.scope.dependencies.len(),
            scope_block.scope.reassignments.len(),
            scope_block.scope.declarations.len()
        );
    }

    let decl_ident = &scope_block.scope.declarations.values().next()?.identifier;
    let decl_id = decl_ident.declaration_id;
    let raw_dep = scope_block.scope.dependencies.first()?;
    let dep_for_codegen = truncate_ref_current_dep(raw_dep, &cx.stable_ref_decls);

    let mut probe = cx.clone();
    let dep_expr = codegen_dependency(&mut probe, &dep_for_codegen);
    let reassign_ident = scope_block.scope.reassignments.first()?.clone();
    let reassign_name = identifier_name_with_cx(&mut probe, &reassign_ident);
    if reassign_name.is_empty() {
        skip!("empty-reassign-name");
    }

    let computation = codegen_scope_computation_no_reset(
        &mut probe,
        &scope_block.scope,
        &scope_block.instructions,
    );
    let decl_name = identifier_name_with_cx(&mut probe, decl_ident);
    let mut pre_exprs: Vec<String> = Vec::new();
    let mut decl_rhs: Option<String> = None;
    for line in computation.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if let Some((_, name, rhs)) = parse_named_temp_binding_line(trimmed)
            && name == decl_name
        {
            decl_rhs = Some(rhs);
            continue;
        }
        let Some(expr) = extract_simple_expression_statement_global(trimmed) else {
            skip!("non-expression-line `{}`", trimmed);
        };
        if let Some(rhs) = expr
            .strip_prefix(&format!("{decl_name} = "))
            .map(|rhs| rhs.trim().to_string())
        {
            decl_rhs = Some(rhs);
            continue;
        }
        pre_exprs.push(expr);
    }

    let Some(decl_rhs) = decl_rhs else {
        skip!(
            "missing-decl-assign decl={} computation={:?}",
            decl_name,
            computation
        );
    };
    if pre_exprs
        .iter()
        .any(|expr| !expr.trim_start().starts_with(&format!("{reassign_name} =")))
    {
        skip!(
            "unexpected-prefix pre_exprs={:?} target={} computation={:?}",
            pre_exprs,
            reassign_name,
            computation
        );
    }

    let seq_items: Vec<String> = pre_exprs
        .iter()
        .map(|expr| wrap_sequence_expr_item_global(expr))
        .collect();
    let final_expr = decl_rhs;
    let branch_expr = if seq_items.is_empty() {
        final_expr
    } else {
        render_sequence_expression_ast(&seq_items, &final_expr)
            .expect("dual reassign branch should stay on AST path")
    };
    if !contains_identifier_token(&branch_expr, &reassign_name) {
        skip!(
            "branch-missing-target branch={} target={}",
            branch_expr,
            reassign_name
        );
    }

    Some(DualReassignScopeBranch {
        decl_id,
        dep_expr,
        branch_expr,
        reassign_ident,
        reassign_name,
    })
}

fn maybe_codegen_fused_named_test_dual_reassign_scope_ternary_return(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    macro_rules! skip {
        ($($arg:tt)*) => {{
            debug_codegen_expr(
                "fused-named-test-dual-reassign-scope-ternary-return-skip",
                format!("start={} {}", start, format!($($arg)*)),
            );
            return None;
        }};
    }

    let ReactiveStatement::Instruction(test_decl_instr) = block.get(start)? else {
        return None;
    };
    let test_decl_lvalue = test_decl_instr.lvalue.as_ref()?;
    let test_name = identifier_name_static(&test_decl_lvalue.identifier);
    if !is_codegen_temp_name(&test_name) || cx.has_declared(&test_decl_lvalue.identifier) {
        skip!(
            "bad-test-decl name={} declared={}",
            test_name,
            cx.has_declared(&test_decl_lvalue.identifier)
        );
    }

    let ReactiveStatement::Scope(first_scope) = block.get(start + 1)? else {
        skip!("next-not-scope");
    };
    let ReactiveStatement::Scope(second_scope) = block.get(start + 2)? else {
        skip!("next2-not-scope");
    };
    let ReactiveStatement::Instruction(ternary_instr) = block.get(start + 3)? else {
        skip!("next3-not-instruction");
    };
    if ternary_instr.lvalue.is_some() {
        skip!("ternary-has-lvalue");
    }
    let InstructionValue::Ternary {
        test,
        consequent,
        alternate,
        ..
    } = &ternary_instr.value
    else {
        skip!("next3-not-ternary");
    };
    if test.identifier.declaration_id != test_decl_lvalue.identifier.declaration_id {
        skip!(
            "test-decl-mismatch ternary={} test_decl={}",
            test.identifier.declaration_id.0,
            test_decl_lvalue.identifier.declaration_id.0
        );
    }

    let Some(first) = parse_dual_reassign_scope_branch(cx, first_scope) else {
        skip!("first-scope-parse-failed");
    };
    let Some(second) = parse_dual_reassign_scope_branch(cx, second_scope) else {
        skip!("second-scope-parse-failed");
    };
    if first.reassign_ident.declaration_id != second.reassign_ident.declaration_id
        || first.reassign_name != second.reassign_name
    {
        skip!(
            "reassign-target-mismatch first={} second={}",
            first.reassign_name,
            second.reassign_name
        );
    }

    let (consequent_branch, alternate_branch) = if consequent.identifier.declaration_id
        == first.decl_id
        && alternate.identifier.declaration_id == second.decl_id
    {
        (&first, &second)
    } else if consequent.identifier.declaration_id == second.decl_id
        && alternate.identifier.declaration_id == first.decl_id
    {
        (&second, &first)
    } else {
        skip!(
            "branch-decl-mismatch cons={} alt={} first={} second={}",
            consequent.identifier.declaration_id.0,
            alternate.identifier.declaration_id.0,
            first.decl_id.0,
            second.decl_id.0
        );
    };

    let mut cursor = start + 4;
    let mut return_decl = first.reassign_ident.declaration_id;
    let mut bridged_return_decls: Vec<DeclarationId> = Vec::new();
    loop {
        let Some(stmt) = block.get(cursor) else {
            skip!("missing-return-tail");
        };
        match stmt {
            ReactiveStatement::Instruction(instr) if is_ignorable_bridge_interstitial(instr) => {
                if let Some(lvalue) = &instr.lvalue {
                    match &instr.value {
                        InstructionValue::LoadLocal { place, .. }
                        | InstructionValue::LoadContext { place, .. }
                            if place.identifier.declaration_id == return_decl =>
                        {
                            return_decl = lvalue.identifier.declaration_id;
                            bridged_return_decls.push(return_decl);
                        }
                        _ => {}
                    }
                }
                cursor += 1;
            }
            ReactiveStatement::Terminal(term_stmt) => {
                let ReactiveTerminal::Return { value, .. } = &term_stmt.terminal else {
                    skip!("tail-terminal-not-return");
                };
                if value.identifier.declaration_id != return_decl || cursor + 1 != block.len() {
                    skip!(
                        "return-check-failed value_decl={} expected_decl={} tail_remaining={}",
                        value.identifier.declaration_id.0,
                        return_decl.0,
                        block.len().saturating_sub(cursor + 1)
                    );
                }
                break;
            }
            _ => skip!("tail-non-ignorable-stmt"),
        }
    }

    let test_ev = codegen_instruction_value_ev(cx, &test_decl_instr.value);
    let cond_expr = if test_ev.prec <= ExprPrecedence::Assignment {
        format!("({})", test_ev.expr)
    } else {
        test_ev.expr
    };

    let cache_var = cx.synthesize_name("$");
    let alternate_dep_slot = cx.alloc_cache_slot();
    let cond_slot = cx.alloc_cache_slot();
    let consequent_dep_slot = cx.alloc_cache_slot();
    let output_slot = cx.alloc_cache_slot();
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);

    let target_name = first.reassign_name.clone();
    if !cx.has_declared(&first.reassign_ident) {
        let statement = ast::Statement::VariableDeclaration(builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Let,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.binding_pattern_binding_identifier(SPAN, builder.ident(&target_name)),
                NONE,
                None,
                false,
            )),
            false,
        ));
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
        cx.mark_decl_runtime_emitted(first.reassign_ident.declaration_id);
    }
    cx.declare(&first.reassign_ident);

    let guard_expr = builder.expression_logical(
        SPAN,
        builder.expression_logical(
            SPAN,
            builder.expression_binary(
                SPAN,
                build_computed_member_expression_ast(
                    builder,
                    &cache_var,
                    builder.expression_numeric_literal(
                        SPAN,
                        alternate_dep_slot as f64,
                        None,
                        NumberBase::Decimal,
                    ),
                ),
                AstBinaryOperator::StrictInequality,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &alternate_branch.dep_expr,
                )
                .ok()?,
            ),
            AstLogicalOperator::Or,
            builder.expression_binary(
                SPAN,
                build_computed_member_expression_ast(
                    builder,
                    &cache_var,
                    builder.expression_numeric_literal(
                        SPAN,
                        cond_slot as f64,
                        None,
                        NumberBase::Decimal,
                    ),
                ),
                AstBinaryOperator::StrictInequality,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &cond_expr,
                )
                .ok()?,
            ),
        ),
        AstLogicalOperator::Or,
        builder.expression_binary(
            SPAN,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    consequent_dep_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
            AstBinaryOperator::StrictInequality,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &consequent_branch.dep_expr,
            )
            .ok()?,
        ),
    );
    let fused_expr = parse_expression_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        &render_conditional_expression_ast(
            &cond_expr,
            &consequent_branch.branch_expr,
            &alternate_branch.branch_expr,
        )?,
    )
    .ok()?;
    let mut consequent = builder.vec1(builder.statement_expression(SPAN, fused_expr));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(
            SPAN,
            alternate_dep_slot as f64,
            None,
            NumberBase::Decimal,
        ),
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &alternate_branch.dep_expr,
        )
        .ok()?,
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, cond_slot as f64, None, NumberBase::Decimal),
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &cond_expr)
            .ok()?,
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(
            SPAN,
            consequent_dep_slot as f64,
            None,
            NumberBase::Decimal,
        ),
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &consequent_branch.dep_expr,
        )
        .ok()?,
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&target_name)),
    ));
    let alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &target_name,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        ),
    ));
    let statement = builder.statement_if(
        SPAN,
        guard_expr,
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));
    for decl_id in bridged_return_decls {
        cx.temp
            .insert(decl_id, Some(ExprValue::primary(target_name.clone())));
    }
    debug_codegen_expr(
        "fused-named-test-dual-reassign-scope-ternary-return",
        format!(
            "target={} cond={} deps=[{},{}]",
            target_name, cond_expr, alternate_branch.dep_expr, consequent_branch.dep_expr
        ),
    );
    Some(cursor - start)
}

fn maybe_codegen_fused_named_test_scope_decl_ternary_statement(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(test_instr) = block.get(start)? else {
        return None;
    };
    let Some(test_lvalue) = &test_instr.lvalue else {
        return None;
    };
    test_lvalue.identifier.name.as_ref()?;
    let test_name = identifier_name_static(&test_lvalue.identifier);
    if !is_codegen_temp_name(&test_name) || cx.has_declared(&test_lvalue.identifier) {
        return None;
    }

    let ReactiveStatement::Scope(scope_block) = block.get(start + 1)? else {
        return None;
    };
    if scope_block.scope.dependencies.len() != 1
        || scope_block.scope.declarations.len() != 1
        || scope_block.scope.reassignments.len() != 1
    {
        return None;
    }
    let scope_decl_id = scope_block
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .declaration_id;

    let ReactiveStatement::Instruction(null_instr) = block.get(start + 2)? else {
        return None;
    };
    let Some(null_lvalue) = &null_instr.lvalue else {
        return None;
    };
    let InstructionValue::Primitive {
        value: PrimitiveValue::Null,
        ..
    } = &null_instr.value
    else {
        return None;
    };

    let ReactiveStatement::Instruction(ternary_instr) = block.get(start + 3)? else {
        return None;
    };
    if ternary_instr.lvalue.is_some() {
        return None;
    }
    let InstructionValue::Ternary {
        test,
        consequent,
        alternate,
        ..
    } = &ternary_instr.value
    else {
        return None;
    };
    if test.identifier.declaration_id != test_lvalue.identifier.declaration_id
        || consequent.identifier.declaration_id != scope_decl_id
        || alternate.identifier.declaration_id != null_lvalue.identifier.declaration_id
    {
        return None;
    }

    // Materialize default statements first so we can safely fall back.
    let test_stmt = codegen_instruction_nullable(cx, test_instr)?;
    let mut scope_stmt = String::new();
    codegen_reactive_scope(
        cx,
        &mut scope_stmt,
        &scope_block.scope,
        &scope_block.instructions,
    );
    let null_stmt = codegen_instruction_nullable(cx, null_instr);
    if codegen_instruction_nullable(cx, ternary_instr).is_none() {
        output.push_str(&test_stmt);
        output.push_str(&scope_stmt);
        if let Some(stmt) = null_stmt {
            output.push_str(&stmt);
        }
        return Some(4);
    }

    let test_ev = codegen_instruction_value_ev(cx, &test_instr.value);
    let cond_expr = if test_ev.prec <= ExprPrecedence::Assignment {
        format!("({})", test_ev.expr)
    } else {
        test_ev.expr
    };

    let mut lines: Vec<&str> = scope_stmt.lines().collect();
    while lines.last().is_some_and(|line| line.trim().is_empty()) {
        lines.pop();
    }
    if lines.len() < 5 {
        return None;
    }

    let decl_line = lines[0].trim();
    let scope_decl_name = parse_uninitialized_declaration_name(decl_line)?;
    let if_line = lines[1].trim();
    let allocator = Allocator::default();
    let if_statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        if_line,
    )
    .ok()?;
    let ast::Statement::IfStatement(if_statement) = if_statement else {
        return None;
    };
    let ast::Expression::BinaryExpression(binary) = if_statement.test.without_parentheses() else {
        return None;
    };
    if binary.operator != AstBinaryOperator::StrictInequality {
        return None;
    }
    let ast::Expression::ComputedMemberExpression(member) = binary.left.without_parentheses()
    else {
        return None;
    };
    let cache_var = codegen_expression_with_flow_cast_restore(&member.object);
    let dep_slot = codegen_expression_with_flow_cast_restore(&member.expression);
    let dep_expr = codegen_expression_with_flow_cast_restore(&binary.right);
    if cache_var.is_empty() || dep_slot.is_empty() || rendered_expr_contains_logical_or(&dep_expr) {
        return None;
    }

    let else_idx = lines.iter().position(|line| line.trim() == "} else {")?;
    let end_idx = lines.iter().rposition(|line| line.trim() == "}")?;
    if else_idx <= 1 || end_idx <= else_idx {
        return None;
    }
    let body_lines = &lines[2..else_idx];
    let else_lines = &lines[else_idx + 1..end_idx];

    let mut pre_exprs: Vec<String> = Vec::new();
    let mut decl_rhs: Option<String> = None;
    let mut decl_slot: Option<String> = None;
    let mut cache_tail_lines: Vec<String> = Vec::new();
    for line in body_lines {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if let Some((_, object, slot, rhs)) = parse_computed_member_assignment_line(trimmed)
            && object == cache_var
        {
            if slot == dep_slot && rhs == dep_expr {
                continue;
            }
            if rhs == scope_decl_name {
                decl_slot = Some(slot);
                continue;
            }
            cache_tail_lines.push(trimmed.to_string());
            continue;
        }
        if let Some((_, name, rhs)) = parse_assignment_statement_line(trimmed)
            && name == scope_decl_name
        {
            decl_rhs = Some(rhs);
            continue;
        }
        let expr = extract_simple_expression_statement_global(trimmed)?;
        pre_exprs.push(expr);
    }

    let decl_rhs = decl_rhs?;
    let decl_slot = decl_slot?;

    let mut else_passthrough: Vec<String> = Vec::new();
    for line in else_lines {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if trimmed == format!("{scope_decl_name} = {cache_var}[{decl_slot}];") {
            continue;
        }
        else_passthrough.push(trimmed.to_string());
    }

    let seq_items: Vec<String> = pre_exprs
        .iter()
        .map(|expr| wrap_sequence_expr_item_global(expr))
        .collect();
    let consequent_expr = if seq_items.is_empty() {
        decl_rhs
    } else {
        render_sequence_expression_ast(&seq_items, &decl_rhs)
            .expect("conditional consequent should stay on AST path")
    };

    let builder = AstBuilder::new(&allocator);
    let mut consequent = builder.vec1(
        builder.statement_expression(
            SPAN,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &render_conditional_expression_ast(&cond_expr, &consequent_expr, "null")?,
            )
            .ok()?,
        ),
    );
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &dep_slot)
            .ok()?,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &cond_expr)
            .ok()?,
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &decl_slot)
            .ok()?,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &dep_expr)
            .ok()?,
    ));
    for line in cache_tail_lines {
        consequent.push(
            parse_single_statement_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &line,
            )
            .ok()?,
        );
    }
    let mut alternate = builder.vec();
    for line in else_passthrough {
        alternate.push(
            parse_single_statement_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &line,
            )
            .ok()?,
        );
    }
    let guard_expr = builder.expression_logical(
        SPAN,
        builder.expression_binary(
            SPAN,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &dep_slot,
                )
                .ok()?,
            ),
            AstBinaryOperator::StrictInequality,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &cond_expr,
            )
            .ok()?,
        ),
        AstLogicalOperator::Or,
        builder.expression_binary(
            SPAN,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &decl_slot,
                )
                .ok()?,
            ),
            AstBinaryOperator::StrictInequality,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &dep_expr,
            )
            .ok()?,
        ),
    );
    let statement = builder.statement_if(
        SPAN,
        guard_expr,
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));
    debug_codegen_expr(
        "fused-named-test-scope-decl-ternary-statement",
        format!(
            "test={} dep_slot={} decl_slot={} dep_expr={}",
            cond_expr, dep_slot, decl_slot, dep_expr
        ),
    );
    Some(4)
}

fn maybe_codegen_fused_named_test_reassign_then_ternary_branch(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    macro_rules! skip {
        ($($arg:tt)*) => {{
            debug_codegen_expr(
                "fused-named-test-reassign-ternary-branch-skip",
                format!("start={} {}", start, format!($($arg)*)),
            );
            return None;
        }};
    }

    let ReactiveStatement::Instruction(test_decl_instr) = block.get(start)? else {
        return None;
    };
    let test_decl_lvalue = test_decl_instr.lvalue.as_ref()?;
    let temp_name = identifier_name_static(&test_decl_lvalue.identifier);
    if !is_codegen_temp_name(&temp_name) {
        skip!("first-not-temp name={}", temp_name);
    }
    let mut probe = cx.clone();
    let mut assign_idx: Option<usize> = None;
    let mut ternary_idx: Option<usize> = None;
    let mut assign_target_idents: Vec<Identifier> = Vec::new();
    let mut ternary_test: Option<Place> = None;
    let mut ternary_consequent: Option<Place> = None;
    let mut ternary_alternate: Option<Place> = None;
    let mut named_bridge_expr_by_decl: HashMap<DeclarationId, String> = HashMap::new();
    let same_assign_targets = |lhs: &[Identifier], rhs: &[Identifier]| -> bool {
        if lhs.len() != rhs.len() {
            return false;
        }
        let mut lhs_ids: Vec<u32> = lhs.iter().map(|ident| ident.declaration_id.0).collect();
        let mut rhs_ids: Vec<u32> = rhs.iter().map(|ident| ident.declaration_id.0).collect();
        lhs_ids.sort_unstable();
        rhs_ids.sort_unstable();
        lhs_ids == rhs_ids
    };

    let mut idx = start + 1;
    while idx < block.len() {
        let ReactiveStatement::Instruction(instr) = &block[idx] else {
            skip!("non-instruction-before-pattern idx={}", idx);
        };
        let is_temp_bridge = instr
            .lvalue
            .as_ref()
            .is_some_and(|lvalue| lvalue.identifier.name.is_none());
        if let Some(lvalue) = &instr.lvalue
            && let Some(name) = lvalue.identifier.name.as_ref().map(IdentifierName::value)
            && is_codegen_temp_name(name)
        {
            let bridge_ev = codegen_instruction_value_ev(&mut probe, &instr.value);
            named_bridge_expr_by_decl.insert(
                lvalue.identifier.declaration_id,
                bridge_ev.wrap_if_needed(ExprPrecedence::Conditional),
            );
            idx += 1;
            continue;
        }

        if instr.lvalue.is_none() {
            let mut reassign_targets: Option<Vec<Identifier>> = None;
            match &instr.value {
                InstructionValue::StoreLocal { lvalue, value, .. }
                | InstructionValue::StoreContext { lvalue, value, .. }
                    if lvalue.kind == InstructionKind::Reassign =>
                {
                    if lvalue.place.identifier.name.is_none() {
                        skip!("candidate-assign-unnamed-target idx={}", idx);
                    }
                    reassign_targets = Some(vec![lvalue.place.identifier.clone()]);
                    let _ = value;
                }
                InstructionValue::Destructure { lvalue, .. }
                    if lvalue.kind == InstructionKind::Reassign =>
                {
                    let mut targets = Vec::new();
                    for operand in pattern_operands(&lvalue.pattern) {
                        if operand.identifier.name.is_some() {
                            targets.push(operand.identifier.clone());
                        }
                    }
                    if targets.is_empty() {
                        skip!("candidate-assign-destructure-no-named-target idx={}", idx);
                    }
                    reassign_targets = Some(targets);
                }
                _ => {}
            }

            if let Some(targets) = reassign_targets {
                if assign_target_idents.is_empty() {
                    assign_target_idents = targets;
                } else if !same_assign_targets(&assign_target_idents, &targets) {
                    skip!(
                        "candidate-assign-target-mismatch idx={} prev={:?} next={:?}",
                        idx,
                        assign_target_idents
                            .iter()
                            .map(|ident| ident.declaration_id.0)
                            .collect::<Vec<_>>(),
                        targets
                            .iter()
                            .map(|ident| ident.declaration_id.0)
                            .collect::<Vec<_>>()
                    );
                } else {
                    assign_target_idents = targets;
                }
                assign_idx = Some(idx);
                idx += 1;
                continue;
            }

            if assign_idx.is_none() {
                skip!(
                    "candidate-assign-not-reassign idx={} value={:?}",
                    idx,
                    instr.value
                );
            }
            let InstructionValue::Ternary {
                test,
                consequent,
                alternate,
                ..
            } = &instr.value
            else {
                skip!("expected-ternary idx={} value={:?}", idx, instr.value);
            };
            if test.identifier.declaration_id != test_decl_lvalue.identifier.declaration_id {
                skip!(
                    "ternary-test-decl-mismatch idx={} test={} expected={}",
                    idx,
                    test.identifier.declaration_id.0,
                    test_decl_lvalue.identifier.declaration_id.0
                );
            }
            ternary_idx = Some(idx);
            ternary_test = Some(test.clone());
            ternary_consequent = Some(consequent.clone());
            ternary_alternate = Some(alternate.clone());
            break;
        }
        if assign_idx.is_none() {
            if is_temp_bridge {
                idx += 1;
                continue;
            }
            skip!(
                "unexpected-before-assign idx={} value={:?}",
                idx,
                instr.value
            );
        }
        if is_temp_bridge {
            idx += 1;
            continue;
        }
        skip!(
            "unexpected-before-ternary idx={} value={:?}",
            idx,
            instr.value
        );
    }

    let assign_idx = assign_idx?;
    let ternary_idx = ternary_idx?;
    if assign_target_idents.is_empty() {
        return None;
    }
    let ternary_test = ternary_test?;
    let ternary_consequent = ternary_consequent?;
    let ternary_alternate = ternary_alternate?;

    // Materialize intermediary temporaries so consequent/alternate places are
    // renderable even when their builder instructions normally emit no output.
    let mut assign_stmt: Option<String> = None;
    for (offset, stmt) in block
        .iter()
        .take(ternary_idx + 1)
        .skip(start + 1)
        .enumerate()
    {
        let bridge_idx = start + 1 + offset;
        let ReactiveStatement::Instruction(instr) = stmt else {
            return None;
        };
        let emitted = codegen_instruction_nullable(&mut probe, instr);
        if let (Some(lvalue), Some(stmt)) = (&instr.lvalue, emitted.as_deref())
            && lvalue.identifier.name.is_some()
            && let Some(rhs) = extract_initializer_rhs_global(stmt)
        {
            named_bridge_expr_by_decl.insert(lvalue.identifier.declaration_id, rhs);
        }
        if bridge_idx == assign_idx {
            assign_stmt = emitted;
        }
    }

    let test_ev = codegen_instruction_value_ev(&mut probe, &test_decl_instr.value);
    let test_expr = if test_ev.prec <= ExprPrecedence::Assignment {
        format!("({})", test_ev.expr)
    } else {
        test_ev.expr
    };
    let assign_expr = extract_simple_expression_statement_global(assign_stmt.as_deref()?)?;
    let assign_target_names: Vec<String> = assign_target_idents
        .iter()
        .map(|ident| identifier_name_with_cx(&mut probe, ident))
        .collect();
    if assign_target_names
        .iter()
        .any(|target| contains_identifier_token(&test_expr, target))
    {
        return None;
    }

    let _ternary_test_expr =
        codegen_place_with_min_prec(&mut probe, &ternary_test, ExprPrecedence::Conditional);
    let mut consequent_expr =
        codegen_place_with_min_prec(&mut probe, &ternary_consequent, ExprPrecedence::Conditional);
    let mut alternate_expr =
        codegen_place_with_min_prec(&mut probe, &ternary_alternate, ExprPrecedence::Conditional);
    if let Some(inlined) =
        named_bridge_expr_by_decl.get(&ternary_consequent.identifier.declaration_id)
    {
        consequent_expr = inlined.clone();
    }
    if let Some(inlined) =
        named_bridge_expr_by_decl.get(&ternary_alternate.identifier.declaration_id)
    {
        alternate_expr = inlined.clone();
    }
    let consequent_uses_target = assign_target_names
        .iter()
        .any(|target| contains_identifier_token(&consequent_expr, target));
    let alternate_uses_target = assign_target_names
        .iter()
        .any(|target| contains_identifier_token(&alternate_expr, target));
    let fused_stmt = if consequent_uses_target != alternate_uses_target {
        let consequent_branch = if consequent_uses_target {
            render_sequence_expression_ast(std::slice::from_ref(&assign_expr), &consequent_expr)
                .expect("fused ternary consequent should stay on AST path")
        } else {
            consequent_expr.clone()
        };
        let alternate_branch = if alternate_uses_target {
            render_sequence_expression_ast(std::slice::from_ref(&assign_expr), &alternate_expr)
                .expect("fused ternary alternate should stay on AST path")
        } else {
            alternate_expr.clone()
        };
        let fused_expr =
            render_conditional_expression_ast(&test_expr, &consequent_branch, &alternate_branch)
                .expect("fused ternary branch should stay on AST path");
        render_reactive_expression_statement_ast(&fused_expr)
            .expect("fused ternary statement should stay on AST path")
    } else if consequent_uses_target && alternate_uses_target {
        let assign_trimmed = assign_expr.trim();
        let consequent_has_assign = consequent_expr.contains(assign_trimmed);
        let alternate_has_assign = alternate_expr.contains(assign_trimmed);
        if consequent_has_assign && !alternate_has_assign {
            let alternate_branch =
                render_sequence_expression_ast(std::slice::from_ref(&assign_expr), &alternate_expr)
                    .expect("fused ternary alternate should stay on AST path");
            let fused_expr =
                render_conditional_expression_ast(&test_expr, &consequent_expr, &alternate_branch)
                    .expect("fused ternary branch should stay on AST path");
            render_reactive_expression_statement_ast(&fused_expr)
                .expect("fused ternary statement should stay on AST path")
        } else if alternate_has_assign && !consequent_has_assign {
            let consequent_branch = render_sequence_expression_ast(
                std::slice::from_ref(&assign_expr),
                &consequent_expr,
            )
            .expect("fused ternary consequent should stay on AST path");
            let fused_expr =
                render_conditional_expression_ast(&test_expr, &consequent_branch, &alternate_expr)
                    .expect("fused ternary branch should stay on AST path");
            render_reactive_expression_statement_ast(&fused_expr)
                .expect("fused ternary statement should stay on AST path")
        } else {
            return None;
        }
    } else {
        return None;
    };
    debug_codegen_expr(
        "fused-named-test-reassign-ternary-branch",
        format!(
            "temp={} targets={:?} test=`{}` assign=`{}` range={}..={}",
            temp_name, assign_target_names, test_expr, assign_expr, assign_idx, ternary_idx
        ),
    );
    output.push_str(&fused_stmt);
    Some(ternary_idx - start + 1)
}

fn maybe_codegen_fused_reassign_then_ternary_branch(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    #[derive(Clone)]
    struct CandidateAssign {
        idx: usize,
        expr: String,
    }

    #[derive(Clone, Copy, PartialEq, Eq)]
    enum BranchKind {
        Consequent,
        Alternate,
    }

    fn collect_named_reassign_targets(instr: &ReactiveInstruction) -> Option<Vec<Identifier>> {
        if instr.lvalue.is_some() {
            return None;
        }
        match &instr.value {
            InstructionValue::StoreLocal { lvalue, .. }
            | InstructionValue::StoreContext { lvalue, .. }
                if lvalue.kind == InstructionKind::Reassign
                    && lvalue.place.identifier.name.is_some() =>
            {
                Some(vec![lvalue.place.identifier.clone()])
            }
            InstructionValue::Destructure { lvalue, .. }
                if lvalue.kind == InstructionKind::Reassign =>
            {
                let targets: Vec<Identifier> = pattern_operands(&lvalue.pattern)
                    .into_iter()
                    .filter(|operand| operand.identifier.name.is_some())
                    .map(|operand| operand.identifier.clone())
                    .collect();
                (!targets.is_empty()).then_some(targets)
            }
            _ => None,
        }
    }

    fn same_target_set(lhs: &[Identifier], rhs: &[Identifier]) -> bool {
        if lhs.len() != rhs.len() {
            return false;
        }
        let mut lhs_ids: Vec<u32> = lhs.iter().map(|ident| ident.declaration_id.0).collect();
        let mut rhs_ids: Vec<u32> = rhs.iter().map(|ident| ident.declaration_id.0).collect();
        lhs_ids.sort_unstable();
        rhs_ids.sort_unstable();
        lhs_ids == rhs_ids
    }

    fn last_assignment_before(
        assignments: &[CandidateAssign],
        lower_bound: usize,
        upper_bound: usize,
    ) -> Option<&CandidateAssign> {
        assignments
            .iter()
            .rev()
            .find(|assign| assign.idx > lower_bound && assign.idx < upper_bound)
    }

    fn maybe_fuse_branch_expr(
        branch_expr: String,
        uses_target: bool,
        assign_expr: Option<&str>,
    ) -> String {
        if !uses_target {
            return branch_expr;
        }
        let Some(assign_expr) = assign_expr else {
            return branch_expr;
        };
        let assign_trimmed = assign_expr.trim();
        if !assign_trimmed.is_empty() && branch_expr.contains(assign_trimmed) {
            branch_expr
        } else {
            render_sequence_expression_ast(&[assign_expr.to_string()], &branch_expr)
                .expect("fused branch sequence should stay on AST path")
        }
    }

    let ReactiveStatement::Instruction(first_assign_instr) = block.get(start)? else {
        return None;
    };
    let target_idents = collect_named_reassign_targets(first_assign_instr)?;
    let mut probe_cx = cx.clone();

    let mut assignments: Vec<CandidateAssign> = Vec::new();
    let mut lvalue_indices: HashMap<DeclarationId, usize> = HashMap::new();
    let mut ternary_idx: Option<usize> = None;
    let mut ternary_operands: Option<(Place, Place, Place)> = None;

    let mut idx = start;
    while idx < block.len() {
        let ReactiveStatement::Instruction(instr) = &block[idx] else {
            return None;
        };

        if instr.lvalue.is_none() {
            if let InstructionValue::Ternary {
                test,
                consequent,
                alternate,
                ..
            } = &instr.value
            {
                ternary_idx = Some(idx);
                ternary_operands = Some((test.clone(), consequent.clone(), alternate.clone()));
                break;
            }

            let targets = collect_named_reassign_targets(instr)?;
            if !same_target_set(&target_idents, &targets) {
                return None;
            }
            let stmt = codegen_instruction_nullable(&mut probe_cx, instr)?;
            let expr = extract_simple_expression_statement_global(&stmt)?;
            assignments.push(CandidateAssign { idx, expr });
            idx += 1;
            continue;
        }

        let lvalue = instr.lvalue.as_ref().expect("checked above");
        lvalue_indices.insert(lvalue.identifier.declaration_id, idx);
        if !is_temp_like_identifier(&probe_cx, &lvalue.identifier) {
            return None;
        }
        if codegen_instruction_nullable(&mut probe_cx, instr).is_some() {
            return None;
        }
        idx += 1;
    }

    let ternary_idx = ternary_idx?;
    let (test, consequent, alternate) = ternary_operands?;

    let target_names: Vec<String> = target_idents
        .iter()
        .map(|ident| identifier_name_with_cx(&mut probe_cx, ident))
        .collect();
    let test_expr = codegen_place_with_min_prec(&mut probe_cx, &test, ExprPrecedence::Conditional);
    if target_names
        .iter()
        .any(|target| contains_identifier_token(&test_expr, target))
    {
        return None;
    }

    let consequent_expr =
        codegen_place_with_min_prec(&mut probe_cx, &consequent, ExprPrecedence::Conditional);
    let alternate_expr =
        codegen_place_with_min_prec(&mut probe_cx, &alternate, ExprPrecedence::Conditional);
    let consequent_uses_target = target_names
        .iter()
        .any(|target| contains_identifier_token(&consequent_expr, target));
    let alternate_uses_target = target_names
        .iter()
        .any(|target| contains_identifier_token(&alternate_expr, target));
    if !consequent_uses_target && !alternate_uses_target {
        return None;
    }

    let consequent_result_idx = lvalue_indices
        .get(&consequent.identifier.declaration_id)
        .copied()
        .unwrap_or(ternary_idx);
    let alternate_result_idx = lvalue_indices
        .get(&alternate.identifier.declaration_id)
        .copied()
        .unwrap_or(ternary_idx);

    let mut branch_ranges = vec![
        (BranchKind::Consequent, consequent_result_idx),
        (BranchKind::Alternate, alternate_result_idx),
    ];
    branch_ranges.sort_by_key(|(_, idx)| *idx);

    let mut lower_bound = start.saturating_sub(1);
    let mut consequent_assign: Option<&str> = None;
    let mut alternate_assign: Option<&str> = None;
    for (branch, result_idx) in branch_ranges {
        let assign = last_assignment_before(&assignments, lower_bound, result_idx)
            .map(|candidate| candidate.expr.as_str());
        match branch {
            BranchKind::Consequent => consequent_assign = assign,
            BranchKind::Alternate => alternate_assign = assign,
        }
        lower_bound = result_idx;
    }

    let fused_consequent = maybe_fuse_branch_expr(
        consequent_expr.clone(),
        consequent_uses_target,
        consequent_assign,
    );
    let fused_alternate = maybe_fuse_branch_expr(
        alternate_expr.clone(),
        alternate_uses_target,
        alternate_assign,
    );
    if fused_consequent == consequent_expr && fused_alternate == alternate_expr {
        return None;
    }

    let fused_stmt =
        render_conditional_expression_ast(&test_expr, &fused_consequent, &fused_alternate)
            .expect("fused ternary branch should stay on AST path");
    debug_codegen_expr(
        "fused-reassign-ternary-branch",
        format!(
            "targets={:?} cons_assign={:?} alt_assign={:?} test=`{}` range={}..={}",
            target_names, consequent_assign, alternate_assign, test_expr, start, ternary_idx
        ),
    );
    output.push_str(
        &render_reactive_expression_statement_ast(&fused_stmt)
            .expect("fused ternary branch should stay on AST path"),
    );
    *cx = probe_cx;
    Some(ternary_idx - start + 1)
}

fn maybe_codegen_fused_reassign_temp_load_then_ternary(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(store_instr) = block.get(start)? else {
        return None;
    };
    let temp_lvalue = store_instr.lvalue.as_ref()?;
    if !is_temp_like_identifier(cx, &temp_lvalue.identifier) {
        return None;
    }

    let reassigned_target = match &store_instr.value {
        InstructionValue::StoreLocal { lvalue, .. }
        | InstructionValue::StoreContext { lvalue, .. }
            if lvalue.kind == InstructionKind::Reassign =>
        {
            lvalue.place.identifier.declaration_id
        }
        _ => return None,
    };

    let ReactiveStatement::Instruction(assign_load_instr) = block.get(start + 1)? else {
        return None;
    };
    if assign_load_instr.lvalue.is_some() {
        return None;
    }
    match &assign_load_instr.value {
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. }
            if place.identifier.declaration_id == temp_lvalue.identifier.declaration_id => {}
        _ => return None,
    };

    let mut probe_cx = cx.clone();
    if codegen_instruction_nullable(&mut probe_cx, store_instr).is_some() {
        return None;
    }
    let assign_stmt = codegen_instruction_nullable(&mut probe_cx, assign_load_instr)?;
    let assign_expr = extract_simple_expression_statement_global(&assign_stmt)?;

    let mut idx = start + 2;
    while idx < block.len() {
        let ReactiveStatement::Instruction(instr) = block.get(idx)? else {
            return None;
        };

        if instr.lvalue.is_none()
            && let InstructionValue::Ternary {
                consequent,
                alternate,
                ..
            } = &instr.value
        {
            let uses_reassign_temp = consequent.identifier.declaration_id
                == temp_lvalue.identifier.declaration_id
                || alternate.identifier.declaration_id == temp_lvalue.identifier.declaration_id;
            let uses_reassign_target = consequent.identifier.declaration_id == reassigned_target
                || alternate.identifier.declaration_id == reassigned_target;
            if !uses_reassign_temp && !uses_reassign_target {
                return None;
            }

            let ternary_stmt = codegen_instruction_nullable(&mut probe_cx, instr)?;
            let ternary_expr = extract_simple_expression_statement_global(&ternary_stmt)?;
            if !ternary_expr.contains(assign_expr.trim()) {
                return None;
            }

            debug_codegen_expr(
                "fused-reassign-temp-load-ternary",
                format!(
                    "temp_decl={} target_decl={} range={}..={} assign=`{}`",
                    temp_lvalue.identifier.declaration_id.0,
                    reassigned_target.0,
                    start,
                    idx,
                    assign_expr
                ),
            );
            output.push_str(&ternary_stmt);
            return Some(idx - start + 1);
        }

        if codegen_instruction_nullable(&mut probe_cx, instr).is_some() {
            return None;
        }
        idx += 1;
    }

    None
}

fn maybe_codegen_fused_temp_load_into_following_stmt(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(load_instr) = block.get(start)? else {
        return None;
    };
    if load_instr.lvalue.is_some() {
        return None;
    }
    let source_place = match &load_instr.value {
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            place
        }
        _ => return None,
    };
    let load_start_line = reactive_instruction_start_line(load_instr);
    let requires_same_line_consumer = source_place.identifier.name.is_some();

    let mut probe_cx = cx.clone();
    let temp_stmt = codegen_instruction_nullable(&mut probe_cx, load_instr)?;
    let mut bridge_exprs = vec![extract_simple_expression_statement_global(&temp_stmt)?];

    // Flattened value-block lowering can push the real consumer statement far
    // beyond the immediate bridge loads (for example nested logical/ternary
    // chains that only materialize at a later named store/destructure). Keep
    // scanning until the first emitted statement instead of bailing out after
    // an arbitrary short window.
    for idx in (start + 1)..block.len() {
        return match block.get(idx)? {
            ReactiveStatement::Instruction(instr) => {
                let Some(stmt) = codegen_instruction_nullable(&mut probe_cx, instr) else {
                    continue;
                };

                let is_bridge_stmt = instr.lvalue.is_none()
                    && matches!(
                        &instr.value,
                        InstructionValue::LoadLocal { place, .. }
                            | InstructionValue::LoadContext { place, .. }
                            if place.identifier.name.is_none()
                    );
                if is_bridge_stmt
                    && let Some(expr) = extract_simple_expression_statement_global(&stmt)
                {
                    bridge_exprs.push(expr);
                    continue;
                }

                let contains_all_bridge_exprs = extract_simple_expression_statement_global(&stmt)
                    .is_some_and(|expr| contains_all_bridge_exprs_normalized(&expr, &bridge_exprs))
                    || extract_initializer_rhs_global(&stmt).is_some_and(|rhs| {
                        contains_all_bridge_exprs_normalized(&rhs, &bridge_exprs)
                    });
                if !contains_all_bridge_exprs {
                    return None;
                }
                if requires_same_line_consumer
                    && load_start_line != reactive_instruction_start_line(instr)
                {
                    return None;
                }

                debug_codegen_expr(
                    "fused-temp-load-following-stmt",
                    format!(
                        "temp_decl={} range={}..={} exprs={:?}",
                        source_place.identifier.declaration_id.0, start, idx, bridge_exprs
                    ),
                );
                output.push_str(&stmt);
                *cx = probe_cx;
                Some(idx - start + 1)
            }
            ReactiveStatement::Terminal(term_stmt) => {
                let stmt = codegen_terminal(&mut probe_cx, &term_stmt.terminal)?;
                let contains_all_bridge_exprs =
                    contains_all_bridge_exprs_normalized(&stmt, &bridge_exprs);
                if !contains_all_bridge_exprs {
                    return None;
                }
                if requires_same_line_consumer
                    && load_start_line != reactive_terminal_start_line(&term_stmt.terminal)
                {
                    return None;
                }

                debug_codegen_expr(
                    "fused-temp-load-following-terminal",
                    format!(
                        "temp_decl={} range={}..={} exprs={:?}",
                        source_place.identifier.declaration_id.0, start, idx, bridge_exprs
                    ),
                );
                append_rendered_terminal_statement(output, term_stmt, &stmt);
                *cx = probe_cx;
                Some(idx - start + 1)
            }
            ReactiveStatement::Scope(_) | ReactiveStatement::PrunedScope(_) => None,
        };
    }

    None
}

fn maybe_codegen_fused_reassign_stmt_into_following_logical(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    if first_instr.lvalue.is_some() {
        return None;
    }
    let (target_ident, value_place) = match &first_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. }
            if lvalue.kind == InstructionKind::Reassign
                && lvalue.place.identifier.name.is_some() =>
        {
            (&lvalue.place.identifier, value)
        }
        _ => return None,
    };
    if value_place.identifier.name.is_some() {
        return None;
    }
    let start_line = reactive_instruction_start_line(first_instr);
    let mut probe_cx = cx.clone();
    let assign_stmt = codegen_instruction_nullable(&mut probe_cx, first_instr)?;
    let assign_expr = extract_simple_expression_statement_global(&assign_stmt)?;
    let assign_rhs = assignment_expression_rhs_global(&assign_expr)?;
    let mut bridge_exprs: Vec<String> = Vec::new();

    for idx in (start + 1)..block.len() {
        return match block.get(idx)? {
            ReactiveStatement::Instruction(instr) => {
                let Some(stmt) = codegen_instruction_nullable(&mut probe_cx, instr) else {
                    continue;
                };
                let is_bridge_stmt = instr.lvalue.is_none()
                    && matches!(
                        &instr.value,
                        InstructionValue::LoadLocal { place, .. }
                            | InstructionValue::LoadContext { place, .. }
                            if place.identifier.name.is_none()
                    );
                if is_bridge_stmt
                    && let Some(expr) = extract_simple_expression_statement_global(&stmt)
                {
                    bridge_exprs.push(expr);
                    continue;
                }

                let InstructionValue::LogicalExpression {
                    operator,
                    left,
                    right,
                    ..
                } = &instr.value
                else {
                    return None;
                };
                if instr.lvalue.is_some() || start_line != reactive_instruction_start_line(instr) {
                    return None;
                }
                if !extract_simple_expression_statement_global(&stmt)
                    .is_some_and(|expr| contains_all_bridge_exprs_normalized(&expr, &bridge_exprs))
                {
                    return None;
                }
                let logical_prec = logical_operator_precedence(operator);
                let left_expr = codegen_logical_operand(&mut probe_cx, left, logical_prec);
                let right_expr = codegen_logical_operand(&mut probe_cx, right, logical_prec);
                let combined_expr = if normalize_fusion_match_text(&right_expr) == "null" {
                    if normalize_fusion_match_text(&assign_rhs)
                        == normalize_fusion_match_text(&left_expr)
                    {
                        render_logical_expression_ast(&assign_expr, *operator, "null")
                            .expect("fused logical reassign should stay on AST path")
                    } else {
                        let sequenced_null = render_sequence_expression_ast(
                            std::slice::from_ref(&assign_expr),
                            "null",
                        )
                        .expect("fused logical null sequence should stay on AST path");
                        render_logical_expression_ast(&left_expr, *operator, &sequenced_null)
                            .expect("fused logical reassign should stay on AST path")
                    }
                } else {
                    let combined_left = render_sequence_expression_ast(
                        std::slice::from_ref(&assign_expr),
                        &left_expr,
                    )
                    .expect("fused logical left sequence should stay on AST path");
                    render_logical_expression_ast(&combined_left, *operator, &right_expr)
                        .expect("fused logical reassign should stay on AST path")
                };
                debug_codegen_expr(
                    "fused-reassign-following-logical",
                    format!(
                        "target={} range={}..={} bridges={:?}",
                        identifier_name_with_cx(&mut probe_cx, target_ident),
                        start,
                        idx,
                        bridge_exprs
                    ),
                );
                output.push_str(
                    &render_reactive_expression_statement_ast(&combined_expr)
                        .expect("fused logical reassign should stay on AST path"),
                );
                *cx = probe_cx;
                Some(idx - start + 1)
            }
            ReactiveStatement::Terminal(_) => None,
            ReactiveStatement::Scope(_) | ReactiveStatement::PrunedScope(_) => None,
        };
    }

    None
}

fn maybe_codegen_fused_reassign_stmt_into_following_null(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    if first_instr.lvalue.is_some() {
        return None;
    }
    match &first_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. }
            if lvalue.kind == InstructionKind::Reassign
                && lvalue.place.identifier.name.is_some()
                && value.identifier.name.is_none() => {}
        _ => return None,
    }
    let ReactiveStatement::Instruction(null_instr) = block.get(start + 1)? else {
        return None;
    };
    if null_instr.lvalue.is_some()
        || !matches!(
            null_instr.value,
            InstructionValue::Primitive {
                value: PrimitiveValue::Null,
                ..
            }
        )
    {
        return None;
    }

    let stmt = codegen_instruction_nullable(cx, first_instr)?;
    output.push_str(&stmt);
    if !stmt.ends_with('\n') {
        output.push('\n');
    }
    debug_codegen_expr(
        "fused-reassign-following-null",
        format!("start={start} target-only"),
    );
    Some(2)
}

fn maybe_codegen_fused_pruned_scope_prefix_into_following_stmt(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let debug_pruned_fusion = std::env::var("DEBUG_PRUNED_FUSION").is_ok();
    let ReactiveStatement::PrunedScope(pruned) = block.get(start)? else {
        return None;
    };
    let ReactiveStatement::Instruction(next_instr) = block.get(start + 1)? else {
        return None;
    };

    let mut probe_cx = cx.clone();
    let inner = codegen_block_no_reset(&mut probe_cx, &pruned.instructions);
    let next_stmt = codegen_instruction_nullable(&mut probe_cx, next_instr)?;
    let next_stmt_expr = extract_simple_expression_statement_global(&next_stmt);
    let next_stmt_rhs = extract_initializer_rhs_global(&next_stmt);
    let next_stmt_contains_all = |bridge_exprs: &[String]| {
        next_stmt_expr
            .as_ref()
            .is_some_and(|expr| contains_all_bridge_exprs_normalized(expr, bridge_exprs))
            || next_stmt_rhs
                .as_ref()
                .is_some_and(|rhs| contains_all_bridge_exprs_normalized(rhs, bridge_exprs))
    };
    let Some(chunks) = split_top_level_statement_chunks_global(&inner) else {
        if debug_pruned_fusion {
            eprintln!(
                "[PRUNED_FUSION] start={} no-chunks inner={:?}",
                start, inner
            );
        }
        return None;
    };
    let mut split_idx = chunks.len();
    let mut bridge_exprs = Vec::new();
    while split_idx > 0 {
        let Some(expr) = extract_simple_expression_statement_global(&chunks[split_idx - 1]) else {
            break;
        };
        let mut candidate = vec![expr];
        candidate.extend(bridge_exprs.iter().cloned());
        if !next_stmt_contains_all(&candidate) {
            break;
        }
        bridge_exprs = candidate;
        split_idx -= 1;
    }
    if bridge_exprs.is_empty() {
        if debug_pruned_fusion {
            eprintln!(
                "[PRUNED_FUSION] start={} no-subsumed-bridge inner={:?} next_stmt={:?} next_expr={:?} next_rhs={:?}",
                start, inner, next_stmt, next_stmt_expr, next_stmt_rhs
            );
        }
        return None;
    }
    let mut prefix_code = String::new();
    for chunk in &chunks[..split_idx] {
        prefix_code.push_str(chunk);
        if !prefix_code.ends_with('\n') {
            prefix_code.push('\n');
        }
    }
    let contains_all_bridge_exprs = next_stmt_contains_all(&bridge_exprs);
    if debug_pruned_fusion {
        eprintln!(
            "[PRUNED_FUSION] start={} bridge_exprs={:?} next_stmt={:?} next_expr={:?} next_rhs={:?} contains={}",
            start,
            bridge_exprs,
            next_stmt,
            next_stmt_expr,
            next_stmt_rhs,
            contains_all_bridge_exprs
        );
    }
    if !contains_all_bridge_exprs {
        return None;
    }

    debug_codegen_expr(
        "fused-pruned-scope-prefix-following-stmt",
        format!(
            "start={} prefix_lines={} exprs={:?}",
            start,
            prefix_code.lines().count(),
            bridge_exprs
                .iter()
                .map(|expr| expr.trim().to_string())
                .collect::<Vec<_>>()
        ),
    );
    output.push_str(&prefix_code);
    output.push_str(&next_stmt);
    *cx = probe_cx;
    Some(2)
}

fn maybe_codegen_fused_named_temp_logical_expression(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    let first_lvalue = first_instr.lvalue.as_ref()?;
    let first_name = first_lvalue.identifier.name.as_ref()?.value();
    if !is_codegen_temp_name(first_name) {
        return None;
    }

    let target_decl = first_lvalue.identifier.declaration_id;
    let mut probe_cx = cx.clone();
    let mut expr_by_identifier: HashMap<IdentifierId, ExprValue> = HashMap::new();
    let mut saw_named_bridge = false;
    let mut idx = start;
    loop {
        let ReactiveStatement::Instruction(instr) = block.get(idx)? else {
            return None;
        };

        if let Some(lvalue) = &instr.lvalue {
            let same_named_target = lvalue.identifier.declaration_id == target_decl
                && lvalue
                    .identifier
                    .name
                    .as_ref()
                    .is_some_and(|name| name.value() == first_name);

            if same_named_target {
                if let InstructionValue::LogicalExpression {
                    operator,
                    left,
                    right,
                    ..
                } = &instr.value
                {
                    if !saw_named_bridge {
                        return None;
                    }
                    let left_ev = expr_by_identifier
                        .get(&left.identifier.id)
                        .cloned()
                        .unwrap_or_else(|| codegen_place_expr_value(&mut probe_cx, left));
                    let right_ev = expr_by_identifier
                        .get(&right.identifier.id)
                        .cloned()
                        .unwrap_or_else(|| codegen_place_expr_value(&mut probe_cx, right));
                    let logical_prec = logical_operator_precedence(operator);
                    let left_expr = codegen_logical_operand_from_expr_value(left_ev, logical_prec);
                    let right_expr =
                        codegen_logical_operand_from_expr_value(right_ev, logical_prec);
                    let target_name = identifier_name_with_cx(&mut probe_cx, &lvalue.identifier);
                    let logical_expr =
                        render_logical_expression_ast(&left_expr, *operator, &right_expr)
                            .expect("fused logical expression should stay on AST path");

                    if has_materialized_named_binding(&probe_cx, &lvalue.identifier) {
                        output.push_str(
                            &render_reactive_assignment_statement_ast(&target_name, &logical_expr)
                                .expect("fused logical assignment should stay on AST path"),
                        );
                    } else {
                        probe_cx.declare(&lvalue.identifier);
                        probe_cx.mark_decl_runtime_emitted(lvalue.identifier.declaration_id);
                        output.push_str(
                            &render_reactive_variable_statement_ast(
                                ast::VariableDeclarationKind::Const,
                                &target_name,
                                Some(&logical_expr),
                            )
                            .expect("fused logical declaration should stay on AST path"),
                        );
                    }
                    probe_cx.set_temp_expr(&lvalue.identifier, None);
                    *cx = probe_cx;
                    return Some(idx - start + 1);
                }

                let rhs_ev = codegen_instruction_value_ev(&mut probe_cx, &instr.value);
                expr_by_identifier.insert(lvalue.identifier.id, rhs_ev);
                saw_named_bridge = true;
                idx += 1;
                continue;
            }
        }

        if reactive_instruction_uses_declaration(instr, target_decl) {
            return None;
        }

        let emitted = codegen_instruction_nullable(&mut probe_cx, instr);
        if emitted
            .as_deref()
            .is_some_and(|stmt| !stmt.trim().is_empty())
        {
            return None;
        }
        idx += 1;
    }
}

fn maybe_codegen_fused_named_temp_ternary_statement(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    let first_lvalue = first_instr.lvalue.as_ref()?;
    let first_name = first_lvalue.identifier.name.as_ref()?.value();
    if !is_codegen_temp_name(first_name)
        || has_materialized_named_binding(cx, &first_lvalue.identifier)
    {
        return None;
    }

    let mut probe_cx = cx.clone();
    let mut inlined_decls: Vec<DeclarationId> = Vec::new();
    let mut inlined_names: Vec<String> = Vec::new();
    let mut idx = start;
    loop {
        let ReactiveStatement::Instruction(instr) = block.get(idx)? else {
            return None;
        };

        if let Some(lvalue) = &instr.lvalue
            && let Some(name) = lvalue.identifier.name.as_ref().map(IdentifierName::value)
            && is_codegen_temp_name(name)
            && !has_materialized_named_binding(&probe_cx, &lvalue.identifier)
        {
            let ev = codegen_instruction_value_ev(&mut probe_cx, &instr.value);
            probe_cx.set_temp_expr(&lvalue.identifier, Some(ev));
            inlined_decls.push(lvalue.identifier.declaration_id);
            inlined_names.push(name.to_string());
            idx += 1;
            continue;
        }

        let InstructionValue::Ternary {
            test,
            consequent,
            alternate,
            ..
        } = &instr.value
        else {
            let emitted = codegen_instruction_nullable(&mut probe_cx, instr);
            if emitted
                .as_deref()
                .is_some_and(|stmt| !stmt.trim().is_empty())
            {
                return None;
            }
            idx += 1;
            continue;
        };
        if instr.lvalue.is_some() {
            return None;
        }

        let uses_inlined_decl = [test, consequent, alternate]
            .iter()
            .any(|place| inlined_decls.contains(&place.identifier.declaration_id));
        if !uses_inlined_decl {
            return None;
        }
        if inlined_decls.iter().any(|decl_id| {
            reactive_block_uses_declaration(&block[idx + 1..], *decl_id)
                || reactive_block_writes_declaration(&block[idx + 1..], *decl_id)
        }) {
            return None;
        }

        let stmt = codegen_instruction_nullable(&mut probe_cx, instr)?;
        if inlined_names
            .iter()
            .any(|name| contains_identifier_token(&stmt, name))
        {
            return None;
        }
        debug_codegen_expr(
            "fused-named-temp-ternary-statement",
            format!("start={} end={} decls={:?}", start, idx, inlined_names),
        );
        output.push_str(&stmt);
        *cx = probe_cx;
        return Some(idx - start + 1);
    }
}

fn maybe_codegen_fused_method_call_eval_order(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    macro_rules! skip {
        ($($arg:tt)*) => {{
            debug_codegen_expr(
                "fused-method-call-eval-order-skip",
                format!("start={} {}", start, format!($($arg)*)),
            );
            return None;
        }};
    }

    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    if !is_eval_order_fusion_participant(first_instr) {
        return None;
    }
    if start > 0
        && let ReactiveStatement::Instruction(prev_instr) = &block[start - 1]
        && is_eval_order_fusion_participant(prev_instr)
    {
        return None;
    }

    let Some(participants) = collect_eval_order_fusion_participants(block, start) else {
        skip!("collect-participants-failed");
    };
    if participants.len() <= 1 {
        skip!("participants-too-short len={}", participants.len());
    }
    let final_idx = participants.len() - 1;
    let final_instr = participants[final_idx].instr;
    let InstructionValue::MethodCall {
        receiver,
        property,
        args,
        receiver_optional,
        call_optional,
        ..
    } = &final_instr.value
    else {
        skip!("final-not-method-call kind={:?}", final_instr.value);
    };
    if final_instr.lvalue.is_some() {
        skip!("final-has-lvalue");
    }

    let has_prefix_side_effect = participants[..final_idx]
        .iter()
        .any(|entry| is_side_effect_call_instruction(entry.instr));
    if !has_prefix_side_effect {
        skip!("no-prefix-side-effect");
    }

    let mut def_idx_by_decl: HashMap<DeclarationId, usize> = HashMap::new();
    for (idx, entry) in participants[..final_idx].iter().enumerate() {
        let instr = entry.instr;
        if let Some(lvalue) = &instr.lvalue {
            def_idx_by_decl.insert(lvalue.identifier.declaration_id, idx);
        }
    }

    let Some(receiver_def_idx) = def_idx_by_decl
        .get(&receiver.identifier.declaration_id)
        .copied()
    else {
        skip!(
            "missing-receiver-def decl={}",
            receiver.identifier.declaration_id.0
        );
    };
    let Some(property_def_idx) = def_idx_by_decl
        .get(&property.identifier.declaration_id)
        .copied()
    else {
        skip!(
            "missing-property-def decl={}",
            property.identifier.declaration_id.0
        );
    };
    let mut arg_def_indices = Vec::with_capacity(args.len());
    for arg in args {
        let decl_id = match arg {
            Argument::Place(place) | Argument::Spread(place) => place.identifier.declaration_id,
        };
        let Some(arg_def_idx) = def_idx_by_decl.get(&decl_id).copied() else {
            skip!("missing-arg-def decl={}", decl_id.0);
        };
        arg_def_indices.push(arg_def_idx);
    }

    let mut ordered_defs = Vec::with_capacity(2 + arg_def_indices.len());
    ordered_defs.push(receiver_def_idx);
    ordered_defs.push(property_def_idx);
    ordered_defs.extend(arg_def_indices.iter().copied());
    if !ordered_defs.windows(2).all(|pair| pair[0] <= pair[1]) {
        skip!("unordered-defs={:?}", ordered_defs);
    }

    let collect_prefix_side_effect_indices = |from: usize, to: usize| -> Option<Vec<usize>> {
        let participants = participants.get(from..to)?;
        let mut indices = Vec::new();
        for (offset, participant) in participants.iter().enumerate() {
            let idx = from + offset;
            let instr = participant.instr;
            if is_side_effect_call_instruction(instr) {
                indices.push(idx);
            } else if instr.lvalue.is_some()
                || is_ignorable_eval_order_fusion_temp_declaration(instr)
                || is_ignorable_eval_order_fusion_interstitial(instr)
            {
                continue;
            } else {
                return None;
            }
        }
        Some(indices)
    };

    let Some(receiver_prefix_indices) = collect_prefix_side_effect_indices(start, receiver_def_idx)
    else {
        skip!("collect-receiver-prefix-failed");
    };
    let Some(property_prefix_indices) =
        collect_prefix_side_effect_indices(receiver_def_idx + 1, property_def_idx)
    else {
        skip!("collect-property-prefix-failed");
    };

    let mut arg_prefix_indices = vec![Vec::new(); args.len()];
    let mut range_start = property_def_idx + 1;
    for (arg_idx, arg_def_idx) in arg_def_indices.iter().enumerate() {
        let Some(collected) = collect_prefix_side_effect_indices(range_start, *arg_def_idx) else {
            skip!("collect-arg-prefix-failed arg_idx={}", arg_idx);
        };
        arg_prefix_indices[arg_idx] = collected;
        range_start = *arg_def_idx + 1;
    }

    let Some(trailing_prefix_indices) = collect_prefix_side_effect_indices(range_start, final_idx)
    else {
        skip!("collect-trailing-prefix-failed");
    };
    if !trailing_prefix_indices.is_empty() {
        skip!("trailing-prefix-not-empty {:?}", trailing_prefix_indices);
    }

    // When only receiver-prefix side effects exist, emitting comma-sequence receiver
    // expressions (e.g. `(x.push(a), x).push(b)`) diverges from upstream, which keeps
    // these as separate statements. Let default emission handle this case.
    if !receiver_prefix_indices.is_empty()
        && property_prefix_indices.is_empty()
        && arg_prefix_indices.iter().all(Vec::is_empty)
    {
        skip!("receiver-only-prefixes");
    }

    if receiver_prefix_indices.is_empty()
        && property_prefix_indices.is_empty()
        && arg_prefix_indices.iter().all(Vec::is_empty)
    {
        skip!("no-prefixes");
    }

    let consumed_top_level = participants[final_idx].top_level_idx - start + 1;
    let tail_start = start + consumed_top_level;
    for idx in 0..final_idx {
        let instr = participants[idx].instr;
        if is_ignorable_eval_order_fusion_temp_declaration(instr) {
            if can_ignore_eval_order_fusion_temp_declaration(block, tail_start, &participants, idx)
            {
                continue;
            }
            skip!(
                "non-droppable-ignorable-temp idx={} value={:?}",
                idx,
                instr.value
            );
        }
        if instr.lvalue.is_none() {
            continue;
        }
        if materialize_fusable_temp_instruction(cx, instr) {
            continue;
        }
        skip!(
            "cannot-materialize idx={} value={:?} lvalue={:?}",
            idx,
            instr.value,
            instr.lvalue
        );
    }

    let recv_prefix_exprs = render_side_effect_prefix_exprs_from_participants(
        cx,
        &participants,
        &receiver_prefix_indices,
    )?;
    let recv_base = codegen_place_to_expression(cx, receiver);
    let mut recv = recv_base.clone();
    recv = wrap_sequence_expr(&recv_prefix_exprs, recv);

    let property_prefix_exprs = render_side_effect_prefix_exprs_from_participants(
        cx,
        &participants,
        &property_prefix_indices,
    )?;
    let (resolved_prop, resolved_is_computed) = resolve_method_property(cx, property, &recv_base);

    let mut rendered_args = Vec::with_capacity(args.len());
    for (arg_idx, arg) in args.iter().enumerate() {
        let prefix_exprs = render_side_effect_prefix_exprs_from_participants(
            cx,
            &participants,
            &arg_prefix_indices[arg_idx],
        )?;
        let arg_expr = codegen_argument(cx, arg);
        rendered_args.push(wrap_sequence_expr(&prefix_exprs, arg_expr));
    }

    let (is_computed, prop, hook_name_owned) = if !property_prefix_indices.is_empty() {
        let property_tail = if resolved_is_computed {
            resolved_prop.clone()
        } else {
            format!("\"{}\"", escape_string(&resolved_prop))
        };
        let property_sequence_expr = wrap_sequence_expr(&property_prefix_exprs, property_tail);
        let hook = if resolved_is_computed {
            None
        } else {
            Some(resolved_prop.clone())
        };
        (true, property_sequence_expr, hook)
    } else {
        // Resolve static-vs-computed against the original receiver expression.
        // `recv` may be sequence-wrapped (e.g. `(console.log("A"), x)`), and
        // using that string here can incorrectly force computed form (`[x.f]`).
        if resolved_is_computed {
            (true, resolved_prop, None)
        } else {
            let hook = resolved_prop.clone();
            (false, resolved_prop, Some(hook))
        }
    };
    let hook_name = hook_name_owned.as_deref();

    maybe_replace_autodeps_with_inferred_deps(
        cx,
        hook_name.unwrap_or(""),
        args,
        &mut rendered_args,
        hook_name.is_some(),
    );
    let call_expr = render_method_call_expression_with_options_ast(
        &recv,
        &prop,
        args,
        &rendered_args,
        is_computed,
        *receiver_optional,
        *call_optional,
    )
    .expect("fused method call should stay on AST path");
    let call_expr = if cx.emit_hook_guards && hook_name.is_some_and(Environment::is_hook_name) {
        guard_hook_call_expression(cx, call_expr)
    } else {
        call_expr
    };

    debug_codegen_expr(
        "fused-method-call-eval-order",
        format!(
            "start={} end={} recv_prefix={} prop_prefix={} arg_prefixes={:?} consumed_top_level={}",
            start,
            final_idx,
            receiver_prefix_indices.len(),
            property_prefix_indices.len(),
            arg_prefix_indices.iter().map(Vec::len).collect::<Vec<_>>(),
            consumed_top_level
        ),
    );
    output.push_str(
        &render_reactive_expression_statement_ast(&call_expr)
            .expect("fused method call should stay on AST path"),
    );
    Some(consumed_top_level)
}

struct EvalOrderFusionParticipant<'a> {
    instr: &'a ReactiveInstruction,
    top_level_idx: usize,
}

fn collect_eval_order_fusion_participants(
    block: &'_ [ReactiveStatement],
    start: usize,
) -> Option<Vec<EvalOrderFusionParticipant<'_>>> {
    let mut participants = Vec::new();
    let mut top_level_idx = start;
    while top_level_idx < block.len() {
        match &block[top_level_idx] {
            ReactiveStatement::Instruction(instr) => {
                if !is_eval_order_fusion_participant(instr)
                    && !is_ignorable_eval_order_fusion_temp_declaration(instr)
                    && !is_ignorable_eval_order_fusion_interstitial(instr)
                {
                    break;
                }
                participants.push(EvalOrderFusionParticipant {
                    instr,
                    top_level_idx,
                });
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                let mut accepted_any = false;
                for stmt in &scope_block.instructions {
                    let ReactiveStatement::Instruction(instr) = stmt else {
                        debug_codegen_expr(
                            "fused-method-call-eval-order-skip",
                            format!(
                                "start={} pruned-scope-non-instruction top_idx={}",
                                start, top_level_idx
                            ),
                        );
                        return None;
                    };
                    if is_eval_order_fusion_participant(instr)
                        || is_ignorable_eval_order_fusion_temp_declaration(instr)
                        || is_ignorable_eval_order_fusion_interstitial(instr)
                    {
                        participants.push(EvalOrderFusionParticipant {
                            instr,
                            top_level_idx,
                        });
                        accepted_any = true;
                        continue;
                    }
                    debug_codegen_expr(
                        "fused-method-call-eval-order-skip",
                        format!(
                            "start={} pruned-scope-reject top_idx={} value={:?} lvalue={:?}",
                            start, top_level_idx, instr.value, instr.lvalue
                        ),
                    );
                    return None;
                }
                if !accepted_any {
                    break;
                }
            }
            _ => break,
        }
        top_level_idx += 1;
    }
    Some(participants)
}

fn is_ignorable_eval_order_fusion_temp_declaration(instr: &ReactiveInstruction) -> bool {
    match &instr.value {
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => is_fusable_temp_lvalue(&lvalue.place),
        _ => false,
    }
}

fn is_ignorable_eval_order_fusion_interstitial(instr: &ReactiveInstruction) -> bool {
    if instr.lvalue.is_some() {
        return false;
    }
    match &instr.value {
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            is_fusable_temp_lvalue(place)
        }
        _ => false,
    }
}

fn can_ignore_eval_order_fusion_temp_declaration(
    block: &[ReactiveStatement],
    tail_start: usize,
    participants: &[EvalOrderFusionParticipant<'_>],
    idx: usize,
) -> bool {
    let instr = participants[idx].instr;
    let decl_id = match &instr.value {
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => lvalue.place.identifier.declaration_id,
        _ => {
            return false;
        }
    };
    if reactive_instruction_writes_declaration(instr, decl_id)
        && reactive_instruction_uses_declaration(instr, decl_id)
    {
        // Ignore self-use checks for declaration instructions themselves.
    } else if reactive_instruction_uses_declaration(instr, decl_id) {
        return false;
    }
    for entry in &participants[idx + 1..] {
        if reactive_instruction_uses_declaration(entry.instr, decl_id) {
            return false;
        }
    }
    !reactive_block_uses_declaration(&block[tail_start..], decl_id)
}

fn is_side_effect_call_instruction(instr: &ReactiveInstruction) -> bool {
    instr.lvalue.is_none()
        && matches!(
            instr.value,
            InstructionValue::CallExpression { .. } | InstructionValue::MethodCall { .. }
        )
}

fn is_eval_order_fusion_participant(instr: &ReactiveInstruction) -> bool {
    if instr.lvalue.is_some() {
        is_fusable_inline_temp_instruction(instr)
    } else {
        is_side_effect_call_instruction(instr)
    }
}

fn render_sequence_expression_ast(prefix_exprs: &[String], final_expr: &str) -> Option<String> {
    if prefix_exprs.is_empty() {
        return Some(final_expr.to_string());
    }
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut expressions = builder.vec();
    for expr in prefix_exprs {
        expressions.push(parse_rendered_expression_ast(&allocator, expr)?);
    }
    expressions.push(parse_rendered_expression_ast(&allocator, final_expr)?);
    let sequence = builder.expression_sequence(SPAN, expressions);
    Some(format!("({})", codegen_expression_with_oxc(&sequence)))
}

fn wrap_sequence_expr(prefix_exprs: &[String], final_expr: String) -> String {
    if prefix_exprs.is_empty() {
        return final_expr;
    }
    render_sequence_expression_ast(prefix_exprs, &final_expr)
        .expect("generated sequence expression should parse")
}

fn render_side_effect_prefix_exprs_from_participants(
    cx: &mut Context,
    participants: &[EvalOrderFusionParticipant<'_>],
    indices: &[usize],
) -> Option<Vec<String>> {
    let mut exprs = Vec::with_capacity(indices.len());
    for idx in indices {
        let instr = participants.get(*idx)?.instr;
        if !is_side_effect_call_instruction(instr) {
            return None;
        }
        exprs.push(codegen_instruction_value_ev(cx, &instr.value).expr);
    }
    Some(exprs)
}

fn maybe_codegen_fused_method_call_destructure_assignment(
    cx: &mut Context,
    block: &[ReactiveStatement],
    start: usize,
    output: &mut String,
) -> Option<usize> {
    let ReactiveStatement::Instruction(first_instr) = block.get(start)? else {
        return None;
    };
    let first_lvalue = first_instr.lvalue.as_ref()?;
    if !is_fusable_temp_lvalue(first_lvalue) {
        return None;
    }
    if !matches!(
        first_instr.value,
        InstructionValue::LoadLocal { .. } | InstructionValue::LoadContext { .. }
    ) {
        return None;
    }

    let mut temp_instr_indices = vec![start];
    let mut destructure_pattern: Option<Pattern> = None;
    let mut destructure_value: Option<Place> = None;
    let mut destructure_idx: Option<usize> = None;
    let receiver_alias_decl = first_lvalue.identifier.declaration_id;
    let end_bound = (start + 8).min(block.len().saturating_sub(1));

    for idx in (start + 1)..=end_bound {
        let ReactiveStatement::Instruction(instr) = &block[idx] else {
            return None;
        };
        match &instr.value {
            InstructionValue::Destructure { lvalue, value, .. } => {
                if lvalue.kind != InstructionKind::Reassign || destructure_pattern.is_some() {
                    return None;
                }
                if pattern_operands(&lvalue.pattern)
                    .iter()
                    .any(|place| !cx.has_declared(&place.identifier))
                {
                    return None;
                }
                destructure_pattern = Some(lvalue.pattern.clone());
                destructure_value = Some(value.clone());
                destructure_idx = Some(idx);
            }
            InstructionValue::MethodCall {
                receiver,
                property,
                args,
                receiver_optional,
                call_optional,
                ..
            } => {
                if instr.lvalue.is_some() {
                    return None;
                }
                if receiver.identifier.declaration_id != receiver_alias_decl {
                    return None;
                }
                let pattern = destructure_pattern.clone()?;
                let value_place = destructure_value.clone()?;
                if destructure_idx != Some(idx.saturating_sub(1)) {
                    return None;
                }

                let assign_arg_index = args.iter().position(|arg| {
                    matches!(
                        arg,
                        Argument::Place(place)
                            if place.identifier.declaration_id == value_place.identifier.declaration_id
                    )
                })?;

                let mut temp_decl_ids: HashSet<DeclarationId> = HashSet::new();
                for stmt_idx in &temp_instr_indices {
                    if let ReactiveStatement::Instruction(temp_instr) = &block[*stmt_idx]
                        && let Some(lvalue) = &temp_instr.lvalue
                    {
                        temp_decl_ids.insert(lvalue.identifier.declaration_id);
                    }
                }
                temp_decl_ids.insert(value_place.identifier.declaration_id);
                for decl_id in temp_decl_ids {
                    if reactive_block_uses_declaration(&block[idx + 1..], decl_id) {
                        return None;
                    }
                }

                for stmt_idx in &temp_instr_indices {
                    let ReactiveStatement::Instruction(temp_instr) = &block[*stmt_idx] else {
                        return None;
                    };
                    if !materialize_fusable_temp_instruction(cx, temp_instr) {
                        return None;
                    }
                }

                let rhs_expr =
                    codegen_place_with_min_prec(cx, &value_place, ExprPrecedence::Assignment);
                let assignment_expr =
                    render_reactive_pattern_assignment_expression_ast(cx, &pattern, &rhs_expr)
                        .expect("generated pattern assignment expression should parse");

                let recv = codegen_member_object_expression(cx, receiver);
                let (prop, is_computed) = resolve_method_property(cx, property, &recv);
                let mut rendered_args: Vec<String> =
                    args.iter().map(|arg| codegen_argument(cx, arg)).collect();
                rendered_args[assign_arg_index] = assignment_expr;
                let hook_name = if is_computed {
                    None
                } else {
                    Some(prop.as_str())
                };
                maybe_replace_autodeps_with_inferred_deps(
                    cx,
                    hook_name.unwrap_or(""),
                    args,
                    &mut rendered_args,
                    hook_name.is_some(),
                );
                let call_expr = render_method_call_expression_with_options_ast(
                    &recv,
                    &prop,
                    args,
                    &rendered_args,
                    is_computed,
                    *receiver_optional,
                    *call_optional,
                )
                .expect("fused destructure call should stay on AST path");
                let call_expr =
                    if cx.emit_hook_guards && hook_name.is_some_and(Environment::is_hook_name) {
                        guard_hook_call_expression(cx, call_expr)
                    } else {
                        call_expr
                    };

                debug_codegen_expr(
                    "fused-method-call-destructure-arg",
                    format!(
                        "start={} end={} receiver={} property={} arg_index={}",
                        start, idx, recv, prop, assign_arg_index
                    ),
                );
                output.push_str(
                    &render_reactive_expression_statement_ast(&call_expr)
                        .expect("fused destructure call should stay on AST path"),
                );
                return Some(idx - start + 1);
            }
            _ => {
                if !is_fusable_inline_temp_instruction(instr) {
                    return None;
                }
                temp_instr_indices.push(idx);
            }
        }
    }

    None
}

fn materialize_fusable_temp_instruction(cx: &mut Context, instr: &ReactiveInstruction) -> bool {
    if !is_fusable_inline_temp_instruction(instr) {
        return false;
    }
    let Some(lvalue) = &instr.lvalue else {
        return false;
    };
    let ev = codegen_instruction_value_ev(cx, &instr.value);
    if is_temp_like_identifier(cx, &lvalue.identifier) {
        cx.inline_identifier_aliases
            .insert(lvalue.identifier.declaration_id, ev.expr.clone());
    }
    cx.set_temp_expr(&lvalue.identifier, Some(ev));
    true
}

fn maybe_defer_inlineable_ternary_into_following_scope(
    cx: &mut Context,
    instr: &ReactiveInstruction,
    preceding_stmts: &[ReactiveStatement],
    following_stmts: &[ReactiveStatement],
) -> bool {
    if cx.disable_memoization_features {
        return false;
    }
    let Some(lvalue) = &instr.lvalue else {
        return false;
    };
    if !is_fusable_temp_lvalue(lvalue) || !matches!(instr.value, InstructionValue::Ternary { .. }) {
        return false;
    }
    let definitions = collect_instruction_definitions(preceding_stmts);
    if !ternary_branches_include_jsx_value(instr, &definitions) {
        return false;
    }
    let Some(scope_id) = find_following_scope_for_deferred_inline_temp(
        following_stmts,
        lvalue.identifier.declaration_id,
    ) else {
        return false;
    };
    let mut root_deps = collect_root_reactive_dependencies_for_instruction(instr, preceding_stmts);
    if root_deps.is_empty() {
        return false;
    }
    root_deps.sort_by(compare_scope_dependency);
    if !materialize_fusable_temp_instruction(cx, instr) {
        return false;
    }
    cx.scope_dependency_overrides.insert(scope_id, root_deps);
    true
}

fn find_following_scope_for_deferred_inline_temp(
    following_stmts: &[ReactiveStatement],
    decl_id: DeclarationId,
) -> Option<ScopeId> {
    let mut target_scope_idx: Option<usize> = None;
    let mut target_scope_id: Option<ScopeId> = None;

    for (idx, stmt) in following_stmts.iter().enumerate().take(8) {
        match stmt {
            ReactiveStatement::Instruction(instr)
                if can_bridge_deferred_inline_temp_instruction(instr, decl_id) => {}
            ReactiveStatement::Scope(scope_block)
                if scope_block.scope.dependencies.len() == 1
                    && scope_block.scope.reassignments.is_empty()
                    && !scope_block.scope.declarations.is_empty()
                    && scope_declares_jsxish_value(scope_block)
                    && scope_block.scope.dependencies[0].identifier.declaration_id == decl_id =>
            {
                target_scope_idx = Some(idx);
                target_scope_id = Some(scope_block.scope.id);
                break;
            }
            _ => return None,
        }
    }

    let (scope_idx, scope_id) = target_scope_idx.zip(target_scope_id)?;
    if reactive_block_uses_declaration(&following_stmts[scope_idx + 1..], decl_id)
        || reactive_block_writes_declaration(&following_stmts[scope_idx + 1..], decl_id)
    {
        return None;
    }
    Some(scope_id)
}

fn collect_instruction_definitions(
    stmts: &[ReactiveStatement],
) -> HashMap<DeclarationId, &ReactiveInstruction> {
    let mut definitions = HashMap::new();
    for stmt in stmts {
        if let ReactiveStatement::Instruction(instr) = stmt
            && let Some(lvalue) = &instr.lvalue
        {
            definitions.insert(lvalue.identifier.declaration_id, &**instr);
        }
    }
    definitions
}

fn ternary_branches_include_jsx_value(
    instr: &ReactiveInstruction,
    definitions: &HashMap<DeclarationId, &ReactiveInstruction>,
) -> bool {
    let InstructionValue::Ternary {
        consequent,
        alternate,
        ..
    } = &instr.value
    else {
        return false;
    };

    let mut seen_defs = HashSet::new();
    place_resolves_to_jsxish_value(consequent, definitions, &mut seen_defs)
        || place_resolves_to_jsxish_value(alternate, definitions, &mut seen_defs)
}

fn scope_declares_jsxish_value(scope_block: &ReactiveScopeBlock) -> bool {
    let definitions = collect_instruction_definitions(&scope_block.instructions);
    scope_block.scope.declarations.values().any(|decl| {
        let place = Place {
            identifier: decl.identifier.clone(),
            effect: Effect::Read,
            reactive: true,
            loc: SourceLocation::Generated,
        };
        let mut seen_defs = HashSet::new();
        place_resolves_to_jsxish_value(&place, &definitions, &mut seen_defs)
    })
}

fn place_resolves_to_jsxish_value(
    place: &Place,
    definitions: &HashMap<DeclarationId, &ReactiveInstruction>,
    seen_defs: &mut HashSet<DeclarationId>,
) -> bool {
    let Some(def_instr) = definitions.get(&place.identifier.declaration_id).copied() else {
        return false;
    };
    if !seen_defs.insert(place.identifier.declaration_id) {
        return false;
    }
    let result = match &def_instr.value {
        InstructionValue::JsxExpression { .. } | InstructionValue::JsxFragment { .. } => true,
        InstructionValue::LoadLocal { place, .. }
        | InstructionValue::LoadContext { place, .. }
        | InstructionValue::TypeCastExpression { value: place, .. } => {
            place_resolves_to_jsxish_value(place, definitions, seen_defs)
        }
        InstructionValue::Ternary {
            consequent,
            alternate,
            ..
        } => {
            place_resolves_to_jsxish_value(consequent, definitions, seen_defs)
                || place_resolves_to_jsxish_value(alternate, definitions, seen_defs)
        }
        _ => false,
    };
    seen_defs.remove(&place.identifier.declaration_id);
    result
}

fn can_bridge_deferred_inline_temp_instruction(
    instr: &ReactiveInstruction,
    decl_id: DeclarationId,
) -> bool {
    let Some(lvalue) = &instr.lvalue else {
        return false;
    };
    lvalue.identifier.name.is_none()
        && is_fusable_inline_temp_instruction(instr)
        && !reactive_instruction_uses_declaration(instr, decl_id)
        && !reactive_instruction_writes_declaration(instr, decl_id)
}

fn collect_root_reactive_dependencies_for_instruction(
    instr: &ReactiveInstruction,
    preceding_stmts: &[ReactiveStatement],
) -> Vec<ReactiveScopeDependency> {
    let definitions = collect_instruction_definitions(preceding_stmts);

    let mut deps = Vec::new();
    let mut seen_defs = HashSet::new();
    visitors::for_each_instruction_value_operand(&instr.value, |place| {
        collect_root_reactive_dependencies_for_place(
            place,
            &definitions,
            &mut seen_defs,
            &mut deps,
        );
    });
    deps
}

fn collect_root_reactive_dependencies_for_place(
    place: &Place,
    definitions: &HashMap<DeclarationId, &ReactiveInstruction>,
    seen_defs: &mut HashSet<DeclarationId>,
    deps: &mut Vec<ReactiveScopeDependency>,
) {
    if place.reactive && place.identifier.name.is_some() {
        push_unique_scope_dependency(
            deps,
            ReactiveScopeDependency {
                identifier: place.identifier.clone(),
                path: Vec::new(),
            },
        );
        return;
    }

    let Some(def_instr) = definitions.get(&place.identifier.declaration_id).copied() else {
        if place.reactive {
            push_unique_scope_dependency(
                deps,
                ReactiveScopeDependency {
                    identifier: place.identifier.clone(),
                    path: Vec::new(),
                },
            );
        }
        return;
    };

    if !seen_defs.insert(place.identifier.declaration_id) {
        return;
    }
    visitors::for_each_instruction_value_operand(&def_instr.value, |inner| {
        collect_root_reactive_dependencies_for_place(inner, definitions, seen_defs, deps);
    });
    seen_defs.remove(&place.identifier.declaration_id);
}

fn push_unique_scope_dependency(
    deps: &mut Vec<ReactiveScopeDependency>,
    candidate: ReactiveScopeDependency,
) {
    if deps.iter().any(|existing| {
        existing.identifier.declaration_id == candidate.identifier.declaration_id
            && existing.path.len() == candidate.path.len()
            && existing
                .path
                .iter()
                .zip(&candidate.path)
                .all(|(left, right)| {
                    left.property == right.property && left.optional == right.optional
                })
    }) {
        return;
    }
    deps.push(candidate);
}

fn is_fusable_inline_temp_instruction(instr: &ReactiveInstruction) -> bool {
    let Some(lvalue) = &instr.lvalue else {
        return false;
    };
    if !is_fusable_temp_lvalue(lvalue) {
        return false;
    }
    !matches!(
        instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::ObjectMethod { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::MethodCall { .. }
    )
}

fn is_fusable_temp_lvalue(place: &Place) -> bool {
    match place.identifier.name.as_ref() {
        None => true,
        Some(IdentifierName::Named(name)) | Some(IdentifierName::Promoted(name)) => {
            is_codegen_temp_name(name.as_str())
        }
    }
}

fn reactive_block_uses_declaration(
    block: &[ReactiveStatement],
    declaration_id: DeclarationId,
) -> bool {
    for stmt in block {
        if reactive_statement_uses_declaration(stmt, declaration_id) {
            return true;
        }
    }
    false
}

fn reactive_block_writes_declaration(
    block: &[ReactiveStatement],
    declaration_id: DeclarationId,
) -> bool {
    for stmt in block {
        if reactive_statement_writes_declaration(stmt, declaration_id) {
            return true;
        }
    }
    false
}

fn unused_temp_named_load_expression(
    cx: &mut Context,
    following_stmts: &[ReactiveStatement],
    instr: &ReactiveInstruction,
) -> Option<String> {
    let lvalue = instr.lvalue.as_ref()?;
    if lvalue.identifier.name.is_some() {
        return None;
    }
    let place = match &instr.value {
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            place
        }
        _ => return None,
    };
    if place.identifier.name.is_none()
        || !cx
            .reassigned_decls
            .contains(&place.identifier.declaration_id)
        || reactive_block_uses_declaration(following_stmts, lvalue.identifier.declaration_id)
    {
        return None;
    }
    Some(codegen_place_to_expression(cx, place))
}

fn reactive_statement_uses_declaration(
    stmt: &ReactiveStatement,
    declaration_id: DeclarationId,
) -> bool {
    match stmt {
        ReactiveStatement::Instruction(instr) => {
            reactive_instruction_uses_declaration(instr, declaration_id)
        }
        ReactiveStatement::Terminal(term_stmt) => {
            reactive_terminal_uses_declaration(&term_stmt.terminal, declaration_id)
        }
        ReactiveStatement::Scope(scope_block) => {
            reactive_block_uses_declaration(&scope_block.instructions, declaration_id)
        }
        ReactiveStatement::PrunedScope(scope_block) => {
            reactive_block_uses_declaration(&scope_block.instructions, declaration_id)
        }
    }
}

fn reactive_statement_writes_declaration(
    stmt: &ReactiveStatement,
    declaration_id: DeclarationId,
) -> bool {
    match stmt {
        ReactiveStatement::Instruction(instr) => {
            reactive_instruction_writes_declaration(instr, declaration_id)
        }
        ReactiveStatement::Terminal(term_stmt) => {
            reactive_terminal_writes_declaration(&term_stmt.terminal, declaration_id)
        }
        ReactiveStatement::Scope(scope_block) => {
            reactive_block_writes_declaration(&scope_block.instructions, declaration_id)
        }
        ReactiveStatement::PrunedScope(scope_block) => {
            reactive_block_writes_declaration(&scope_block.instructions, declaration_id)
        }
    }
}

fn reactive_instruction_uses_declaration(
    instr: &ReactiveInstruction,
    declaration_id: DeclarationId,
) -> bool {
    if instr
        .lvalue
        .as_ref()
        .is_some_and(|place| place.identifier.declaration_id == declaration_id)
    {
        return true;
    }

    let mut has_operand = false;
    visitors::for_each_instruction_value_operand(&instr.value, |place| {
        if place.identifier.declaration_id == declaration_id {
            has_operand = true;
        }
    });
    if has_operand {
        return true;
    }

    match &instr.value {
        InstructionValue::StoreLocal { lvalue, .. }
        | InstructionValue::StoreContext { lvalue, .. }
        | InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => {
            lvalue.place.identifier.declaration_id == declaration_id
        }
        InstructionValue::Destructure { lvalue, .. } => pattern_operands(&lvalue.pattern)
            .iter()
            .any(|place| place.identifier.declaration_id == declaration_id),
        InstructionValue::PrefixUpdate { lvalue, .. }
        | InstructionValue::PostfixUpdate { lvalue, .. } => {
            lvalue.identifier.declaration_id == declaration_id
        }
        _ => false,
    }
}

fn reactive_instruction_writes_declaration(
    instr: &ReactiveInstruction,
    declaration_id: DeclarationId,
) -> bool {
    if instr
        .lvalue
        .as_ref()
        .is_some_and(|place| place.identifier.declaration_id == declaration_id)
    {
        return true;
    }

    match &instr.value {
        InstructionValue::StoreLocal { lvalue, .. }
        | InstructionValue::StoreContext { lvalue, .. }
        | InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => {
            lvalue.place.identifier.declaration_id == declaration_id
        }
        InstructionValue::Destructure { lvalue, .. } => pattern_operands(&lvalue.pattern)
            .iter()
            .any(|place| place.identifier.declaration_id == declaration_id),
        InstructionValue::PrefixUpdate { lvalue, .. }
        | InstructionValue::PostfixUpdate { lvalue, .. } => {
            lvalue.identifier.declaration_id == declaration_id
        }
        _ => false,
    }
}

fn reactive_terminal_uses_declaration(
    terminal: &ReactiveTerminal,
    declaration_id: DeclarationId,
) -> bool {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => false,
        ReactiveTerminal::Return { value, .. } | ReactiveTerminal::Throw { value, .. } => {
            value.identifier.declaration_id == declaration_id
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            test.identifier.declaration_id == declaration_id
                || reactive_block_uses_declaration(consequent, declaration_id)
                || alternate
                    .as_ref()
                    .is_some_and(|block| reactive_block_uses_declaration(block, declaration_id))
        }
        ReactiveTerminal::Switch { test, cases, .. } => {
            test.identifier.declaration_id == declaration_id
                || cases.iter().any(|case| {
                    case.test
                        .as_ref()
                        .is_some_and(|place| place.identifier.declaration_id == declaration_id)
                        || case.block.as_ref().is_some_and(|block| {
                            reactive_block_uses_declaration(block, declaration_id)
                        })
                })
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            loop_block,
            ..
        } => {
            reactive_block_uses_declaration(init, declaration_id)
                || test.identifier.declaration_id == declaration_id
                || update
                    .as_ref()
                    .is_some_and(|block| reactive_block_uses_declaration(block, declaration_id))
                || reactive_block_uses_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            reactive_block_uses_declaration(init, declaration_id)
                || test.identifier.declaration_id == declaration_id
                || reactive_block_uses_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            reactive_block_uses_declaration(init, declaration_id)
                || reactive_block_uses_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::While {
            test, loop_block, ..
        }
        | ReactiveTerminal::DoWhile {
            test, loop_block, ..
        } => {
            test.identifier.declaration_id == declaration_id
                || reactive_block_uses_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::Label { block, .. } => {
            reactive_block_uses_declaration(block, declaration_id)
        }
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => {
            handler_binding
                .as_ref()
                .is_some_and(|place| place.identifier.declaration_id == declaration_id)
                || reactive_block_uses_declaration(block, declaration_id)
                || reactive_block_uses_declaration(handler, declaration_id)
        }
    }
}

fn reactive_terminal_writes_declaration(
    terminal: &ReactiveTerminal,
    declaration_id: DeclarationId,
) -> bool {
    match terminal {
        ReactiveTerminal::Break { .. } | ReactiveTerminal::Continue { .. } => false,
        ReactiveTerminal::Return { .. } | ReactiveTerminal::Throw { .. } => false,
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            reactive_block_writes_declaration(consequent, declaration_id)
                || alternate
                    .as_ref()
                    .is_some_and(|block| reactive_block_writes_declaration(block, declaration_id))
        }
        ReactiveTerminal::Switch { cases, .. } => cases.iter().any(|case| {
            case.block
                .as_ref()
                .is_some_and(|block| reactive_block_writes_declaration(block, declaration_id))
        }),
        ReactiveTerminal::DoWhile {
            test, loop_block, ..
        } => {
            let _ = test;
            reactive_block_writes_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::While {
            test, loop_block, ..
        } => {
            let _ = test;
            reactive_block_writes_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            loop_block,
            ..
        } => {
            let _ = test;
            reactive_block_writes_declaration(init, declaration_id)
                || update
                    .as_ref()
                    .is_some_and(|block| reactive_block_writes_declaration(block, declaration_id))
                || reactive_block_writes_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            let _ = test;
            reactive_block_writes_declaration(init, declaration_id)
                || reactive_block_writes_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            reactive_block_writes_declaration(init, declaration_id)
                || reactive_block_writes_declaration(loop_block, declaration_id)
        }
        ReactiveTerminal::Label { block, .. } => {
            reactive_block_writes_declaration(block, declaration_id)
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            reactive_block_writes_declaration(block, declaration_id)
                || reactive_block_writes_declaration(handler, declaration_id)
        }
    }
}

fn maybe_codegen_inline_literal_init_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let InlineLiteralInitScopeMatch {
        source_instr,
        store_instr,
        store_lvalue,
    } = match_inline_literal_init_scope(scope_block, following_stmts)?;

    let rhs = codegen_instruction_value_ev(cx, &source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let kind = if has_materialized_named_binding(cx, &store_lvalue.place.identifier) {
        InstructionKind::Reassign
    } else {
        store_lvalue.kind
    };
    if let Some(stmt) = codegen_store(cx, store_instr, kind, &store_lvalue.place, &rhs) {
        output.push_str(&stmt);
        if !stmt.ends_with('\n') {
            output.push('\n');
        }
    }
    Some(1)
}

fn codegen_scope_computation_no_reset(
    cx: &mut Context,
    scope: &ReactiveScope,
    block: &ReactiveBlock,
) -> String {
    if should_drop_trailing_scope_temp_declare(scope, block) {
        if std::env::var("DEBUG_SCOPE_BLANK").is_ok() {
            eprintln!("[SCOPE_BLANK] path=1 (drop trailing temp declare)");
        }
        return codegen_block_no_reset_with_options(cx, &block[..block.len() - 1], true);
    }

    if let Some((target_ident, rhs_place)) = scope_tail_sequence_reassign(scope, block) {
        let debug_scope_blank = std::env::var("DEBUG_SCOPE_BLANK").is_ok();
        let mut output = String::new();
        let mut last_end_line: Option<u32> = None;
        for stmt in &block[..block.len().saturating_sub(1)] {
            match stmt {
                ReactiveStatement::Instruction(instr) => {
                    if let Some(stmt_text) = codegen_instruction_nullable(cx, instr) {
                        if debug_scope_blank {
                            eprintln!(
                                "[SCOPE_BLANK] stmt={:?} loc={:?} last_end={:?}",
                                stmt_text.trim(),
                                &instr.loc,
                                last_end_line
                            );
                        }
                        // Insert blank line if source locations have a gap > 1 line
                        if let SourceLocation::Source(range) = &instr.loc
                            && let Some(prev_end) = last_end_line
                            && range.start.line > prev_end + 1
                            && !output.ends_with("\n\n")
                        {
                            if !output.ends_with('\n') {
                                output.push('\n');
                            }
                            output.push('\n');
                        }
                        output.push_str(&stmt_text);
                        if !stmt_text.ends_with('\n') {
                            output.push('\n');
                        }
                        if let SourceLocation::Source(range) = &instr.loc {
                            last_end_line = Some(range.end.line);
                        }
                    }
                }
                ReactiveStatement::PrunedScope(pruned) => {
                    output.push_str(&codegen_block_no_reset(cx, &pruned.instructions));
                    last_end_line = None;
                }
                ReactiveStatement::Scope(scope_block) => {
                    let temp_snapshot = cx.snapshot_temps();
                    codegen_reactive_scope(
                        cx,
                        &mut output,
                        &scope_block.scope,
                        &scope_block.instructions,
                    );
                    cx.restore_temps(temp_snapshot);
                    last_end_line = None;
                }
                ReactiveStatement::Terminal(term_stmt) => {
                    if let Some(stmt_text) = codegen_terminal(cx, &term_stmt.terminal) {
                        let term_loc = reactive_terminal_loc(&term_stmt.terminal);
                        if let SourceLocation::Source(range) = term_loc
                            && let Some(prev_end) = last_end_line
                            && range.start.line > prev_end + 1
                            && !output.ends_with("\n\n")
                        {
                            if !output.ends_with('\n') {
                                output.push('\n');
                            }
                            output.push('\n');
                        }
                        output.push_str(&stmt_text);
                        if !stmt_text.ends_with('\n') {
                            output.push('\n');
                        }
                        if let SourceLocation::Source(range) = term_loc {
                            last_end_line = Some(range.end.line);
                        }
                    }
                }
            }
        }
        let target_name = identifier_name_with_cx(cx, target_ident);
        let rhs_expr = codegen_place_to_expression(cx, rhs_place);
        if rhs_expr == "undefined"
            && matches!(rhs_place.identifier.loc, SourceLocation::Generated)
            && !output.contains("break bb")
        {
            return output;
        }
        output.push_str(
            &render_reactive_assignment_statement_ast(&target_name, &rhs_expr)
                .expect("reactive assignment should stay on AST path"),
        );
        return drop_redundant_assignment_tail_identifier_read_lines(output);
    }

    drop_redundant_assignment_tail_identifier_read_lines(codegen_block_no_reset_with_options(
        cx, block, true,
    ))
}

fn should_drop_trailing_scope_temp_declare(scope: &ReactiveScope, block: &ReactiveBlock) -> bool {
    if block.is_empty()
        || !scope.dependencies.is_empty()
        || !scope.declarations.is_empty()
        || scope.reassignments.len() != 1
    {
        return false;
    }
    let ReactiveStatement::Instruction(last_instr) = &block[block.len() - 1] else {
        return false;
    };
    let decl_lvalue = match &last_instr.value {
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => lvalue,
        _ => return false,
    };
    if !is_fusable_temp_lvalue(&decl_lvalue.place) {
        return false;
    }
    let decl_id = decl_lvalue.place.identifier.declaration_id;
    if reactive_block_uses_declaration(&block[..block.len() - 1], decl_id) {
        return false;
    }
    debug_codegen_expr(
        "scope-drop-trailing-temp-declare",
        format!("scope={} decl_id={}", scope.id.0, decl_id.0),
    );
    true
}

fn scope_tail_sequence_reassign<'a>(
    scope: &'a ReactiveScope,
    block: &'a ReactiveBlock,
) -> Option<(&'a Identifier, &'a Place)> {
    if scope.reassignments.len() != 1 || block.is_empty() {
        return None;
    }
    let target_decl = scope.reassignments[0].declaration_id;
    let ReactiveStatement::Instruction(last_instr) = block.last()? else {
        return None;
    };
    match &last_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. }
            if lvalue.kind == InstructionKind::Reassign
                && lvalue.place.identifier.declaration_id == target_decl =>
        {
            debug_codegen_expr(
                "sequence-tail-reassign",
                format!(
                    "scope={} target_decl={} source_decl={}",
                    scope.id.0,
                    lvalue.place.identifier.declaration_id.0,
                    value.identifier.declaration_id.0
                ),
            );
            Some((&lvalue.place.identifier, value))
        }
        _ => None,
    }
}

fn maybe_codegen_fused_ternary_source_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let debug = std::env::var("DEBUG_SCOPE_INLINE").is_ok();
    if scope_block.scope.dependencies.len() != 1
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
    {
        if debug {
            eprintln!(
                "[SCOPE_FUSE_TERNARY] reject precheck deps={} reassignments={} decls={}",
                scope_block.scope.dependencies.len(),
                scope_block.scope.reassignments.len(),
                scope_block.scope.declarations.len()
            );
        }
        return None;
    }
    let decl = scope_block.scope.declarations.values().next()?;
    if debug {
        let mut descs = Vec::new();
        for stmt in following_stmts.iter().take(3) {
            let desc = match stmt {
                ReactiveStatement::Instruction(instr) => {
                    let has_lv = instr.lvalue.is_some();
                    let kind = match &instr.value {
                        InstructionValue::Ternary { .. } => "Ternary",
                        InstructionValue::StoreLocal { .. } => "StoreLocal",
                        InstructionValue::StoreContext { .. } => "StoreContext",
                        InstructionValue::LoadLocal { .. } => "LoadLocal",
                        InstructionValue::LoadContext { .. } => "LoadContext",
                        InstructionValue::DeclareLocal { .. } => "DeclareLocal",
                        InstructionValue::DeclareContext { .. } => "DeclareContext",
                        _ => "Other",
                    };
                    format!("Instruction(kind={}, lvalue={})", kind, has_lv)
                }
                ReactiveStatement::Scope(_) => "Scope".to_string(),
                ReactiveStatement::PrunedScope(_) => "PrunedScope".to_string(),
                ReactiveStatement::Terminal(_) => "Terminal".to_string(),
            };
            descs.push(desc);
        }
        eprintln!("[SCOPE_FUSE_TERNARY] lookahead={:?}", descs);
    }
    let mut ternary_idx: Option<usize> = None;
    let mut scope_is_consequent: Option<bool> = None;
    for (idx, stmt) in following_stmts.iter().enumerate().take(8) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if idx > 0
            && !is_ignorable_bridge_interstitial(instr)
            && !matches!(&instr.value, InstructionValue::Ternary { .. })
        {
            continue;
        }
        let Some(lvalue) = &instr.lvalue else {
            continue;
        };
        let InstructionValue::Ternary {
            consequent,
            alternate,
            ..
        } = &instr.value
        else {
            continue;
        };
        if debug {
            eprintln!(
                "[SCOPE_FUSE_TERNARY] inspect ternary idx={} cons_decl={} scope_decl={} lv_decl={} alt={}",
                idx,
                consequent.identifier.declaration_id.0,
                decl.identifier.declaration_id.0,
                lvalue.identifier.declaration_id.0,
                codegen_place_to_expression(cx, alternate)
            );
        }
        let cons_is_scope = consequent.identifier.declaration_id == decl.identifier.declaration_id;
        let alt_is_scope = alternate.identifier.declaration_id == decl.identifier.declaration_id;
        if !cons_is_scope && !alt_is_scope {
            continue;
        }
        if lvalue.identifier.declaration_id == decl.identifier.declaration_id {
            continue;
        }
        ternary_idx = Some(idx);
        scope_is_consequent = Some(cons_is_scope);
        break;
    }
    let Some(ternary_idx) = ternary_idx else {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: no matching ternary lookahead");
        }
        return None;
    };
    let scope_is_consequent = scope_is_consequent?;
    for stmt in &following_stmts[..ternary_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            if debug {
                eprintln!("[SCOPE_FUSE_TERNARY] reject: non-instruction before ternary");
            }
            return None;
        };
        if !is_ignorable_bridge_interstitial(instr) {
            if debug {
                eprintln!("[SCOPE_FUSE_TERNARY] reject: non-ignorable instruction before ternary");
            }
            return None;
        }
        let _ = codegen_instruction_nullable(cx, instr);
    }
    let Some(ReactiveStatement::Instruction(ternary_instr)) = following_stmts.get(ternary_idx)
    else {
        return None;
    };
    let Some(ternary_lvalue) = &ternary_instr.lvalue else {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: matching ternary has no lvalue");
        }
        return None;
    };
    let InstructionValue::Ternary {
        test,
        consequent,
        alternate,
        ..
    } = &ternary_instr.value
    else {
        return None;
    };
    let non_scope_branch_expr_raw = if scope_is_consequent {
        codegen_place_to_expression(cx, alternate)
    } else {
        codegen_place_to_expression(cx, consequent)
    };
    let non_scope_is_inlineable_primitive =
        is_inlineable_primitive_literal_expression(non_scope_branch_expr_raw.trim());
    if non_scope_branch_expr_raw != "null" && !non_scope_is_inlineable_primitive {
        if debug {
            eprintln!(
                "[SCOPE_FUSE_TERNARY] reject: ternary non-scope branch resolves to {}",
                non_scope_branch_expr_raw
            );
        }
        return None;
    }
    if scope_block.instructions.is_empty() {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: scope has no instructions");
        }
        return None;
    }
    let source_idx = scope_block.instructions.len() - 1;
    for prefix_stmt in &scope_block.instructions[..source_idx] {
        let ReactiveStatement::Instruction(prefix_instr) = prefix_stmt else {
            if debug {
                eprintln!("[SCOPE_FUSE_TERNARY] reject: non-instruction prefix in scope");
            }
            return None;
        };
        let emitted = codegen_instruction_nullable(cx, prefix_instr);
        if emitted
            .as_deref()
            .is_some_and(|stmt| !stmt.trim().is_empty())
        {
            if debug {
                eprintln!(
                    "[SCOPE_FUSE_TERNARY] reject: prefix emits statement `{}`",
                    emitted.as_deref().unwrap_or_default()
                );
            }
            return None;
        }
    }
    let Some(ReactiveStatement::Instruction(source_instr)) =
        scope_block.instructions.get(source_idx)
    else {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: scope source stmt is not instruction");
        }
        return None;
    };
    let Some(source_lvalue) = &source_instr.lvalue else {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: source instruction has no lvalue");
        }
        return None;
    };
    if source_lvalue.identifier.declaration_id != decl.identifier.declaration_id {
        if debug {
            eprintln!(
                "[SCOPE_FUSE_TERNARY] reject: source decl {} != scope decl {}",
                source_lvalue.identifier.declaration_id.0, decl.identifier.declaration_id.0
            );
        }
        return None;
    }
    if matches!(
        &source_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        if debug {
            eprintln!("[SCOPE_FUSE_TERNARY] reject: source instruction kind not supported");
        }
        return None;
    }

    let raw_dep = &scope_block.scope.dependencies[0];
    if debug {
        let path_desc: Vec<String> = raw_dep
            .path
            .iter()
            .map(|entry| {
                format!(
                    "{}{}",
                    if entry.optional { "?." } else { "." },
                    entry.property
                )
            })
            .collect();
        eprintln!(
            "[SCOPE_FUSE_TERNARY] raw_dep id={} name={:?} path={:?}",
            raw_dep.identifier.id.0, raw_dep.identifier.name, path_desc
        );
    }
    let cond_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
    let dep_for_codegen = truncate_ref_current_dep(raw_dep, &cx.stable_ref_decls);
    let mut dep_expr = codegen_dependency(cx, &dep_for_codegen);
    let mut force_root_dep = false;
    if !scope_is_consequent && !dep_for_codegen.path.is_empty() {
        let root_expr = identifier_name_with_cx(cx, &dep_for_codegen.identifier);
        if cond_expr.contains(&format!("{}?.", root_expr)) {
            dep_expr = root_expr;
            force_root_dep = true;
        }
    }
    let cond_is_non_local = cx
        .non_local_binding_decls
        .contains(&test.identifier.declaration_id);
    let include_cond_dep = !force_root_dep
        && !cond_is_non_local
        && !is_inlineable_primitive_literal_expression(cond_expr.trim());
    let source_ev = codegen_instruction_value_ev(cx, &source_instr.value);
    let mut source_expr = source_ev.wrap_if_needed(ExprPrecedence::Conditional);
    let should_compact_source_expr = match &source_instr.value {
        InstructionValue::ObjectExpression { properties, .. } => {
            properties.iter().any(|property| {
                matches!(
                    property,
                    ObjectPropertyOrSpread::Property(ObjectProperty {
                        type_: ObjectPropertyType::Method,
                        ..
                    })
                )
            })
        }
        InstructionValue::CallExpression { .. } => true,
        _ => false,
    };
    if source_expr.contains('\n') && should_compact_source_expr && !source_expr.contains('`') {
        source_expr = compact_single_statement(&source_expr);
    }
    let consequent_expr = if scope_is_consequent {
        source_expr.clone()
    } else {
        codegen_place_with_min_prec(cx, consequent, ExprPrecedence::Conditional)
    };
    let alternate_expr = if scope_is_consequent {
        codegen_place_with_min_prec(cx, alternate, ExprPrecedence::Conditional)
    } else {
        source_expr.clone()
    };
    if debug {
        eprintln!(
            "[SCOPE_FUSE_TERNARY] expr cond=`{}` dep=`{}` source=`{}` cons=`{}` alt=`{}`",
            cond_expr, dep_expr, source_expr, consequent_expr, alternate_expr
        );
    }

    let cache_var = cx.synthesize_name("$");
    let cond_slot = include_cond_dep.then(|| cx.alloc_cache_slot());
    let dep_slot = cx.alloc_cache_slot();
    let output_slot = cx.alloc_cache_slot();
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let decl_name = identifier_name_with_cx(cx, &decl.identifier);
    if !has_materialized_named_binding(cx, &decl.identifier) {
        let statement = ast::Statement::VariableDeclaration(builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Let,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.binding_pattern_binding_identifier(SPAN, builder.ident(&decl_name)),
                NONE,
                None,
                false,
            )),
            false,
        ));
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
        cx.mark_decl_runtime_emitted(decl.identifier.declaration_id);
    }
    cx.declare(&decl.identifier);

    if debug {
        eprintln!(
            "[SCOPE_FUSE_TERNARY] cond_dep include={} non_local={} decl={}",
            include_cond_dep, cond_is_non_local, test.identifier.declaration_id.0
        );
    }

    let dep_guard_expr =
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &dep_expr)
            .expect("fused ternary dependency comparison should stay on AST path");
    let dep_guard = builder.expression_binary(
        SPAN,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, dep_slot as f64, None, NumberBase::Decimal),
        ),
        AstBinaryOperator::StrictInequality,
        dep_guard_expr,
    );
    let guard_test = if let Some(cond_slot) = cond_slot {
        let cond_guard_expr = parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &cond_expr,
        )
        .expect("fused ternary condition comparison should stay on AST path");
        builder.expression_logical(
            SPAN,
            builder.expression_binary(
                SPAN,
                build_computed_member_expression_ast(
                    builder,
                    &cache_var,
                    builder.expression_numeric_literal(
                        SPAN,
                        cond_slot as f64,
                        None,
                        NumberBase::Decimal,
                    ),
                ),
                AstBinaryOperator::StrictInequality,
                cond_guard_expr,
            ),
            AstLogicalOperator::Or,
            dep_guard,
        )
    } else {
        dep_guard
    };
    let rhs_expr = parse_expression_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        &render_conditional_expression_ast(&cond_expr, &consequent_expr, &alternate_expr)
            .expect("fused ternary expression should stay on AST path"),
    )
    .expect("fused ternary assignment should stay on AST path");
    let mut consequent = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder, &decl_name, rhs_expr,
    ));
    if let Some(cond_slot) = cond_slot {
        consequent.push(build_computed_member_assignment_statement_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, cond_slot as f64, None, NumberBase::Decimal),
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &cond_expr,
            )
            .expect("fused ternary condition store should stay on AST path"),
        ));
    }
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, dep_slot as f64, None, NumberBase::Decimal),
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &dep_expr)
            .expect("fused ternary dependency store should stay on AST path"),
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&decl_name)),
    ));
    let alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &decl_name,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        ),
    ));
    let statement = builder.statement_if(
        SPAN,
        guard_test,
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));

    // The skipped ternary instruction's lvalue aliases the fused scope output.
    cx.set_temp_expr(
        &ternary_lvalue.identifier,
        Some(ExprValue::primary(decl_name)),
    );
    let suppressed_display_idx = ternary_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(ternary_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }
    if debug {
        eprintln!("[SCOPE_FUSE_TERNARY] accept");
    }
    Some(ternary_idx + 1)
}

fn maybe_codegen_inline_zero_dep_literal_into_following_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let debug = std::env::var("DEBUG_SCOPE_INLINE").is_ok();
    let (source_decl, source_instr) = zero_dep_single_decl_scope_source(scope_block)?;
    if !matches!(
        &source_instr.value,
        InstructionValue::Primitive { .. }
            | InstructionValue::ArrayExpression { .. }
            | InstructionValue::ObjectExpression { .. }
    ) {
        return None;
    }
    let source_lvalue = source_instr.lvalue.as_ref()?;

    let ReactiveStatement::Scope(next_scope) = following_stmts.first()? else {
        return None;
    };
    if next_scope.scope.dependencies.is_empty() {
        return None;
    }
    let ReactiveStatement::Instruction(first_instr) = next_scope.instructions.first()? else {
        return None;
    };
    let (store_lvalue, store_value) = match &first_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => (lvalue, value),
        _ => return None,
    };
    if store_value.identifier.declaration_id != source_decl
        || store_lvalue.place.identifier.name.is_none()
        || first_instr.lvalue.is_some()
    {
        return None;
    }
    if reactive_block_uses_declaration(&next_scope.instructions[1..], source_decl) {
        return None;
    }

    let target_ident = &store_lvalue.place.identifier;
    let source_seed_expr = codegen_instruction_value_ev(cx, &source_instr.value);

    // Alias the seed temp to the literal itself while generating the
    // following dep scope, so the initial store is emitted inside the
    // recompute branch as `target = literal`.
    let temp_snapshot = cx.snapshot_temps();
    cx.set_temp_expr(&source_lvalue.identifier, Some(source_seed_expr));
    codegen_reactive_scope(cx, output, &next_scope.scope, &next_scope.instructions);
    cx.restore_temps(temp_snapshot);

    let suppressed_display_idx = source_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(source_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }

    if debug {
        eprintln!(
            "[SCOPE_INLINE_ZERO_DEP] accept source_decl={} target_decl={} scope={}",
            source_decl.0, target_ident.declaration_id.0, next_scope.scope.id.0
        );
    }

    Some(1)
}

fn maybe_codegen_fused_dual_zero_dep_literal_ternary_scope(
    cx: &mut Context,
    first_scope: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let (first_decl, first_source_instr) = zero_dep_single_decl_scope_source(first_scope)?;

    let ReactiveStatement::Instruction(first_store_instr) = following_stmts.first()? else {
        return None;
    };
    let (target_ident, first_store_result_decl) =
        parse_named_store_from_decl(first_store_instr, first_decl)?;
    let first_store_result_decl = first_store_result_decl?;

    let ReactiveStatement::Scope(second_scope) = following_stmts.get(1)? else {
        return None;
    };
    let (second_decl, second_source_instr) = zero_dep_single_decl_scope_source(second_scope)?;

    let ReactiveStatement::Instruction(second_store_instr) = following_stmts.get(2)? else {
        return None;
    };
    let (second_target_ident, second_store_result_decl) =
        parse_named_store_from_decl(second_store_instr, second_decl)?;
    if second_target_ident.declaration_id != target_ident.declaration_id {
        return None;
    }
    let second_store_result_decl = second_store_result_decl?;

    let ReactiveStatement::Instruction(ternary_instr) = following_stmts.get(3)? else {
        return None;
    };
    if ternary_instr.lvalue.is_some() {
        return None;
    }
    let InstructionValue::Ternary {
        test,
        consequent,
        alternate,
        ..
    } = &ternary_instr.value
    else {
        return None;
    };

    let (cons_source_instr, alt_source_instr) = if consequent.identifier.declaration_id
        == first_store_result_decl
        && alternate.identifier.declaration_id == second_store_result_decl
    {
        (first_source_instr, second_source_instr)
    } else if consequent.identifier.declaration_id == second_store_result_decl
        && alternate.identifier.declaration_id == first_store_result_decl
    {
        (second_source_instr, first_source_instr)
    } else {
        return None;
    };

    if reactive_block_uses_declaration(&following_stmts[4..], first_store_result_decl)
        || reactive_block_uses_declaration(&following_stmts[4..], second_store_result_decl)
    {
        return None;
    }

    let target_name = identifier_name_with_cx(cx, target_ident);
    let cond_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
    let cons_expr = codegen_instruction_value_ev(cx, &cons_source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let alt_expr = codegen_instruction_value_ev(cx, &alt_source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let computation = format!(
        "{} ? ({} = {}) : ({} = {});\n",
        cond_expr, target_name, cons_expr, target_name, alt_expr
    );
    emit_zero_dep_target_guard(cx, output, target_ident, &computation);
    debug_codegen_expr(
        "fused-dual-zero-dep-ternary-scope",
        format!(
            "target={} first_decl={} second_decl={}",
            target_name, first_decl.0, second_decl.0
        ),
    );
    Some(4)
}

fn maybe_codegen_fused_zero_dep_literal_store_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let (scope_decl, source_instr) = zero_dep_single_decl_scope_source(scope_block)?;

    let ReactiveStatement::Instruction(store_instr) = following_stmts.first()? else {
        return None;
    };
    let (target_ident, store_result_decl) = parse_named_store_from_decl(store_instr, scope_decl)?;
    if cx
        .function_decl_decls
        .contains(&target_ident.declaration_id)
    {
        return None;
    }
    if reactive_block_writes_declaration(&following_stmts[1..], target_ident.declaration_id) {
        return None;
    }
    if matches!(following_stmts.get(1), Some(ReactiveStatement::Scope(_))) {
        return None;
    }

    let target_name = identifier_name_with_cx(cx, target_ident);
    let source_expr = codegen_instruction_value_ev(cx, &source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);

    let mut logical_idx: Option<usize> = None;
    let mut bridge_instrs: Vec<&ReactiveInstruction> = Vec::new();
    let mut cursor = 1usize;
    while let Some(stmt) = following_stmts.get(cursor) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if instr.lvalue.is_none()
            && matches!(instr.value, InstructionValue::LogicalExpression { .. })
        {
            logical_idx = Some(cursor);
            break;
        }
        if is_fusable_inline_temp_instruction(instr) {
            bridge_instrs.push(instr);
            cursor += 1;
            continue;
        }
        break;
    }

    let mut consumed_following = 1usize;
    let computation = if let Some(logical_idx) = logical_idx {
        for instr in bridge_instrs {
            if !materialize_fusable_temp_instruction(cx, instr) {
                return None;
            }
        }
        let ReactiveStatement::Instruction(logical_instr) = &following_stmts[logical_idx] else {
            return None;
        };
        let InstructionValue::LogicalExpression {
            operator,
            left,
            right,
            ..
        } = &logical_instr.value
        else {
            return None;
        };
        let logical_prec = logical_operator_precedence(operator);
        let left_expr = codegen_logical_operand(cx, left, logical_prec);
        let right_is_store_result =
            store_result_decl.is_some_and(|decl| right.identifier.declaration_id == decl);
        let right_expr = if right_is_store_result {
            render_global_store_expression_ast(&target_name, &source_expr)
                .expect("fused logical store expression should stay on AST path")
        } else {
            let right_expr_raw = codegen_place_to_expression(cx, right);
            if *operator == LogicalOperator::And && right_expr_raw == "null" {
                render_sequence_expression_ast(
                    &[
                        render_global_store_expression_ast(&target_name, &source_expr)
                            .expect("fused logical store expression should stay on AST path"),
                    ],
                    "null",
                )
                .expect("fused logical null sequence should stay on AST path")
            } else {
                return None;
            }
        };
        consumed_following = logical_idx + 1;
        render_reactive_expression_statement_ast(
            &render_logical_expression_ast(&left_expr, *operator, &right_expr)
                .expect("fused logical statement should stay on AST path"),
        )
        .expect("fused logical statement should stay on AST path")
    } else {
        if let Some(store_result_decl) = store_result_decl
            && reactive_block_uses_declaration(&following_stmts[1..], store_result_decl)
        {
            return None;
        }
        render_reactive_assignment_statement_ast(&target_name, &source_expr)
            .expect("fused zero-dep assignment should stay on AST path")
    };

    if !has_direct_return_tail_for_decl(
        &following_stmts[consumed_following..],
        target_ident.declaration_id,
    ) {
        return None;
    }

    emit_zero_dep_target_guard(cx, output, target_ident, &computation);
    debug_codegen_expr(
        "fused-zero-dep-literal-store-scope",
        format!(
            "target={} consumed_following={}",
            target_name, consumed_following
        ),
    );
    Some(consumed_following)
}

fn maybe_codegen_fused_zero_dep_sequence_logical_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let (target_ident, source_instr, scope_decl) =
        parse_zero_dep_sequence_null_scope_target(scope_block)?;
    if cx
        .function_decl_decls
        .contains(&target_ident.declaration_id)
    {
        return None;
    }
    let ReactiveStatement::Instruction(logical_instr) = following_stmts.first()? else {
        return None;
    };
    let InstructionValue::LogicalExpression {
        operator,
        left,
        right,
        ..
    } = &logical_instr.value
    else {
        return None;
    };
    if *operator != LogicalOperator::And || right.identifier.declaration_id != scope_decl {
        return None;
    }
    if reactive_block_uses_declaration(&following_stmts[1..], scope_decl)
        || reactive_block_writes_declaration(&following_stmts[1..], target_ident.declaration_id)
    {
        return None;
    }
    if !has_direct_return_tail_for_decl(&following_stmts[1..], target_ident.declaration_id) {
        return None;
    }

    let logical_prec = logical_operator_precedence(operator);
    let left_expr = codegen_logical_operand(cx, left, logical_prec);
    let target_name = identifier_name_with_cx(cx, target_ident);
    let source_expr = codegen_instruction_value_ev(cx, &source_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let computation = format!(
        "{} && (({} = {}), null);\n",
        left_expr, target_name, source_expr
    );
    emit_zero_dep_target_guard(cx, output, target_ident, &computation);
    debug_codegen_expr(
        "fused-zero-dep-sequence-logical-scope",
        format!("target={} scope_decl={}", target_name, scope_decl.0),
    );
    Some(1)
}

fn parse_zero_dep_sequence_null_scope_target(
    scope_block: &ReactiveScopeBlock,
) -> Option<(&Identifier, &ReactiveInstruction, DeclarationId)> {
    if !scope_block.scope.dependencies.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.scope.reassignments.len() != 1
        || scope_block.instructions.len() != 4
    {
        return None;
    }
    let target_ident = &scope_block.scope.reassignments[0];
    let scope_decl = scope_block
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .declaration_id;

    let ReactiveStatement::Instruction(source_instr) = &scope_block.instructions[0] else {
        return None;
    };
    let source_decl = source_instr
        .lvalue
        .as_ref()
        .map(|lvalue| lvalue.identifier.declaration_id)?;

    let ReactiveStatement::Instruction(store_instr) = &scope_block.instructions[1] else {
        return None;
    };
    let (store_lvalue, store_value) = match &store_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => (lvalue, value),
        _ => return None,
    };
    if store_lvalue.kind != InstructionKind::Reassign
        || store_lvalue.place.identifier.declaration_id != target_ident.declaration_id
        || store_value.identifier.declaration_id != source_decl
    {
        return None;
    }

    let ReactiveStatement::Instruction(null_instr) = &scope_block.instructions[2] else {
        return None;
    };
    let null_decl = match &null_instr.value {
        InstructionValue::Primitive {
            value: PrimitiveValue::Null,
            ..
        } => null_instr
            .lvalue
            .as_ref()
            .map(|lvalue| lvalue.identifier.declaration_id)?,
        _ => return None,
    };

    let ReactiveStatement::Instruction(scope_decl_instr) = &scope_block.instructions[3] else {
        return None;
    };
    let scope_decl_lvalue = scope_decl_instr
        .lvalue
        .as_ref()
        .map(|lvalue| lvalue.identifier.declaration_id)?;
    let InstructionValue::LoadLocal { place, .. } = &scope_decl_instr.value else {
        return None;
    };
    if scope_decl_lvalue != scope_decl || place.identifier.declaration_id != null_decl {
        return None;
    }

    Some((target_ident, source_instr, scope_decl))
}

fn has_direct_return_tail_for_decl(
    trailing_stmts: &[ReactiveStatement],
    target_decl: DeclarationId,
) -> bool {
    match trailing_stmts {
        [ReactiveStatement::Terminal(term_stmt)] => matches!(
            &term_stmt.terminal,
            ReactiveTerminal::Return { value, .. }
                if value.identifier.declaration_id == target_decl
        ),
        [
            ReactiveStatement::Instruction(load_instr),
            ReactiveStatement::Terminal(term_stmt),
        ] => {
            let InstructionValue::LoadLocal { place, .. } = &load_instr.value else {
                return false;
            };
            if place.identifier.declaration_id != target_decl {
                return false;
            }
            let Some(load_result_decl) = load_instr
                .lvalue
                .as_ref()
                .map(|lvalue| lvalue.identifier.declaration_id)
            else {
                return false;
            };
            matches!(
                &term_stmt.terminal,
                ReactiveTerminal::Return { value, .. }
                    if value.identifier.declaration_id == load_result_decl
            )
        }
        _ => false,
    }
}

fn zero_dep_single_decl_scope_source(
    scope_block: &ReactiveScopeBlock,
) -> Option<(DeclarationId, &ReactiveInstruction)> {
    if !scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.len() != 1
    {
        return None;
    }
    let decl = scope_block.scope.declarations.values().next()?;
    let ReactiveStatement::Instruction(source_instr) = scope_block.instructions.first()? else {
        return None;
    };
    let source_lvalue = source_instr.lvalue.as_ref()?;
    if source_lvalue.identifier.declaration_id != decl.identifier.declaration_id {
        return None;
    }
    if matches!(
        &source_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::FunctionExpression { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }
    Some((decl.identifier.declaration_id, source_instr))
}

fn parse_named_store_from_decl(
    store_instr: &ReactiveInstruction,
    source_decl: DeclarationId,
) -> Option<(&Identifier, Option<DeclarationId>)> {
    let (store_lvalue, store_value) = match &store_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => (lvalue, value),
        _ => return None,
    };
    if store_value.identifier.declaration_id != source_decl
        || store_lvalue.place.identifier.name.is_none()
    {
        return None;
    }
    let store_result_decl = store_instr
        .lvalue
        .as_ref()
        .map(|lvalue| lvalue.identifier.declaration_id);
    Some((&store_lvalue.place.identifier, store_result_decl))
}

fn emit_zero_dep_target_guard(
    cx: &mut Context,
    output: &mut String,
    target_ident: &Identifier,
    computation_stmt: &str,
) {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let cache_var = cx.synthesize_name("$");
    let output_slot = cx.alloc_cache_slot();
    let target_name = identifier_name_with_cx(cx, target_ident);
    if !has_materialized_named_binding(cx, target_ident) {
        let statement = ast::Statement::VariableDeclaration(builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Let,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.binding_pattern_binding_identifier(SPAN, builder.ident(&target_name)),
                NONE,
                None,
                false,
            )),
            false,
        ));
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
        cx.mark_decl_runtime_emitted(target_ident.declaration_id);
    }
    cx.declare(target_ident);
    let mut consequent = parse_statement_list_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        computation_stmt,
    )
    .expect("memo cache computation should stay on AST path");
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&target_name)),
    ));
    let alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &target_name,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        ),
    ));
    let statement = builder.statement_if(
        SPAN,
        builder.expression_binary(
            SPAN,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    output_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
            AstBinaryOperator::StrictEquality,
            build_symbol_for_call_expression_ast(builder, MEMO_CACHE_SENTINEL),
        ),
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));
}

fn maybe_codegen_fused_zero_dep_ternary_default_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    let debug = std::env::var("DEBUG_SCOPE_INLINE").is_ok();
    if !scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.is_empty()
    {
        if debug {
            eprintln!(
                "[SCOPE_FUSE_ZERO_DEP_DEFAULT] reject precheck deps={} reassignments={} decls={} instrs={}",
                scope_block.scope.dependencies.len(),
                scope_block.scope.reassignments.len(),
                scope_block.scope.declarations.len(),
                scope_block.instructions.len()
            );
        }
        return None;
    }

    let decl = scope_block.scope.declarations.values().next()?;
    let source_decl_id = decl.identifier.declaration_id;
    let mut probe_cx = cx.clone();
    let mut source_instr: Option<&ReactiveInstruction> = None;
    for stmt in &scope_block.instructions {
        let ReactiveStatement::Instruction(instr) = stmt else {
            return None;
        };
        let source_expr = codegen_instruction_value_ev(&mut probe_cx, &instr.value);
        let Some(lvalue) = &instr.lvalue else {
            return None;
        };
        probe_cx
            .temp
            .insert(lvalue.identifier.declaration_id, Some(source_expr));
        if lvalue.identifier.declaration_id == source_decl_id {
            source_instr = Some(instr);
        }
    }
    let source_instr = source_instr?;
    let source_lvalue = source_instr.lvalue.as_ref()?;
    if source_lvalue.identifier.declaration_id != source_decl_id {
        return None;
    }
    if matches!(
        &source_instr.value,
        InstructionValue::StoreLocal { .. }
            | InstructionValue::StoreContext { .. }
            | InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::Destructure { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::Debugger { .. }
            | InstructionValue::ObjectMethod { .. }
    ) {
        if debug {
            eprintln!("[SCOPE_FUSE_ZERO_DEP_DEFAULT] reject: unsupported source instruction");
        }
        return None;
    }

    let mut source_alias_decls: HashSet<DeclarationId> = HashSet::new();
    source_alias_decls.insert(source_decl_id);

    let mut ternary_idx: Option<usize> = None;
    let mut source_is_consequent = false;
    let mut source_place: Option<Place> = None;
    let mut dep_place: Option<Place> = None;
    for (idx, stmt) in following_stmts.iter().enumerate().take(8) {
        let ReactiveStatement::Instruction(instr) = stmt else {
            break;
        };
        if let Some(lvalue) = &instr.lvalue {
            let source_derived = match &instr.value {
                InstructionValue::LoadLocal { place, .. }
                | InstructionValue::LoadContext { place, .. } => {
                    source_alias_decls.contains(&place.identifier.declaration_id)
                }
                InstructionValue::TypeCastExpression { value, .. } => {
                    source_alias_decls.contains(&value.identifier.declaration_id)
                }
                _ => false,
            };
            if source_derived {
                source_alias_decls.insert(lvalue.identifier.declaration_id);
            }
        }
        if idx > 0
            && !is_ignorable_bridge_interstitial(instr)
            && !matches!(&instr.value, InstructionValue::Ternary { .. })
        {
            continue;
        }
        let Some(_) = &instr.lvalue else {
            continue;
        };
        let InstructionValue::Ternary {
            test: _,
            consequent,
            alternate,
            ..
        } = &instr.value
        else {
            continue;
        };
        let cons_is_source = source_alias_decls.contains(&consequent.identifier.declaration_id);
        let alt_is_source = source_alias_decls.contains(&alternate.identifier.declaration_id);
        if cons_is_source == alt_is_source {
            continue;
        }
        let candidate_dep = if cons_is_source {
            alternate
        } else {
            consequent
        };
        if candidate_dep.identifier.declaration_id == decl.identifier.declaration_id {
            continue;
        }
        let dep_expr = codegen_place_to_expression(cx, candidate_dep);
        if !is_valid_js_identifier_name(dep_expr.trim()) {
            if debug {
                eprintln!(
                    "[SCOPE_FUSE_ZERO_DEP_DEFAULT] reject: non-simple dep expr `{}`",
                    dep_expr
                );
            }
            continue;
        }
        ternary_idx = Some(idx);
        source_is_consequent = cons_is_source;
        source_place = Some(if cons_is_source {
            consequent.clone()
        } else {
            alternate.clone()
        });
        dep_place = Some(candidate_dep.clone());
        break;
    }

    let ternary_idx = ternary_idx?;
    let source_seed_expr = probe_cx
        .temp
        .get(&source_decl_id)
        .cloned()
        .flatten()
        .unwrap_or_else(|| codegen_instruction_value_ev(&mut probe_cx, &source_instr.value));
    let cx_snapshot = cx.clone();
    cx.set_temp_expr(&source_lvalue.identifier, Some(source_seed_expr));
    for stmt in &following_stmts[..ternary_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            *cx = cx_snapshot;
            return None;
        };
        let bridge_stmt = codegen_instruction_nullable(cx, instr);
        if bridge_stmt
            .as_deref()
            .is_some_and(|text| !text.trim().is_empty())
        {
            if debug {
                eprintln!(
                    "[SCOPE_FUSE_ZERO_DEP_DEFAULT] reject: bridge emits statement `{}`",
                    bridge_stmt.as_deref().unwrap_or_default()
                );
            }
            *cx = cx_snapshot;
            return None;
        }
    }

    let Some(ReactiveStatement::Instruction(ternary_instr)) = following_stmts.get(ternary_idx)
    else {
        return None;
    };
    let Some(ternary_lvalue) = &ternary_instr.lvalue else {
        return None;
    };
    let InstructionValue::Ternary {
        test,
        consequent: _,
        alternate: _,
        ..
    } = &ternary_instr.value
    else {
        *cx = cx_snapshot;
        return None;
    };
    let dep_place = dep_place?;
    let source_place = source_place?;

    let cond_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
    let source_expr = codegen_place_with_min_prec(cx, &source_place, ExprPrecedence::Conditional);
    let dep_expr_cond = codegen_place_with_min_prec(cx, &dep_place, ExprPrecedence::Conditional);
    let dep_expr_guard = codegen_place_to_expression(cx, &dep_place);

    let use_ternary_lvalue =
        ternary_lvalue
            .identifier
            .name
            .as_ref()
            .is_some_and(|name| match name {
                IdentifierName::Named(n) | IdentifierName::Promoted(n) => {
                    !(n.starts_with('t') && n[1..].chars().all(|ch| ch.is_ascii_digit()))
                }
            });
    let output_ident = if use_ternary_lvalue {
        &ternary_lvalue.identifier
    } else {
        &decl.identifier
    };
    let output_name = identifier_name_with_cx(cx, output_ident);
    let cache_var = cx.synthesize_name("$");
    let dep_slot = cx.alloc_cache_slot();
    let output_slot = cx.alloc_cache_slot();
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);

    if !has_materialized_named_binding(cx, output_ident) {
        let statement = ast::Statement::VariableDeclaration(builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Let,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.binding_pattern_binding_identifier(SPAN, builder.ident(&output_name)),
                NONE,
                None,
                false,
            )),
            false,
        ));
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
        cx.mark_decl_runtime_emitted(output_ident.declaration_id);
    }
    cx.declare(output_ident);

    let rhs_expr = if source_is_consequent {
        render_conditional_expression_ast(&cond_expr, &source_expr, &dep_expr_cond)
    } else {
        render_conditional_expression_ast(&cond_expr, &dep_expr_cond, &source_expr)
    }
    .expect("conditional output expression should stay on AST path");

    let mut consequent = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &output_name,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &rhs_expr)
            .expect("conditional output assignment should stay on AST path"),
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, dep_slot as f64, None, NumberBase::Decimal),
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &dep_expr_guard,
        )
        .expect("conditional dependency store should stay on AST path"),
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&output_name)),
    ));
    let alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &output_name,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(SPAN, output_slot as f64, None, NumberBase::Decimal),
        ),
    ));
    let statement = builder.statement_if(
        SPAN,
        builder.expression_binary(
            SPAN,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    dep_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
            AstBinaryOperator::StrictInequality,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &dep_expr_guard,
            )
            .expect("conditional output guard should stay on AST path"),
        ),
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));

    cx.set_temp_expr(
        &ternary_lvalue.identifier,
        Some(ExprValue::primary(output_name.clone())),
    );
    cx.temp.insert(
        decl.identifier.declaration_id,
        Some(ExprValue::primary(output_name)),
    );
    let suppressed_display_idx = ternary_lvalue
        .identifier
        .name
        .as_ref()
        .and_then(|name| match name {
            IdentifierName::Named(n) | IdentifierName::Promoted(n) => n
                .strip_prefix('t')
                .and_then(|suffix| suffix.parse::<u32>().ok()),
        })
        .unwrap_or(ternary_lvalue.identifier.id.0);
    if !cx.suppressed_temp_ids.contains(&suppressed_display_idx) {
        cx.suppressed_temp_ids.push(suppressed_display_idx);
    }
    if debug {
        eprintln!("[SCOPE_FUSE_ZERO_DEP_DEFAULT] accept");
    }

    Some(ternary_idx + 1)
}

fn maybe_codegen_fused_callback_reassign_scope(
    cx: &mut Context,
    callback_scope: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    // Pattern (narrow):
    //   1) zero-dep callback temp scope:
    //      scope { tX = () => ... }
    //   2) optional ignorable load/primitive bridge instructions
    //   3) dep scope with non-empty deps (typically mutating callback capture source)
    //   4) load+store alias into named var:
    //      tY = tX; named = tY;
    //
    // Emit a single guard keyed by dep scope deps and cache the named callback.
    if !callback_scope.scope.dependencies.is_empty()
        || !callback_scope.scope.reassignments.is_empty()
        || callback_scope.scope.declarations.len() != 1
        || callback_scope.instructions.len() != 1
    {
        return None;
    }

    let callback_decl = callback_scope
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .declaration_id;

    let ReactiveStatement::Instruction(callback_instr) = callback_scope.instructions.first()?
    else {
        return None;
    };
    let callback_lvalue = callback_instr.lvalue.as_ref()?;
    if callback_lvalue.identifier.declaration_id != callback_decl {
        return None;
    }
    if !matches!(
        callback_instr.value,
        InstructionValue::FunctionExpression { .. } | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    // Find the following dependency scope, allowing only ignorable bridge instructions.
    let mut dep_scope_idx: Option<usize> = None;
    for (idx, stmt) in following_stmts.iter().enumerate() {
        match stmt {
            ReactiveStatement::Instruction(instr) if is_ignorable_bridge_interstitial(instr) => {}
            ReactiveStatement::Scope(scope_block) => {
                if scope_block.scope.dependencies.is_empty() {
                    return None;
                }
                dep_scope_idx = Some(idx);
                break;
            }
            _ => return None,
        }
    }
    let dep_scope_idx = dep_scope_idx?;
    let ReactiveStatement::Scope(dep_scope) = following_stmts.get(dep_scope_idx)? else {
        return None;
    };

    // Find load+store alias into a named callback variable after the dep scope.
    // Allow a small postfix sequence of interstitial instructions (e.g. ternary bridge)
    // before the alias pair.
    let mut post_dep_instructions: Vec<&ReactiveInstruction> = Vec::new();
    let mut cursor = dep_scope_idx + 1;
    let (target_ident, consumed_after_dep) = loop {
        let ReactiveStatement::Instruction(instr) = following_stmts.get(cursor)? else {
            return None;
        };
        let load_lvalue = instr.lvalue.as_ref();
        let load_from_callback = match &instr.value {
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => {
                place.identifier.declaration_id == callback_decl
            }
            _ => false,
        };
        if load_from_callback {
            let alias_load_lvalue = load_lvalue?;
            let alias_temp_decl = alias_load_lvalue.identifier.declaration_id;
            let ReactiveStatement::Instruction(alias_store) = following_stmts.get(cursor + 1)?
            else {
                return None;
            };
            let (target_ident, alias_matches) = match &alias_store.value {
                InstructionValue::StoreLocal { lvalue, value, .. }
                | InstructionValue::StoreContext { lvalue, value, .. } => (
                    lvalue.place.identifier.clone(),
                    value.identifier.declaration_id == alias_temp_decl
                        && lvalue.place.identifier.name.is_some(),
                ),
                _ => return None,
            };
            if !alias_matches {
                return None;
            }
            break (target_ident, (cursor + 2) - dep_scope_idx);
        }
        let is_reassign_store = matches!(
            instr.value,
            InstructionValue::StoreLocal { ref lvalue, .. }
                | InstructionValue::StoreContext { ref lvalue, .. }
                if lvalue.kind == InstructionKind::Reassign
        );
        if is_ignorable_bridge_interstitial(instr)
            || matches!(instr.value, InstructionValue::Ternary { .. })
            || is_reassign_store
        {
            post_dep_instructions.push(instr);
            cursor += 1;
            continue;
        }
        return None;
    };

    // Truncate ref.current deps to just ref (upstream: PropagateScopeDependenciesHIR.ts L610-620).
    let truncated_deps: Vec<ReactiveScopeDependency> = dep_scope
        .scope
        .dependencies
        .iter()
        .map(|dep| truncate_ref_current_dep(dep, &cx.stable_ref_decls))
        .collect();
    let mut sorted_deps: Vec<&ReactiveScopeDependency> = truncated_deps.iter().collect();
    sort_scope_dependency_refs_for_codegen(cx, &mut sorted_deps);
    let mut seen_dep_keys: HashSet<String> = HashSet::new();
    let mut dep_exprs: Vec<String> = Vec::new();
    let mut post_dep_reassign_decls: HashSet<DeclarationId> = HashSet::new();
    for instr in &post_dep_instructions {
        if let InstructionValue::StoreLocal { lvalue, .. }
        | InstructionValue::StoreContext { lvalue, .. } = &instr.value
            && lvalue.kind == InstructionKind::Reassign
        {
            post_dep_reassign_decls.insert(lvalue.place.identifier.declaration_id);
        }
    }
    for dep in sorted_deps {
        let key = format_dependency_name(dep);
        if seen_dep_keys.insert(key) {
            dep_exprs.push(codegen_dependency(cx, dep));
        }
    }
    // Include additional deps observed in pre-dep bridge loads (e.g. `foo` in
    // callback+control-flow patterns).
    for stmt in &following_stmts[..dep_scope_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            continue;
        };
        if let InstructionValue::LoadLocal { place, .. }
        | InstructionValue::LoadContext { place, .. } = &instr.value
            && place.identifier.name.is_some()
            && !post_dep_reassign_decls.contains(&place.identifier.declaration_id)
        {
            let expr = codegen_place_to_expression(cx, place);
            if !is_inlineable_primitive_literal_expression(expr.trim())
                && seen_dep_keys.insert(expr.clone())
            {
                dep_exprs.push(expr);
            }
        }
    }
    // Include additional deps observed in post-dep bridge loads (e.g. ternary test `foo`).
    for instr in &post_dep_instructions {
        if let InstructionValue::LoadLocal { place, .. }
        | InstructionValue::LoadContext { place, .. } = &instr.value
            && place.identifier.name.is_some()
            && !post_dep_reassign_decls.contains(&place.identifier.declaration_id)
        {
            let expr = codegen_place_to_expression(cx, place);
            if !is_inlineable_primitive_literal_expression(expr.trim())
                && seen_dep_keys.insert(expr.clone())
            {
                dep_exprs.push(expr);
            }
        }
    }
    dep_exprs.sort();
    dep_exprs.dedup();
    if dep_exprs.is_empty() {
        return None;
    }

    let target_name = identifier_name_with_cx(cx, &target_ident);
    if target_name.is_empty() {
        return None;
    }

    if !has_materialized_named_binding(cx, &target_ident) {
        output.push_str(&render_reactive_variable_statement_ast(
            ast::VariableDeclarationKind::Let,
            &target_name,
            None,
        )?);
        cx.mark_decl_runtime_emitted(target_ident.declaration_id);
    }
    cx.declare(&target_ident);

    let temp_snapshot = cx.snapshot_temps();

    let cache_var = cx.synthesize_name("$");
    let mut change_exprs: Vec<String> = Vec::new();
    let mut cache_store_stmts: Vec<String> = Vec::new();
    for dep_expr in &dep_exprs {
        let dep_slot = cx.alloc_cache_slot();
        change_exprs.push(
            render_cache_slot_comparison_expression_ast(
                &cache_var,
                dep_slot,
                BinaryOperator::StrictNotEq,
                dep_expr,
            )
            .expect("callback dependency comparison should stay on AST path"),
        );
        cache_store_stmts.push(
            render_cache_slot_store_statement_ast(&cache_var, dep_slot, dep_expr)
                .expect("callback dependency store should stay on AST path"),
        );
    }
    let callback_slot = cx.alloc_cache_slot();

    let callback_ev = codegen_instruction_value_ev(cx, &callback_instr.value);
    let callback_expr = callback_ev.wrap_if_needed(ExprPrecedence::Assignment);

    let mut computation = String::new();
    computation.push_str(
        &render_reactive_assignment_statement_ast(&target_name, &callback_expr)
            .expect("callback assignment should stay on AST path"),
    );

    for stmt in &following_stmts[..dep_scope_idx] {
        let ReactiveStatement::Instruction(instr) = stmt else {
            cx.restore_temps(temp_snapshot);
            return None;
        };
        if let Some(stmt_text) = codegen_instruction_nullable(cx, instr) {
            computation.push_str(&stmt_text);
            if !stmt_text.ends_with('\n') {
                computation.push('\n');
            }
        }
    }

    computation.push_str(&codegen_scope_computation_no_reset(
        cx,
        &dep_scope.scope,
        &dep_scope.instructions,
    ));
    for instr in post_dep_instructions {
        if let Some(stmt_text) = codegen_instruction_nullable(cx, instr) {
            computation.push_str(&stmt_text);
            if !stmt_text.ends_with('\n') {
                computation.push('\n');
            }
        }
    }
    cache_store_stmts.push(
        render_cache_slot_store_statement_ast(&cache_var, callback_slot, &target_name)
            .expect("callback cache store should stay on AST path"),
    );

    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut consequent = parse_statement_list_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        &computation,
    )
    .ok()?;
    for stmt in &cache_store_stmts {
        consequent.extend(
            parse_statement_list_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                stmt,
            )
            .ok()?,
        );
    }
    let alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &target_name,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(
                SPAN,
                callback_slot as f64,
                None,
                NumberBase::Decimal,
            ),
        ),
    ));
    let statement = builder.statement_if(
        SPAN,
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &render_logical_chain_expression_ast(&change_exprs, LogicalOperator::Or)
                .expect("callback change guard should stay on AST path"),
        )
        .expect("callback change guard should stay on AST path"),
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    );
    output.push_str(&format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ));

    cx.restore_temps(temp_snapshot);
    Some(dep_scope_idx + consumed_after_dep)
}

fn is_zero_dep_empty_array_scope(stmt: &ReactiveStatement) -> Option<DeclarationId> {
    let ReactiveStatement::Scope(scope_block) = stmt else {
        return None;
    };
    let (decl_id, source_instr) = zero_dep_single_decl_scope_source(scope_block)?;
    match &source_instr.value {
        InstructionValue::ArrayExpression { elements, .. } if elements.is_empty() => Some(decl_id),
        _ => None,
    }
}

fn args_match_effect_callback_and_deps(
    args: &[Argument],
    callback_decl: DeclarationId,
    deps_decl: DeclarationId,
) -> bool {
    let Some(callback_idx) = args.iter().position(|arg| {
        matches!(arg, Argument::Place(place) if place.identifier.declaration_id == callback_decl)
    }) else {
        return false;
    };
    args.iter().skip(callback_idx + 1).any(
        |arg| matches!(arg, Argument::Place(place) if place.identifier.declaration_id == deps_decl),
    )
}

fn maybe_codegen_fused_effect_callback_empty_array_scope(
    cx: &mut Context,
    callback_scope: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
    output: &mut String,
) -> Option<usize> {
    if !callback_scope.scope.reassignments.is_empty()
        || callback_scope.scope.declarations.len() != 1
        || callback_scope.instructions.len() != 1
    {
        return None;
    }

    let callback_decl = callback_scope
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .declaration_id;
    let callback_ident = callback_scope
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .clone();
    let ReactiveStatement::Instruction(callback_instr) = callback_scope.instructions.first()?
    else {
        return None;
    };
    let callback_lvalue = callback_instr.lvalue.as_ref()?;
    if callback_lvalue.identifier.declaration_id != callback_decl {
        return None;
    }
    if !matches!(
        callback_instr.value,
        InstructionValue::FunctionExpression { .. } | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    let filtered_callback_deps: Vec<ReactiveScopeDependency> = callback_scope
        .scope
        .dependencies
        .iter()
        .filter(|dep| {
            !cx.stable_zero_dep_decls
                .contains(&dep.identifier.declaration_id)
        })
        .cloned()
        .collect();
    if !filtered_callback_deps.is_empty() {
        return None;
    }

    let ReactiveStatement::Scope(deps_scope) = following_stmts.first()? else {
        return None;
    };
    if !deps_scope.scope.dependencies.is_empty()
        || !deps_scope.scope.reassignments.is_empty()
        || deps_scope.scope.declarations.len() != 1
        || deps_scope.instructions.len() != 1
    {
        return None;
    }

    let deps_decl = deps_scope
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .declaration_id;
    let deps_ident = deps_scope
        .scope
        .declarations
        .values()
        .next()?
        .identifier
        .clone();
    let ReactiveStatement::Instruction(deps_instr) = deps_scope.instructions.first()? else {
        return None;
    };
    let deps_lvalue = deps_instr.lvalue.as_ref()?;
    if deps_lvalue.identifier.declaration_id != deps_decl {
        return None;
    }
    if !matches!(
        &deps_instr.value,
        InstructionValue::ArrayExpression { elements, .. } if elements.is_empty()
    ) {
        return None;
    }

    let ReactiveStatement::Instruction(hook_instr) = following_stmts.get(1)? else {
        return None;
    };
    let matches_effect_hook = match &hook_instr.value {
        InstructionValue::CallExpression { callee, args, .. } => resolve_place_name(cx, callee)
            .and_then(|name| extract_hook_name(&name).map(str::to_string))
            .is_some_and(|hook_name| {
                is_effect_like_hook_name(&hook_name)
                    && args_match_effect_callback_and_deps(args, callback_decl, deps_decl)
            }),
        InstructionValue::MethodCall { property, args, .. } => resolve_place_name(cx, property)
            .and_then(|name| extract_hook_name(&name).map(str::to_string))
            .is_some_and(|hook_name| {
                is_effect_like_hook_name(&hook_name)
                    && args_match_effect_callback_and_deps(args, callback_decl, deps_decl)
            }),
        _ => false,
    };
    if !matches_effect_hook {
        return None;
    }

    let callback_name = identifier_name_with_cx(cx, &callback_ident);
    let deps_name = identifier_name_with_cx(cx, &deps_ident);
    if callback_name.is_empty() || deps_name.is_empty() {
        return None;
    }

    let cache_var = cx.synthesize_name("$");
    let callback_slot = cx.alloc_cache_slot();
    let deps_slot = cx.alloc_cache_slot();
    let callback_expr = codegen_instruction_value_ev(cx, &callback_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let deps_expr = codegen_instruction_value_ev(cx, &deps_instr.value)
        .wrap_if_needed(ExprPrecedence::Assignment);
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);

    let mut rendered = builder.vec();
    if !has_materialized_named_binding(cx, &callback_ident) {
        rendered.push(ast::Statement::VariableDeclaration(
            builder.alloc_variable_declaration(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.vec1(builder.variable_declarator(
                    SPAN,
                    ast::VariableDeclarationKind::Let,
                    builder.binding_pattern_binding_identifier(SPAN, builder.ident(&callback_name)),
                    NONE,
                    None,
                    false,
                )),
                false,
            ),
        ));
        cx.mark_decl_runtime_emitted(callback_ident.declaration_id);
    }
    if !has_materialized_named_binding(cx, &deps_ident) {
        rendered.push(ast::Statement::VariableDeclaration(
            builder.alloc_variable_declaration(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.vec1(builder.variable_declarator(
                    SPAN,
                    ast::VariableDeclarationKind::Let,
                    builder.binding_pattern_binding_identifier(SPAN, builder.ident(&deps_name)),
                    NONE,
                    None,
                    false,
                )),
                false,
            ),
        ));
        cx.mark_decl_runtime_emitted(deps_ident.declaration_id);
    }
    cx.declare(&callback_ident);
    cx.declare(&deps_ident);

    let mut consequent = builder.vec();
    consequent.push(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &callback_name,
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &callback_expr,
        )
        .ok()?,
    ));
    consequent.push(build_identifier_assignment_statement_ast_with_expression(
        builder,
        &deps_name,
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), &deps_expr)
            .ok()?,
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, callback_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&callback_name)),
    ));
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        &cache_var,
        builder.expression_numeric_literal(SPAN, deps_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(&deps_name)),
    ));

    let alternate = builder.vec_from_iter([
        build_identifier_assignment_statement_ast_with_expression(
            builder,
            &callback_name,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    callback_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
        ),
        build_identifier_assignment_statement_ast_with_expression(
            builder,
            &deps_name,
            build_computed_member_expression_ast(
                builder,
                &cache_var,
                builder.expression_numeric_literal(
                    SPAN,
                    deps_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
        ),
    ]);

    let test = builder.expression_binary(
        SPAN,
        build_computed_member_expression_ast(
            builder,
            &cache_var,
            builder.expression_numeric_literal(
                SPAN,
                callback_slot as f64,
                None,
                NumberBase::Decimal,
            ),
        ),
        AstBinaryOperator::StrictEquality,
        build_symbol_for_call_expression_ast(builder, MEMO_CACHE_SENTINEL),
    );
    rendered.push(builder.statement_if(
        SPAN,
        test,
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    ));
    for statement in rendered {
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
    }

    cx.stable_zero_dep_decls
        .insert(callback_ident.declaration_id);
    cx.stable_zero_dep_decls.insert(deps_ident.declaration_id);

    Some(1)
}

fn filtered_effect_callback_deps_for_explicit_empty_array(
    cx: &Context,
    scope_block: &ReactiveScopeBlock,
    following_stmts: &[ReactiveStatement],
) -> Option<Vec<ReactiveScopeDependency>> {
    if scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.len() != 1
    {
        return None;
    }

    let callback_decl = scope_block
        .scope
        .declarations
        .values()
        .next()
        .map(|decl| decl.identifier.declaration_id)?;
    let ReactiveStatement::Instruction(callback_instr) = scope_block.instructions.first()? else {
        return None;
    };
    if callback_instr
        .lvalue
        .as_ref()
        .is_none_or(|lvalue| lvalue.identifier.declaration_id != callback_decl)
    {
        return None;
    }
    if !matches!(
        callback_instr.value,
        InstructionValue::FunctionExpression { .. } | InstructionValue::ObjectMethod { .. }
    ) {
        return None;
    }

    let deps_decl = following_stmts
        .first()
        .and_then(is_zero_dep_empty_array_scope)?;
    let Some(ReactiveStatement::Instruction(hook_instr)) = following_stmts.get(1) else {
        return None;
    };

    let matches_effect_hook = match &hook_instr.value {
        InstructionValue::CallExpression { callee, args, .. } => resolve_place_name(cx, callee)
            .and_then(|name| extract_hook_name(&name).map(str::to_string))
            .is_some_and(|hook_name| {
                is_effect_like_hook_name(&hook_name)
                    && args_match_effect_callback_and_deps(args, callback_decl, deps_decl)
            }),
        InstructionValue::MethodCall { property, args, .. } => resolve_place_name(cx, property)
            .and_then(|name| extract_hook_name(&name).map(str::to_string))
            .is_some_and(|hook_name| {
                is_effect_like_hook_name(&hook_name)
                    && args_match_effect_callback_and_deps(args, callback_decl, deps_decl)
            }),
        _ => false,
    };

    if !matches_effect_hook {
        return None;
    }

    let filtered: Vec<ReactiveScopeDependency> = scope_block
        .scope
        .dependencies
        .iter()
        .filter(|dep| {
            !cx.stable_zero_dep_decls
                .contains(&dep.identifier.declaration_id)
        })
        .cloned()
        .collect();

    if filtered.len() == scope_block.scope.dependencies.len() {
        return None;
    }

    if std::env::var("DEBUG_SCOPE_DEP_OVERRIDE").is_ok() {
        eprintln!(
            "[SCOPE_DEP_OVERRIDE] drop stable zero-dep effect callback deps callback_decl={} scope={} before={:?} after={:?}",
            callback_decl.0,
            scope_block.scope.id.0,
            scope_block
                .scope
                .dependencies
                .iter()
                .map(format_dependency_name)
                .collect::<Vec<_>>(),
            filtered
                .iter()
                .map(format_dependency_name)
                .collect::<Vec<_>>()
        );
    }

    Some(filtered)
}

fn should_inline_zero_dep_global_zero_arg_call_scope(
    cx: &mut Context,
    scope_block: &ReactiveScopeBlock,
    preceding_stmts: &[ReactiveStatement],
    following_stmts: &[ReactiveStatement],
) -> bool {
    if !scope_block.scope.dependencies.is_empty()
        || !scope_block.scope.reassignments.is_empty()
        || scope_block.scope.declarations.len() != 1
        || scope_block.instructions.len() != 1
    {
        return false;
    }
    // Keep this memo scope when downstream calls still consume AUTODEPS values
    // (typical hook lowering), otherwise we can lose an upstream cache slot.
    let has_autodeps_call =
        block_contains_autodeps_call_usage(following_stmts, &mut HashSet::new());
    let has_hook_call = block_contains_hook_call(cx, following_stmts);
    if has_autodeps_call {
        return false;
    }
    // Keep this memo scope when downstream statements contain hook calls.
    // Upstream frequently preserves a cache slot for values captured by later hooks.
    if has_hook_call {
        return false;
    }
    // Avoid inlining inside blocks that already passed through control-flow
    // terminals (if/switch/loops/try), where upstream usually preserves memo slots.
    if preceding_stmts
        .iter()
        .any(|stmt| matches!(stmt, ReactiveStatement::Terminal(_)))
    {
        return false;
    }
    // Keep this optimization narrow: only inline when the scope output is
    // immediately forwarded into a local binding that is returned.
    let Some(scope_decl_id) = scope_block
        .scope
        .declarations
        .values()
        .next()
        .map(|decl| decl.identifier.declaration_id)
    else {
        return false;
    };
    if !matches_immediate_return_passthrough(scope_decl_id, following_stmts) {
        return false;
    }
    let Some(ReactiveStatement::Instruction(instr)) = scope_block.instructions.first() else {
        return false;
    };
    if instruction_has_autodeps_placeholder(cx, instr)
        || instruction_has_callback_and_array_args(cx, instr)
    {
        return false;
    }
    match &instr.value {
        InstructionValue::CallExpression { callee, args, .. } => {
            if !args.is_empty() {
                return false;
            }
            // Restrict to non-local/global callees to avoid inlining local
            // callback scopes (e.g. callback() wrappers that upstream memoizes).
            // Lowered imports often flow through LoadGlobal temporaries with
            // non-zero declaration ids, so rely on tracked origin metadata.
            if callee.identifier.declaration_id.0 != 0
                && !cx
                    .non_local_binding_decls
                    .contains(&callee.identifier.declaration_id)
            {
                return false;
            }
            let callee_name = resolve_place_name(cx, callee)
                .unwrap_or_else(|| codegen_place_to_expression(cx, callee));
            extract_hook_name(&callee_name).is_none()
        }
        _ => false,
    }
}

fn matches_immediate_return_passthrough(
    scope_output_decl: DeclarationId,
    following_stmts: &[ReactiveStatement],
) -> bool {
    if following_stmts.len() != 3 {
        return false;
    }

    let (
        ReactiveStatement::Instruction(store_instr),
        ReactiveStatement::Instruction(load_instr),
        ReactiveStatement::Terminal(term_stmt),
    ) = (
        &following_stmts[0],
        &following_stmts[1],
        &following_stmts[2],
    )
    else {
        return false;
    };

    let (store_target_decl, store_rhs_decl) = match &store_instr.value {
        InstructionValue::StoreLocal { lvalue, value, .. } => {
            if lvalue.kind == InstructionKind::Reassign {
                return false;
            }
            (
                lvalue.place.identifier.declaration_id,
                value.identifier.declaration_id,
            )
        }
        _ => return false,
    };
    if store_rhs_decl != scope_output_decl {
        return false;
    }

    let load_lvalue_decl = match &load_instr.value {
        InstructionValue::LoadLocal { place, .. }
            if place.identifier.declaration_id == store_target_decl =>
        {
            load_instr
                .lvalue
                .as_ref()
                .map(|lvalue| lvalue.identifier.declaration_id)
        }
        _ => None,
    };
    let Some(load_lvalue_decl) = load_lvalue_decl else {
        return false;
    };

    matches!(
        &term_stmt.terminal,
        ReactiveTerminal::Return { value, .. } if value.identifier.declaration_id == load_lvalue_decl
    )
}

fn block_contains_autodeps_call_usage(
    block: &[ReactiveStatement],
    autodeps_decls: &mut HashSet<DeclarationId>,
) -> bool {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if instruction_contains_autodeps_call_usage(instr, autodeps_decls) {
                    return true;
                }
            }
            ReactiveStatement::Scope(scope_block) => {
                let mut nested_autodeps = autodeps_decls.clone();
                if block_contains_autodeps_call_usage(
                    &scope_block.instructions,
                    &mut nested_autodeps,
                ) {
                    return true;
                }
                autodeps_decls.extend(nested_autodeps);
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                let mut nested_autodeps = autodeps_decls.clone();
                if block_contains_autodeps_call_usage(
                    &scope_block.instructions,
                    &mut nested_autodeps,
                ) {
                    return true;
                }
                autodeps_decls.extend(nested_autodeps);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                let mut nested_autodeps = autodeps_decls.clone();
                if terminal_contains_autodeps_call_usage(&term_stmt.terminal, &mut nested_autodeps)
                {
                    return true;
                }
                autodeps_decls.extend(nested_autodeps);
            }
        }
    }
    false
}

fn block_contains_hook_call(cx: &mut Context, block: &[ReactiveStatement]) -> bool {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                if instruction_is_hook_call(cx, instr) {
                    return true;
                }
            }
            ReactiveStatement::Scope(scope_block) => {
                if block_contains_hook_call(cx, &scope_block.instructions) {
                    return true;
                }
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                if block_contains_hook_call(cx, &scope_block.instructions) {
                    return true;
                }
            }
            ReactiveStatement::Terminal(term_stmt) => {
                if terminal_contains_hook_call(cx, &term_stmt.terminal) {
                    return true;
                }
            }
        }
    }
    false
}

fn terminal_contains_hook_call(cx: &mut Context, terminal: &ReactiveTerminal) -> bool {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            block_contains_hook_call(cx, consequent)
                || alternate
                    .as_ref()
                    .is_some_and(|block| block_contains_hook_call(cx, block))
        }
        ReactiveTerminal::Switch { cases, .. } => cases
            .iter()
            .filter_map(|case| case.block.as_ref())
            .any(|block| block_contains_hook_call(cx, block)),
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => block_contains_hook_call(cx, loop_block),
        ReactiveTerminal::Try { block, handler, .. } => {
            block_contains_hook_call(cx, block) || block_contains_hook_call(cx, handler)
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => false,
    }
}

fn instruction_is_hook_call(cx: &mut Context, instr: &ReactiveInstruction) -> bool {
    match &instr.value {
        InstructionValue::CallExpression { callee, .. } => {
            let callee_name = resolve_place_name(cx, callee)
                .unwrap_or_else(|| codegen_place_to_expression(cx, callee));
            extract_hook_name(&callee_name).is_some()
        }
        InstructionValue::MethodCall {
            receiver, property, ..
        } => {
            let receiver_name = resolve_place_name(cx, receiver)
                .unwrap_or_else(|| codegen_place_to_expression(cx, receiver));
            let (property_name, _) = resolve_method_property(cx, property, &receiver_name);
            Environment::is_hook_name(&property_name)
        }
        _ => false,
    }
}

fn collect_declaration_assignment_edges_in_block(
    block: &[ReactiveStatement],
    out: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => match &instr.value {
                InstructionValue::StoreLocal { lvalue, value, .. }
                | InstructionValue::StoreContext { lvalue, value, .. } => {
                    out.push((
                        value.identifier.declaration_id,
                        lvalue.place.identifier.declaration_id,
                    ));
                }
                _ => {}
            },
            ReactiveStatement::Scope(scope_block) => {
                collect_declaration_assignment_edges_in_block(&scope_block.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                collect_declaration_assignment_edges_in_block(&scope_block.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_declaration_assignment_edges_in_terminal(&term_stmt.terminal, out);
            }
        }
    }
}

fn collect_declaration_assignment_edges_in_terminal(
    terminal: &ReactiveTerminal,
    out: &mut Vec<(DeclarationId, DeclarationId)>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_declaration_assignment_edges_in_block(consequent, out);
            if let Some(alt) = alternate {
                collect_declaration_assignment_edges_in_block(alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_declaration_assignment_edges_in_block(block, out);
                }
            }
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_declaration_assignment_edges_in_block(loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_declaration_assignment_edges_in_block(block, out);
            collect_declaration_assignment_edges_in_block(handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_hook_callback_decl_ids_in_block(
    cx: &mut Context,
    block: &[ReactiveStatement],
    out: &mut HashSet<DeclarationId>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                collect_hook_callback_decl_ids_from_instruction(cx, instr, out);
            }
            ReactiveStatement::Scope(scope_block) => {
                collect_hook_callback_decl_ids_in_block(cx, &scope_block.instructions, out);
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                collect_hook_callback_decl_ids_in_block(cx, &scope_block.instructions, out);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_hook_callback_decl_ids_in_terminal(cx, &term_stmt.terminal, out);
            }
        }
    }
}

fn collect_hook_callback_decl_ids_in_terminal(
    cx: &mut Context,
    terminal: &ReactiveTerminal,
    out: &mut HashSet<DeclarationId>,
) {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_hook_callback_decl_ids_in_block(cx, consequent, out);
            if let Some(alt) = alternate {
                collect_hook_callback_decl_ids_in_block(cx, alt, out);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_hook_callback_decl_ids_in_block(cx, block, out);
                }
            }
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => {
            collect_hook_callback_decl_ids_in_block(cx, loop_block, out);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_hook_callback_decl_ids_in_block(cx, block, out);
            collect_hook_callback_decl_ids_in_block(cx, handler, out);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_hook_callback_decl_ids_from_instruction(
    cx: &mut Context,
    instr: &ReactiveInstruction,
    out: &mut HashSet<DeclarationId>,
) {
    prime_hook_name_resolution_from_instruction(cx, instr);
    match &instr.value {
        InstructionValue::CallExpression { callee, args, .. } => {
            out.insert(callee.identifier.declaration_id);
            let is_hook_call = resolve_place_name(cx, callee)
                .is_some_and(|name| extract_hook_name(&name).is_some());
            if !is_hook_call {
                return;
            }
            for arg in args {
                if let Argument::Place(place) = arg {
                    out.insert(place.identifier.declaration_id);
                }
            }
        }
        InstructionValue::MethodCall { property, args, .. } => {
            let is_hook_call = resolve_place_name(cx, property)
                .is_some_and(|name| extract_hook_name(&name).is_some());
            if !is_hook_call {
                return;
            }
            for arg in args {
                if let Argument::Place(place) = arg {
                    out.insert(place.identifier.declaration_id);
                }
            }
        }
        InstructionValue::FunctionExpression { lowered_func, .. }
        | InstructionValue::ObjectMethod { lowered_func, .. } => {
            collect_invoked_capture_decls_from_lowered_function(lowered_func, out);
        }
        _ => {}
    }
}

fn collect_invoked_capture_decls_from_lowered_function(
    lowered_func: &LoweredFunction,
    out: &mut HashSet<DeclarationId>,
) {
    let mut captured_roots: HashSet<DeclarationId> = HashSet::new();
    for place in &lowered_func.func.context {
        captured_roots.insert(place.identifier.declaration_id);
    }
    if captured_roots.is_empty() {
        return;
    }

    let mut alias_to_capture: HashMap<DeclarationId, DeclarationId> = HashMap::new();
    for (_, block) in &lowered_func.func.body.blocks {
        for instr in &block.instructions {
            let lvalue_decl = instr.lvalue.identifier.declaration_id;
            match &instr.value {
                InstructionValue::LoadContext { place, .. } => {
                    let source_decl = place.identifier.declaration_id;
                    if captured_roots.contains(&source_decl) {
                        alias_to_capture.insert(lvalue_decl, source_decl);
                    }
                }
                InstructionValue::LoadLocal { place, .. }
                | InstructionValue::TypeCastExpression { value: place, .. } => {
                    if let Some(source_root) = alias_to_capture
                        .get(&place.identifier.declaration_id)
                        .copied()
                    {
                        alias_to_capture.insert(lvalue_decl, source_root);
                    }
                }
                _ => {}
            }

            if let InstructionValue::CallExpression { callee, .. } = &instr.value {
                let callee_decl = callee.identifier.declaration_id;
                if let Some(source_root) = alias_to_capture.get(&callee_decl).copied() {
                    out.insert(source_root);
                } else if captured_roots.contains(&callee_decl) {
                    out.insert(callee_decl);
                }
            }

            match &instr.value {
                InstructionValue::FunctionExpression { lowered_func, .. }
                | InstructionValue::ObjectMethod { lowered_func, .. } => {
                    collect_invoked_capture_decls_from_lowered_function(lowered_func, out);
                }
                _ => {}
            }
        }
    }
}

fn prime_hook_name_resolution_from_instruction(cx: &mut Context, instr: &ReactiveInstruction) {
    let Some(lvalue) = &instr.lvalue else {
        return;
    };
    match &instr.value {
        InstructionValue::LoadGlobal { binding, .. } => {
            cx.resolved_names
                .insert(lvalue.identifier.id, load_global_resolved_name(binding));
        }
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            if let Some(name) = resolve_place_name(cx, place) {
                cx.resolved_names.insert(lvalue.identifier.id, name);
            }
        }
        InstructionValue::TypeCastExpression { value, .. } => {
            if let Some(name) = resolve_place_name(cx, value) {
                cx.resolved_names.insert(lvalue.identifier.id, name);
            }
        }
        InstructionValue::PropertyLoad {
            object,
            property: PropertyLiteral::String(prop),
            ..
        } => {
            if let Some(base) = resolve_place_name(cx, object) {
                cx.resolved_names
                    .insert(lvalue.identifier.id, format!("{base}.{prop}"));
            }
        }
        _ => {}
    }
}

fn terminal_contains_autodeps_call_usage(
    terminal: &ReactiveTerminal,
    autodeps_decls: &mut HashSet<DeclarationId>,
) -> bool {
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            let mut conseq_autodeps = autodeps_decls.clone();
            if block_contains_autodeps_call_usage(consequent, &mut conseq_autodeps) {
                return true;
            }
            autodeps_decls.extend(conseq_autodeps);
            if let Some(alt) = alternate {
                let mut alt_autodeps = autodeps_decls.clone();
                if block_contains_autodeps_call_usage(alt, &mut alt_autodeps) {
                    return true;
                }
                autodeps_decls.extend(alt_autodeps);
            }
            false
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(case_block) = &case.block {
                    let mut case_autodeps = autodeps_decls.clone();
                    if block_contains_autodeps_call_usage(case_block, &mut case_autodeps) {
                        return true;
                    }
                    autodeps_decls.extend(case_autodeps);
                }
            }
            false
        }
        ReactiveTerminal::For { loop_block, .. }
        | ReactiveTerminal::ForOf { loop_block, .. }
        | ReactiveTerminal::ForIn { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. }
        | ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::Label {
            block: loop_block, ..
        } => block_contains_autodeps_call_usage(loop_block, autodeps_decls),
        ReactiveTerminal::Try { block, handler, .. } => {
            let mut try_autodeps = autodeps_decls.clone();
            if block_contains_autodeps_call_usage(block, &mut try_autodeps) {
                return true;
            }
            let mut catch_autodeps = autodeps_decls.clone();
            if block_contains_autodeps_call_usage(handler, &mut catch_autodeps) {
                return true;
            }
            autodeps_decls.extend(try_autodeps);
            autodeps_decls.extend(catch_autodeps);
            false
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => false,
    }
}

fn instruction_contains_autodeps_call_usage(
    instr: &ReactiveInstruction,
    autodeps_decls: &mut HashSet<DeclarationId>,
) -> bool {
    let track_lvalue_if_autodeps = |autodeps_decls: &mut HashSet<DeclarationId>| {
        if let Some(lvalue) = &instr.lvalue {
            autodeps_decls.insert(lvalue.identifier.declaration_id);
        }
    };
    match &instr.value {
        InstructionValue::LoadGlobal { binding, .. } => {
            if non_local_binding_is_autodeps(binding) {
                track_lvalue_if_autodeps(autodeps_decls);
            }
        }
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            if place_is_autodeps_value(place, autodeps_decls) {
                track_lvalue_if_autodeps(autodeps_decls);
            }
        }
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => {
            if place_is_autodeps_value(value, autodeps_decls) {
                autodeps_decls.insert(lvalue.place.identifier.declaration_id);
            }
        }
        InstructionValue::PropertyLoad {
            object, property, ..
        } => {
            if property_literal_is_autodeps(property)
                || place_is_autodeps_value(object, autodeps_decls)
            {
                track_lvalue_if_autodeps(autodeps_decls);
            }
        }
        InstructionValue::CallExpression { args, .. }
        | InstructionValue::MethodCall { args, .. } => {
            if args
                .iter()
                .any(|arg| argument_is_autodeps_value(arg, autodeps_decls))
            {
                return true;
            }
        }
        _ => {}
    }
    false
}

fn non_local_binding_is_autodeps(binding: &NonLocalBinding) -> bool {
    match binding {
        NonLocalBinding::ImportSpecifier { name, imported, .. } => {
            name == "AUTODEPS" || imported == "AUTODEPS"
        }
        NonLocalBinding::ImportDefault { name, .. }
        | NonLocalBinding::ImportNamespace { name, .. }
        | NonLocalBinding::ModuleLocal { name }
        | NonLocalBinding::Global { name } => name == "AUTODEPS",
    }
}

fn property_literal_is_autodeps(property: &PropertyLiteral) -> bool {
    matches!(property, PropertyLiteral::String(name) if name == "AUTODEPS")
}

fn argument_is_autodeps_value(arg: &Argument, autodeps_decls: &HashSet<DeclarationId>) -> bool {
    match arg {
        Argument::Place(place) | Argument::Spread(place) => {
            place_is_autodeps_value(place, autodeps_decls)
        }
    }
}

fn place_is_autodeps_value(place: &Place, autodeps_decls: &HashSet<DeclarationId>) -> bool {
    autodeps_decls.contains(&place.identifier.declaration_id)
        || place
            .identifier
            .name
            .as_ref()
            .is_some_and(|name| name.value() == "AUTODEPS")
}

fn is_codegen_temp_name(name: &str) -> bool {
    let trimmed = name.trim();
    if !trimmed.starts_with('t') {
        return false;
    }
    trimmed[1..].chars().all(|c| c.is_ascii_digit())
}

fn is_temp_like_identifier(_cx: &Context, id: &Identifier) -> bool {
    match &id.name {
        None => true,
        // Upstream codegen only treats unnamed identifiers as temporaries.
        // Promoted `tN` names are runtime bindings that earlier passes chose to
        // materialize, so re-inlining them here breaks evaluation order.
        Some(IdentifierName::Promoted(_)) | Some(IdentifierName::Named(_)) => false,
    }
}

fn parse_codegen_temp_index(name: &str) -> Option<u32> {
    let trimmed = name.trim();
    let suffix = trimmed.strip_prefix('t')?;
    if suffix.is_empty() || !suffix.chars().all(|c| c.is_ascii_digit()) {
        return None;
    }
    suffix.parse::<u32>().ok()
}

fn debug_codegen_expr(tag: &str, detail: impl AsRef<str>) {
    if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
        eprintln!("[CODEGEN_EXPR] {} {}", tag, detail.as_ref());
    }
}

fn instruction_value_tag(value: &InstructionValue) -> &'static str {
    match value {
        InstructionValue::Primitive { .. } => "Primitive",
        InstructionValue::LoadLocal { .. } => "LoadLocal",
        InstructionValue::LoadContext { .. } => "LoadContext",
        InstructionValue::LoadGlobal { .. } => "LoadGlobal",
        InstructionValue::StoreLocal { .. } => "StoreLocal",
        InstructionValue::StoreContext { .. } => "StoreContext",
        InstructionValue::DeclareLocal { .. } => "DeclareLocal",
        InstructionValue::DeclareContext { .. } => "DeclareContext",
        InstructionValue::CallExpression { .. } => "CallExpression",
        InstructionValue::MethodCall { .. } => "MethodCall",
        InstructionValue::ReactiveSequenceExpression { .. } => "ReactiveSequenceExpression",
        InstructionValue::ReactiveOptionalExpression { .. } => "ReactiveOptionalExpression",
        InstructionValue::ReactiveLogicalExpression { .. } => "ReactiveLogicalExpression",
        InstructionValue::ReactiveConditionalExpression { .. } => "ReactiveConditionalExpression",
        InstructionValue::JsxExpression { .. } => "JsxExpression",
        InstructionValue::StartMemoize { .. } => "StartMemoize",
        InstructionValue::FinishMemoize { .. } => "FinishMemoize",
        _ => "Other",
    }
}

/// Check if a reactive block references an identifier with the given name.
/// Used to detect whether a catch body uses the original catch binding name.
fn handler_block_references_name(block: &ReactiveBlock, name: &str) -> bool {
    fn check_place(place: &Place, name: &str) -> bool {
        match &place.identifier.name {
            Some(IdentifierName::Named(n)) | Some(IdentifierName::Promoted(n)) => n == name,
            None => false,
        }
    }

    fn check_arg(arg: &Argument, name: &str) -> bool {
        match arg {
            Argument::Place(p) | Argument::Spread(p) => check_place(p, name),
        }
    }

    fn check_instr(instr: &ReactiveInstruction, name: &str) -> bool {
        // Check lvalue
        if let Some(ref lv) = instr.lvalue
            && check_place(lv, name)
        {
            return true;
        }
        // Check instruction value operands
        match &instr.value {
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => check_place(place, name),
            InstructionValue::StoreLocal { lvalue, value, .. } => {
                check_place(&lvalue.place, name) || check_place(value, name)
            }
            InstructionValue::CallExpression { callee, args, .. } => {
                check_place(callee, name) || args.iter().any(|a| check_arg(a, name))
            }
            InstructionValue::MethodCall {
                receiver,
                property,
                args,
                ..
            } => {
                check_place(receiver, name)
                    || check_place(property, name)
                    || args.iter().any(|a| check_arg(a, name))
            }
            InstructionValue::PropertyLoad { object, .. } => check_place(object, name),
            InstructionValue::ArrayExpression { elements, .. } => {
                elements.iter().any(|e| match e {
                    ArrayElement::Place(p) | ArrayElement::Spread(p) => check_place(p, name),
                    ArrayElement::Hole => false,
                })
            }
            InstructionValue::LoadGlobal { binding, .. } => binding.name() == name,
            _ => false,
        }
    }

    fn check_block(block: &ReactiveBlock, name: &str) -> bool {
        for stmt in block {
            match stmt {
                ReactiveStatement::Instruction(instr) => {
                    if check_instr(instr, name) {
                        return true;
                    }
                }
                ReactiveStatement::Terminal(term_stmt) => {
                    if check_terminal(&term_stmt.terminal, name) {
                        return true;
                    }
                }
                ReactiveStatement::Scope(scope_block) => {
                    if check_block(&scope_block.instructions, name) {
                        return true;
                    }
                }
                ReactiveStatement::PrunedScope(pruned) => {
                    if check_block(&pruned.instructions, name) {
                        return true;
                    }
                }
            }
        }
        false
    }

    fn check_terminal(terminal: &ReactiveTerminal, name: &str) -> bool {
        match terminal {
            ReactiveTerminal::Return { value, .. } | ReactiveTerminal::Throw { value, .. } => {
                check_place(value, name)
            }
            ReactiveTerminal::If {
                consequent,
                alternate,
                ..
            } => {
                check_block(consequent, name)
                    || alternate.as_ref().is_some_and(|b| check_block(b, name))
            }
            ReactiveTerminal::Switch { cases, .. } => cases
                .iter()
                .any(|c| c.block.as_ref().is_some_and(|b| check_block(b, name))),
            ReactiveTerminal::For { loop_block, .. }
            | ReactiveTerminal::ForOf { loop_block, .. }
            | ReactiveTerminal::ForIn { loop_block, .. }
            | ReactiveTerminal::While { loop_block, .. }
            | ReactiveTerminal::DoWhile { loop_block, .. } => check_block(loop_block, name),
            ReactiveTerminal::Label { block, .. } => check_block(block, name),
            ReactiveTerminal::Try { block, handler, .. } => {
                check_block(block, name) || check_block(handler, name)
            }
            _ => false,
        }
    }

    check_block(block, name)
}

fn instruction_has_autodeps_placeholder(cx: &mut Context, instr: &ReactiveInstruction) -> bool {
    let args: &[Argument] = match &instr.value {
        InstructionValue::CallExpression { args, .. }
        | InstructionValue::MethodCall { args, .. } => args.as_slice(),
        _ => return false,
    };
    args.iter()
        .map(|arg| codegen_argument(cx, arg))
        .any(|arg| rendered_expr_is_autodeps_placeholder(&arg))
}

fn instruction_has_callback_and_array_args(cx: &mut Context, instr: &ReactiveInstruction) -> bool {
    let args: &[Argument] = match &instr.value {
        InstructionValue::CallExpression { args, .. }
        | InstructionValue::MethodCall { args, .. } => args.as_slice(),
        _ => return false,
    };
    let rendered_args: Vec<String> = args.iter().map(|arg| codegen_argument(cx, arg)).collect();
    let has_callback_arg = rendered_args
        .iter()
        .any(|arg| rendered_expr_is_function_like(arg))
        || args.iter().any(is_function_argument);
    let has_array_arg = rendered_args
        .iter()
        .any(|arg| rendered_expr_is_array_literal(arg))
        || args.iter().any(is_array_argument);
    has_callback_arg && has_array_arg
}

fn is_function_argument(arg: &Argument) -> bool {
    let place = match arg {
        Argument::Place(p) | Argument::Spread(p) => p,
    };
    matches!(place.identifier.type_, Type::Function { .. })
}

fn is_array_argument(arg: &Argument) -> bool {
    let place = match arg {
        Argument::Place(p) | Argument::Spread(p) => p,
    };
    matches!(
        &place.identifier.type_,
        Type::Object {
            shape_id: Some(shape),
        } if shape == BUILT_IN_ARRAY_ID
    )
}

fn memoizable_if_reassignment_scope_bridge<'a>(
    terminal: &'a ReactiveTerminal,
    following_stmts: &'a [ReactiveStatement],
) -> Option<(&'a Place, Identifier)> {
    let debug = std::env::var("DEBUG_SCOPE_BRIDGE").is_ok();

    let ReactiveTerminal::If {
        test,
        consequent,
        alternate: Some(alternate),
        ..
    } = terminal
    else {
        if debug {
            eprintln!("[SCOPE_BRIDGE] reject: terminal is not if-with-else");
        }
        return None;
    };

    let Some(cons_target) = extract_single_reassign_target(consequent) else {
        if debug {
            eprintln!("[SCOPE_BRIDGE] reject: consequent is not single reassign");
        }
        return None;
    };
    let Some(alt_target) = extract_single_reassign_target(alternate) else {
        if debug {
            eprintln!("[SCOPE_BRIDGE] reject: alternate is not single reassign");
        }
        return None;
    };
    if cons_target.declaration_id != alt_target.declaration_id {
        if debug {
            eprintln!(
                "[SCOPE_BRIDGE] reject: branch targets differ cons={} alt={}",
                cons_target.declaration_id.0, alt_target.declaration_id.0
            );
        }
        return None;
    }

    let mut next_scope = None;
    for stmt in following_stmts {
        match stmt {
            ReactiveStatement::Instruction(instr) if is_ignorable_bridge_interstitial(instr) => {}
            ReactiveStatement::Scope(scope_stmt) => {
                next_scope = Some(scope_stmt);
                break;
            }
            _ => break,
        }
    }
    let Some(next_scope) = next_scope else {
        if debug {
            eprintln!("[SCOPE_BRIDGE] reject: no reachable next scope");
        }
        return None;
    };
    let used_by_next_scope = next_scope.scope.dependencies.iter().any(|dep| {
        dep.path.is_empty() && dep.identifier.declaration_id == cons_target.declaration_id
    });
    if !used_by_next_scope {
        if debug {
            eprintln!(
                "[SCOPE_BRIDGE] reject: next scope does not depend on target decl={} name={}",
                cons_target.declaration_id.0,
                identifier_name_static(&cons_target)
            );
        }
        return None;
    }

    if debug {
        eprintln!(
            "[SCOPE_BRIDGE] accept: target decl={} name={} dep_count={}",
            cons_target.declaration_id.0,
            identifier_name_static(&cons_target),
            next_scope.scope.dependencies.len()
        );
    }

    Some((test, cons_target))
}

fn is_ignorable_bridge_interstitial(instr: &ReactiveInstruction) -> bool {
    matches!(
        instr.value,
        InstructionValue::DeclareLocal { .. }
            | InstructionValue::DeclareContext { .. }
            | InstructionValue::StartMemoize { .. }
            | InstructionValue::FinishMemoize { .. }
            | InstructionValue::LoadGlobal { .. }
            | InstructionValue::LoadLocal { .. }
            | InstructionValue::LoadContext { .. }
            | InstructionValue::Primitive { .. }
            | InstructionValue::TypeCastExpression { .. }
    )
}

fn extract_single_reassign_target(block: &ReactiveBlock) -> Option<Identifier> {
    let debug = std::env::var("DEBUG_SCOPE_BRIDGE").is_ok();
    if debug {
        eprintln!(
            "[SCOPE_BRIDGE] inspect branch block: {} statements",
            block.len()
        );
    }
    let mut target: Option<Identifier> = None;

    for (idx, stmt) in block.iter().enumerate() {
        if debug {
            let kind = match stmt {
                ReactiveStatement::Instruction(_) => "Instruction",
                ReactiveStatement::Scope(_) => "Scope",
                ReactiveStatement::PrunedScope(_) => "PrunedScope",
                ReactiveStatement::Terminal(_) => "Terminal",
            };
            eprintln!("[SCOPE_BRIDGE]   stmt[{idx}] kind={kind}");
        }
        let ReactiveStatement::Instruction(instr) = stmt else {
            continue;
        };
        if debug {
            if let Some(lv) = &instr.lvalue {
                eprintln!(
                    "[SCOPE_BRIDGE]   - lvalue decl={} name={:?}",
                    lv.identifier.declaration_id.0, lv.identifier.name
                );
            } else {
                eprintln!("[SCOPE_BRIDGE]   - instruction has no outer lvalue");
            }
            eprintln!("[SCOPE_BRIDGE]   - value={:?}", instr.value);
        }
        match &instr.value {
            InstructionValue::StoreLocal { lvalue, .. }
            | InstructionValue::StoreContext { lvalue, .. }
                if lvalue.kind == InstructionKind::Reassign =>
            {
                if let Some(existing) = &target {
                    if existing.declaration_id != lvalue.place.identifier.declaration_id {
                        if debug {
                            eprintln!(
                                "[SCOPE_BRIDGE]   - reject: conflicting reassignment target decl={} vs {}",
                                existing.declaration_id.0, lvalue.place.identifier.declaration_id.0
                            );
                        }
                        return None;
                    }
                } else {
                    target = Some(lvalue.place.identifier.clone());
                    if debug {
                        eprintln!(
                            "[SCOPE_BRIDGE]   - captured target decl={} name={}",
                            lvalue.place.identifier.declaration_id.0,
                            identifier_name_static(&lvalue.place.identifier)
                        );
                    }
                }
            }
            InstructionValue::StoreLocal { lvalue, .. }
            | InstructionValue::StoreContext { lvalue, .. } => {
                if lvalue.place.identifier.name.is_some()
                    && target
                        .as_ref()
                        .is_some_and(|t| t.declaration_id != lvalue.place.identifier.declaration_id)
                {
                    if debug {
                        eprintln!(
                            "[SCOPE_BRIDGE]   - reject: non-reassign store to different named decl={} target={}",
                            lvalue.place.identifier.declaration_id.0,
                            target
                                .as_ref()
                                .map(|t| t.declaration_id.0.to_string())
                                .unwrap_or_else(|| "?".to_string())
                        );
                    }
                    return None;
                }
            }
            _ => {
                // Reject writes to a different named declaration inside the branch.
                if instr
                    .lvalue
                    .as_ref()
                    .is_some_and(|lv| lv.identifier.name.is_some())
                    && target
                        .as_ref()
                        .zip(instr.lvalue.as_ref())
                        .is_some_and(|(t, lv)| t.declaration_id != lv.identifier.declaration_id)
                {
                    if debug {
                        let decl_id = instr
                            .lvalue
                            .as_ref()
                            .map(|lv| lv.identifier.declaration_id.0)
                            .unwrap_or(0);
                        eprintln!(
                            "[SCOPE_BRIDGE]   - reject: write to different named decl={} target={}",
                            decl_id,
                            target
                                .as_ref()
                                .map(|t| t.declaration_id.0.to_string())
                                .unwrap_or_else(|| "?".to_string())
                        );
                    }
                    return None;
                }
            }
        }
    }

    if debug {
        match &target {
            Some(t) => eprintln!(
                "[SCOPE_BRIDGE] branch target resolved decl={} name={}",
                t.declaration_id.0,
                identifier_name_static(t)
            ),
            None => eprintln!("[SCOPE_BRIDGE] branch target unresolved"),
        }
    }

    target
}

fn update_scope_line_span(
    loc: &SourceLocation,
    start_line: &mut Option<u32>,
    end_line: &mut Option<u32>,
) {
    let SourceLocation::Source(range) = loc else {
        return;
    };
    let (Some(start), Some(mut end)) = (if range.start.line == 0 && range.end.line == 0 {
        (
            crate::source_lines::line_from_offset(range.start.column),
            crate::source_lines::line_from_offset(range.end.column),
        )
    } else {
        (Some(range.start.line), Some(range.end.line))
    }) else {
        return;
    };
    if end < start {
        end = start;
    }
    *start_line = Some(start_line.map_or(start, |line| line.min(start)));
    *end_line = Some(end_line.map_or(end, |line| line.max(end)));
}

fn collect_scope_line_span_from_terminal(
    terminal: &ReactiveTerminal,
    start_line: &mut Option<u32>,
    end_line: &mut Option<u32>,
) {
    match terminal {
        ReactiveTerminal::Break { loc, .. }
        | ReactiveTerminal::Continue { loc, .. }
        | ReactiveTerminal::Return { loc, .. }
        | ReactiveTerminal::Throw { loc, .. }
        | ReactiveTerminal::Switch { loc, .. }
        | ReactiveTerminal::DoWhile { loc, .. }
        | ReactiveTerminal::While { loc, .. }
        | ReactiveTerminal::For { loc, .. }
        | ReactiveTerminal::ForOf { loc, .. }
        | ReactiveTerminal::ForIn { loc, .. }
        | ReactiveTerminal::If { loc, .. }
        | ReactiveTerminal::Label { loc, .. }
        | ReactiveTerminal::Try { loc, .. } => update_scope_line_span(loc, start_line, end_line),
    }
    match terminal {
        ReactiveTerminal::If {
            consequent,
            alternate,
            ..
        } => {
            collect_scope_line_span_from_block(consequent, start_line, end_line);
            if let Some(alt) = alternate {
                collect_scope_line_span_from_block(alt, start_line, end_line);
            }
        }
        ReactiveTerminal::Switch { cases, .. } => {
            for case in cases {
                if let Some(block) = &case.block {
                    collect_scope_line_span_from_block(block, start_line, end_line);
                }
            }
        }
        ReactiveTerminal::DoWhile { loop_block, .. }
        | ReactiveTerminal::While { loop_block, .. } => {
            collect_scope_line_span_from_block(loop_block, start_line, end_line);
        }
        ReactiveTerminal::For {
            init,
            update,
            loop_block,
            ..
        } => {
            collect_scope_line_span_from_block(init, start_line, end_line);
            if let Some(update_block) = update {
                collect_scope_line_span_from_block(update_block, start_line, end_line);
            }
            collect_scope_line_span_from_block(loop_block, start_line, end_line);
        }
        ReactiveTerminal::ForOf {
            init, loop_block, ..
        }
        | ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            collect_scope_line_span_from_block(init, start_line, end_line);
            collect_scope_line_span_from_block(loop_block, start_line, end_line);
        }
        ReactiveTerminal::Label { block, .. } => {
            collect_scope_line_span_from_block(block, start_line, end_line);
        }
        ReactiveTerminal::Try { block, handler, .. } => {
            collect_scope_line_span_from_block(block, start_line, end_line);
            collect_scope_line_span_from_block(handler, start_line, end_line);
        }
        ReactiveTerminal::Break { .. }
        | ReactiveTerminal::Continue { .. }
        | ReactiveTerminal::Return { .. }
        | ReactiveTerminal::Throw { .. } => {}
    }
}

fn collect_scope_line_span_from_block(
    block: &ReactiveBlock,
    start_line: &mut Option<u32>,
    end_line: &mut Option<u32>,
) {
    for stmt in block {
        match stmt {
            ReactiveStatement::Instruction(instr) => {
                update_scope_line_span(&instr.loc, start_line, end_line);
            }
            ReactiveStatement::Terminal(term_stmt) => {
                collect_scope_line_span_from_terminal(&term_stmt.terminal, start_line, end_line);
            }
            ReactiveStatement::Scope(scope_block) => {
                collect_scope_line_span_from_block(&scope_block.instructions, start_line, end_line);
            }
            ReactiveStatement::PrunedScope(scope_block) => {
                collect_scope_line_span_from_block(&scope_block.instructions, start_line, end_line);
            }
        }
    }
}

fn format_change_detection_scope_loc(scope: &ReactiveScope, block: &ReactiveBlock) -> String {
    let mut start_line: Option<u32> = None;
    let mut end_line: Option<u32> = None;
    for decl in scope.declarations.values() {
        update_scope_line_span(&decl.identifier.loc, &mut start_line, &mut end_line);
    }
    for reassignment in &scope.reassignments {
        update_scope_line_span(&reassignment.loc, &mut start_line, &mut end_line);
    }
    collect_scope_line_span_from_block(block, &mut start_line, &mut end_line);
    if let (Some(start), Some(end)) = (start_line, end_line) {
        format!("({}:{})", start, end)
    } else {
        "unknown location".to_string()
    }
}

fn debug_loc(loc: &SourceLocation) -> String {
    match loc {
        SourceLocation::Source(range) => format!(
            "{}:{}-{}:{}",
            range.start.line, range.start.column, range.end.line, range.end.column
        ),
        SourceLocation::Generated => "generated".to_string(),
    }
}

fn is_readonly_console_callee(callee: &ast::Expression<'_>) -> bool {
    match callee.without_parentheses() {
        ast::Expression::StaticMemberExpression(member) => {
            let object = member.object.without_parentheses();
            matches!(
                object,
                ast::Expression::Identifier(identifier) if identifier.name == "console"
            ) || matches!(
                object,
                ast::Expression::StaticMemberExpression(parent)
                    if matches!(
                        parent.object.without_parentheses(),
                        ast::Expression::Identifier(identifier) if identifier.name == "global"
                    ) && parent.property.name == "console"
            )
        }
        ast::Expression::ChainExpression(chain) => match &chain.expression {
            ast::ChainElement::StaticMemberExpression(member) => {
                let object = member.object.without_parentheses();
                matches!(
                    object,
                    ast::Expression::Identifier(identifier) if identifier.name == "console"
                ) || matches!(
                    object,
                    ast::Expression::StaticMemberExpression(parent)
                        if matches!(
                            parent.object.without_parentheses(),
                            ast::Expression::Identifier(identifier) if identifier.name == "global"
                        ) && parent.property.name == "console"
                )
            }
            _ => false,
        },
        _ => false,
    }
}

fn strip_wrapping_parens(mut expr: &str) -> &str {
    loop {
        let trimmed = expr.trim();
        if trimmed.len() < 2 || !trimmed.starts_with('(') || !trimmed.ends_with(')') {
            return trimmed;
        }
        let mut depth = 0i32;
        let mut wraps_entire_expr = true;
        for (idx, ch) in trimmed.char_indices() {
            match ch {
                '(' => depth += 1,
                ')' => {
                    depth -= 1;
                    if depth == 0 && idx + ch.len_utf8() < trimmed.len() {
                        wraps_entire_expr = false;
                        break;
                    }
                }
                _ => {}
            }
            if depth < 0 {
                wraps_entire_expr = false;
                break;
            }
        }
        if !wraps_entire_expr || depth != 0 {
            return trimmed;
        }
        expr = &trimmed[1..trimmed.len() - 1];
    }
}

fn is_readonly_output_call_line(line: &str, output_names: &HashSet<String>) -> bool {
    let trimmed = line.trim();
    if trimmed.is_empty() || !trimmed.ends_with(");") {
        return false;
    }
    let allocator = Allocator::default();
    let statement = match parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        trimmed,
    ) {
        Ok(statement) => statement,
        Err(_) => return false,
    };
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return false;
    };
    let (callee, arguments) = match expression_statement.expression.without_parentheses() {
        ast::Expression::CallExpression(call) => (&call.callee, &call.arguments),
        ast::Expression::ChainExpression(chain) => match &chain.expression {
            ast::ChainElement::CallExpression(call) => (&call.callee, &call.arguments),
            _ => return false,
        },
        _ => return false,
    };
    if !is_readonly_console_callee(callee) {
        return false;
    }
    arguments.iter().any(|arg| {
        let ast::Argument::SpreadElement(_) = arg else {
            let rendered = codegen_expression_with_flow_cast_restore(arg.to_expression());
            let normalized = strip_wrapping_parens(&rendered);
            return output_names.contains(normalized);
        };
        false
    })
}

fn split_deferred_readonly_output_calls(
    computation: &str,
    output_names: &HashSet<String>,
) -> (String, Vec<String>) {
    let mut retained_lines: Vec<String> = Vec::new();
    let mut deferred_calls: Vec<String> = Vec::new();

    for line in computation.lines() {
        if is_readonly_output_call_line(line, output_names) {
            deferred_calls.push(format!("{}\n", line.trim()));
        } else {
            retained_lines.push(format!("{line}\n"));
        }
    }

    (retained_lines.concat(), deferred_calls)
}

fn parse_expression_statement_source(statement_source: &str) -> Option<String> {
    let allocator = Allocator::default();
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        statement_source,
    )
    .ok()?;
    let ast::Statement::ExpressionStatement(expression_statement) = statement else {
        return None;
    };
    Some(codegen_expression_with_flow_cast_restore(
        &expression_statement.expression,
    ))
}

fn split_deferred_readonly_output_calls_from_setup_statements(
    setup_statements: Vec<String>,
    output_names: &HashSet<String>,
) -> Option<(Vec<String>, Vec<String>)> {
    if output_names.is_empty() || setup_statements.is_empty() {
        return Some((setup_statements, Vec::new()));
    }

    let mut retained_statements = Vec::with_capacity(setup_statements.len());
    let mut deferred_expressions = Vec::new();

    for statement_source in setup_statements {
        if is_readonly_output_call_line(&statement_source, output_names) {
            deferred_expressions.push(parse_expression_statement_source(&statement_source)?);
        } else {
            retained_statements.push(statement_source);
        }
    }

    Some((retained_statements, deferred_expressions))
}

/// Generate a reactive scope (memoization block).
///
/// Emits: `if ($[n] !== dep || ...) { ...compute... $[n] = dep; $[m] = output; } else { output = $[m]; }`
fn codegen_reactive_scope(
    cx: &mut Context,
    output: &mut String,
    scope: &ReactiveScope,
    block: &ReactiveBlock,
) {
    if std::env::var("DEBUG_REACTIVE_SCOPE_INFO").is_ok() {
        eprintln!(
            "[REACTIVE_SCOPE] scope={} range=({},{})",
            scope.id.0, scope.range.start.0, scope.range.end.0
        );
        if !scope.dependencies.is_empty() {
            eprintln!("[REACTIVE_SCOPE] deps:");
            for dep in &scope.dependencies {
                eprintln!(
                    "  - id={} decl={} name={:?} path={:?}",
                    dep.identifier.id.0,
                    dep.identifier.declaration_id.0,
                    dep.identifier.name,
                    dep.path
                );
            }
        }
        if !scope.declarations.is_empty() {
            eprintln!("[REACTIVE_SCOPE] declarations:");
            for (id, decl) in &scope.declarations {
                eprintln!(
                    "  - key_id={} decl_id={} name={:?} scope={} loc={}",
                    id.0,
                    decl.identifier.declaration_id.0,
                    decl.identifier.name,
                    decl.scope.id.0,
                    debug_loc(&decl.identifier.loc)
                );
            }
        }
        if !scope.reassignments.is_empty() {
            eprintln!("[REACTIVE_SCOPE] reassignments:");
            for id in &scope.reassignments {
                eprintln!(
                    "  - id={} decl={} name={:?} loc={}",
                    id.id.0,
                    id.declaration_id.0,
                    id.name,
                    debug_loc(&id.loc)
                );
            }
        }
        if !block.is_empty() {
            eprintln!("[REACTIVE_SCOPE] block_locs:");
            for stmt in block {
                match stmt {
                    ReactiveStatement::Instruction(instr) => {
                        eprintln!(
                            "  - instr id={} loc={} kind={:?}",
                            instr.id.0,
                            debug_loc(&instr.loc),
                            instr.value
                        );
                    }
                    ReactiveStatement::Terminal(term_stmt) => {
                        let loc = match &term_stmt.terminal {
                            ReactiveTerminal::Break { loc, .. }
                            | ReactiveTerminal::Continue { loc, .. }
                            | ReactiveTerminal::Return { loc, .. }
                            | ReactiveTerminal::Throw { loc, .. }
                            | ReactiveTerminal::Switch { loc, .. }
                            | ReactiveTerminal::DoWhile { loc, .. }
                            | ReactiveTerminal::While { loc, .. }
                            | ReactiveTerminal::For { loc, .. }
                            | ReactiveTerminal::ForOf { loc, .. }
                            | ReactiveTerminal::ForIn { loc, .. }
                            | ReactiveTerminal::If { loc, .. }
                            | ReactiveTerminal::Label { loc, .. }
                            | ReactiveTerminal::Try { loc, .. } => loc,
                        };
                        eprintln!("  - terminal loc={}", debug_loc(loc));
                    }
                    ReactiveStatement::Scope(scope_block) => {
                        eprintln!("  - nested scope id={}", scope_block.scope.id.0);
                    }
                    ReactiveStatement::PrunedScope(pruned) => {
                        eprintln!("  - nested pruned scope id={}", pruned.scope.id.0);
                    }
                }
            }
        }
    }

    let cache_var = cx.synthesize_name("$");
    let mut change_exprs: Vec<String> = Vec::new();
    let mut change_var_stmts: Vec<String> = Vec::new();
    let mut cache_store_stmts: Vec<String> = Vec::new();
    let mut cache_load_stmts: Vec<String> = Vec::new();

    // Collect callback deps for function expressions in this scope block before
    // generating the guard, since `codegen_block` (which also records callback
    // deps) runs after dependency guards are emitted.
    let mut hook_callback_decl_ids: HashSet<DeclarationId> = HashSet::new();
    let scope_decl_ids: HashSet<DeclarationId> = scope
        .declarations
        .values()
        .map(|decl| decl.identifier.declaration_id)
        .collect();
    for decl in scope.declarations.values() {
        let decl_id = decl.identifier.declaration_id;
        if cx.hook_callback_arg_decls.contains(&decl_id) {
            hook_callback_decl_ids.insert(decl_id);
        }
    }
    for stmt in block {
        let ReactiveStatement::Instruction(instr) = stmt else {
            continue;
        };
        match &instr.value {
            InstructionValue::StoreLocal { lvalue, value, .. }
            | InstructionValue::StoreContext { lvalue, value, .. } => {
                let source_decl = value.identifier.declaration_id;
                if !scope_decl_ids.contains(&source_decl) {
                    continue;
                }
                let target_decl = lvalue.place.identifier.declaration_id;
                if cx.hook_callback_arg_decls.contains(&target_decl) {
                    hook_callback_decl_ids.insert(source_decl);
                }
            }
            _ => {}
        }
    }
    for reassignment in &scope.reassignments {
        if cx
            .hook_callback_arg_decls
            .contains(&reassignment.declaration_id)
        {
            hook_callback_decl_ids.insert(reassignment.declaration_id);
        }
    }
    let mut scope_callback_deps: HashMap<DeclarationId, Vec<String>> = HashMap::new();
    if !hook_callback_decl_ids.is_empty() {
        let primitive_literals_for_callbacks = cx.primitive_literals_for_child();
        collect_callback_deps_from_reactive_block(
            block,
            &cx.stable_ref_decls,
            &cx.stable_setter_decls,
            &cx.stable_effect_event_decls,
            &cx.multi_source_decls,
            &primitive_literals_for_callbacks,
            &mut scope_callback_deps,
        );
    }

    // Dependencies: each gets a cache slot, generate change checks and store statements.
    // Truncate ref.current deps to just ref (upstream: PropagateScopeDependenciesHIR.ts L610-620).
    let drop_deps_for_single_iteration_do_while = scope.dependencies.len() == 1
        && scope.reassignments.is_empty()
        && scope.declarations.len() == 1
        && is_single_iteration_do_while_scope_block(block);
    let truncated_deps: Vec<ReactiveScopeDependency> = if drop_deps_for_single_iteration_do_while {
        Vec::new()
    } else {
        scope
            .dependencies
            .iter()
            .map(|dep| truncate_ref_current_dep(dep, &cx.stable_ref_decls))
            .collect()
    };
    let mut sorted_deps: Vec<&ReactiveScopeDependency> = truncated_deps.iter().collect();
    sort_scope_dependency_refs_for_codegen(cx, &mut sorted_deps);
    let manual_memo_dep_roots_for_scope: HashSet<DeclarationId> = scope
        .declarations
        .values()
        .flat_map(|decl| {
            cx.manual_memo_dep_roots_by_decl
                .get(&decl.identifier.declaration_id)
                .into_iter()
                .flat_map(|roots| roots.iter().copied())
        })
        .collect();
    let mut seen_dep_keys: HashSet<String> = HashSet::new();
    let mut scope_dep_exprs: Vec<String> = Vec::new();
    let debug_scope_dep_filter = std::env::var("DEBUG_SCOPE_DEP_FILTER").is_ok();
    for dep in sorted_deps {
        if dep.path.is_empty()
            && cx
                .stable_setter_decls
                .contains(&dep.identifier.declaration_id)
            && !cx
                .multi_source_decls
                .contains(&dep.identifier.declaration_id)
            && !manual_memo_dep_roots_for_scope.contains(&dep.identifier.declaration_id)
            && !cx
                .pending_manual_memo_reads
                .contains(&dep.identifier.declaration_id)
        {
            if debug_scope_dep_filter {
                eprintln!(
                    "[SCOPE_DEP_FILTER] skip=stable_setter scope={} decl={} id={} name={:?} path={:?}",
                    scope.id.0,
                    dep.identifier.declaration_id.0,
                    dep.identifier.id.0,
                    dep.identifier.name,
                    dep.path
                );
            }
            continue;
        }
        let key = format_dependency_identity(dep);
        if seen_dep_keys.insert(key) {
            scope_dep_exprs.push(codegen_dependency(cx, dep));
        }
    }
    if block_has_optional_computed_load_call_key(block) {
        let mut widened: Vec<String> = Vec::new();
        let mut seen: HashSet<String> = HashSet::new();
        for dep in scope_dep_exprs {
            let dep = widen_member_dep_expr_to_root(&dep).unwrap_or(dep);
            if seen.insert(dep.clone()) {
                widened.push(dep);
            }
        }
        scope_dep_exprs = widened;
    }
    // Do NOT use infer_fallback_scope_dep_exprs here.
    // When scope deps are empty (pruned by prune_non_reactive_deps_reactive),
    // the scope should be sentinel-based. Re-inferring deps from JSX props
    // would re-add non-reactive deps that were intentionally pruned.
    //
    // Upstream note:
    // Guard deps come from scope deps; callback deps only provide an override
    // when callback-capture metadata is strictly more precise for this scope.
    let mut hook_callback_decl_ids_sorted: Vec<DeclarationId> =
        hook_callback_decl_ids.into_iter().collect();
    hook_callback_decl_ids_sorted.sort_by_key(|id| id.0);
    let mut callback_dep_exprs: Vec<String> = Vec::new();
    for decl_id in &hook_callback_decl_ids_sorted {
        if let Some(deps) = cx
            .callback_deps
            .get(decl_id)
            .or_else(|| scope_callback_deps.get(decl_id))
        {
            callback_dep_exprs.extend(deps.iter().cloned());
        }
    }
    callback_dep_exprs = dedupe_dependency_paths(callback_dep_exprs);
    let override_dep_exprs = if std::env::var("DISABLE_CALLBACK_DEP_OVERRIDE").is_ok() {
        Vec::new()
    } else if !callback_dep_exprs.is_empty() {
        choose_callback_dep_override(&scope_dep_exprs, &callback_dep_exprs)
    } else {
        Vec::new()
    };
    if std::env::var("DEBUG_SCOPE_DEP_OVERRIDE").is_ok() {
        let mut scope_callback_keys: Vec<u32> =
            scope_callback_deps.keys().map(|decl| decl.0).collect();
        scope_callback_keys.sort_unstable();
        let hook_decl_ids: Vec<u32> = hook_callback_decl_ids_sorted
            .iter()
            .map(|id| id.0)
            .collect();
        eprintln!(
            "[SCOPE_DEP_OVERRIDE] scope={} hook_decl_ids={:?} scope_callback_keys={:?} scope_deps={:?} callback_deps={:?} override={:?}",
            scope.id.0,
            hook_decl_ids,
            scope_callback_keys,
            scope_dep_exprs,
            callback_dep_exprs,
            override_dep_exprs
        );
    }

    let reassigned_decl_ids: HashSet<DeclarationId> = scope
        .reassignments
        .iter()
        .map(|id| id.declaration_id)
        .collect();
    // Declarations: each gets a cache slot
    let mut sorted_decls: Vec<(&IdentifierId, &ScopeDeclaration)> =
        scope.declarations.iter().collect();
    sorted_decls.sort_by(|a, b| {
        let a_reassigned = reassigned_decl_ids.contains(&a.1.identifier.declaration_id);
        let b_reassigned = reassigned_decl_ids.contains(&b.1.identifier.declaration_id);
        match a_reassigned.cmp(&b_reassigned) {
            std::cmp::Ordering::Equal => {}
            non_eq => return non_eq,
        }
        let a_name = identifier_name_static(&a.1.identifier);
        let b_name = identifier_name_static(&b.1.identifier);
        match a_name.cmp(&b_name) {
            std::cmp::Ordering::Equal => {
                a.1.identifier
                    .declaration_id
                    .0
                    .cmp(&b.1.identifier.declaration_id.0)
            }
            non_eq => non_eq,
        }
    });

    if !override_dep_exprs.is_empty() {
        for decl_id in &hook_callback_decl_ids_sorted {
            if cx.callback_deps.contains_key(decl_id) || scope_callback_deps.contains_key(decl_id) {
                cx.callback_deps
                    .insert(*decl_id, override_dep_exprs.clone());
            }
        }
    }

    let mut selected_dep_exprs = if !override_dep_exprs.is_empty() {
        override_dep_exprs.clone()
    } else {
        scope_dep_exprs.clone()
    };
    if block.len() == 1
        && selected_dep_exprs
            .iter()
            .all(|dep| !rendered_expr_contains_optional_chain(dep))
    {
        let fallback_dep_exprs = infer_fallback_scope_dep_exprs(cx, block);
        if fallback_dep_exprs
            .iter()
            .any(|dep| rendered_expr_contains_optional_chain(dep))
        {
            selected_dep_exprs =
                replace_dep_exprs_with_optional_fallbacks(selected_dep_exprs, &fallback_dep_exprs);
        }
    }
    let output_decl_is_scope_dependency = sorted_decls.first().is_some_and(|(_, decl)| {
        cx.scope_dependency_decls
            .contains(&decl.identifier.declaration_id)
    });
    let should_dememoize_zero_dep_call_scope = selected_dep_exprs.is_empty()
        && scope.reassignments.is_empty()
        && scope.declarations.len() == 1
        && block.len() == 1
        && matches!(
            &block[0],
            ReactiveStatement::Instruction(instr)
                if matches!(
                    &instr.value,
                    InstructionValue::CallExpression {
                        callee,
                        args,
                        optional,
                        ..
                    }
                        if cx
                            .hook_call_by_decl
                            .get(&callee.identifier.declaration_id)
                            .is_some_and(|hook| hook == "useCallback")
                            || (output_decl_is_scope_dependency
                                && !optional
                                && args.is_empty()
                                && matches!(callee.effect, Effect::Read)
                                && !callee.reactive)
                )
        );
    if should_dememoize_zero_dep_call_scope {
        output.push_str(&codegen_scope_computation_no_reset(cx, scope, block));
        for decl in scope.declarations.values() {
            cx.stable_zero_dep_decls
                .insert(decl.identifier.declaration_id);
        }
        return;
    }
    let mut optional_dep_alias: Option<(String, String)> = None;
    let single_decl_is_function_like = matches!(
        block.first(),
        Some(ReactiveStatement::Instruction(instr))
            if matches!(
                &instr.value,
                InstructionValue::FunctionExpression { .. } | InstructionValue::ObjectMethod { .. }
            )
    );
    if sorted_decls.len() == 1
        && scope.reassignments.is_empty()
        && block.len() == 1
        && !single_decl_is_function_like
        && let Some(dep_index) = selected_dep_exprs
            .iter()
            .position(|dep| rendered_expr_contains_optional_chain(dep))
    {
        let dep_expr = selected_dep_exprs[dep_index].clone();
        let decl = sorted_decls[0].1;
        let alias_name = identifier_name_with_cx(cx, &decl.identifier);
        if let Some(alias_index) = parse_codegen_temp_index(&alias_name) {
            let mut shifted_index = alias_index + 1;
            let mut shifted_name = format!("t{}", shifted_index);
            while shifted_name == alias_name
                || cx.used_declaration_names.contains(&shifted_name)
                || cx.reserved_child_decl_names.contains(&shifted_name)
            {
                shifted_index += 1;
                shifted_name = format!("t{}", shifted_index);
            }
            cx.declaration_name_overrides
                .insert(decl.identifier.declaration_id, shifted_name.clone());
            cx.used_declaration_names.insert(shifted_name.clone());
            cx.unique_identifiers.insert(shifted_name);

            output.push_str(
                &render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Const,
                    &alias_name,
                    Some(&dep_expr),
                )
                .expect("optional dependency alias should stay on AST path"),
            );
            selected_dep_exprs[dep_index] = alias_name.clone();
            optional_dep_alias = Some((dep_expr, alias_name));
        }
    }
    for dep_expr in &selected_dep_exprs {
        let index = cx.alloc_cache_slot();
        let comparison = render_cache_slot_comparison_expression_ast(
            &cache_var,
            index,
            BinaryOperator::StrictNotEq,
            dep_expr,
        )
        .expect("dependency comparison should stay on AST path");
        if cx.enable_change_variable_codegen {
            let change_name = cx.synthesize_name(&format!("c_{}", index));
            change_var_stmts.push(
                render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Const,
                    &change_name,
                    Some(&comparison),
                )
                .expect("change variable should stay on AST path"),
            );
            change_exprs.push(change_name);
        } else {
            change_exprs.push(comparison);
        }
        cache_store_stmts.push(
            render_cache_slot_store_statement_ast(&cache_var, index, dep_expr)
                .expect("dependency cache store should stay on AST path"),
        );
    }
    let active_dep_exprs: HashSet<String> = selected_dep_exprs.iter().cloned().collect();

    for stmt in &change_var_stmts {
        output.push_str(stmt);
    }

    let mut first_output_index: Option<u32> = None;
    let mut cache_loads: Vec<(String, u32)> = Vec::new();
    let mut seen_output_names: HashSet<String> = HashSet::new();

    for (_, decl) in &sorted_decls {
        let mut name = identifier_name_with_cx(cx, &decl.identifier);
        let name_in_current_block = cx
            .block_scope_output_names
            .last()
            .is_some_and(|names| names.contains(&name));
        if is_codegen_temp_name(&name)
            && (active_dep_exprs.contains(&name)
                || (!has_materialized_named_binding(cx, &decl.identifier) && name_in_current_block))
        {
            // Avoid `tN` output names that collide with dependency expressions in
            // the same guard, e.g. `if ($[0] !== t0) { t0 = ... }`.
            // Also avoid reusing an already-emitted `tN` scope output binding in
            // the current lexical block.
            let fresh = fresh_temp_name(cx);
            cx.declaration_name_overrides
                .insert(decl.identifier.declaration_id, fresh.clone());
            cx.used_declaration_names.insert(fresh.clone());
            name = fresh;
        }
        if std::env::var("DEBUG_REACTIVE_SCOPE_NAMES").is_ok() {
            eprintln!(
                "[REACTIVE_SCOPE_NAME] fn={} scope={} decl_id={} ident_id={} ident_name={:?} emitted={}",
                cx.function_name,
                scope.id.0,
                decl.identifier.declaration_id.0,
                decl.identifier.id.0,
                decl.identifier.name,
                name
            );
        }
        if !seen_output_names.insert(name.clone()) {
            cx.declare(&decl.identifier);
            continue;
        }
        let index = cx.alloc_cache_slot();
        if first_output_index.is_none() {
            first_output_index = Some(index);
        }
        if !has_materialized_named_binding(cx, &decl.identifier) {
            output.push_str(
                &render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Let,
                    &name,
                    None,
                )
                .expect("scope output declaration should stay on AST path"),
            );
            if let Some(names) = cx.block_scope_output_names.last_mut() {
                names.insert(name.clone());
            }
            cx.mark_decl_runtime_emitted(decl.identifier.declaration_id);
        }
        cache_loads.push((name.clone(), index));
        cx.declare(&decl.identifier);
    }

    // Reassignments
    for reassignment in &scope.reassignments {
        let name = identifier_name_with_cx(cx, reassignment);
        if std::env::var("DEBUG_REACTIVE_SCOPE_NAMES").is_ok() {
            eprintln!(
                "[REACTIVE_SCOPE_NAME] fn={} scope={} reassignment_decl_id={} ident_id={} ident_name={:?} emitted={}",
                cx.function_name,
                scope.id.0,
                reassignment.declaration_id.0,
                reassignment.id.0,
                reassignment.name,
                name
            );
        }
        if !seen_output_names.insert(name.clone()) {
            continue;
        }
        let index = cx.alloc_cache_slot();
        if first_output_index.is_none() {
            first_output_index = Some(index);
        }
        cache_loads.push((name, index));
    }

    // Build test condition
    let mut test_condition = if change_exprs.is_empty() {
        // No dependencies - check if first output is sentinel
        if let Some(first_idx) = first_output_index {
            render_cache_slot_comparison_expression_ast(
                &cache_var,
                first_idx,
                BinaryOperator::StrictEq,
                &render_symbol_for_call_expression_source(MEMO_CACHE_SENTINEL),
            )
            .expect("memo sentinel comparison should stay on AST path")
        } else {
            "true".to_string()
        }
    } else {
        render_logical_chain_expression_ast(&change_exprs, LogicalOperator::Or)
            .expect("memo change condition should stay on AST path")
    };
    if cx.disable_memoization_for_debugging {
        test_condition =
            render_logical_expression_ast(&test_condition, LogicalOperator::Or, "true")
                .expect("debug memo change condition should stay on AST path");
    }

    // Generate computation block
    // Scope computations are emitted inside this scope's cache-guard body.
    // Keep their temporary output name tracking isolated from the surrounding
    // lexical block so inner `let tN` declarations do not force unrelated
    // outer-scope renames.
    cx.block_scope_output_names.push(HashSet::new());
    cx.block_scope_declared_temp_names.push(HashSet::new());
    let mut computation = codegen_scope_computation_no_reset(cx, scope, block);
    let _ = cx.block_scope_declared_temp_names.pop();
    let _ = cx.block_scope_output_names.pop();
    computation = rewrite_named_test_reassign_ternary_in_scope_computation(&computation);
    computation = rewrite_named_test_sequence_ternary_in_scope_computation(&computation);
    computation = rewrite_named_temp_ternary_in_scope_computation(&computation);
    if let Some((dep_expr, alias)) = &optional_dep_alias {
        computation = computation.replace(dep_expr, alias);
    }
    let mut deferred_post_scope_calls: Vec<String> = Vec::new();
    let block_is_flat_instructions = block
        .iter()
        .all(|stmt| matches!(stmt, ReactiveStatement::Instruction(_)));
    if block_is_flat_instructions && !cache_loads.is_empty() {
        let output_names: HashSet<String> =
            cache_loads.iter().map(|(name, _)| name.clone()).collect();
        let (next_computation, deferred_calls) =
            split_deferred_readonly_output_calls(&computation, &output_names);
        if !deferred_calls.is_empty() {
            computation = next_computation;
            deferred_post_scope_calls = deferred_calls;
        }
    }

    // Note: we intentionally do NOT insert blank-line markers into the
    // computation here. Blank lines inside scope bodies flow through the
    // body-shape → memoized_setup_statements path instead (via
    // preserve_scope_setup_statement_blank_lines).  Marker insertion here
    // would create false-positive (before,after) pair matches in
    // transfer_blank_lines_from_string_bodies.

    // Build cache store statements for outputs
    for (name, index) in &cache_loads {
        cache_store_stmts.push(
            render_cache_slot_store_statement_ast(&cache_var, *index, name)
                .expect("scope output cache store should stay on AST path"),
        );
    }

    // Build cache load statements for outputs
    for (name, index) in &cache_loads {
        cache_load_stmts.push(
            render_cache_slot_load_assignment_statement_ast(name, &cache_var, *index)
                .expect("scope output cache load should stay on AST path"),
        );
    }

    // Emit debug change detection scope form (upstream: enableChangeDetectionForDebugging).
    if cx.enable_change_detection_for_debugging && !change_exprs.is_empty() {
        cx.needs_structural_check_import = true;
        let condition_name = cx.synthesize_name("condition");
        let scope_loc = format_change_detection_scope_loc(scope, block);
        let allocator = Allocator::default();
        let builder = AstBuilder::new(&allocator);
        let mut debug_block = parse_statement_list_for_ast_codegen_with_context(
            &allocator,
            SourceType::mjs().with_jsx(true),
            cx.function_is_async,
            cx.function_is_generator,
            &computation,
        )
        .expect("change detection computation should stay on AST path");
        debug_block.push(ast::Statement::VariableDeclaration(
            builder.alloc_variable_declaration(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.vec1(
                    builder.variable_declarator(
                        SPAN,
                        ast::VariableDeclarationKind::Let,
                        builder.binding_pattern_binding_identifier(
                            SPAN,
                            builder.ident(&condition_name),
                        ),
                        NONE,
                        Some(
                            parse_expression_for_ast_codegen(
                                &allocator,
                                SourceType::mjs().with_jsx(true),
                                &test_condition,
                            )
                            .expect("change detection condition should stay on AST path"),
                        ),
                        false,
                    ),
                ),
                false,
            ),
        ));
        let mut cached_body = builder.vec();
        for (name, index) in &cache_loads {
            let old_name = cx.synthesize_name(&format!("old${}", name));
            cached_body.push(ast::Statement::VariableDeclaration(
                builder.alloc_variable_declaration(
                    SPAN,
                    ast::VariableDeclarationKind::Let,
                    builder.vec1(builder.variable_declarator(
                        SPAN,
                        ast::VariableDeclarationKind::Let,
                        builder.binding_pattern_binding_identifier(SPAN, builder.ident(&old_name)),
                        NONE,
                        Some(build_computed_member_expression_ast(
                            builder,
                            &cache_var,
                            builder.expression_numeric_literal(
                                SPAN,
                                *index as f64,
                                None,
                                NumberBase::Decimal,
                            ),
                        )),
                        false,
                    )),
                    false,
                ),
            ));
            cached_body.push(
                builder.statement_expression(
                    SPAN,
                    parse_expression_for_ast_codegen(
                        &allocator,
                        SourceType::mjs().with_jsx(true),
                        &render_call_expression_from_rendered_args_ast(
                            "$structuralCheck",
                            &[
                                old_name.clone(),
                                name.clone(),
                                format!("\"{}\"", escape_string(name)),
                                format!("\"{}\"", escape_string(&cx.function_name)),
                                "\"cached\"".to_string(),
                                format!("\"{}\"", escape_string(&scope_loc)),
                            ],
                            false,
                        )
                        .expect("cached structural check should stay on AST path"),
                    )
                    .expect("cached structural check should stay on AST path"),
                ),
            );
        }
        debug_block.push(
            builder.statement_if(
                SPAN,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &render_unary_expression_ast(UnaryOperator::Not, &condition_name)
                        .expect("cached structural check condition should stay on AST path"),
                )
                .expect("cached structural check condition should stay on AST path"),
                builder.statement_block(SPAN, cached_body),
                None,
            ),
        );
        for stmt in &cache_store_stmts {
            debug_block.extend(
                parse_statement_list_for_ast_codegen_with_context(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    cx.function_is_async,
                    cx.function_is_generator,
                    stmt,
                )
                .expect("debug cache store should stay on AST path"),
            );
        }
        let mut recomputed_body = parse_statement_list_for_ast_codegen_with_context(
            &allocator,
            SourceType::mjs().with_jsx(true),
            cx.function_is_async,
            cx.function_is_generator,
            &computation,
        )
        .expect("recomputed structural check body should stay on AST path");
        for (name, index) in &cache_loads {
            recomputed_body.push(builder.statement_expression(
                SPAN,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &render_call_expression_from_rendered_args_ast(
                        "$structuralCheck",
                        &[
                            render_cache_slot_access_expression_ast(&cache_var, *index).expect(
                                "recomputed structural check cache access should stay on AST path",
                            ),
                            name.clone(),
                            format!("\"{}\"", escape_string(name)),
                            format!("\"{}\"", escape_string(&cx.function_name)),
                            "\"recomputed\"".to_string(),
                            format!("\"{}\"", escape_string(&scope_loc)),
                        ],
                        false,
                    )
                    .expect("recomputed structural check should stay on AST path"),
                )
                .expect("recomputed structural check should stay on AST path"),
            ));
            recomputed_body.push(build_identifier_assignment_statement_ast_with_expression(
                builder,
                name,
                build_computed_member_expression_ast(
                    builder,
                    &cache_var,
                    builder.expression_numeric_literal(
                        SPAN,
                        *index as f64,
                        None,
                        NumberBase::Decimal,
                    ),
                ),
            ));
        }
        debug_block.push(builder.statement_if(
            SPAN,
            builder.expression_identifier(SPAN, builder.ident(&condition_name)),
            builder.statement_block(SPAN, recomputed_body),
            None,
        ));
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&builder.statement_block(SPAN, debug_block))
        ));
    } else {
        // Emit the standard if/else memoization guard.
        let allocator = Allocator::default();
        let builder = AstBuilder::new(&allocator);
        let parsed_test = parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &test_condition,
        )
        .expect("memo cache guard condition should stay on AST path");
        let mut consequent = parse_statement_list_for_ast_codegen_with_context(
            &allocator,
            SourceType::mjs().with_jsx(true),
            cx.function_is_async,
            cx.function_is_generator,
            &computation,
        )
        .expect("memo cache guard consequent should stay on AST path");
        for stmt in &cache_store_stmts {
            consequent.extend(
                parse_statement_list_for_ast_codegen_with_context(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    cx.function_is_async,
                    cx.function_is_generator,
                    stmt,
                )
                .expect("memo cache store should stay on AST path"),
            );
        }
        let mut alternate = builder.vec();
        for stmt in &cache_load_stmts {
            alternate.extend(
                parse_statement_list_for_ast_codegen_with_context(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    cx.function_is_async,
                    cx.function_is_generator,
                    stmt,
                )
                .expect("memo cache load should stay on AST path"),
            );
        }
        let statement = builder.statement_if(
            SPAN,
            parsed_test,
            builder.statement_block(SPAN, consequent),
            Some(builder.statement_block(SPAN, alternate)),
        );
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
    }
    for stmt in &deferred_post_scope_calls {
        output.push_str(stmt);
    }

    if selected_dep_exprs.is_empty()
        && scope.reassignments.is_empty()
        && block.len() == 1
        && let ReactiveStatement::Instruction(instr) = &block[0]
        && matches!(
            instr.value,
            InstructionValue::FunctionExpression { .. }
                | InstructionValue::ObjectMethod { .. }
                | InstructionValue::Primitive { .. }
                | InstructionValue::ArrayExpression { .. }
                | InstructionValue::ObjectExpression { .. }
        )
    {
        for (_, decl) in &sorted_decls {
            cx.stable_zero_dep_decls
                .insert(decl.identifier.declaration_id);
        }
    }

    // Early return value
    if let Some(early_return) = &scope.early_return_value {
        let name = identifier_name_with_cx(cx, &early_return.value);
        let allocator = Allocator::default();
        let builder = AstBuilder::new(&allocator);
        let test = parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            &render_binary_expression_ast(
                &name,
                BinaryOperator::StrictNotEq,
                &render_symbol_for_call_expression_source(EARLY_RETURN_SENTINEL),
            )
            .expect("early return sentinel guard should stay on AST path"),
        )
        .expect("early return guard should stay on AST path");
        let statement = builder.statement_if(
            SPAN,
            test,
            builder.statement_block(
                SPAN,
                builder.vec1(builder.statement_return(
                    SPAN,
                    Some(builder.expression_identifier(SPAN, builder.ident(&name))),
                )),
            ),
            None,
        );
        output.push_str(&format!(
            "{}\n",
            codegen_statement_with_flow_cast_restore(&statement)
        ));
    }
}

fn reactive_terminal_loc(terminal: &ReactiveTerminal) -> &SourceLocation {
    match terminal {
        ReactiveTerminal::Break { loc, .. }
        | ReactiveTerminal::Continue { loc, .. }
        | ReactiveTerminal::Return { loc, .. }
        | ReactiveTerminal::Throw { loc, .. }
        | ReactiveTerminal::Switch { loc, .. }
        | ReactiveTerminal::DoWhile { loc, .. }
        | ReactiveTerminal::While { loc, .. }
        | ReactiveTerminal::For { loc, .. }
        | ReactiveTerminal::ForOf { loc, .. }
        | ReactiveTerminal::ForIn { loc, .. }
        | ReactiveTerminal::If { loc, .. }
        | ReactiveTerminal::Try { loc, .. }
        | ReactiveTerminal::Label { loc, .. } => loc,
    }
}

/// Generate a terminal statement.
fn codegen_terminal(cx: &mut Context, terminal: &ReactiveTerminal) -> Option<String> {
    fn extract_single_labeled_break_target(code: &str) -> Option<String> {
        let allocator = Allocator::default();
        let statement = parse_single_statement_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            code.trim(),
        )
        .ok()?;
        let ast::Statement::BreakStatement(statement) = statement else {
            return None;
        };
        let label = statement.unbox().label?;
        if !label.name.starts_with("bb") {
            return None;
        }
        Some(format!("break {};", label.name))
    }

    fn trim_trailing_labeled_break_if_matches_default(
        current_case_code: &str,
        next_case_is_default: bool,
        next_case_code: Option<&str>,
    ) -> String {
        if !next_case_is_default {
            return current_case_code.to_string();
        }
        let Some(next_code) = next_case_code else {
            return current_case_code.to_string();
        };
        let Some(next_break) = extract_single_labeled_break_target(next_code) else {
            return current_case_code.to_string();
        };

        let trimmed = current_case_code.trim_end();
        let Some(last_newline) = trimmed.rfind('\n') else {
            return current_case_code.to_string();
        };
        let last_line = trimmed[last_newline + 1..].trim();
        if last_line == next_break {
            let mut out = trimmed[..last_newline].to_string();
            if !out.is_empty() {
                out.push('\n');
            }
            out
        } else {
            current_case_code.to_string()
        }
    }

    fn has_explicit_break_terminator(block: &[ReactiveStatement]) -> bool {
        match block.last() {
            Some(ReactiveStatement::Terminal(term_stmt)) => {
                matches!(
                    term_stmt.terminal,
                    ReactiveTerminal::Break {
                        target_kind: ReactiveTerminalTargetKind::Unlabeled
                            | ReactiveTerminalTargetKind::Labeled,
                        ..
                    }
                )
            }
            _ => false,
        }
    }

    fn extract_direct_store_assignment(
        stmt: &ReactiveStatement,
    ) -> Option<(DeclarationId, DeclarationId)> {
        let ReactiveStatement::Instruction(instr) = stmt else {
            return None;
        };
        match &instr.value {
            InstructionValue::StoreLocal { lvalue, value, .. }
            | InstructionValue::StoreContext { lvalue, value, .. } => Some((
                lvalue.place.identifier.declaration_id,
                value.identifier.declaration_id,
            )),
            _ => None,
        }
    }

    fn is_zero_dep_literal_scope_decl(
        stmt: &ReactiveStatement,
        declaration_id: DeclarationId,
    ) -> bool {
        let scope_block = match stmt {
            ReactiveStatement::Scope(scope_block) => scope_block,
            _ => return false,
        };
        if !scope_block.scope.dependencies.is_empty()
            || !scope_block.scope.reassignments.is_empty()
            || scope_block.scope.declarations.len() != 1
            || scope_block.instructions.len() != 1
        {
            return false;
        }
        let Some(scope_decl) = scope_block.scope.declarations.values().next() else {
            return false;
        };
        if scope_decl.identifier.declaration_id != declaration_id {
            return false;
        }
        let ReactiveStatement::Instruction(instr) = &scope_block.instructions[0] else {
            return false;
        };
        let Some(lvalue) = &instr.lvalue else {
            return false;
        };
        if lvalue.identifier.declaration_id != declaration_id {
            return false;
        }
        matches!(
            instr.value,
            InstructionValue::Primitive { .. }
                | InstructionValue::ArrayExpression { .. }
                | InstructionValue::ObjectExpression { .. }
        )
    }

    fn is_simple_fallthrough_reassign_block(
        block: &[ReactiveStatement],
        target_decl: DeclarationId,
    ) -> bool {
        if block.is_empty() {
            return false;
        }
        let mut saw_store = false;
        for stmt in block {
            if let Some((store_target, _)) = extract_direct_store_assignment(stmt)
                && store_target == target_decl
            {
                saw_store = true;
                continue;
            }

            if !saw_store {
                let ReactiveStatement::Instruction(instr) = stmt else {
                    return false;
                };
                if reactive_instruction_uses_declaration(instr, target_decl)
                    || reactive_instruction_writes_declaration(instr, target_decl)
                    || !is_fusable_inline_temp_instruction(instr)
                {
                    return false;
                }
                continue;
            }

            if !matches!(
                stmt,
                ReactiveStatement::Terminal(ReactiveTerminalStatement {
                    terminal: ReactiveTerminal::Break { .. },
                    ..
                })
            ) {
                return false;
            }
        }
        saw_store
    }

    fn has_direct_store_assignment(block: &[ReactiveStatement]) -> bool {
        block
            .iter()
            .any(|stmt| extract_direct_store_assignment(stmt).is_some())
    }

    fn is_synthetic_switch_exit_break(
        stmt: &ReactiveStatement,
        switch_loc: &SourceLocation,
    ) -> bool {
        matches!(
            stmt,
            ReactiveStatement::Terminal(ReactiveTerminalStatement {
                terminal: ReactiveTerminal::Break { loc, .. },
                ..
            }) if loc == switch_loc
        )
    }

    fn trim_trailing_synthetic_switch_exit_break<'a>(
        block: &'a [ReactiveStatement],
        switch_loc: &SourceLocation,
    ) -> &'a [ReactiveStatement] {
        if block
            .last()
            .is_some_and(|stmt| is_synthetic_switch_exit_break(stmt, switch_loc))
        {
            &block[..block.len().saturating_sub(1)]
        } else {
            block
        }
    }

    fn maybe_trim_dead_switch_case_tail_for_fallthrough(
        previous_case_block: Option<&[ReactiveStatement]>,
        current_case_block: &[ReactiveStatement],
        next_case_block: Option<&[ReactiveStatement]>,
        switch_loc: &SourceLocation,
    ) -> Option<usize> {
        let next_case_block = next_case_block?;
        if current_case_block.len() < 2 || !has_explicit_break_terminator(current_case_block) {
            return None;
        }

        // Pattern 0: case value is overwritten by the next case/default before any
        // externally visible use. Keep this case empty to preserve fallthrough shape.
        let current_store_idx = current_case_block.len() - 2;
        let next_store_idx = next_case_block.len().checked_sub(2)?;
        if let Some((current_target, _)) =
            extract_direct_store_assignment(&current_case_block[current_store_idx])
            && let Some((next_target, _)) =
                extract_direct_store_assignment(&next_case_block[next_store_idx])
            && previous_case_block.is_none_or(|prev| !has_direct_store_assignment(prev))
            && current_target == next_target
            && current_case_block[current_store_idx + 1..]
                .iter()
                .all(|stmt| {
                    matches!(
                        stmt,
                        ReactiveStatement::Terminal(ReactiveTerminalStatement {
                            terminal: ReactiveTerminal::Break { loc, .. },
                            ..
                        }) if loc == switch_loc
                    )
                })
        {
            let mut prefix_is_pure = true;
            for stmt in &current_case_block[..current_store_idx] {
                let ReactiveStatement::Instruction(instr) = stmt else {
                    prefix_is_pure = false;
                    break;
                };
                if reactive_instruction_uses_declaration(instr, current_target)
                    || reactive_instruction_writes_declaration(instr, current_target)
                    || !is_fusable_inline_temp_instruction(instr)
                {
                    prefix_is_pure = false;
                    break;
                }
            }
            if prefix_is_pure {
                debug_codegen_expr(
                    "switch-fallthrough-dead-store-trim",
                    format!(
                        "drop_case_body current_len={} next_len={} target_decl={}",
                        current_case_block.len(),
                        next_case_block.len(),
                        current_target.0
                    ),
                );
                return Some(0);
            }
        }

        let store_idx = current_case_block.len() - 2;
        let scope_idx = current_case_block.len() - 3;
        let (target_decl, source_decl) =
            extract_direct_store_assignment(&current_case_block[store_idx])?;

        if target_decl == source_decl
            || !is_zero_dep_literal_scope_decl(&current_case_block[scope_idx], source_decl)
            || !is_simple_fallthrough_reassign_block(next_case_block, target_decl)
            || reactive_block_uses_declaration(&current_case_block[..scope_idx], source_decl)
            || reactive_block_uses_declaration(next_case_block, source_decl)
        {
            return None;
        }

        Some(scope_idx)
    }

    match terminal {
        ReactiveTerminal::Break {
            target,
            target_kind,
            ..
        } => match target_kind {
            ReactiveTerminalTargetKind::Implicit => None,
            ReactiveTerminalTargetKind::Unlabeled => render_reactive_break_statement_ast(None),
            ReactiveTerminalTargetKind::Labeled => {
                render_reactive_break_statement_ast(Some(&format!("bb{}", target.0)))
            }
        },
        ReactiveTerminal::Continue {
            target,
            target_kind,
            ..
        } => match target_kind {
            ReactiveTerminalTargetKind::Implicit => None,
            ReactiveTerminalTargetKind::Unlabeled => render_reactive_continue_statement_ast(None),
            ReactiveTerminalTargetKind::Labeled => {
                render_reactive_continue_statement_ast(Some(&format!("bb{}", target.0)))
            }
        },
        ReactiveTerminal::Return { value, .. } => {
            let expr = codegen_place_to_expression(cx, value);
            if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                eprintln!(
                    "[CODEGEN_RETURN] id={} decl={} name={:?} expr={}",
                    value.identifier.id.0,
                    value.identifier.declaration_id.0,
                    value.identifier.name,
                    expr
                );
            }
            if expr == "undefined" {
                render_reactive_return_statement_ast(None)
            } else {
                render_reactive_return_statement_ast(Some(&expr))
            }
        }
        ReactiveTerminal::Throw { value, .. } => {
            let expr = codegen_place_to_expression(cx, value);
            render_reactive_throw_statement_ast(&expr)
        }
        ReactiveTerminal::If {
            test,
            consequent,
            alternate,
            ..
        } => {
            let test_expr = codegen_place_to_expression(cx, test);
            let cons_block = codegen_block(cx, consequent);
            let alt_block = alternate.as_ref().map(|alt| codegen_block(cx, alt));
            let allocator = Allocator::default();
            let builder = AstBuilder::new(&allocator);
            let statement = builder.statement_if(
                SPAN,
                parse_expression_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &test_expr,
                )
                .ok()?,
                builder.statement_block(
                    SPAN,
                    parse_statement_list_for_ast_codegen_with_context(
                        &allocator,
                        SourceType::mjs().with_jsx(true),
                        cx.function_is_async,
                        cx.function_is_generator,
                        &cons_block,
                    )
                    .ok()?,
                ),
                alt_block
                    .as_deref()
                    .filter(|body| !body.trim().is_empty())
                    .map(|body| {
                        builder.statement_block(
                            SPAN,
                            parse_statement_list_for_ast_codegen_with_context(
                                &allocator,
                                SourceType::mjs().with_jsx(true),
                                cx.function_is_async,
                                cx.function_is_generator,
                                body,
                            )
                            .expect("if alternate should stay on AST path"),
                        )
                    }),
            );
            Some(format!(
                "{}\n",
                codegen_statement_with_flow_cast_restore(&statement)
            ))
        }
        ReactiveTerminal::Switch {
            test, cases, loc, ..
        } => {
            let test_expr = codegen_place_to_expression(cx, test);
            let original_case_blocks: Vec<Option<&[ReactiveStatement]>> =
                cases.iter().map(|case| case.block.as_deref()).collect();
            let trimmed_case_blocks: Vec<Option<&[ReactiveStatement]>> = cases
                .iter()
                .map(|case| {
                    case.block
                        .as_deref()
                        .map(|block| trim_trailing_synthetic_switch_exit_break(block, loc))
                })
                .collect();
            let block_codes: Vec<Option<String>> = cases
                .iter()
                .enumerate()
                .map(|(index, _case)| {
                    original_case_blocks[index].map(|block| {
                        let cleaned_prefix_len = maybe_trim_dead_switch_case_tail_for_fallthrough(
                            index
                                .checked_sub(1)
                                .and_then(|prev| original_case_blocks.get(prev).copied().flatten()),
                            block,
                            original_case_blocks.get(index + 1).copied().flatten(),
                            loc,
                        );
                        if let Some(prefix_len) = cleaned_prefix_len {
                            debug_codegen_expr(
                                "switch-fallthrough-tail-trim",
                                format!(
                                    "case_index={} dropped={} total={}",
                                    index,
                                    block.len().saturating_sub(prefix_len),
                                    block.len()
                                ),
                            );
                            codegen_block(
                                cx,
                                trim_trailing_synthetic_switch_exit_break(
                                    &block[..prefix_len],
                                    loc,
                                ),
                            )
                        } else {
                            codegen_block(cx, trimmed_case_blocks[index].unwrap_or(block))
                        }
                    })
                })
                .collect();
            let mut rendered_cases: Vec<(Option<String>, Option<String>)> =
                Vec::with_capacity(cases.len());
            for (index, case) in cases.iter().enumerate() {
                // Pre-compute block code to decide formatting and allow simple
                // fallthrough cleanup against the following default case.
                let mut block_code = block_codes[index].clone();
                if let Some(code) = &block_code
                    && let Some(next_case) = cases.get(index + 1)
                {
                    block_code = Some(trim_trailing_labeled_break_if_matches_default(
                        code,
                        next_case.test.is_none(),
                        block_codes.get(index + 1).and_then(|c| c.as_deref()),
                    ));
                }
                rendered_cases.push((
                    case.test
                        .as_ref()
                        .map(|test| codegen_place_to_expression(cx, test)),
                    block_code.filter(|code| !code.trim().is_empty()),
                ));
            }
            render_reactive_switch_statement_ast(&test_expr, &rendered_cases)
        }
        ReactiveTerminal::For {
            init,
            test,
            update,
            update_value,
            loop_block,
            loc,
            ..
        } => {
            let mut init_code = codegen_for_init(cx, init);
            let test_expr = codegen_place_to_expression(cx, test);
            let update_code = if let Some(upd) = update {
                codegen_for_update(cx, upd, update_value.as_deref())
            } else {
                String::new()
            };
            if let Some(filled_init) =
                maybe_fill_for_header_initializer_from_update(&init_code, &update_code)
            {
                init_code = filled_init;
            }
            let body = codegen_block(cx, loop_block);
            let _ = loc;
            render_reactive_for_statement_ast(&init_code, &test_expr, &update_code, &body)
        }
        ReactiveTerminal::ForOf {
            init,
            test,
            loop_block,
            ..
        } => {
            // Keep init/test-derived temporaries available for collection/lvalue
            // reconstruction in the for-of header.
            let init_out = codegen_block_no_reset(cx, init);
            let (kind, lval, collection_place) = extract_for_in_of_header_from_init(cx, init);
            let collection_expr = if let Some(place) = collection_place {
                codegen_place_to_expression(cx, &place)
            } else if test.identifier.id.0 == 0 {
                let s = init_out.trim().trim_end_matches(';').to_string();
                if s.is_empty() {
                    codegen_place_to_expression(cx, test)
                } else {
                    s
                }
            } else {
                codegen_place_to_expression(cx, test)
            };
            let body = codegen_block(cx, loop_block);
            render_reactive_for_of_statement_ast(&kind, &lval, &collection_expr, &body)
        }
        ReactiveTerminal::ForIn {
            init, loop_block, ..
        } => {
            let init_out = codegen_block_no_reset(cx, init);
            let (kind, lval, collection_place) = extract_for_in_of_header_from_init(cx, init);
            let collection = if let Some(place) = collection_place {
                codegen_place_to_expression(cx, &place)
            } else {
                init_out.trim().trim_end_matches(';').to_string()
            };
            let body = codegen_block(cx, loop_block);
            render_reactive_for_in_statement_ast(&kind, &lval, &collection, &body)
        }
        ReactiveTerminal::While {
            test, loop_block, ..
        } => {
            let test_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
            let body = codegen_block(cx, loop_block);
            render_reactive_while_statement_ast(&test_expr, &body)
        }
        ReactiveTerminal::DoWhile {
            test, loop_block, ..
        } => {
            if block_has_unconditional_break_terminator(loop_block) {
                let mut one_pass = String::new();
                for stmt in loop_block {
                    match stmt {
                        ReactiveStatement::Instruction(instr) => {
                            if let Some(code) = codegen_instruction_nullable(cx, instr) {
                                one_pass.push_str(&code);
                                if !code.ends_with('\n') {
                                    one_pass.push('\n');
                                }
                            }
                        }
                        ReactiveStatement::Terminal(term_stmt)
                            if matches!(term_stmt.terminal, ReactiveTerminal::Break { .. }) =>
                        {
                            break;
                        }
                        _ => return None,
                    }
                }
                Some(one_pass)
            } else {
                let test_expr = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
                let body = codegen_block(cx, loop_block);
                render_reactive_do_while_statement_ast(&body, &test_expr)
            }
        }
        ReactiveTerminal::Label { block, .. } => Some(codegen_block(cx, block)),
        ReactiveTerminal::Try {
            block,
            handler_binding,
            handler,
            ..
        } => {
            let try_body = codegen_block(cx, block);
            let (catch_param, catch_alias) = if let Some(binding) = handler_binding {
                cx.set_temp_expr(&binding.identifier, None);
                let original_name = identifier_name_with_cx(cx, &binding.identifier);
                // Upstream promotes catch bindings to temporaries (e.g., e → t1).
                // If the binding has a user-visible (non-temp) name, generate a temp
                // name for the catch parameter and add a `const e = t1;` alias if
                // the original name is referenced in the catch body.
                if !is_codegen_temp_name(&original_name) {
                    let temp_name = fresh_temp_name(cx);
                    // Check if the original name is referenced in the handler block
                    let original_used = handler_block_references_name(handler, &original_name);
                    let alias = if original_used {
                        render_reactive_variable_statement_ast(
                            ast::VariableDeclarationKind::Const,
                            &original_name,
                            Some(&temp_name),
                        )
                    } else {
                        None
                    };
                    (temp_name, alias)
                } else {
                    (original_name, None)
                }
            } else {
                (String::new(), None)
            };
            let catch_body = codegen_block(cx, handler);
            let allocator = Allocator::default();
            let builder = AstBuilder::new(&allocator);
            let try_block = parse_block_statement_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                &try_body,
            )
            .ok()?;
            let mut catch_statements = if catch_body.trim().is_empty() {
                builder.vec()
            } else {
                parse_statement_list_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    &catch_body,
                )
                .ok()?
            };
            if let Some(alias) = &catch_alias {
                let mut alias_statements = parse_statement_list_for_ast_codegen(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    alias,
                )
                .ok()?;
                alias_statements.extend(catch_statements);
                catch_statements = alias_statements;
            }
            let param = if catch_param.is_empty() {
                None
            } else {
                Some(builder.catch_parameter(
                    SPAN,
                    builder.binding_pattern_binding_identifier(
                        SPAN,
                        builder.ident(catch_param.as_str()),
                    ),
                    NONE,
                ))
            };
            let statement = builder.statement_try(
                SPAN,
                try_block,
                Some(builder.alloc_catch_clause(
                    SPAN,
                    param,
                    builder.block_statement(SPAN, catch_statements),
                )),
                Option::<oxc_allocator::Box<'_, ast::BlockStatement<'_>>>::None,
            );
            Some(format!(
                "{}\n",
                codegen_statement_with_flow_cast_restore(&statement)
            ))
        }
    }
}

/// Generate code for an instruction, returning None if no statement is needed.
fn codegen_instruction_nullable(cx: &mut Context, instr: &ReactiveInstruction) -> Option<String> {
    // Track stable setter declarations (setState/dispatch-like values).
    if let Some(lvalue) = &instr.lvalue
        && is_stable_setter_identifier(&lvalue.identifier)
    {
        cx.mark_stable_setter_identifier(&lvalue.identifier);
    }

    // Track resolved names through lowered aliases for better hook matching.
    if let Some(lvalue) = &instr.lvalue {
        match &instr.value {
            InstructionValue::CallExpression { callee, .. } => {
                if let Some(name) = resolve_place_name(cx, callee)
                    && let Some(hook) = extract_hook_name(&name)
                {
                    cx.hook_call_by_decl
                        .insert(lvalue.identifier.declaration_id, hook.to_string());
                    if hook == "useEffectEvent" {
                        cx.stable_effect_event_decls
                            .insert(lvalue.identifier.declaration_id);
                    }
                }
            }
            InstructionValue::MethodCall { property, .. } => {
                if let Some(name) = resolve_place_name(cx, property)
                    && let Some(hook) = extract_hook_name(&name)
                {
                    cx.hook_call_by_decl
                        .insert(lvalue.identifier.declaration_id, hook.to_string());
                    if hook == "useEffectEvent" {
                        cx.stable_effect_event_decls
                            .insert(lvalue.identifier.declaration_id);
                    }
                }
            }
            InstructionValue::LoadGlobal { binding, .. } => {
                cx.resolved_names
                    .insert(lvalue.identifier.id, load_global_resolved_name(binding));
                cx.non_local_binding_decls
                    .insert(lvalue.identifier.declaration_id);
            }
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => {
                if let Some(name) = resolve_place_name(cx, place) {
                    cx.resolved_names.insert(lvalue.identifier.id, name);
                }
                if cx
                    .multi_source_decls
                    .contains(&place.identifier.declaration_id)
                {
                    cx.multi_source_decls
                        .insert(lvalue.identifier.declaration_id);
                }
                if cx
                    .non_local_binding_decls
                    .contains(&place.identifier.declaration_id)
                {
                    cx.non_local_binding_decls
                        .insert(lvalue.identifier.declaration_id);
                }
                if let Some(hook) = cx
                    .hook_call_by_decl
                    .get(&place.identifier.declaration_id)
                    .cloned()
                {
                    cx.hook_call_by_decl
                        .insert(lvalue.identifier.declaration_id, hook);
                    if cx
                        .stable_effect_event_decls
                        .contains(&place.identifier.declaration_id)
                    {
                        cx.stable_effect_event_decls
                            .insert(lvalue.identifier.declaration_id);
                    }
                }
            }
            InstructionValue::TypeCastExpression { value, .. } => {
                if let Some(name) = resolve_place_name(cx, value) {
                    cx.resolved_names.insert(lvalue.identifier.id, name);
                }
                if cx
                    .multi_source_decls
                    .contains(&value.identifier.declaration_id)
                {
                    cx.multi_source_decls
                        .insert(lvalue.identifier.declaration_id);
                }
                if cx
                    .non_local_binding_decls
                    .contains(&value.identifier.declaration_id)
                {
                    cx.non_local_binding_decls
                        .insert(lvalue.identifier.declaration_id);
                }
                if let Some(hook) = cx
                    .hook_call_by_decl
                    .get(&value.identifier.declaration_id)
                    .cloned()
                {
                    cx.hook_call_by_decl
                        .insert(lvalue.identifier.declaration_id, hook);
                    if cx
                        .stable_effect_event_decls
                        .contains(&value.identifier.declaration_id)
                    {
                        cx.stable_effect_event_decls
                            .insert(lvalue.identifier.declaration_id);
                    }
                }
            }
            InstructionValue::Primitive {
                value: PrimitiveValue::String(s),
                ..
            } => {
                cx.resolved_names.insert(lvalue.identifier.id, s.clone());
            }
            InstructionValue::PropertyLoad {
                object,
                property,
                optional,
                ..
            } => {
                if let Some(object_name) = resolve_place_name(cx, object) {
                    let resolved =
                        render_property_access_expression_ast(&object_name, property, *optional)
                            .expect("resolved property access should stay on AST path");
                    cx.resolved_names.insert(lvalue.identifier.id, resolved);
                } else if let PropertyLiteral::String(prop) = property {
                    cx.resolved_names.insert(lvalue.identifier.id, prop.clone());
                }
            }
            _ => {}
        }
    }

    // Mark stable destructured hook tuple positions (e.g. useState setter).
    if let InstructionValue::Destructure { lvalue, value, .. } = &instr.value
        && is_stable_setter_hook_result_type(&value.identifier)
        && let Some(hook_name) = cx
            .hook_call_by_decl
            .get(&value.identifier.declaration_id)
            .cloned()
        && let Pattern::Array(arr) = &lvalue.pattern
    {
        for (idx, elem) in arr.items.iter().enumerate() {
            if let ArrayElement::Place(place) = elem
                && is_stable_setter_hook_element(&hook_name, idx)
            {
                cx.mark_stable_setter_identifier(&place.identifier);
            }
        }
    }

    // Track stable `useRef` values (and aliases) so infer-effect-deps can
    // avoid over-capturing `.current` usage for stable local refs.
    if let Some(lvalue) = &instr.lvalue {
        let stable_from_rhs = match &instr.value {
            InstructionValue::CallExpression { callee, .. } => {
                resolve_place_name(cx, callee).is_some_and(|name| is_use_ref_name(&name))
            }
            InstructionValue::MethodCall { property, .. } => {
                resolve_place_name(cx, property).is_some_and(|name| is_use_ref_name(&name))
            }
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => cx
                .stable_ref_decls
                .contains(&place.identifier.declaration_id),
            InstructionValue::TypeCastExpression { value, .. } => cx
                .stable_ref_decls
                .contains(&value.identifier.declaration_id),
            InstructionValue::Ternary {
                consequent,
                alternate,
                ..
            } => {
                cx.stable_ref_decls
                    .contains(&consequent.identifier.declaration_id)
                    && cx
                        .stable_ref_decls
                        .contains(&alternate.identifier.declaration_id)
            }
            InstructionValue::LogicalExpression { left, right, .. } => {
                cx.stable_ref_decls
                    .contains(&left.identifier.declaration_id)
                    && cx
                        .stable_ref_decls
                        .contains(&right.identifier.declaration_id)
            }
            _ => false,
        };
        if stable_from_rhs {
            cx.mark_stable_ref_identifier(&lvalue.identifier);
        }
    }

    // Track callback dependency metadata across aliases so later calls with
    // AUTODEPS can materialize concrete dependency arrays.
    if let Some(lvalue) = &instr.lvalue {
        match &instr.value {
            InstructionValue::FunctionExpression { lowered_func, .. }
            | InstructionValue::ObjectMethod { lowered_func, .. } => {
                let decl_id = lvalue.identifier.declaration_id;
                let has_existing_non_empty = cx
                    .callback_deps
                    .get(&decl_id)
                    .is_some_and(|deps| !deps.is_empty());
                if !has_existing_non_empty {
                    let primitive_literals_for_child = cx.primitive_literals_for_child();
                    let deps = infer_callback_dependency_paths(
                        lowered_func,
                        &cx.stable_ref_decls,
                        &cx.stable_setter_decls,
                        &cx.stable_effect_event_decls,
                        &cx.multi_source_decls,
                        &primitive_literals_for_child,
                    );
                    cx.callback_deps.insert(decl_id, deps);
                } else if std::env::var("DEBUG_AUTODEPS_FLOW").is_ok() {
                    eprintln!(
                        "[AUTODEPS_FLOW] preserve callback deps for decl={} (existing scope override)",
                        decl_id.0
                    );
                }
            }
            InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } => {
                if cx
                    .stable_zero_dep_decls
                    .contains(&place.identifier.declaration_id)
                {
                    cx.stable_zero_dep_decls
                        .insert(lvalue.identifier.declaration_id);
                } else {
                    cx.stable_zero_dep_decls
                        .remove(&lvalue.identifier.declaration_id);
                }
                if let Some(hook) = cx
                    .hook_call_by_decl
                    .get(&place.identifier.declaration_id)
                    .cloned()
                {
                    cx.hook_call_by_decl
                        .insert(lvalue.identifier.declaration_id, hook);
                }
                if let Some(deps) = cx.callback_deps.get(&place.identifier.declaration_id) {
                    cx.callback_deps
                        .insert(lvalue.identifier.declaration_id, deps.clone());
                }
            }
            InstructionValue::TypeCastExpression { value, .. } => {
                if cx
                    .stable_zero_dep_decls
                    .contains(&value.identifier.declaration_id)
                {
                    cx.stable_zero_dep_decls
                        .insert(lvalue.identifier.declaration_id);
                } else {
                    cx.stable_zero_dep_decls
                        .remove(&lvalue.identifier.declaration_id);
                }
                if let Some(deps) = cx.callback_deps.get(&value.identifier.declaration_id) {
                    cx.callback_deps
                        .insert(lvalue.identifier.declaration_id, deps.clone());
                }
            }
            _ => {}
        }
    }

    if let Some(stmt) = maybe_codegen_inline_hook_callback_with_autodeps(cx, instr) {
        return Some(stmt);
    }

    match &instr.value {
        // Store/declare instructions
        InstructionValue::StoreLocal { lvalue, value, .. } => {
            let decl_id = lvalue.place.identifier.declaration_id;
            if lvalue.kind == InstructionKind::Reassign {
                let sources = cx.decl_assignment_sources.entry(decl_id).or_default();
                sources.insert(value.identifier.declaration_id);
                if sources.len() > 1 {
                    cx.multi_source_decls.insert(decl_id);
                }
            }
            if cx
                .multi_source_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.multi_source_decls.insert(decl_id);
            }
            if cx
                .stable_ref_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.mark_stable_ref_identifier(&lvalue.place.identifier);
            }
            if cx
                .stable_setter_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.mark_stable_setter_identifier(&lvalue.place.identifier);
            }
            if cx
                .stable_effect_event_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.stable_effect_event_decls.insert(decl_id);
            }
            if let Some(hook) = cx
                .hook_call_by_decl
                .get(&value.identifier.declaration_id)
                .cloned()
            {
                cx.hook_call_by_decl.insert(decl_id, hook);
            }
            if let Some(deps) = cx.callback_deps.get(&value.identifier.declaration_id) {
                cx.callback_deps.insert(decl_id, deps.clone());
            }
            if cx
                .stable_zero_dep_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.stable_zero_dep_decls.insert(decl_id);
            } else if lvalue.kind == InstructionKind::Reassign {
                cx.stable_zero_dep_decls.remove(&decl_id);
            }

            if lvalue.kind == InstructionKind::Reassign {
                cx.capturable_primitive_literals.remove(&decl_id);
                cx.inline_primitive_literals.remove(&decl_id);
            } else if let Some(literal) = extract_inlineable_primitive_from_place(cx, value) {
                let can_inline = !cx.reassigned_decls.contains(&decl_id)
                    && cx.captured_in_child_functions.contains(&decl_id)
                    && !cx.mutable_captured_in_child_functions.contains(&decl_id);
                if can_inline {
                    cx.capturable_primitive_literals
                        .insert(decl_id, literal.clone());
                    cx.inline_primitive_literals.insert(decl_id, literal);
                } else {
                    cx.capturable_primitive_literals.remove(&decl_id);
                    cx.inline_primitive_literals.remove(&decl_id);
                }
            } else {
                cx.capturable_primitive_literals.remove(&decl_id);
                cx.inline_primitive_literals.remove(&decl_id);
            }
            let kind = if has_materialized_named_binding(cx, &lvalue.place.identifier) {
                InstructionKind::Reassign
            } else {
                lvalue.kind
            };
            let rhs = codegen_place_to_expression(cx, value);
            if rhs == "undefined"
                && kind == InstructionKind::Reassign
                && matches!(value.identifier.loc, SourceLocation::Generated)
            {
                let is_temp_reassign =
                    lvalue
                        .place
                        .identifier
                        .name
                        .as_ref()
                        .is_some_and(|name| match name {
                            IdentifierName::Named(n) | IdentifierName::Promoted(n) => {
                                is_codegen_temp_name(n)
                            }
                        });
                if is_temp_reassign {
                    // Preserve generated temp reassigns to `undefined` for
                    // control-flow lowered value-blocks (upstream keeps these).
                } else {
                    // Lowering sometimes introduces a synthetic `x = undefined` statement
                    // for previously-declared vars. Upstream omits this write.
                    return None;
                }
            }
            if can_inline_generated_undefined_alias(cx, lvalue, value, &rhs) {
                cx.inline_identifier_aliases.insert(decl_id, rhs);
                cx.elided_named_declarations.remove(&decl_id);
                return None;
            }
            if lvalue.kind == InstructionKind::Const
                && can_elide_captured_const_alias_declaration(
                    cx,
                    &lvalue.place.identifier,
                    value.identifier.declaration_id,
                    &rhs,
                )
            {
                cx.inline_identifier_aliases.insert(decl_id, rhs);
                cx.declare(&lvalue.place.identifier);
                cx.elided_named_declarations.insert(decl_id);
                return None;
            }
            if can_inline_jsx_component_tag_alias(
                cx,
                &lvalue.place.identifier,
                value.identifier.declaration_id,
                &rhs,
            ) {
                cx.inline_identifier_aliases.insert(decl_id, rhs);
                cx.declare(&lvalue.place.identifier);
                cx.elided_named_declarations.insert(decl_id);
                return None;
            }

            let mut emitted = String::new();
            if let Some(prefix) =
                maybe_materialize_elided_named_declaration(cx, &lvalue.place.identifier)
            {
                emitted.push_str(&prefix);
            }
            cx.inline_identifier_aliases.remove(&decl_id);
            if let Some(stmt) = codegen_store(cx, instr, kind, &lvalue.place, &rhs) {
                emitted.push_str(&stmt);
            }
            if emitted.is_empty() {
                None
            } else {
                Some(emitted)
            }
        }
        InstructionValue::StoreContext { lvalue, value, .. } => {
            let decl_id = lvalue.place.identifier.declaration_id;
            if lvalue.kind == InstructionKind::Reassign {
                let sources = cx.decl_assignment_sources.entry(decl_id).or_default();
                sources.insert(value.identifier.declaration_id);
                if sources.len() > 1 {
                    cx.multi_source_decls.insert(decl_id);
                }
            }
            if cx
                .multi_source_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.multi_source_decls.insert(decl_id);
            }
            if cx
                .stable_ref_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.mark_stable_ref_identifier(&lvalue.place.identifier);
            }
            if cx
                .stable_setter_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.mark_stable_setter_identifier(&lvalue.place.identifier);
            }
            if cx
                .stable_effect_event_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.stable_effect_event_decls.insert(decl_id);
            }
            if let Some(hook) = cx
                .hook_call_by_decl
                .get(&value.identifier.declaration_id)
                .cloned()
            {
                cx.hook_call_by_decl.insert(decl_id, hook);
            }
            if let Some(deps) = cx.callback_deps.get(&value.identifier.declaration_id) {
                cx.callback_deps.insert(decl_id, deps.clone());
            }
            if cx
                .stable_zero_dep_decls
                .contains(&value.identifier.declaration_id)
            {
                cx.stable_zero_dep_decls.insert(decl_id);
            } else if lvalue.kind == InstructionKind::Reassign {
                cx.stable_zero_dep_decls.remove(&decl_id);
            }

            if lvalue.kind == InstructionKind::Reassign {
                cx.capturable_primitive_literals.remove(&decl_id);
                cx.inline_primitive_literals.remove(&decl_id);
            } else if let Some(literal) = extract_inlineable_primitive_from_place(cx, value) {
                let can_inline = !cx.reassigned_decls.contains(&decl_id)
                    && cx.captured_in_child_functions.contains(&decl_id)
                    && !cx.mutable_captured_in_child_functions.contains(&decl_id);
                if can_inline {
                    cx.capturable_primitive_literals
                        .insert(decl_id, literal.clone());
                    cx.inline_primitive_literals.insert(decl_id, literal);
                } else {
                    cx.capturable_primitive_literals.remove(&decl_id);
                    cx.inline_primitive_literals.remove(&decl_id);
                }
            } else {
                cx.capturable_primitive_literals.remove(&decl_id);
                cx.inline_primitive_literals.remove(&decl_id);
            }
            let rhs = codegen_place_to_expression(cx, value);
            if rhs == "undefined"
                && lvalue.kind == InstructionKind::Reassign
                && matches!(value.identifier.loc, SourceLocation::Generated)
            {
                let is_temp_reassign =
                    lvalue
                        .place
                        .identifier
                        .name
                        .as_ref()
                        .is_some_and(|name| match name {
                            IdentifierName::Named(n) | IdentifierName::Promoted(n) => {
                                is_codegen_temp_name(n)
                            }
                        });
                if !is_temp_reassign {
                    // Upstream omits synthetic `x = undefined` reassignments
                    // introduced by lowering when the variable is already declared.
                    return None;
                }
            }
            if instr.lvalue.is_some() && lvalue.kind == InstructionKind::Reassign {
                // Upstream codegen treats StoreContext reassignment expressions with an
                // instruction lvalue as full statements, not temp-only aliases.
                // This preserves source ordering when assignment results are consumed
                // later across interposing side effects.
                let lhs = identifier_name_with_cx(cx, &lvalue.place.identifier);
                let expr = render_assignment_expression_ast(&lhs, &rhs)
                    .expect("generated reassignment expression should parse");
                return codegen_instruction_expr_with_prec_kind(
                    cx,
                    instr,
                    &expr,
                    ExprPrecedence::Assignment,
                    ExprKind::Normal,
                );
            }
            if can_inline_generated_undefined_alias(cx, lvalue, value, &rhs) {
                cx.inline_identifier_aliases.insert(decl_id, rhs);
                cx.elided_named_declarations.remove(&decl_id);
                return None;
            }
            if lvalue.kind == InstructionKind::Const
                && can_elide_captured_const_alias_declaration(
                    cx,
                    &lvalue.place.identifier,
                    value.identifier.declaration_id,
                    &rhs,
                )
            {
                cx.inline_identifier_aliases.insert(decl_id, rhs);
                cx.declare(&lvalue.place.identifier);
                cx.elided_named_declarations.insert(decl_id);
                return None;
            }
            let mut emitted = String::new();
            if let Some(prefix) =
                maybe_materialize_elided_named_declaration(cx, &lvalue.place.identifier)
            {
                emitted.push_str(&prefix);
            }
            cx.inline_identifier_aliases.remove(&decl_id);
            if let Some(stmt) = codegen_store(cx, instr, lvalue.kind, &lvalue.place, &rhs) {
                emitted.push_str(&stmt);
            }
            if emitted.is_empty() {
                None
            } else {
                Some(emitted)
            }
        }
        InstructionValue::DeclareLocal { lvalue, .. }
        | InstructionValue::DeclareContext { lvalue, .. } => {
            if instr.lvalue.is_some() {
                match lvalue.kind {
                    InstructionKind::Const
                    | InstructionKind::HoistedConst
                    | InstructionKind::Let
                    | InstructionKind::HoistedLet => {
                        set_const_declaration_expression_error(cx, lvalue.kind);
                    }
                    InstructionKind::Function | InstructionKind::HoistedFunction => {
                        set_function_declaration_expression_error(cx, lvalue.kind);
                    }
                    _ => {}
                }
            }
            // DeclareLocal with Catch kind produces no output (matches upstream
            // CodegenReactiveFunction behavior: catch bindings are declared
            // via the catch clause parameter, not via DeclareLocal).
            if lvalue.kind == InstructionKind::Catch {
                return None;
            }
            if cx.has_declared(&lvalue.place.identifier) {
                return None;
            }
            let decl_id = lvalue.place.identifier.declaration_id;
            let raw_name = identifier_name_static(&lvalue.place.identifier);
            let shadows_existing_name = cx.used_declaration_names.contains(&raw_name)
                || raw_name.rsplit_once('_').is_some_and(|(base, suffix)| {
                    !base.is_empty()
                        && suffix.chars().all(|ch| ch.is_ascii_digit())
                        && cx.used_declaration_names.contains(base)
                });
            let can_drop_dead_declare = !cx.read_declarations.contains(&decl_id)
                && !cx.reassigned_decls.contains(&decl_id)
                && !cx.preserve_loop_header_inits
                && shadows_existing_name
                && matches!(
                    lvalue.kind,
                    InstructionKind::Const
                        | InstructionKind::HoistedConst
                        | InstructionKind::Let
                        | InstructionKind::HoistedLet
                );
            if std::env::var("DEBUG_DECLARE_DROP").is_ok() {
                let identifier_name = lvalue
                    .place
                    .identifier
                    .name
                    .as_ref()
                    .map(IdentifierName::value)
                    .unwrap_or("-");
                eprintln!(
                    "[DECLARE_DROP] decl={} ident={} kind={:?} loc={} read={} reassigned={} shadowed_name={} drop={}",
                    decl_id.0,
                    identifier_name,
                    lvalue.kind,
                    debug_loc(&lvalue.place.identifier.loc),
                    cx.read_declarations.contains(&decl_id),
                    cx.reassigned_decls.contains(&decl_id),
                    shadows_existing_name,
                    can_drop_dead_declare
                );
            }
            if can_drop_dead_declare {
                // Keep declaration tracking coherent while omitting dead runtime
                // `let` placeholders that upstream prunes.
                cx.declare(&lvalue.place.identifier);
                cx.inline_identifier_aliases.remove(&decl_id);
                cx.elided_named_declarations.remove(&decl_id);
                return None;
            }
            let name = identifier_name_with_cx(cx, &lvalue.place.identifier);
            cx.declare(&lvalue.place.identifier);
            cx.inline_identifier_aliases.remove(&decl_id);
            cx.elided_named_declarations.remove(&decl_id);
            cx.mark_decl_runtime_emitted(decl_id);
            if lvalue.kind == InstructionKind::Let
                && let Some(init) = crate::optimization::dead_code_elimination::preserved_top_level_let_initializer_for_decl(decl_id)
            {
                return render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Let,
                    &name,
                    Some(&init),
                );
            }
            render_reactive_declare_local_statement_ast(&name)
        }
        InstructionValue::Destructure { lvalue, value, .. } => {
            let kind = lvalue.kind;
            if instr.lvalue.is_some() {
                match kind {
                    InstructionKind::Const
                    | InstructionKind::HoistedConst
                    | InstructionKind::Let
                    | InstructionKind::HoistedLet => {
                        set_const_declaration_expression_error(cx, kind);
                    }
                    InstructionKind::Function | InstructionKind::HoistedFunction => {
                        set_function_declaration_expression_error(cx, kind);
                    }
                    _ => {}
                }
            }
            let rhs = codegen_place_to_expression(cx, value);
            let pattern = if is_stable_setter_hook_result_type(&value.identifier)
                && let (Some(hook_name), Pattern::Array(arr)) = (
                    cx.hook_call_by_decl.get(&value.identifier.declaration_id),
                    &lvalue.pattern,
                ) {
                let mut arr = arr.clone();
                for (idx, item) in arr.items.iter_mut().enumerate() {
                    if let ArrayElement::Place(place) = item {
                        let decl_id = place.identifier.declaration_id;
                        if !is_stable_setter_hook_element(hook_name, idx)
                            && !cx.read_declarations.contains(&decl_id)
                        {
                            *item = ArrayElement::Hole;
                        }
                    }
                }
                Pattern::Array(arr)
            } else {
                lvalue.pattern.clone()
            };
            let lval = codegen_pattern(cx, &pattern);
            let operands = pattern_operands(&pattern);

            // Check if all pattern operands are already declared
            let all_declared = operands.iter().all(|p| cx.has_declared(&p.identifier));
            let all_codegen_temps = !operands.is_empty()
                && operands.iter().all(|p| {
                    let name = identifier_name_static(&p.identifier);
                    is_codegen_temp_name(&name)
                });
            // Upstream consistently emits temporary-pattern destructures as
            // declarations, even when our lowered kind is `Reassign`.
            let force_temp_declare = all_codegen_temps;
            debug_codegen_expr(
                "destructure",
                format!(
                    "kind={:?} pattern={} rhs={} all_declared={} force_temp_declare={} mutable_source={}",
                    kind,
                    lval,
                    rhs,
                    all_declared,
                    force_temp_declare,
                    cx.mutable_destructure_sources
                        .contains(&value.identifier.declaration_id)
                ),
            );

            let declaration_kind = reactive_destructure_declaration_kind(cx, kind, &pattern);
            if let Some(bridged) =
                maybe_codegen_captured_context_destructure_bridge(cx, &pattern, &rhs, all_declared)
            {
                return Some(bridged);
            }

            if (all_declared || kind == InstructionKind::Reassign) && !force_temp_declare {
                render_reactive_destructure_statement_ast(cx, &pattern, &rhs, None)
            } else {
                // Declare all pattern operands
                for p in operands {
                    cx.declare(&p.identifier);
                    if force_temp_declare
                        && let Some(name) = cx
                            .declaration_name_overrides
                            .get(&p.identifier.declaration_id)
                        && let Some(names) = cx.block_scope_declared_temp_names.last_mut()
                    {
                        names.insert(name.clone());
                    }
                }
                render_reactive_destructure_statement_ast(
                    cx,
                    &pattern,
                    &rhs,
                    Some(declaration_kind),
                )
            }
        }
        // No-op instructions
        InstructionValue::StartMemoize {
            manual_memo_id,
            deps,
            ..
        } => {
            let mut dep_roots: HashSet<DeclarationId> = HashSet::new();
            if let Some(deps) = deps {
                for dep in deps {
                    if let ManualMemoRoot::NamedLocal(place) = &dep.root {
                        dep_roots.insert(place.identifier.declaration_id);
                        if dep.path.is_empty() {
                            if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                                eprintln!(
                                    "[START_MEMO_DEP] decl={} name={:?}",
                                    place.identifier.declaration_id.0, place.identifier.name
                                );
                            }
                            cx.pending_manual_memo_reads
                                .insert(place.identifier.declaration_id);
                        }
                    }
                }
            }
            cx.manual_memo_dep_roots_by_id
                .insert(*manual_memo_id, dep_roots);
            None
        }
        InstructionValue::FinishMemoize {
            manual_memo_id,
            decl,
            pruned,
            ..
        } => {
            if let Some(dep_roots) = cx.manual_memo_dep_roots_by_id.get(manual_memo_id).cloned() {
                cx.manual_memo_dep_roots_by_decl
                    .insert(decl.identifier.declaration_id, dep_roots);
            }
            if *pruned {
                cx.pruned_manual_memo_decls
                    .insert(decl.identifier.declaration_id);
            }
            None
        }
        InstructionValue::Debugger { .. } => Some("debugger;\n".to_string()),
        InstructionValue::ObjectMethod { lowered_func, .. } => {
            if let Some(lvalue) = &instr.lvalue {
                let info = ObjectMethodInfo {
                    lowered_func: lowered_func.clone(),
                };
                let idx = cx.object_methods_store.len();
                cx.object_methods_store.push(info);
                cx.object_methods.insert(lvalue.identifier.id, idx);
                let rendered = render_lowered_function_expression_source(
                    cx,
                    lowered_func,
                    None,
                    &FunctionExpressionType::FunctionExpression,
                    None,
                );
                cx.set_temp_expr(&lvalue.identifier, rendered.map(ExprValue::primary));
            }
            None
        }
        InstructionValue::LoadGlobal { binding: _, .. } => {
            let ev = codegen_instruction_value_ev(cx, &instr.value);
            codegen_instruction_expr_with_prec_kind(cx, instr, &ev.expr, ev.prec, ExprKind::Normal)
        }
        // All other instruction values -> expression
        _ => {
            let ev = codegen_instruction_value_ev(cx, &instr.value);
            let stmt =
                codegen_instruction_expr_with_prec_kind(cx, instr, &ev.expr, ev.prec, ev.kind);
            if let InstructionValue::FunctionExpression { lowered_func, .. }
            | InstructionValue::ObjectMethod { lowered_func, .. } = &instr.value
            {
                cx.reserved_child_decl_names.extend(
                    collect_local_declaration_names_from_lowered_function(lowered_func),
                );
            }
            stmt
        }
    }
}

fn maybe_codegen_inline_hook_callback_with_autodeps(
    cx: &mut Context,
    instr: &ReactiveInstruction,
) -> Option<String> {
    // Keep this narrowly scoped: only transform statement-position hook calls
    // that still contain an inline callback and AUTODEPS placeholder.
    if instr
        .lvalue
        .as_ref()
        .and_then(|lv| lv.identifier.name.as_ref())
        .is_some()
    {
        return None;
    }

    match &instr.value {
        InstructionValue::CallExpression {
            callee,
            args,
            optional,
            ..
        } => {
            let is_hook_call = resolve_place_name(cx, callee)
                .as_deref()
                .is_some_and(|name| extract_hook_name(name).is_some());
            let callee_expr = codegen_place_to_expression(cx, callee);
            let mut rendered_args: Vec<String> =
                args.iter().map(|a| codegen_argument(cx, a)).collect();
            let autodeps_index = find_rendered_autodeps_index(&rendered_args)?;
            let hook_name = callee
                .identifier
                .name
                .as_ref()
                .map(|n| n.value().to_string())
                .unwrap_or_else(|| callee_expr.clone());
            let hook_is_direct = callee.identifier.name.is_some();
            maybe_replace_autodeps_with_inferred_deps(
                cx,
                &hook_name,
                args,
                &mut rendered_args,
                hook_is_direct,
            );
            let needs_wrap = rendered_expr_is_function_like(&callee_expr);
            let callee_final = if needs_wrap {
                format!("({})", callee_expr)
            } else {
                callee_expr.clone()
            };
            if cx.disable_memoization_features {
                let call_expr =
                    render_call_expression_ast(&callee_final, args, &rendered_args, *optional)
                        .expect("autodeps call should stay on AST path");
                let call_expr = if cx.emit_hook_guards && is_hook_call {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                return render_reactive_expression_statement_ast(&call_expr);
            }
            let callback_index = (0..autodeps_index).rev().find(|idx| {
                let arg = rendered_args[*idx].trim();
                rendered_expr_is_function_like(arg)
            })?;
            let mut call_args = rendered_args.clone();
            let cb_expr = call_args[callback_index].clone();
            let cb_name = fresh_temp_name(cx);
            call_args[callback_index] = cb_name.clone();
            let deps_array_index = if callback_index + 1 < autodeps_index {
                let idx = callback_index + 1;
                let arg = call_args[idx].trim();
                if parse_rendered_array_deps(arg).is_some() {
                    Some(idx)
                } else {
                    None
                }
            } else {
                None
            };
            let pre = if let Some(dep_idx) = deps_array_index {
                let deps_expr = rendered_args[autodeps_index].clone();
                let deps_name = fresh_temp_name(cx);
                let cb_slot = cx.alloc_cache_slot();
                let deps_slot = cx.alloc_cache_slot();
                call_args[dep_idx] = deps_name.clone();
                let call_expr =
                    render_call_expression_ast(&callee_final, args, &call_args, *optional)
                        .expect("cached autodeps call should stay on AST path");
                let call_expr = if cx.emit_hook_guards && is_hook_call {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                render_cached_inline_hook_callback_block_ast(
                    &cb_name,
                    &cb_expr,
                    cb_slot,
                    Some((&deps_name, &deps_expr, deps_slot)),
                    &call_expr,
                )?
            } else {
                let slot = cx.alloc_cache_slot();
                let call_expr =
                    render_call_expression_ast(&callee_final, args, &call_args, *optional)
                        .expect("cached autodeps call should stay on AST path");
                let call_expr = if cx.emit_hook_guards && is_hook_call {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                render_cached_inline_hook_callback_block_ast(
                    &cb_name, &cb_expr, slot, None, &call_expr,
                )?
            };
            Some(pre)
        }
        InstructionValue::MethodCall {
            receiver,
            property,
            args,
            receiver_optional,
            call_optional,
            ..
        } => {
            let recv = codegen_member_object_expression(cx, receiver);
            let (prop, is_computed) = resolve_method_property(cx, property, &recv);
            if is_computed || !Environment::is_hook_name(&prop) {
                return None;
            }
            let mut rendered_args: Vec<String> =
                args.iter().map(|a| codegen_argument(cx, a)).collect();
            let autodeps_index = find_rendered_autodeps_index(&rendered_args)?;
            maybe_replace_autodeps_with_inferred_deps(cx, &prop, args, &mut rendered_args, true);
            if cx.disable_memoization_features {
                let call_expr = render_method_call_expression_with_options_ast(
                    &recv,
                    &prop,
                    args,
                    &rendered_args,
                    false,
                    *receiver_optional,
                    *call_optional,
                )
                .expect("autodeps method call should stay on AST path");
                let call_expr = if cx.emit_hook_guards {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                return render_reactive_expression_statement_ast(&call_expr);
            }
            let callback_index = (0..autodeps_index).rev().find(|idx| {
                let arg = rendered_args[*idx].trim();
                rendered_expr_is_function_like(arg)
            })?;
            let mut call_args = rendered_args.clone();
            let cb_expr = call_args[callback_index].clone();
            let cb_name = fresh_temp_name(cx);
            call_args[callback_index] = cb_name.clone();
            let deps_array_index = if callback_index + 1 < autodeps_index {
                let idx = callback_index + 1;
                let arg = call_args[idx].trim();
                if parse_rendered_array_deps(arg).is_some() {
                    Some(idx)
                } else {
                    None
                }
            } else {
                None
            };
            let pre = if let Some(dep_idx) = deps_array_index {
                let deps_expr = rendered_args[autodeps_index].clone();
                let deps_name = fresh_temp_name(cx);
                let cb_slot = cx.alloc_cache_slot();
                let deps_slot = cx.alloc_cache_slot();
                call_args[dep_idx] = deps_name.clone();
                let call_expr = render_method_call_expression_with_options_ast(
                    &recv,
                    &prop,
                    args,
                    &call_args,
                    false,
                    *receiver_optional,
                    *call_optional,
                )
                .expect("cached autodeps method call should stay on AST path");
                let call_expr = if cx.emit_hook_guards {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                render_cached_inline_hook_callback_block_ast(
                    &cb_name,
                    &cb_expr,
                    cb_slot,
                    Some((&deps_name, &deps_expr, deps_slot)),
                    &call_expr,
                )?
            } else {
                let slot = cx.alloc_cache_slot();
                let call_expr = render_method_call_expression_with_options_ast(
                    &recv,
                    &prop,
                    args,
                    &call_args,
                    false,
                    *receiver_optional,
                    *call_optional,
                )
                .expect("cached autodeps method call should stay on AST path");
                let call_expr = if cx.emit_hook_guards {
                    guard_hook_call_expression(cx, call_expr)
                } else {
                    call_expr
                };
                render_cached_inline_hook_callback_block_ast(
                    &cb_name, &cb_expr, slot, None, &call_expr,
                )?
            };
            Some(pre)
        }
        _ => None,
    }
}

/// Handle store-like instructions (StoreLocal, StoreContext).
fn is_simple_identifier_expression(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let mut chars = trimmed.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !(first.is_ascii_alphabetic() || first == '_' || first == '$') {
        return false;
    }
    chars.all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '$')
}

fn can_inline_jsx_component_tag_alias(
    cx: &Context,
    target_identifier: &Identifier,
    source_decl: DeclarationId,
    rhs: &str,
) -> bool {
    let decl_id = target_identifier.declaration_id;
    let component_like_name = target_identifier.name.as_ref().is_some_and(|name| {
        name.value()
            .chars()
            .next()
            .is_some_and(|ch| ch.is_ascii_uppercase())
    });
    if !cx.jsx_only_component_tag_decls.contains(&decl_id) && !component_like_name {
        return false;
    }
    if cx.captured_in_child_functions.contains(&decl_id)
        || cx.mutable_captured_in_child_functions.contains(&decl_id)
    {
        return false;
    }
    if !(cx.non_local_binding_decls.contains(&source_decl)
        || cx.inline_identifier_aliases.contains_key(&source_decl))
    {
        return false;
    }
    if !is_simple_identifier_expression(rhs) {
        return false;
    }
    !cx.has_declared_by_runtime_emission(decl_id) || cx.elided_named_declarations.contains(&decl_id)
}

fn can_inline_generated_undefined_alias(
    cx: &Context,
    lvalue: &LValue,
    value: &Place,
    rhs: &str,
) -> bool {
    rhs == "undefined"
        && lvalue.kind != InstructionKind::Reassign
        && value.identifier.name.is_none()
        && cx
            .pruned_manual_memo_decls
            .contains(&value.identifier.declaration_id)
        && !cx
            .reassigned_decls
            .contains(&lvalue.place.identifier.declaration_id)
}

fn can_elide_captured_const_alias_declaration(
    cx: &Context,
    target_identifier: &Identifier,
    source_decl: DeclarationId,
    rhs: &str,
) -> bool {
    let decl_id = target_identifier.declaration_id;
    !matches!(target_identifier.type_, Type::Function { .. })
        && !cx.direct_read_declarations.contains(&decl_id)
        && cx.captured_in_child_functions.contains(&decl_id)
        && !cx.mutable_captured_in_child_functions.contains(&decl_id)
        && !cx.reassigned_decls.contains(&decl_id)
        && !cx.manual_memo_root_decls.contains(&decl_id)
        && !cx.function_decl_decls.contains(&decl_id)
        && !cx.preserve_loop_header_inits
        && (is_inlineable_primitive_literal_expression(rhs)
            || (is_simple_identifier_expression(rhs)
                && cx.non_local_binding_decls.contains(&source_decl)))
}

fn maybe_materialize_elided_named_declaration(cx: &mut Context, id: &Identifier) -> Option<String> {
    if !cx.elided_named_declarations.contains(&id.declaration_id) {
        return None;
    }
    let name = identifier_name_with_cx(cx, id);
    let init = cx
        .inline_identifier_aliases
        .get(&id.declaration_id)
        .cloned();
    cx.inline_identifier_aliases.remove(&id.declaration_id);
    cx.elided_named_declarations.remove(&id.declaration_id);
    cx.mark_decl_runtime_emitted(id.declaration_id);
    if let Some(init_expr) = init {
        render_reactive_variable_statement_ast(
            ast::VariableDeclarationKind::Let,
            &name,
            Some(&init_expr),
        )
    } else {
        render_reactive_variable_statement_ast(ast::VariableDeclarationKind::Let, &name, None)
    }
}

fn has_materialized_named_binding(cx: &Context, id: &Identifier) -> bool {
    cx.has_declared_by_runtime_emission(id.declaration_id)
        || cx.elided_named_declarations.contains(&id.declaration_id)
}

fn codegen_store(
    cx: &mut Context,
    instr: &ReactiveInstruction,
    kind: InstructionKind,
    place: &Place,
    rhs: &str,
) -> Option<String> {
    if instr.lvalue.is_some() {
        match kind {
            InstructionKind::Const | InstructionKind::Let | InstructionKind::HoistedLet => {
                set_const_declaration_expression_error(cx, kind);
            }
            InstructionKind::Function => {
                set_function_declaration_expression_error(cx, kind);
            }
            _ => {}
        }
    }

    let name = identifier_name_with_cx(cx, &place.identifier);
    if std::env::var("DEBUG_CODEGEN_STORE").is_ok() {
        eprintln!(
            "[CODEGEN_STORE] kind={:?} decl={} name={} has_outer_lvalue={} rhs={}",
            kind,
            place.identifier.declaration_id.0,
            name,
            instr.lvalue.is_some(),
            rhs
        );
    }
    match kind {
        InstructionKind::Const | InstructionKind::Function => {
            let decl_id = place.identifier.declaration_id;
            let can_drop_unused_const_literal = kind == InstructionKind::Const
                && instr.lvalue.is_none()
                && !cx.read_declarations.contains(&decl_id)
                && !cx.manual_memo_root_decls.contains(&decl_id)
                && !cx.function_decl_decls.contains(&decl_id)
                && !cx.preserve_loop_header_inits
                && is_inlineable_primitive_literal_expression(rhs);
            if can_drop_unused_const_literal {
                // Parity: upstream drops dead primitive const stores after propagation.
                // Preserve declaration tracking so later declaration checks stay coherent.
                cx.declare(&place.identifier);
                return None;
            }
            let should_emit_fn_decl =
                kind == InstructionKind::Function || cx.function_decl_decls.contains(&decl_id);
            if should_emit_fn_decl && let Some(fn_decl) = function_expr_as_declaration(&name, rhs) {
                cx.declare(&place.identifier);
                cx.mark_decl_runtime_emitted(decl_id);
                return Some(format!("{fn_decl}\n"));
            }
            cx.declare(&place.identifier);
            cx.mark_decl_runtime_emitted(decl_id);
            render_reactive_variable_statement_ast(
                ast::VariableDeclarationKind::Const,
                &name,
                Some(rhs),
            )
        }
        InstructionKind::Let | InstructionKind::HoistedLet => {
            let decl_id = place.identifier.declaration_id;
            if cx.function_decl_decls.contains(&decl_id)
                && let Some(fn_decl) = function_expr_as_declaration(&name, rhs)
            {
                cx.declare(&place.identifier);
                cx.mark_decl_runtime_emitted(decl_id);
                return Some(format!("{fn_decl}\n"));
            }
            cx.declare(&place.identifier);
            cx.mark_decl_runtime_emitted(decl_id);
            let omit_initializer = rhs == "undefined"
                || (rhs == "null"
                    && cx.elidable_null_initializer_decls.contains(&decl_id)
                    && !cx.captured_in_child_functions.contains(&decl_id)
                    && !cx.mutable_captured_in_child_functions.contains(&decl_id));
            if omit_initializer {
                render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Let,
                    &name,
                    None,
                )
            } else {
                render_reactive_variable_statement_ast(
                    ast::VariableDeclarationKind::Let,
                    &name,
                    Some(rhs),
                )
            }
        }
        InstructionKind::Reassign => {
            if instr.lvalue.is_none() && rhs.trim() == name {
                let is_context_store = matches!(instr.value, InstructionValue::StoreContext { .. });
                if !is_context_store {
                    return None;
                }
            }
            let expr = render_assignment_expression_ast(&name, rhs)
                .expect("generated assignment expression should parse");
            if let Some(lvalue) = &instr.lvalue {
                if std::env::var("DEBUG_CODEGEN_STORE").is_ok() {
                    eprintln!(
                        "[CODEGEN_STORE] cached temp id={} expr={}",
                        lvalue.identifier.id.0, expr
                    );
                }
                // Store as temp for later reference
                if is_temp_like_identifier(cx, &lvalue.identifier) {
                    cx.inline_identifier_aliases
                        .insert(lvalue.identifier.declaration_id, expr.clone());
                }
                cx.set_temp_expr(
                    &lvalue.identifier,
                    Some(ExprValue::new(expr, ExprPrecedence::Assignment)),
                );
                None
            } else {
                render_reactive_assignment_statement_ast(&name, rhs)
            }
        }
        InstructionKind::Catch => {
            // Catch binding: `const e = t1;` inside handler body.
            // The catch temp is declared as the catch param, so this creates
            // a named alias for the catch parameter.
            cx.declare(&place.identifier);
            cx.mark_decl_runtime_emitted(place.identifier.declaration_id);
            render_reactive_variable_statement_ast(
                ast::VariableDeclarationKind::Const,
                &name,
                Some(rhs),
            )
        }
        InstructionKind::HoistedConst | InstructionKind::HoistedFunction => {
            // Should have been pruned by PruneHoistedContexts
            cx.declare(&place.identifier);
            cx.mark_decl_runtime_emitted(place.identifier.declaration_id);
            render_reactive_variable_statement_ast(
                ast::VariableDeclarationKind::Const,
                &name,
                Some(rhs),
            )
        }
    }
}

fn codegen_instruction_expr_with_prec_kind(
    cx: &mut Context,
    instr: &ReactiveInstruction,
    value: &str,
    prec: ExprPrecedence,
    kind: ExprKind,
) -> Option<String> {
    if let Some(lvalue) = &instr.lvalue {
        if is_temp_like_identifier(cx, &lvalue.identifier) {
            if let InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } = &instr.value
                && place.identifier.name.is_some()
            {
                let source_decl = place.identifier.declaration_id;
                let temp_decl = lvalue.identifier.declaration_id;
                let has_pending = cx.pending_manual_memo_reads.contains(&source_decl);
                let is_reassigned = cx.reassigned_decls.contains(&source_decl);
                let temp_is_read = cx.read_declarations.contains(&temp_decl);
                if is_reassigned && !temp_is_read {
                    if has_pending {
                        cx.pending_manual_memo_reads.remove(&source_decl);
                    }
                    debug_codegen_expr(
                        "stmt-expr-emit-unused-temp-load",
                        format!("source_decl={} expr={}", source_decl.0, value),
                    );
                    return render_reactive_expression_statement_ast(value);
                }
            }
            // Temporary - store for later
            if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                eprintln!(
                    "[CODEGEN_TEMP_SET] id={} decl={} expr={}",
                    lvalue.identifier.id.0, lvalue.identifier.declaration_id.0, value
                );
            }
            cx.inline_identifier_aliases
                .insert(lvalue.identifier.declaration_id, value.to_string());
            cx.set_temp_expr(
                &lvalue.identifier,
                Some(ExprValue {
                    expr: value.to_string(),
                    prec,
                    kind,
                }),
            );
            if let InstructionValue::LoadLocal { place, .. }
            | InstructionValue::LoadContext { place, .. } = &instr.value
                && place.identifier.name.is_some()
            {
                let decl_id = place.identifier.declaration_id;
                let has_pending = cx.pending_manual_memo_reads.contains(&decl_id);
                let is_reassigned = cx.reassigned_decls.contains(&decl_id);
                if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                    eprintln!(
                        "[CODEGEN_TEMP_LOAD] decl={} name={:?} reassigned={} pending={}",
                        decl_id.0, place.identifier.name, is_reassigned, has_pending
                    );
                }
                if is_reassigned && has_pending {
                    cx.pending_manual_memo_reads.remove(&decl_id);
                }
            }
            None
        } else {
            let name = identifier_name_with_cx(cx, &lvalue.identifier);
            let rhs = if prec <= ExprPrecedence::Assignment {
                format!("({})", value)
            } else {
                value.to_string()
            };
            let has_runtime_binding = has_materialized_named_binding(cx, &lvalue.identifier);
            if std::env::var("DEBUG_CODEGEN_EXPR").is_ok() {
                eprintln!(
                    "[CODEGEN_NAMED_LVALUE] id={} decl={} name={} declared={} runtime={} elided={} rhs={}",
                    lvalue.identifier.id.0,
                    lvalue.identifier.declaration_id.0,
                    name,
                    cx.has_declared(&lvalue.identifier),
                    cx.has_declared_by_runtime_emission(lvalue.identifier.declaration_id),
                    cx.elided_named_declarations
                        .contains(&lvalue.identifier.declaration_id),
                    rhs
                );
            }
            if has_runtime_binding {
                let mut emitted = String::new();
                if let Some(prefix) =
                    maybe_materialize_elided_named_declaration(cx, &lvalue.identifier)
                {
                    emitted.push_str(&prefix);
                }
                emitted.push_str(&render_reactive_assignment_statement_ast(&name, &rhs)?);
                Some(emitted)
            } else {
                cx.declare(&lvalue.identifier);
                cx.mark_decl_runtime_emitted(lvalue.identifier.declaration_id);
                let decl_kind =
                    if matches!(lvalue.identifier.name, Some(IdentifierName::Promoted(_))) {
                        ast::VariableDeclarationKind::Let
                    } else {
                        ast::VariableDeclarationKind::Const
                    };
                render_reactive_variable_statement_ast(decl_kind, &name, Some(&rhs))
            }
        }
    } else if value == "undefined" {
        None
    } else if let InstructionValue::LoadLocal { place, .. }
    | InstructionValue::LoadContext { place, .. } = &instr.value
    {
        if place.identifier.name.is_none()
            && (is_inlineable_primitive_literal_expression(value)
                || is_simple_identifier_expression(value))
        {
            // Preserve upstream parity: unnamed-temp literal loads in statement
            // position are dead no-ops after lowering and should be elided.
            None
        } else {
            debug_codegen_expr(
                "stmt-expr-emit",
                format!(
                    "kind={} expr={}",
                    instruction_value_tag(&instr.value),
                    value
                ),
            );
            render_reactive_expression_statement_ast(value)
        }
    } else {
        debug_codegen_expr(
            "stmt-expr-emit",
            format!(
                "kind={} expr={}",
                instruction_value_tag(&instr.value),
                value
            ),
        );
        render_reactive_expression_statement_ast(value)
    }
}

/// Generate an ExprValue from an instruction value (with proper precedence tracking).
fn codegen_instruction_value_ev(cx: &mut Context, value: &InstructionValue) -> ExprValue {
    match value {
        InstructionValue::Primitive { value: prim, .. } => {
            let expr =
                render_primitive_expression_ast(prim).unwrap_or_else(|| codegen_primitive(prim));
            ExprValue::primary(expr)
        }
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            codegen_place_expr_value(cx, place)
        }
        InstructionValue::LoadGlobal { binding, .. } => {
            ExprValue::primary(binding.name().to_string())
        }
        InstructionValue::BinaryExpression {
            left,
            right,
            operator,
            ..
        } => {
            let prec = binary_operator_precedence(operator);
            let l = codegen_place_with_min_prec(cx, left, prec);
            let r = codegen_place_with_min_prec(cx, right, prec);
            let expr = render_binary_expression_ast(&l, *operator, &r)
                .expect("generated binary expression should parse");
            ExprValue::new(expr, prec)
        }
        InstructionValue::UnaryExpression {
            value: operand,
            operator,
            ..
        } => {
            let expr = codegen_place_with_min_prec(cx, operand, ExprPrecedence::Unary);
            let rendered = render_unary_expression_ast(*operator, &expr)
                .expect("generated unary expression should parse");
            ExprValue::new(rendered, ExprPrecedence::Unary)
        }
        InstructionValue::CallExpression {
            callee,
            args,
            optional,
            ..
        } => {
            let is_hook_call = resolve_place_name(cx, callee)
                .as_deref()
                .is_some_and(|name| extract_hook_name(name).is_some());
            let callee_expr = codegen_place_to_expression(cx, callee);
            let mut rendered_args: Vec<String> =
                args.iter().map(|a| codegen_argument(cx, a)).collect();
            maybe_replace_autodeps_with_inferred_deps(
                cx,
                &callee_expr,
                args,
                &mut rendered_args,
                true,
            );
            // Wrap arrow/functions in parens for IIFE callee position.
            let needs_wrap = rendered_expr_is_function_like(&callee_expr);
            let callee_final = if needs_wrap {
                format!("({})", callee_expr)
            } else {
                callee_expr
            };
            debug_codegen_expr(
                "call-expression",
                format!(
                    "callee={} optional={} args={:?}",
                    callee_final, optional, rendered_args
                ),
            );
            let call_expr =
                render_call_expression_ast(&callee_final, args, &rendered_args, *optional)
                    .expect("generated call expression should parse");
            if cx.emit_hook_guards && is_hook_call {
                ExprValue::primary(guard_hook_call_expression(cx, call_expr))
            } else {
                ExprValue::primary(call_expr)
            }
        }
        InstructionValue::MethodCall {
            receiver,
            property,
            args,
            receiver_optional,
            call_optional,
            ..
        } => {
            let recv = codegen_member_object_expression(cx, receiver);
            let (prop, is_computed) = resolve_method_property(cx, property, &recv);
            let mut rendered_args: Vec<String> =
                args.iter().map(|a| codegen_argument(cx, a)).collect();
            if std::env::var("DEBUG_METHODCALL").is_ok() {
                let arg_decls: Vec<u32> = args
                    .iter()
                    .map(|a| match a {
                        Argument::Place(p) | Argument::Spread(p) => p.identifier.declaration_id.0,
                    })
                    .collect();
                eprintln!(
                    "[METHODCALL] recv={} prop={} computed={} args_decl={:?} rendered_args={:?}",
                    recv, prop, is_computed, arg_decls, rendered_args
                );
            }
            let hook_name = if is_computed {
                None
            } else {
                Some(prop.as_str())
            };
            maybe_replace_autodeps_with_inferred_deps(
                cx,
                hook_name.unwrap_or(""),
                args,
                &mut rendered_args,
                hook_name.is_some(),
            );
            debug_codegen_expr(
                "method-call",
                format!(
                    "receiver={} property={} computed={} recv_optional={} call_optional={} args={:?}",
                    recv, prop, is_computed, receiver_optional, call_optional, rendered_args
                ),
            );
            let is_hook_call = !is_computed && Environment::is_hook_name(&prop);
            let call_expr = render_method_call_expression_with_options_ast(
                &recv,
                &prop,
                args,
                &rendered_args,
                is_computed,
                *receiver_optional,
                *call_optional,
            )
            .expect("method call should stay on AST path");
            if cx.emit_hook_guards && is_hook_call {
                ExprValue::primary(guard_hook_call_expression(cx, call_expr))
            } else {
                ExprValue::primary(call_expr)
            }
        }
        InstructionValue::NewExpression { callee, args, .. } => {
            let expr = render_new_expression_ast(cx, callee, args)
                .expect("generated new expression should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::ObjectExpression { properties, .. } => {
            if properties.is_empty() {
                return ExprValue::primary("{}".to_string());
            }
            let expr = render_object_expression_ast(cx, properties)
                .expect("generated object expression should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::ArrayExpression { elements, .. } => {
            let expr = render_array_expression_ast(cx, elements)
                .expect("generated array expression should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::PropertyLoad {
            object,
            property,
            optional,
            loc,
        } => {
            if !optional && let Some(source_expr) = maybe_render_grouped_optional_member_source(loc)
            {
                return ExprValue::primary(source_expr);
            }
            let obj = codegen_member_object_expression(cx, object);
            let expr = render_property_access_expression_ast(&obj, property, *optional)
                .expect("generated property load should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::PropertyStore {
            object,
            property,
            value: val,
            ..
        } => {
            let obj = codegen_member_object_expression(cx, object);
            let v = codegen_place_to_expression(cx, val);
            let expr = render_property_store_expression_ast(&obj, property, &v)
                .expect("generated property store should parse");
            ExprValue::new(expr, ExprPrecedence::Assignment)
        }
        InstructionValue::PropertyDelete {
            object, property, ..
        } => {
            let obj = codegen_member_object_expression(cx, object);
            let expr = render_property_delete_expression_ast(&obj, property)
                .expect("generated property delete should parse");
            ExprValue::new(expr, ExprPrecedence::Unary)
        }
        InstructionValue::ComputedLoad {
            object,
            property,
            optional,
            loc,
        } => {
            if !optional && let Some(source_expr) = maybe_render_grouped_optional_member_source(loc)
            {
                return ExprValue::primary(source_expr);
            }
            let obj = codegen_member_object_expression(cx, object);
            let prop = codegen_place_to_expression(cx, property);
            let expr = render_computed_access_expression_ast(&obj, &prop, *optional)
                .expect("generated computed load should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::ComputedStore {
            object,
            property,
            value: val,
            ..
        } => {
            let obj = codegen_member_object_expression(cx, object);
            let prop = codegen_place_to_expression(cx, property);
            let v = codegen_place_to_expression(cx, val);
            let expr = render_computed_store_expression_ast(&obj, &prop, &v)
                .expect("generated computed store should parse");
            ExprValue::new(expr, ExprPrecedence::Assignment)
        }
        InstructionValue::ComputedDelete {
            object, property, ..
        } => {
            let obj = codegen_member_object_expression(cx, object);
            let prop = codegen_place_to_expression(cx, property);
            let expr = render_computed_delete_expression_ast(&obj, &prop)
                .expect("generated computed delete should parse");
            ExprValue::new(expr, ExprPrecedence::Unary)
        }
        InstructionValue::StoreGlobal {
            name, value: val, ..
        } => {
            let v = codegen_place_to_expression(cx, val);
            let expr = render_global_store_expression_ast(name, &v)
                .expect("generated global store should parse");
            ExprValue::new(expr, ExprPrecedence::Assignment)
        }
        InstructionValue::JsxExpression {
            tag,
            props,
            children,
            ..
        } => {
            let expr = render_jsx_expression_ast(cx, tag, props, children)
                .expect("generated jsx element should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::JsxFragment { children, .. } => {
            let expr =
                render_jsx_fragment_ast(cx, children).expect("generated jsx fragment should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::JSXText { value: text, .. } => {
            ExprValue::jsx_text(format!("\"{}\"", escape_jsx_text(text)))
        }
        InstructionValue::FunctionExpression {
            lowered_func,
            name,
            expr_type,
            ..
        } => ExprValue::primary(codegen_function_expression(
            cx,
            lowered_func,
            name,
            expr_type,
        )),
        InstructionValue::ObjectMethod { lowered_func, .. } => {
            let expr = render_lowered_function_expression_source(
                cx,
                lowered_func,
                None,
                &FunctionExpressionType::FunctionExpression,
                None,
            )
            .expect("object method should stay on AST path");
            ExprValue::primary(expr)
        }
        InstructionValue::TaggedTemplateExpression {
            tag, raw, cooked, ..
        } => {
            let expr = render_tagged_template_expression_ast(cx, tag, raw, cooked.as_deref())
                .expect("generated tagged template literal should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::TemplateLiteral {
            quasis, subexprs, ..
        } => {
            let expr = render_template_literal_ast(cx, quasis, subexprs)
                .expect("generated template literal should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::TypeCastExpression {
            value: val,
            type_annotation,
            type_annotation_kind,
            ..
        } => {
            let value_expr =
                codegen_place_expr_value(cx, val).wrap_if_needed(match type_annotation_kind {
                    TypeAnnotationKind::Cast => ExprPrecedence::Assignment,
                    TypeAnnotationKind::As | TypeAnnotationKind::Satisfies => {
                        ExprPrecedence::Relational
                    }
                });
            let expr = render_ts_type_cast_expression_ast(
                &value_expr,
                type_annotation,
                *type_annotation_kind,
            )
            .expect("generated type cast should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::RegExpLiteral { pattern, flags, .. } => {
            let expr = render_regexp_literal_expression_ast(pattern, flags)
                .expect("generated regexp literal should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::MetaProperty { meta, property, .. } => {
            let expr = render_meta_property_expression_ast(meta, property)
                .expect("generated meta property should parse");
            ExprValue::primary(expr)
        }
        InstructionValue::Await { value: val, .. } => {
            let expr = codegen_place_to_expression(cx, val);
            let rendered = render_await_expression_ast(&expr)
                .expect("generated await expression should parse");
            ExprValue::new(rendered, ExprPrecedence::Unary)
        }
        InstructionValue::GetIterator { collection, .. } => {
            codegen_place_expr_value(cx, collection)
        }
        InstructionValue::IteratorNext { iterator, .. } => codegen_place_expr_value(cx, iterator),
        InstructionValue::NextPropertyOf { value: val, .. } => codegen_place_expr_value(cx, val),
        InstructionValue::PostfixUpdate {
            value, operation, ..
        } => {
            // Use `value` (read operand) rather than `lvalue` (write operand).
            // After SSA, `lvalue` gets a new IdentifierId that has no entry in
            // cx.temp, so codegen would fall back to a synthetic "tN" name.
            // `value` still maps to the LoadLocal that loaded the original variable.
            let expr = codegen_place_to_expression(cx, value);
            let rendered = render_update_expression_ast(&expr, *operation, false)
                .expect("generated postfix update should parse");
            ExprValue::primary(rendered)
        }
        InstructionValue::PrefixUpdate {
            value, operation, ..
        } => {
            let expr = codegen_place_to_expression(cx, value);
            let rendered = render_update_expression_ast(&expr, *operation, true)
                .expect("generated prefix update should parse");
            ExprValue::primary(rendered)
        }
        InstructionValue::ReactiveSequenceExpression {
            instructions,
            value,
            ..
        } => codegen_reactive_sequence_expression_ev(cx, instructions, value),
        InstructionValue::ReactiveOptionalExpression {
            optional, value, ..
        } => {
            let inner_ev = codegen_instruction_value_ev(cx, value);
            if let Some(expr) = apply_optional_to_rendered_expr(&inner_ev.expr, *optional) {
                ExprValue::primary(expr)
            } else {
                set_codegen_error_once(
                    cx,
                    "Expected an optional value to resolve to a call expression or member expression",
                    inner_ev.expr.clone(),
                );
                inner_ev
            }
        }
        InstructionValue::ReactiveConditionalExpression {
            test,
            consequent,
            alternate,
            ..
        } => {
            let test_ev = codegen_instruction_value_ev(cx, test);
            let test_str = test_ev.wrap_if_needed(ExprPrecedence::Conditional);
            let cons_ev = codegen_instruction_value_ev(cx, consequent);
            let alt_ev = codegen_instruction_value_ev(cx, alternate);
            let cons_str = if needs_parens_in_ternary_branch(&cons_ev) {
                format!("({})", cons_ev.expr)
            } else {
                cons_ev.expr
            };
            let alt_str = if needs_parens_in_ternary_branch(&alt_ev) {
                format!("({})", alt_ev.expr)
            } else {
                alt_ev.expr
            };
            let expr = render_conditional_expression_ast(&test_str, &cons_str, &alt_str)
                .expect("generated reactive conditional expression should parse");
            ExprValue::new(expr, ExprPrecedence::Conditional)
        }
        InstructionValue::ReactiveLogicalExpression {
            operator,
            left,
            right,
            ..
        } => {
            let prec = logical_operator_precedence(operator);
            let l = codegen_logical_operand_from_expr_value(
                codegen_instruction_value_ev(cx, left),
                prec,
            );
            let mut r = codegen_logical_operand_from_expr_value(
                codegen_instruction_value_ev(cx, right),
                prec,
            );
            if *operator == LogicalOperator::NullishCoalescing {
                let rhs_trimmed = r.trim();
                if rendered_expr_is_jsx_like(rhs_trimmed) && !is_wrapped_in_parens(rhs_trimmed) {
                    r = format!("(\n{}\n)", rhs_trimmed);
                }
            }
            let expr = render_logical_expression_ast(&l, *operator, &r)
                .expect("generated reactive logical expression should parse");
            ExprValue::new(expr, prec)
        }
        InstructionValue::Ternary {
            test,
            consequent,
            alternate,
            ..
        } => {
            let test_str = codegen_place_with_min_prec(cx, test, ExprPrecedence::Conditional);
            let cons_ev = codegen_place_expr_value(cx, consequent);
            let alt_ev = codegen_place_expr_value(cx, alternate);
            let cons_str = if needs_parens_in_ternary_branch(&cons_ev) {
                format!("({})", cons_ev.expr)
            } else {
                cons_ev.expr
            };
            let alt_str = if needs_parens_in_ternary_branch(&alt_ev) {
                format!("({})", alt_ev.expr)
            } else {
                alt_ev.expr
            };
            let expr = render_conditional_expression_ast(&test_str, &cons_str, &alt_str)
                .expect("generated ternary expression should parse");
            ExprValue::new(expr, ExprPrecedence::Conditional)
        }
        InstructionValue::LogicalExpression {
            operator,
            left,
            right,
            ..
        } => {
            let prec = logical_operator_precedence(operator);
            let l = codegen_logical_operand(cx, left, prec);
            let mut r = codegen_logical_operand(cx, right, prec);
            if *operator == LogicalOperator::NullishCoalescing {
                let rhs_trimmed = r.trim();
                if rendered_expr_is_jsx_like(rhs_trimmed) && !is_wrapped_in_parens(rhs_trimmed) {
                    r = format!("(\n{}\n)", rhs_trimmed);
                }
            }
            let expr = render_logical_expression_ast(&l, *operator, &r)
                .expect("generated logical expression should parse");
            ExprValue::new(expr, prec)
        }
        // These should be handled in codegen_instruction_nullable directly
        InstructionValue::StoreLocal { .. }
        | InstructionValue::StoreContext { .. }
        | InstructionValue::DeclareLocal { .. }
        | InstructionValue::DeclareContext { .. }
        | InstructionValue::Destructure { .. }
        | InstructionValue::StartMemoize { .. }
        | InstructionValue::FinishMemoize { .. }
        | InstructionValue::Debugger { .. } => {
            // Should not reach here
            ExprValue::primary("/* unexpected */".to_string())
        }
    }
}

// ---- Precedence helpers ----

fn binary_operator_precedence(op: &BinaryOperator) -> ExprPrecedence {
    match op {
        BinaryOperator::Eq
        | BinaryOperator::NotEq
        | BinaryOperator::StrictEq
        | BinaryOperator::StrictNotEq => ExprPrecedence::Equality,
        BinaryOperator::Lt
        | BinaryOperator::LtEq
        | BinaryOperator::Gt
        | BinaryOperator::GtEq
        | BinaryOperator::InstanceOf
        | BinaryOperator::In => ExprPrecedence::Relational,
        BinaryOperator::Add | BinaryOperator::Sub => ExprPrecedence::Additive,
        BinaryOperator::Mul | BinaryOperator::Div | BinaryOperator::Mod => {
            ExprPrecedence::Multiplicative
        }
        BinaryOperator::Exp => ExprPrecedence::Exponentiation,
        BinaryOperator::LShift | BinaryOperator::RShift | BinaryOperator::URShift => {
            ExprPrecedence::Shift
        }
        BinaryOperator::BitAnd => ExprPrecedence::BitwiseAnd,
        BinaryOperator::BitOr => ExprPrecedence::BitwiseOr,
        BinaryOperator::BitXor => ExprPrecedence::BitwiseXor,
    }
}

fn logical_operator_precedence(op: &LogicalOperator) -> ExprPrecedence {
    match op {
        LogicalOperator::And => ExprPrecedence::LogicalAnd,
        LogicalOperator::Or => ExprPrecedence::LogicalOr,
        LogicalOperator::NullishCoalescing => ExprPrecedence::NullishCoalescing,
    }
}

fn codegen_logical_operand_from_expr_value(ev: ExprValue, parent_prec: ExprPrecedence) -> String {
    let is_logical = matches!(
        ev.prec,
        ExprPrecedence::LogicalAnd | ExprPrecedence::LogicalOr | ExprPrecedence::NullishCoalescing
    );
    if is_logical && ev.prec != parent_prec {
        format!("({})", ev.expr)
    } else {
        ev.wrap_if_needed(parent_prec)
    }
}

fn codegen_logical_operand(cx: &mut Context, place: &Place, parent_prec: ExprPrecedence) -> String {
    codegen_logical_operand_from_expr_value(codegen_place_expr_value(cx, place), parent_prec)
}

fn needs_parens_in_ternary_branch(ev: &ExprValue) -> bool {
    ev.prec <= ExprPrecedence::NullishCoalescing
        || ev.expr.contains(" as ")
        || ev.expr.contains(" satisfies ")
}

fn codegen_reactive_sequence_expression_ev(
    cx: &mut Context,
    instructions: &[ReactiveInstruction],
    value: &InstructionValue,
) -> ExprValue {
    let mut probe_cx = cx.clone();
    let mut prefix_exprs = Vec::new();
    let uses_decl = |value: &InstructionValue, decl_id: DeclarationId| {
        let mut used = false;
        visitors::for_each_instruction_value_operand(value, |place| {
            if place.identifier.declaration_id == decl_id {
                used = true;
            }
        });
        used
    };
    for (idx, instr) in instructions.iter().enumerate() {
        match codegen_instruction_nullable(&mut probe_cx, instr) {
            Some(stmt) => {
                if let Some(expr) = extract_simple_expression_statement_global(&stmt) {
                    let wrapped = if is_assignment_like_sequence_expr_global(&expr)
                        && !(expr.starts_with('(') && expr.ends_with(')'))
                    {
                        format!("({expr})")
                    } else {
                        expr
                    };
                    prefix_exprs.push(wrapped);
                } else {
                    set_codegen_error_once(
                        cx,
                        "Cannot declare variables in a value block",
                        stmt.trim().to_string(),
                    );
                    return ExprValue::primary("/* unexpected value block */".to_string());
                }
            }
            None => {
                let Some(lvalue) = &instr.lvalue else {
                    continue;
                };
                if !is_temp_like_identifier(&probe_cx, &lvalue.identifier) {
                    continue;
                }
                let decl_id = lvalue.identifier.declaration_id;
                let used_later = instructions[idx + 1..]
                    .iter()
                    .any(|later| uses_decl(&later.value, decl_id))
                    || uses_decl(value, decl_id);
                if used_later {
                    continue;
                }
                let maybe_expr = match &instr.value {
                    InstructionValue::StoreLocal {
                        lvalue: store_lvalue,
                        value: store_value,
                        ..
                    } => {
                        let lhs = codegen_place_to_expression(&mut probe_cx, &store_lvalue.place);
                        let rhs = codegen_place_to_expression(&mut probe_cx, store_value);
                        render_assignment_expression_ast(&lhs, &rhs)
                    }
                    InstructionValue::StoreContext {
                        lvalue: store_lvalue,
                        value: store_value,
                        ..
                    } => {
                        let lhs = codegen_place_to_expression(&mut probe_cx, &store_lvalue.place);
                        let rhs = codegen_place_to_expression(&mut probe_cx, store_value);
                        render_assignment_expression_ast(&lhs, &rhs)
                    }
                    InstructionValue::CallExpression { .. }
                    | InstructionValue::MethodCall { .. }
                    | InstructionValue::PropertyStore { .. }
                    | InstructionValue::ComputedStore { .. }
                    | InstructionValue::PropertyDelete { .. }
                    | InstructionValue::ComputedDelete { .. }
                    | InstructionValue::PrefixUpdate { .. }
                    | InstructionValue::PostfixUpdate { .. } => {
                        Some(codegen_instruction_value_ev(&mut probe_cx, &instr.value).expr)
                    }
                    _ => None,
                };
                if let Some(expr) = maybe_expr {
                    let wrapped = if is_assignment_like_sequence_expr_global(&expr)
                        && !(expr.starts_with('(') && expr.ends_with(')'))
                    {
                        format!("({expr})")
                    } else {
                        expr
                    };
                    prefix_exprs.push(wrapped);
                }
            }
        }
    }
    let final_ev = codegen_instruction_value_ev(&mut probe_cx, value);
    adopt_codegen_error(cx, probe_cx.codegen_error.take());
    if prefix_exprs.is_empty() {
        final_ev
    } else {
        ExprValue::primary(wrap_sequence_expr(&prefix_exprs, final_ev.expr))
    }
}

fn apply_optional_to_rendered_expr(expr: &str, optional: bool) -> Option<String> {
    if !optional {
        return Some(expr.to_string());
    }
    let trimmed = expr.trim();
    if rendered_expr_contains_optional_chain(trimmed) {
        return Some(trimmed.to_string());
    }
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let parsed =
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), trimmed)
            .ok()?;
    let expression = match parsed {
        ast::Expression::CallExpression(call) => {
            let mut call = call.unbox();
            call.optional = true;
            builder.expression_chain(SPAN, ast::ChainElement::CallExpression(builder.alloc(call)))
        }
        ast::Expression::ComputedMemberExpression(member) => {
            let mut member = member.unbox();
            member.optional = true;
            builder.expression_chain(
                SPAN,
                ast::ChainElement::ComputedMemberExpression(builder.alloc(member)),
            )
        }
        ast::Expression::StaticMemberExpression(member) => {
            let mut member = member.unbox();
            member.optional = true;
            builder.expression_chain(
                SPAN,
                ast::ChainElement::StaticMemberExpression(builder.alloc(member)),
            )
        }
        ast::Expression::PrivateFieldExpression(member) => {
            let mut member = member.unbox();
            member.optional = true;
            builder.expression_chain(
                SPAN,
                ast::ChainElement::PrivateFieldExpression(builder.alloc(member)),
            )
        }
        _ => return None,
    };
    Some(strip_top_level_parenthesized_expression(
        codegen_expression_with_flow_cast_restore(&expression),
    ))
}

fn parse_rendered_expression_ast<'a>(
    allocator: &'a Allocator,
    expr: &str,
) -> Option<ast::Expression<'a>> {
    parse_expression_for_ast_codegen(allocator, SourceType::mjs().with_jsx(true), expr).ok()
}

fn rendered_expr_is_function_like(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    matches!(
        expression.without_parentheses(),
        ast::Expression::FunctionExpression(_) | ast::Expression::ArrowFunctionExpression(_)
    )
}

fn rendered_expr_is_array_literal(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    matches!(
        expression.without_parentheses(),
        ast::Expression::ArrayExpression(_)
    )
}

fn rendered_expr_is_array_seed_like(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return matches!(
            trimmed.strip_prefix('t'),
            Some(rest) if !rest.is_empty() && rest.chars().all(|ch| ch.is_ascii_digit())
        );
    };
    match expression.without_parentheses() {
        ast::Expression::ArrayExpression(_) => true,
        ast::Expression::Identifier(identifier) => is_codegen_temp_name(identifier.name.as_str()),
        ast::Expression::LogicalExpression(logical)
            if logical.operator == AstLogicalOperator::Coalesce =>
        {
            matches!(
                logical.right.without_parentheses(),
                ast::Expression::ArrayExpression(_)
            )
        }
        _ => false,
    }
}

fn rendered_expr_is_autodeps_placeholder(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    match expression.without_parentheses() {
        ast::Expression::Identifier(identifier) => identifier.name == "AUTODEPS",
        ast::Expression::StaticMemberExpression(member) => member.property.name == "AUTODEPS",
        ast::Expression::ComputedMemberExpression(member) => matches!(
            member.expression.without_parentheses(),
            ast::Expression::StringLiteral(literal) if literal.value == "AUTODEPS"
        ),
        ast::Expression::ChainExpression(chain) => match &chain.expression {
            ast::ChainElement::StaticMemberExpression(member) => member.property.name == "AUTODEPS",
            ast::ChainElement::ComputedMemberExpression(member) => matches!(
                member.expression.without_parentheses(),
                ast::Expression::StringLiteral(literal) if literal.value == "AUTODEPS"
            ),
            _ => false,
        },
        _ => false,
    }
}

fn find_rendered_autodeps_index(rendered_args: &[String]) -> Option<usize> {
    rendered_args
        .iter()
        .position(|arg| rendered_expr_is_autodeps_placeholder(arg))
}

struct LogicalOrDetector {
    found: bool,
}

impl<'a> Visit<'a> for LogicalOrDetector {
    fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
        if self.found {
            return;
        }
        if let ast::Expression::LogicalExpression(logical) = expression.without_parentheses()
            && logical.operator == AstLogicalOperator::Or
        {
            self.found = true;
            return;
        }
        walk::walk_expression(self, expression);
    }
}

fn rendered_expr_contains_logical_or(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    let mut detector = LogicalOrDetector { found: false };
    detector.visit_expression(&expression);
    detector.found
}

struct OptionalChainDetector {
    found: bool,
}

impl<'a> Visit<'a> for OptionalChainDetector {
    fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
        if self.found {
            return;
        }
        if matches!(
            expression.without_parentheses(),
            ast::Expression::ChainExpression(_)
        ) {
            self.found = true;
            return;
        }
        walk::walk_expression(self, expression);
    }
}

fn rendered_expr_contains_optional_chain(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    let mut detector = OptionalChainDetector { found: false };
    detector.visit_expression(&expression);
    detector.found
}

struct PropertyPathDetector {
    found: bool,
}

impl<'a> Visit<'a> for PropertyPathDetector {
    fn visit_expression(&mut self, expression: &ast::Expression<'a>) {
        if self.found {
            return;
        }
        let is_property_path = match expression.without_parentheses() {
            ast::Expression::StaticMemberExpression(_)
            | ast::Expression::ComputedMemberExpression(_)
            | ast::Expression::PrivateFieldExpression(_) => true,
            ast::Expression::ChainExpression(chain) => matches!(
                &chain.expression,
                ast::ChainElement::StaticMemberExpression(_)
                    | ast::ChainElement::ComputedMemberExpression(_)
                    | ast::ChainElement::PrivateFieldExpression(_)
            ),
            _ => false,
        };
        if is_property_path {
            self.found = true;
            return;
        }
        walk::walk_expression(self, expression);
    }
}

fn rendered_expr_has_property_path(expr: &str) -> bool {
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return false;
    }
    let allocator = Allocator::default();
    let Some(expression) = parse_rendered_expression_ast(&allocator, trimmed) else {
        return false;
    };
    let mut detector = PropertyPathDetector { found: false };
    detector.visit_expression(&expression);
    detector.found
}

