fn render_reactive_if_statement_ast_with_context(
    test: &str,
    consequent_body: &str,
    alternate_body: Option<&str>,
    is_async: bool,
    is_generator: bool,
) -> Option<String> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let parsed_test =
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), test)
            .ok()?;
    let consequent = builder.statement_block(
        SPAN,
        parse_statement_list_for_ast_codegen_with_context(
            &allocator,
            SourceType::mjs().with_jsx(true),
            is_async,
            is_generator,
            consequent_body,
        )
        .ok()?,
    );
    let alternate = match alternate_body.filter(|body| !body.trim().is_empty()) {
        Some(body) => Some(
            builder.statement_block(
                SPAN,
                parse_statement_list_for_ast_codegen_with_context(
                    &allocator,
                    SourceType::mjs().with_jsx(true),
                    is_async,
                    is_generator,
                    body,
                )
                .ok()?,
            ),
        ),
        None => None,
    };
    let statement = builder.statement_if(SPAN, parsed_test, consequent, alternate);
    Some(format!(
        "{}\n",
        codegen_statement_with_flow_cast_restore(&statement)
    ))
}

