fn apply_function_body_preludes_ast<'a>(
    builder: AstBuilder<'a>,
    allocator: &'a Allocator,
    body: &mut ast::FunctionBody<'a>,
    directives: &[String],
    cache_prologue: Option<&CachePrologue>,
    needs_function_hook_guard_wrapper: bool,
) -> Option<()> {
    if !directives.is_empty() {
        body.directives = builder.vec_from_iter(directives.iter().map(|directive| {
            builder.directive(
                SPAN,
                builder.string_literal(SPAN, builder.atom(directive.as_str()), None),
                builder.atom(directive.as_str()),
            )
        }));
    }

    if needs_function_hook_guard_wrapper {
        let mut try_statements = builder.vec1(build_hook_guard_call_statement_ast(
            builder,
            HOOK_GUARD_PUSH,
        ));
        try_statements.extend(
            body.statements
                .iter()
                .map(|statement| statement.clone_in(allocator)),
        );
        let finalizer = builder.alloc_block_statement(
            SPAN,
            builder.vec1(build_hook_guard_call_statement_ast(builder, HOOK_GUARD_POP)),
        );
        body.statements = builder.vec1(ast::Statement::TryStatement(builder.alloc_try_statement(
            SPAN,
            builder.alloc_block_statement(SPAN, try_statements),
            None::<oxc_allocator::Box<'a, ast::CatchClause<'a>>>,
            Some(finalizer),
        )));
    }

    let Some(cache_prologue) = cache_prologue else {
        return Some(());
    };

    let mut statements = builder.vec1(ast::Statement::VariableDeclaration(
        builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Const,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Const,
                builder.binding_pattern_binding_identifier(
                    SPAN,
                    builder.ident(&cache_prologue.binding_name),
                ),
                NONE,
                Some(build_runtime_cache_call_expression_ast(
                    builder,
                    cache_prologue.size,
                )),
                false,
            )),
            false,
        ),
    ));

    if let Some(fast_refresh) = &cache_prologue.fast_refresh {
        statements.push(build_fast_refresh_cache_reset_statement_ast(
            builder,
            cache_prologue,
            fast_refresh,
        )?);
    }

    statements.extend(
        body.statements
            .iter()
            .map(|statement| statement.clone_in(allocator)),
    );
    body.statements = statements;
    Some(())
}

fn build_computed_member_expression_ast<'a>(
    builder: AstBuilder<'a>,
    object_name: &str,
    slot_expr: ast::Expression<'a>,
) -> ast::Expression<'a> {
    ast::Expression::from(builder.member_expression_computed(
        SPAN,
        builder.expression_identifier(SPAN, builder.ident(object_name)),
        slot_expr,
        false,
    ))
}

fn build_computed_member_assignment_statement_ast<'a>(
    builder: AstBuilder<'a>,
    object_name: &str,
    slot_expr: ast::Expression<'a>,
    value: ast::Expression<'a>,
) -> ast::Statement<'a> {
    let target = ast::AssignmentTarget::from(ast::SimpleAssignmentTarget::from(
        builder.member_expression_computed(
            SPAN,
            builder.expression_identifier(SPAN, builder.ident(object_name)),
            slot_expr,
            false,
        ),
    ));
    builder.statement_expression(
        SPAN,
        builder.expression_assignment(SPAN, AssignmentOperator::Assign, target, value),
    )
}

fn build_symbol_for_call_expression_ast<'a>(
    builder: AstBuilder<'a>,
    value: &str,
) -> ast::Expression<'a> {
    builder.expression_call(
        SPAN,
        ast::Expression::from(builder.member_expression_static(
            SPAN,
            builder.expression_identifier(SPAN, builder.ident("Symbol")),
            builder.identifier_name(SPAN, builder.ident("for")),
            false,
        )),
        NONE,
        builder.vec1(ast::Argument::from(builder.expression_string_literal(
            SPAN,
            builder.atom(value),
            None,
        ))),
        false,
    )
}

fn build_runtime_cache_call_expression_ast(builder: AstBuilder, size: u32) -> ast::Expression {
    builder.expression_call(
        SPAN,
        builder.expression_identifier(SPAN, builder.ident("_c")),
        NONE,
        builder.vec1(ast::Argument::from(builder.expression_numeric_literal(
            SPAN,
            size as f64,
            None,
            NumberBase::Decimal,
        ))),
        false,
    )
}

fn build_fast_refresh_cache_reset_statement_ast<'a>(
    builder: AstBuilder<'a>,
    cache_prologue: &CachePrologue,
    fast_refresh: &FastRefreshPrologue,
) -> Option<ast::Statement<'a>> {
    let hash_slot = builder.expression_numeric_literal(
        SPAN,
        fast_refresh.cache_index as f64,
        None,
        NumberBase::Decimal,
    );
    let test = builder.expression_binary(
        SPAN,
        build_computed_member_expression_ast(builder, &cache_prologue.binding_name, hash_slot),
        AstBinaryOperator::StrictInequality,
        builder.expression_string_literal(SPAN, builder.atom(&fast_refresh.hash), None),
    );

    let index_name = &fast_refresh.index_binding_name;
    let index_identifier =
        builder.binding_pattern_binding_identifier(SPAN, builder.ident(index_name));
    let loop_init = builder.for_statement_init_variable_declaration(
        SPAN,
        ast::VariableDeclarationKind::Let,
        builder.vec1(builder.variable_declarator(
            SPAN,
            ast::VariableDeclarationKind::Let,
            index_identifier,
            NONE,
            Some(builder.expression_numeric_literal(SPAN, 0.0, None, NumberBase::Decimal)),
            false,
        )),
        false,
    );
    let loop_test = builder.expression_binary(
        SPAN,
        builder.expression_identifier(SPAN, builder.ident(index_name)),
        AstBinaryOperator::LessThan,
        builder.expression_numeric_literal(
            SPAN,
            cache_prologue.size as f64,
            None,
            NumberBase::Decimal,
        ),
    );
    let loop_update = builder.expression_assignment(
        SPAN,
        AssignmentOperator::Addition,
        ast::AssignmentTarget::from(
            builder.simple_assignment_target_assignment_target_identifier(
                SPAN,
                builder.ident(index_name),
            ),
        ),
        builder.expression_numeric_literal(SPAN, 1.0, None, NumberBase::Decimal),
    );
    let loop_body = builder.statement_block(
        SPAN,
        builder.vec1(build_computed_member_assignment_statement_ast(
            builder,
            &cache_prologue.binding_name,
            builder.expression_identifier(SPAN, builder.ident(index_name)),
            build_symbol_for_call_expression_ast(builder, MEMO_CACHE_SENTINEL),
        )),
    );
    let refresh_loop = builder.statement_for(
        SPAN,
        Some(loop_init),
        Some(loop_test),
        Some(loop_update),
        loop_body,
    );

    let hash_store = build_computed_member_assignment_statement_ast(
        builder,
        &cache_prologue.binding_name,
        builder.expression_numeric_literal(
            SPAN,
            fast_refresh.cache_index as f64,
            None,
            NumberBase::Decimal,
        ),
        builder.expression_string_literal(SPAN, builder.atom(&fast_refresh.hash), None),
    );

    Some(builder.statement_if(
        SPAN,
        test,
        builder.statement_block(SPAN, builder.vec_from_iter([refresh_loop, hash_store])),
        None,
    ))
}

fn render_cached_inline_hook_callback_block_ast(
    callback_name: &str,
    callback_expr: &str,
    callback_slot: u32,
    deps: Option<(&str, &str, u32)>,
    call_expr: &str,
) -> Option<String> {
    let allocator = Allocator::default();
    let builder = AstBuilder::new(&allocator);
    let mut statements = builder.vec();

    statements.push(ast::Statement::VariableDeclaration(
        builder.alloc_variable_declaration(
            SPAN,
            ast::VariableDeclarationKind::Let,
            builder.vec1(builder.variable_declarator(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.binding_pattern_binding_identifier(SPAN, builder.ident(callback_name)),
                NONE,
                None,
                false,
            )),
            false,
        ),
    ));
    if let Some((deps_name, _, _)) = deps {
        statements.push(ast::Statement::VariableDeclaration(
            builder.alloc_variable_declaration(
                SPAN,
                ast::VariableDeclarationKind::Let,
                builder.vec1(builder.variable_declarator(
                    SPAN,
                    ast::VariableDeclarationKind::Let,
                    builder.binding_pattern_binding_identifier(SPAN, builder.ident(deps_name)),
                    NONE,
                    None,
                    false,
                )),
                false,
            ),
        ));
    }

    let mut consequent = builder.vec();
    consequent.push(build_identifier_assignment_statement_ast_with_expression(
        builder,
        callback_name,
        parse_expression_for_ast_codegen(
            &allocator,
            SourceType::mjs().with_jsx(true),
            callback_expr,
        )
        .ok()?,
    ));
    if let Some((deps_name, deps_expr, deps_slot)) = deps {
        consequent.push(build_identifier_assignment_statement_ast_with_expression(
            builder,
            deps_name,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                deps_expr,
            )
            .ok()?,
        ));
        consequent.push(build_computed_member_assignment_statement_ast(
            builder,
            "$",
            builder.expression_numeric_literal(SPAN, deps_slot as f64, None, NumberBase::Decimal),
            builder.expression_identifier(SPAN, builder.ident(deps_name)),
        ));
    }
    consequent.push(build_computed_member_assignment_statement_ast(
        builder,
        "$",
        builder.expression_numeric_literal(SPAN, callback_slot as f64, None, NumberBase::Decimal),
        builder.expression_identifier(SPAN, builder.ident(callback_name)),
    ));

    let mut alternate = builder.vec1(build_identifier_assignment_statement_ast_with_expression(
        builder,
        callback_name,
        build_computed_member_expression_ast(
            builder,
            "$",
            builder.expression_numeric_literal(
                SPAN,
                callback_slot as f64,
                None,
                NumberBase::Decimal,
            ),
        ),
    ));
    if let Some((deps_name, _, deps_slot)) = deps {
        alternate.push(build_identifier_assignment_statement_ast_with_expression(
            builder,
            deps_name,
            build_computed_member_expression_ast(
                builder,
                "$",
                builder.expression_numeric_literal(
                    SPAN,
                    deps_slot as f64,
                    None,
                    NumberBase::Decimal,
                ),
            ),
        ));
    }

    let sentinel_test = builder.expression_binary(
        SPAN,
        build_computed_member_expression_ast(
            builder,
            "$",
            builder.expression_numeric_literal(
                SPAN,
                callback_slot as f64,
                None,
                NumberBase::Decimal,
            ),
        ),
        AstBinaryOperator::StrictEquality,
        build_symbol_for_call_expression_ast(builder, MEMO_CACHE_SENTINEL),
    );
    statements.push(builder.statement_if(
        SPAN,
        sentinel_test,
        builder.statement_block(SPAN, consequent),
        Some(builder.statement_block(SPAN, alternate)),
    ));
    statements.push(
        builder.statement_expression(
            SPAN,
            parse_expression_for_ast_codegen(
                &allocator,
                SourceType::mjs().with_jsx(true),
                call_expr,
            )
            .ok()?,
        ),
    );

    Some(format!(
        "{}\n",
        codegen_statements_with_flow_cast_restore(&statements)
    ))
}

pub(crate) fn parse_for_statement_init_ast<'a>(
    allocator: &'a Allocator,
    init: &str,
) -> Option<Option<ast::ForStatementInit<'a>>> {
    let trimmed = init.trim();
    if trimmed.is_empty() {
        return Some(None);
    }
    let source = if trimmed.ends_with(';') {
        trimmed.to_string()
    } else {
        format!("{trimmed};")
    };
    let statement = parse_single_statement_for_ast_codegen(
        allocator,
        SourceType::mjs().with_jsx(true),
        &source,
    )
    .ok()?;
    match statement {
        ast::Statement::VariableDeclaration(declaration) => Some(Some(
            ast::ForStatementInit::VariableDeclaration(declaration),
        )),
        ast::Statement::ExpressionStatement(expression) => Some(Some(ast::ForStatementInit::from(
            expression.unbox().expression,
        ))),
        _ => None,
    }
}

fn parse_for_statement_left_ast<'a>(
    allocator: &'a Allocator,
    kind: &str,
    lvalue: &str,
) -> Option<ast::ForStatementLeft<'a>> {
    let statement_source = format!("let {lvalue} = __codex_loop_left;");
    let statement = parse_single_statement_for_ast_codegen(
        allocator,
        SourceType::mjs().with_jsx(true),
        &statement_source,
    )
    .ok()?;
    let builder = AstBuilder::new(allocator);
    match statement {
        ast::Statement::VariableDeclaration(declaration) => {
            let mut declaration = declaration.unbox();
            declaration.kind = match kind {
                "var" => ast::VariableDeclarationKind::Var,
                "let" => ast::VariableDeclarationKind::Let,
                _ => ast::VariableDeclarationKind::Const,
            };
            for declarator in declaration.declarations.iter_mut() {
                declarator.kind = declaration.kind;
                declarator.init = None;
            }
            Some(ast::ForStatementLeft::VariableDeclaration(
                builder.alloc(declaration),
            ))
        }
        _ => None,
    }
}

pub(crate) fn parse_for_statement_left_source_ast<'a>(
    allocator: &'a Allocator,
    left: &str,
    is_for_of: bool,
) -> Option<ast::ForStatementLeft<'a>> {
    let keyword = if is_for_of { "of" } else { "in" };
    let statement_source = format!("for ({left} {keyword} __codex_loop_right) {{}}");
    let statement = parse_single_statement_for_ast_codegen(
        allocator,
        SourceType::mjs().with_jsx(true),
        &statement_source,
    )
    .ok()?;
    match statement {
        ast::Statement::ForInStatement(for_statement) => Some(for_statement.unbox().left),
        ast::Statement::ForOfStatement(for_statement) => Some(for_statement.unbox().left),
        _ => None,
    }
}

fn build_identifier_assignment_statement_ast_with_expression<'a>(
    builder: AstBuilder<'a>,
    target_name: &str,
    rhs_expression: ast::Expression<'a>,
) -> ast::Statement<'a> {
    builder.statement_expression(
        SPAN,
        builder.expression_assignment(
            SPAN,
            AssignmentOperator::Assign,
            ast::AssignmentTarget::from(
                builder.simple_assignment_target_assignment_target_identifier(
                    SPAN,
                    builder.ident(target_name),
                ),
            ),
            rhs_expression,
        ),
    )
}

fn render_function_expression_ast(spec: &FunctionExpressionRenderSpec<'_>) -> Option<String> {
    let allocator = Allocator::default();
    let parsed_body = build_function_body_from_generated_shape_for_ast_codegen(
        AstBuilder::new(&allocator),
        &allocator,
        &spec.body,
    )?;
    let mut parsed_body = parsed_body;
    let builder = AstBuilder::new(&allocator);
    let formal_params =
        make_reactive_formal_params(builder, spec.body.params, spec.body.param_names)?;
    let expression = match spec.fn_type {
        FunctionExpressionType::ArrowFunctionExpression => {
            if spec.body.directives.is_empty()
                && spec.body.cache_prologue.is_none()
                && !spec.body.needs_function_hook_guard_wrapper
                && let Some(return_expr) =
                    single_return_expression_from_body(&allocator, &parsed_body)
            {
                builder.expression_arrow_function(
                    SPAN,
                    true,
                    spec.body.is_async,
                    NONE,
                    formal_params,
                    NONE,
                    builder.alloc(builder.function_body(
                        SPAN,
                        builder.vec(),
                        builder.vec1(builder.statement_expression(SPAN, return_expr)),
                    )),
                )
            } else {
                apply_function_body_preludes_ast(
                    builder,
                    &allocator,
                    &mut parsed_body,
                    spec.body.directives,
                    spec.body.cache_prologue,
                    spec.body.needs_function_hook_guard_wrapper,
                )?;
                builder.expression_arrow_function(
                    SPAN,
                    false,
                    spec.body.is_async,
                    NONE,
                    formal_params,
                    NONE,
                    builder.alloc(parsed_body),
                )
            }
        }
        FunctionExpressionType::FunctionExpression
        | FunctionExpressionType::FunctionDeclaration => {
            apply_function_body_preludes_ast(
                builder,
                &allocator,
                &mut parsed_body,
                spec.body.directives,
                spec.body.cache_prologue,
                spec.body.needs_function_hook_guard_wrapper,
            )?;
            builder.expression_function(
                SPAN,
                ast::FunctionType::FunctionExpression,
                spec.name
                    .map(|name| builder.binding_identifier(SPAN, builder.atom(name))),
                spec.body.is_generator,
                spec.body.is_async,
                false,
                NONE,
                NONE,
                formal_params,
                NONE,
                Some(builder.alloc(parsed_body)),
            )
        }
    };
    let expression = if let Some(name_hint) = spec.anonymous_name_hint {
        wrap_named_anonymous_function_expression(builder, expression, name_hint)
    } else {
        expression
    };
    Some(codegen_expression_with_flow_cast_restore(&expression))
}

fn function_expr_as_declaration(name: &str, rhs: &str) -> Option<String> {
    let allocator = Allocator::default();
    let mut expression =
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), rhs).ok()?;
    let function = loop {
        match expression {
            ast::Expression::FunctionExpression(function) => break function,
            ast::Expression::ParenthesizedExpression(parenthesized) => {
                expression = parenthesized.unbox().expression;
            }
            _ => return None,
        }
    };
    let builder = AstBuilder::new(&allocator);
    let mut function = function.unbox();
    if function
        .id
        .as_ref()
        .is_some_and(|binding_identifier| binding_identifier.name.as_str() != name)
    {
        return None;
    }
    function.r#type = ast::FunctionType::FunctionDeclaration;
    if function.id.is_none() {
        function.id = Some(builder.binding_identifier(SPAN, builder.atom(name)));
    }
    Some(codegen_statement_with_oxc(
        &ast::Statement::FunctionDeclaration(builder.alloc(function)),
    ))
}

fn render_lowered_function_expression_source(
    cx: &mut Context,
    lowered_func: &LoweredFunction,
    name: Option<&str>,
    fn_type: &FunctionExpressionType,
    anonymous_name_hint: Option<&str>,
) -> Option<String> {
    let inner_hir = lowered_func.func.clone();
    let mut reactive_func = super::build_reactive_function::build_reactive_function(inner_hir);

    super::prune_unused_labels_reactive::prune_unused_labels(&mut reactive_func);
    super::prune_unused_lvalues::prune_unused_lvalues(&mut reactive_func);
    let _ = super::prune_hoisted_contexts::prune_hoisted_contexts(&mut reactive_func);

    let inherited_decl_name_overrides =
        collect_inherited_decl_name_overrides_for_lowered_function(cx, lowered_func);
    if std::env::var("DEBUG_INNER_CAPTURE_MAP").is_ok() {
        let mut pairs: Vec<(u32, String)> = inherited_decl_name_overrides
            .iter()
            .map(|(decl, name)| (decl.0, name.clone()))
            .collect();
        pairs.sort_by_key(|(decl, _)| *decl);
        eprintln!("[INNER_CAPTURE_MAP] fn={name:?} inherited={pairs:?}");
    }

    let mut inner_result = codegen_reactive_function_with_primitives(
        &reactive_func,
        cx.unique_identifiers.clone(),
        CodegenReactiveInputs {
            inline_primitive_literals: cx.primitive_literals_for_child(),
            inherited_declaration_name_overrides: inherited_decl_name_overrides,
            initial_temp_snapshot: cx.snapshot_temps(),
            fbt_operands: cx.fbt_operands.clone(),
            inherited_reserved_child_decl_names: HashSet::new(),
            emit_function_hook_guard: false,
        },
        cx.child_codegen_options(),
    );
    adopt_codegen_error(cx, inner_result.error.take());

    render_function_expression_ast(&FunctionExpressionRenderSpec {
        body: FunctionBodyRenderSpec {
            params: &lowered_func.func.params,
            param_names: &inner_result.param_names,
            body_shape: &inner_result.body_shape,
            directives: &lowered_func.func.directives,
            cache_prologue: inner_result.cache_prologue.as_ref(),
            needs_function_hook_guard_wrapper: inner_result.needs_function_hook_guard_wrapper,
            is_async: lowered_func.func.async_,
            is_generator: lowered_func.func.generator,
        },
        name,
        fn_type,
        anonymous_name_hint,
    })
}

fn codegen_function_expression(
    cx: &mut Context,
    lowered_func: &LoweredFunction,
    name: &Option<String>,
    fn_type: &FunctionExpressionType,
) -> String {
    if let Some(rendered) = render_lowered_function_expression_source(
        cx,
        lowered_func,
        name.as_deref(),
        fn_type,
        if cx.enable_name_anonymous_functions && name.is_none() {
            lowered_func.func.id.as_deref()
        } else {
            None
        },
    ) {
        rendered
    } else {
        cx.codegen_error.get_or_insert_with(|| {
            CompilerError::Bail(BailOut {
                reason: "Failed to AST-render nested function expression".to_string(),
                diagnostics: vec![CompilerDiagnostic {
                    severity: DiagnosticSeverity::Invariant,
                    message: lowered_func.func.id.as_ref().map_or_else(
                        || "nested function expression AST render failed".to_string(),
                        |id| format!("nested function expression AST render failed: {id}"),
                    ),
                }],
            })
        });
        "(() => {})".to_string()
    }
}

fn compact_single_statement(code: &str) -> String {
    let mut out = String::new();
    let mut prev_space = false;
    for line in code.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        if !out.is_empty() && !prev_space {
            out.push(' ');
        }
        out.push_str(trimmed);
        prev_space = out.ends_with(' ');
    }
    out
}

// ---- For-loop init/update helpers ----

fn codegen_for_init(cx: &mut Context, init_block: &ReactiveBlock) -> String {
    // The init block typically contains variable declarations
    let preserve_snapshot = cx.preserve_loop_header_inits;
    cx.preserve_loop_header_inits = true;
    let code = codegen_block(cx, init_block);
    cx.preserve_loop_header_inits = preserve_snapshot;
    if let Some(reconstructed) = reconstruct_for_init_declaration(&code) {
        return reconstructed;
    }
    let trimmed = code.trim().trim_end_matches(';');
    trimmed.to_string()
}

fn for_update_block_produces_declaration(
    update_block: &ReactiveBlock,
    declaration_id: DeclarationId,
) -> bool {
    update_block.iter().any(|stmt| match stmt {
        ReactiveStatement::Instruction(instr) => {
            instr
                .lvalue
                .as_ref()
                .is_some_and(|lvalue| lvalue.identifier.declaration_id == declaration_id)
                || match &instr.value {
                    InstructionValue::StoreLocal { lvalue, .. }
                    | InstructionValue::StoreContext { lvalue, .. }
                    | InstructionValue::DeclareLocal { lvalue, .. }
                    | InstructionValue::DeclareContext { lvalue, .. } => {
                        lvalue.place.identifier.declaration_id == declaration_id
                    }
                    InstructionValue::Destructure { lvalue, .. } => {
                        pattern_operands(&lvalue.pattern)
                            .iter()
                            .any(|place| place.identifier.declaration_id == declaration_id)
                    }
                    _ => false,
                }
        }
        ReactiveStatement::Scope(scope) => {
            for_update_block_produces_declaration(&scope.instructions, declaration_id)
        }
        ReactiveStatement::PrunedScope(scope) => {
            for_update_block_produces_declaration(&scope.instructions, declaration_id)
        }
        ReactiveStatement::Terminal(_) => false,
    })
}

fn codegen_for_update_value_expr(
    cx: &mut Context,
    update_block: &ReactiveBlock,
    value: &InstructionValue,
) -> Option<String> {
    match value {
        InstructionValue::LoadLocal { place, .. } | InstructionValue::LoadContext { place, .. } => {
            if !for_update_block_produces_declaration(update_block, place.identifier.declaration_id)
            {
                return None;
            }
            Some(if place.identifier.name.is_some() {
                identifier_name_with_cx(cx, &place.identifier)
            } else {
                codegen_place_to_expression(cx, place)
            })
        }
        InstructionValue::StoreLocal { lvalue, value, .. }
        | InstructionValue::StoreContext { lvalue, value, .. } => {
            let lhs = codegen_place_to_expression(cx, &lvalue.place);
            let rhs = codegen_place_to_expression(cx, value);
            render_assignment_expression_ast(&lhs, &rhs)
        }
        InstructionValue::DeclareLocal { .. }
        | InstructionValue::DeclareContext { .. }
        | InstructionValue::Destructure { .. }
        | InstructionValue::StartMemoize { .. }
        | InstructionValue::FinishMemoize { .. }
        | InstructionValue::Debugger { .. } => None,
        _ => Some(codegen_instruction_value_ev(cx, value).expr),
    }
}

fn codegen_for_update(
    cx: &mut Context,
    update_block: &ReactiveBlock,
    update_value: Option<&InstructionValue>,
) -> String {
    fn collapse_statement_lines_to_sequence_expr(raw: &str) -> String {
        let fallback = raw.trim().trim_end_matches(';').to_string();
        let allocator = Allocator::default();
        let Ok(statements) =
            parse_statement_list_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), raw)
        else {
            return fallback;
        };
        let mut exprs: Vec<String> = Vec::with_capacity(statements.len());
        for statement in statements {
            let ast::Statement::ExpressionStatement(expression_statement) = statement else {
                return fallback;
            };
            exprs.push(codegen_expression_with_flow_cast_restore(
                &expression_statement.expression,
            ));
        }

        match exprs.len() {
            0 => fallback,
            1 => exprs.pop().unwrap_or_default(),
            _ => exprs.join(", "),
        }
    }

    let preserve_snapshot = cx.preserve_loop_header_inits;
    let temp_snapshot = cx.snapshot_temps();
    let decl_snapshot = cx.declarations.clone();
    cx.block_scope_output_names.push(HashSet::new());
    cx.block_scope_declared_temp_names.push(HashSet::new());
    cx.preserve_loop_header_inits = true;
    let (code, final_expr) = if let Some(update_value) = update_value {
        if let Some((ReactiveStatement::Instruction(final_instr), prefix)) =
            update_block.split_last()
        {
            let prefix_code = if prefix.is_empty() {
                String::new()
            } else {
                let prefix_block: ReactiveBlock = prefix.to_vec();
                codegen_block_no_reset(cx, &prefix_block)
            };
            let final_expr = codegen_for_update_value_expr(cx, update_block, update_value);
            let final_stmt = codegen_instruction_nullable(cx, final_instr);
            (
                if final_expr.is_some() {
                    prefix_code
                } else {
                    format!("{}{}", prefix_code, final_stmt.unwrap_or_default())
                },
                final_expr,
            )
        } else {
            (
                codegen_block_no_reset(cx, update_block),
                codegen_for_update_value_expr(cx, update_block, update_value),
            )
        }
    } else {
        (codegen_block_no_reset(cx, update_block), None)
    };
    let mut trimmed = code.trim().trim_end_matches(';').to_string();
    if trimmed.contains('\n') {
        trimmed = collapse_statement_lines_to_sequence_expr(&trimmed);
    }
    if let Some(final_expr) = final_expr {
        let normalized_trimmed = normalize_fusion_match_text(&trimmed);
        let normalized_final = normalize_fusion_match_text(&final_expr);
        if trimmed.is_empty() {
            trimmed = final_expr;
        } else if normalized_trimmed != normalized_final {
            let prefix_expr = trimmed.clone();
            trimmed =
                render_sequence_expression_ast(std::slice::from_ref(&prefix_expr), &final_expr)
                    .unwrap_or_else(|| format!("{prefix_expr}, {final_expr}"));
        } else {
            trimmed = final_expr;
        }
    } else if trimmed.is_empty()
        && let Some(last_lvalue_decl) = update_block.iter().rev().find_map(|stmt| match stmt {
            ReactiveStatement::Instruction(instr) => instr
                .lvalue
                .as_ref()
                .map(|lvalue| lvalue.identifier.declaration_id),
            _ => None,
        })
        && let Some(expr) = cx
            .temp
            .get(&last_lvalue_decl)
            .and_then(|expr| expr.as_ref())
    {
        trimmed = expr.expr.clone();
    }

    let _ = cx.block_scope_declared_temp_names.pop();
    let _ = cx.block_scope_output_names.pop();
    cx.preserve_loop_header_inits = preserve_snapshot;
    cx.restore_temps(temp_snapshot);
    cx.declarations = decl_snapshot;
    trimmed
}

fn maybe_fill_for_header_initializer_from_update(
    init_code: &str,
    update_code: &str,
) -> Option<String> {
    let allocator = Allocator::default();
    let init = init_code.trim();
    if init.is_empty() {
        return None;
    }
    let statement_source = format!("{init} = __codex_fill;");
    let statement = parse_single_statement_for_ast_codegen(
        &allocator,
        SourceType::mjs().with_jsx(true),
        &statement_source,
    )
    .ok()?;
    let ast::Statement::VariableDeclaration(declaration) = statement else {
        return None;
    };
    if declaration.declarations.len() != 1 {
        return None;
    }
    let declarator = declaration.declarations.first()?;
    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
        return None;
    };
    let update = update_code.trim();
    if update.is_empty() || !is_inlineable_primitive_literal_expression(update) {
        return None;
    }
    let update_expr =
        parse_expression_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), update)
            .ok()?;
    render_variable_declaration_header_ast(
        declaration.kind,
        &[(
            identifier.name.to_string(),
            Some(codegen_expression_with_flow_cast_restore(&update_expr)),
        )],
    )
}

fn reconstruct_for_init_declaration(code: &str) -> Option<String> {
    #[derive(Clone)]
    struct Declarator {
        name: String,
        init: Option<String>,
    }

    let allocator = Allocator::default();
    let statements =
        parse_statement_list_for_ast_codegen(&allocator, SourceType::mjs().with_jsx(true), code)
            .ok()?;
    let mut declarators: Vec<Declarator> = Vec::new();
    let mut header_kind: Option<ast::VariableDeclarationKind> = None;

    for statement in statements {
        match statement {
            ast::Statement::VariableDeclaration(declaration) => {
                let kind = match declaration.kind {
                    ast::VariableDeclarationKind::Const => ast::VariableDeclarationKind::Const,
                    _ => ast::VariableDeclarationKind::Let,
                };
                header_kind = Some(match (header_kind, kind) {
                    (Some(ast::VariableDeclarationKind::Let), _) => {
                        ast::VariableDeclarationKind::Let
                    }
                    (_, ast::VariableDeclarationKind::Let) => ast::VariableDeclarationKind::Let,
                    (Some(existing), _) => existing,
                    (None, current) => current,
                });
                for declarator in &declaration.declarations {
                    let ast::BindingPattern::BindingIdentifier(identifier) = &declarator.id else {
                        return None;
                    };
                    declarators.push(Declarator {
                        name: identifier.name.to_string(),
                        init: declarator
                            .init
                            .as_ref()
                            .map(codegen_expression_with_flow_cast_restore),
                    });
                }
            }
            ast::Statement::ExpressionStatement(expression_statement) => {
                let ast::Expression::AssignmentExpression(assignment) =
                    &expression_statement.expression
                else {
                    return None;
                };
                if assignment.operator != AssignmentOperator::Assign {
                    return None;
                }
                let ast::AssignmentTarget::AssignmentTargetIdentifier(identifier) =
                    &assignment.left
                else {
                    return None;
                };
                let last = declarators.last_mut()?;
                if last.init.is_some() || last.name != identifier.name.as_str() {
                    return None;
                }
                last.init = Some(codegen_expression_with_flow_cast_restore(&assignment.right));
            }
            _ => return None,
        }
    }

    if declarators.is_empty() {
        return None;
    }

    let kind = header_kind.unwrap_or(ast::VariableDeclarationKind::Let);
    render_variable_declaration_header_ast(
        kind,
        &declarators
            .into_iter()
            .map(|decl| (decl.name, decl.init))
            .collect::<Vec<_>>(),
    )
}

fn loop_lvalue_kind_keyword(kind: InstructionKind) -> &'static str {
    match kind {
        InstructionKind::Const => "const",
        InstructionKind::Let => "let",
        _ => "const",
    }
}

/// Extract `(kind, lvalue, collection)` for for-in/of headers from the
/// terminal-owned init payload. This mirrors upstream where the iterator
/// collection and loop assignment are encoded as instruction values.
fn extract_for_in_of_header_from_init(
    cx: &mut Context,
    init_block: &[ReactiveStatement],
) -> (String, String, Option<Place>) {
    let mut decl_kind = "const".to_string();
    let mut decl_lvalue = "_".to_string();
    let mut collection_place: Option<Place> = None;

    for stmt in init_block {
        let ReactiveStatement::Instruction(instr) = stmt else {
            continue;
        };

        match &instr.value {
            InstructionValue::IteratorNext { collection, .. } => {
                collection_place = Some(collection.clone());
            }
            InstructionValue::NextPropertyOf { value, .. } => {
                collection_place = Some(value.clone());
            }
            InstructionValue::StoreLocal { lvalue, .. } => {
                decl_kind = loop_lvalue_kind_keyword(lvalue.kind).to_string();
                decl_lvalue = identifier_name_with_cx(cx, &lvalue.place.identifier);
                cx.declare(&lvalue.place.identifier);
            }
            InstructionValue::Destructure { lvalue, .. } => {
                decl_kind = loop_lvalue_kind_keyword(lvalue.kind).to_string();
                decl_lvalue = codegen_pattern(cx, &lvalue.pattern);
                for p in pattern_operands(&lvalue.pattern) {
                    cx.declare(&p.identifier);
                }
            }
            InstructionValue::DeclareLocal { .. } => {
                // Keep scanning: declaration often precedes the assignment
                // that carries the final lvalue kind/pattern.
            }
            _ => {}
        }
    }

    (decl_kind, decl_lvalue, collection_place)
}

// ---- Primitive codegen ----

fn codegen_primitive(value: &PrimitiveValue) -> String {
    match value {
        PrimitiveValue::Null => "null".to_string(),
        PrimitiveValue::Undefined => "undefined".to_string(),
        PrimitiveValue::Boolean(b) => b.to_string(),
        PrimitiveValue::Number(n) => {
            if *n == 0.0 && n.is_sign_negative() {
                // Negative zero: emit as 0
                "0".to_string()
            } else if *n < 0.0 {
                format!("-{}", -n)
            } else {
                format!("{}", n)
            }
        }
        PrimitiveValue::String(s) => format!("\"{}\"", escape_string(s)),
    }
}

// ---- String helpers ----

fn escape_string(s: &str) -> String {
    s.replace('\\', "\\\\")
        .replace('"', "\\\"")
        .replace('\n', "\\n")
        .replace('\r', "\\r")
        .replace('\t', "\\t")
        .replace('\u{0008}', "\\b")
        .replace('\u{000C}', "\\f")
}

/// Escape JSXText content. Unlike JS string literals, double quotes are valid
/// in JSX text and should not be escaped.
fn escape_jsx_text(s: &str) -> String {
    s.to_string()
}

// ---- JSX helpers ----

fn jsx_attr_needs_expression_container(escaped_inner: &str) -> bool {
    escaped_inner.contains('\\') || !escaped_inner.is_ascii()
}

fn jsx_text_needs_expression_container(escaped_inner: &str) -> bool {
    escaped_inner
        .chars()
        .any(|c| matches!(c, '<' | '>' | '&' | '{' | '}'))
}

