    #[test]
    fn canonicalizes_nested_prefix_chain_before_tail_body_shape() {
        let shape =
            super::canonicalize_generated_body_shape(super::GeneratedBodyShape::Sequential {
                prefix: Box::new(super::GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![super::GeneratedBinding {
                        kind: ast::VariableDeclarationKind::Const,
                        pattern: "x".to_string(),
                        expression: "makeObject()".to_string(),
                        promote_to_function_declaration: false,
                    }],
                    inner: Box::new(super::GeneratedBodyShape::PrefixedDeclarations {
                        declarations: vec![super::GeneratedDeclaration {
                            kind: ast::VariableDeclarationKind::Let,
                            pattern: "t0".to_string(),
                        }],
                        inner: Box::new(super::GeneratedBodyShape::Sequential {
                            prefix: Box::new(
                                super::GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
                                    sentinel_slot: 0,
                                    setup_statements: vec!["t0 = {};".to_string()],
                                    cached_values: vec![super::GeneratedCachedValue {
                                        name: "t0".to_string(),
                                        slot: 0,
                                    }],
                                    restored_values: vec![super::GeneratedCachedValue {
                                        name: "t0".to_string(),
                                        slot: 0,
                                    }],
                                },
                            ),
                            inner: Box::new(super::GeneratedBodyShape::ExpressionStatements(vec![
                                "posts.push(t0)".to_string(),
                            ])),
                        }),
                    }),
                }),
                inner: Box::new(super::GeneratedBodyShape::PrefixedBindings {
                    bindings: vec![super::GeneratedBinding {
                        kind: ast::VariableDeclarationKind::Const,
                        pattern: "count".to_string(),
                        expression: "posts.length".to_string(),
                        promote_to_function_declaration: false,
                    }],
                    inner: Box::new(super::GeneratedBodyShape::ExpressionStatements(vec![
                        "foo(count)".to_string(),
                    ])),
                }),
            });

        assert_eq!(
            shape,
            super::GeneratedBodyShape::PrefixedBindings {
                bindings: vec![super::GeneratedBinding {
                    kind: ast::VariableDeclarationKind::Const,
                    pattern: "x".to_string(),
                    expression: "makeObject()".to_string(),
                    promote_to_function_declaration: false,
                }],
                inner: Box::new(super::GeneratedBodyShape::PrefixedDeclarations {
                    declarations: vec![super::GeneratedDeclaration {
                        kind: ast::VariableDeclarationKind::Let,
                        pattern: "t0".to_string(),
                    }],
                    inner: Box::new(super::GeneratedBodyShape::Sequential {
                        prefix: Box::new(
                            super::GeneratedBodyShape::ZeroDependencyMemoizedCachedValues {
                                sentinel_slot: 0,
                                setup_statements: vec!["t0 = {};".to_string()],
                                cached_values: vec![super::GeneratedCachedValue {
                                    name: "t0".to_string(),
                                    slot: 0,
                                }],
                                restored_values: vec![super::GeneratedCachedValue {
                                    name: "t0".to_string(),
                                    slot: 0,
                                }],
                            },
                        ),
                        inner: Box::new(super::GeneratedBodyShape::PrefixedExpressionStatements {
                            expressions: vec!["posts.push(t0)".to_string()],
                            inner: Box::new(super::GeneratedBodyShape::PrefixedBindings {
                                bindings: vec![super::GeneratedBinding {
                                    kind: ast::VariableDeclarationKind::Const,
                                    pattern: "count".to_string(),
                                    expression: "posts.length".to_string(),
                                    promote_to_function_declaration: false,
                                }],
                                inner: Box::new(super::GeneratedBodyShape::ExpressionStatements(
                                    vec!["foo(count)".to_string()],
                                )),
                            }),
                        }),
                    }),
                }),
            }
        );
    }

    #[test]
    fn canonicalizes_nested_cached_helper_slots_inside_memoized_return() {
        let shape = super::canonicalize_generated_body_shape(
            super::GeneratedBodyShape::AliasedReturn {
                alias_name: "result".to_string(),
                alias_kind: ast::VariableDeclarationKind::Const,
                source_name: "t2".to_string(),
                inner: Box::new(super::GeneratedBodyShape::PrefixedDeclarations {
                    declarations: vec![
                        super::GeneratedDeclaration {
                            kind: ast::VariableDeclarationKind::Let,
                            pattern: "t0".to_string(),
                        },
                        super::GeneratedDeclaration {
                            kind: ast::VariableDeclarationKind::Let,
                            pattern: "t1".to_string(),
                        },
                        super::GeneratedDeclaration {
                            kind: ast::VariableDeclarationKind::Let,
                            pattern: "t2".to_string(),
                        },
                    ],
                    inner: Box::new(
                        super::GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                            value_name: "t2".to_string(),
                            deps: vec![(6, "arr".to_string()), (7, "props.y".to_string())],
                            value_slot: 8,
                            memoized_bindings: vec![],
                            memoized_assignments: vec![],
                            memoized_expressions: vec![],
                            memoized_setup_statements: vec![
                                "let t3;".to_string(),
                                "if ($[4] !== props.y) {\n  t3 = bar(props.y);\n  $[4] = props.y;\n  $[5] = t3;\n} else {\n  t3 = $[5];\n}".to_string(),
                                "t2 = arr.at(t3);".to_string(),
                            ],
                            memoized_expr: None,
                        },
                    ),
                }),
            },
        );

        let super::GeneratedBodyShape::AliasedReturn { inner, .. } = shape else {
            panic!("expected aliased return, got {shape:?}");
        };
        let super::GeneratedBodyShape::PrefixedDeclarations { inner, .. } = inner.as_ref() else {
            panic!("expected prefixed declarations, got {inner:?}");
        };
        let super::GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
            deps,
            value_slot,
            memoized_setup_statements,
            ..
        } = inner.as_ref()
        else {
            panic!("expected multi dependency existing return, got {inner:?}");
        };
        assert_eq!(
            deps.as_slice(),
            vec![(4, "arr".to_string()), (5, "props.y".to_string())].as_slice()
        );
        assert_eq!(*value_slot, 6);
        assert_eq!(
            memoized_setup_statements.as_slice(),
            vec![
                "let t3;".to_string(),
                "if ($[7] !== props.y) {\n  t3 = bar(props.y);\n  $[7] = props.y;\n  $[8] = t3;\n} else {\n  t3 = $[8];\n}".to_string(),
                "t2 = arr.at(t3);".to_string(),
            ]
            .as_slice()
        );
    }

    #[test]
    fn canonicalizes_aliased_return_into_assigned_alias_when_outer_decl_exists() {
        let shape = super::canonicalize_generated_body_shape(
            super::GeneratedBodyShape::PrefixedDeclarations {
                declarations: vec![
                    super::GeneratedDeclaration {
                        kind: ast::VariableDeclarationKind::Let,
                        pattern: "x".to_string(),
                    },
                    super::GeneratedDeclaration {
                        kind: ast::VariableDeclarationKind::Let,
                        pattern: "t0".to_string(),
                    },
                ],
                inner: Box::new(super::GeneratedBodyShape::AliasedReturn {
                    alias_name: "x".to_string(),
                    alias_kind: ast::VariableDeclarationKind::Let,
                    source_name: "t0".to_string(),
                    inner: Box::new(super::GeneratedBodyShape::ReturnIdentifier(
                        "t0".to_string(),
                    )),
                }),
            },
        );

        let super::GeneratedBodyShape::AssignedAliasReturn {
            alias_name,
            source_name,
            inner,
        } = shape
        else {
            panic!("expected assigned alias return, got {shape:?}");
        };
        assert_eq!(alias_name, "x");
        assert_eq!(source_name, "t0");
        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = inner.as_ref()
        else {
            panic!("expected prefixed declarations, got {inner:?}");
        };
        assert_eq!(declarations.len(), 2);
        assert_eq!(declarations[0].pattern, "x");
        assert_eq!(declarations[1].pattern, "t0");
        assert_eq!(
            inner.as_ref(),
            &super::GeneratedBodyShape::ReturnIdentifier("t0".to_string())
        );
    }

    #[test]
    fn canonicalizes_nested_cached_helper_slots_inside_existing_memoized_computed_return() {
        let shape = super::canonicalize_generated_body_shape(
            super::GeneratedBodyShape::MemoizedComputedReturn {
                value_name: "element".to_string(),
                value_kind: None,
                deps: vec![(3, "childProps".to_string())],
                value_slot: 4,
                computation: Box::new(super::GeneratedBodyShape::Sequential {
                    prefix: Box::new(super::GeneratedBodyShape::PrefixedDeclarations {
                        declarations: vec![super::GeneratedDeclaration {
                            kind: ast::VariableDeclarationKind::Let,
                            pattern: "t0".to_string(),
                        }],
                        inner: Box::new(
                            super::GeneratedBodyShape::ZeroDependencyMemoizedExistingReturn {
                                value_name: "t0".to_string(),
                                value_slot: 2,
                                memoized_bindings: vec![],
                                memoized_assignments: vec![],
                                memoized_expressions: vec![],
                                memoized_setup_statements: vec![],
                                memoized_expr: Some("[\"hello world\"]".to_string()),
                            },
                        ),
                    }),
                    inner: Box::new(super::GeneratedBodyShape::AssignedExpressionReturn {
                        value_name: "element".to_string(),
                        value_kind: ast::VariableDeclarationKind::Let,
                        expression: "React.createElement(\"div\", childProps, t0)".to_string(),
                    }),
                }),
            },
        );

        let super::GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
            dep_slot,
            value_slot,
            memoized_setup_statements,
            ..
        } = shape
        else {
            panic!("expected single dependency existing return, got {shape:?}");
        };
        assert_eq!(dep_slot, 2);
        assert_eq!(value_slot, 3);
        assert!(memoized_setup_statements.iter().any(|statement| {
            statement.contains("$[4] === Symbol.for(\"react.memo_cache_sentinel\")")
                && statement.contains("$[4] = t0;")
                && statement.contains("t0 = $[4];")
        }));
    }

