    #[test]
    fn analyzes_multi_dependency_memoized_body_shape_with_existing_value_mutation() {
        let shape = super::analyze_generated_body_shape(
            "let x;\nif ($[0] !== props.cond || $[1] !== props.foo) {\n  props.cond ? ([x] = [[]], x.push(props.foo)) : null;\n  $[0] = props.cond;\n  $[1] = props.foo;\n  $[2] = x;\n} else {\n  x = $[2];\n}\nreturn x;\n",
        );

        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = shape
        else {
            panic!("expected prefixed declarations shape, got {shape:?}");
        };
        assert_eq!(declarations.len(), 1);
        assert_eq!(declarations[0].pattern, "x");
        assert!(matches!(
            inner.as_ref(),
            super::GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                value_name,
                deps,
                value_slot,
                memoized_expressions,
                memoized_setup_statements,
                memoized_expr,
                ..
            } if value_name == "x"
                && deps == &vec![(0, "props.cond".to_string()), (1, "props.foo".to_string())]
                && *value_slot == 2
                && memoized_expressions
                    == &vec!["props.cond ? ([x] = [[]], x.push(props.foo)) : null".to_string()]
                && memoized_setup_statements.is_empty()
                && memoized_expr.is_none()
        ));
    }

    #[test]
    fn analyzes_sequential_memoized_body_shape_with_existing_value_mutation() {
        let body = "let x;\nif ($[0] !== props.bar) {\n  x = [];\n  x.push(props.bar);\n  $[0] = props.bar;\n  $[1] = x;\n} else {\n  x = $[1];\n}\nif ($[2] !== props.cond || $[3] !== props.foo) {\n  props.cond ? ([x] = [[]], x.push(props.foo)) : null;\n  $[2] = props.cond;\n  $[3] = props.foo;\n  $[4] = x;\n} else {\n  x = $[4];\n}\nreturn x;\n";
        let shape = super::analyze_generated_body_shape(body);
        assert!(
            !matches!(shape, super::GeneratedBodyShape::Unknown),
            "expected structured shape, got {shape:?}"
        );
    }

    #[test]
    fn analyzes_memoized_cached_values_body_shape() {
        let body = "let a;\nlet b;\nif ($[0] !== props.a || $[1] !== props.b) {\n  a = compute(props.a);\n  b = compute(props.b);\n  foo(a, b);\n  $[0] = props.a;\n  $[1] = props.b;\n  $[2] = a;\n  $[3] = b;\n} else {\n  a = $[2];\n  b = $[3];\n}\n";
        let shape = super::analyze_generated_body_shape(body);
        let suffix_shape = super::analyze_generated_body_shape(
            "if ($[0] !== props.a || $[1] !== props.b) {\n  a = compute(props.a);\n  b = compute(props.b);\n  foo(a, b);\n  $[0] = props.a;\n  $[1] = props.b;\n  $[2] = a;\n  $[3] = b;\n} else {\n  a = $[2];\n  b = $[3];\n}\n",
        );

        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = shape
        else {
            panic!(
                "expected prefixed declarations shape, got {shape:?}; suffix_shape={suffix_shape:?}"
            );
        };
        assert_eq!(declarations.len(), 2);
        assert_eq!(declarations[0].pattern, "a");
        assert_eq!(declarations[1].pattern, "b");
        let super::GeneratedBodyShape::MemoizedCachedValues {
            deps,
            setup_statements,
            cached_values,
            restored_values,
        } = inner.as_ref()
        else {
            panic!("expected memoized cached values shape, got {inner:?}");
        };
        assert_eq!(
            deps,
            &vec![(0, "props.a".to_string()), (1, "props.b".to_string())]
        );
        assert_eq!(
            setup_statements,
            &vec![
                "a = compute(props.a);".to_string(),
                "b = compute(props.b);".to_string(),
                "foo(a, b);".to_string(),
            ]
        );
        assert_eq!(
            cached_values,
            &vec![
                super::GeneratedCachedValue {
                    name: "a".to_string(),
                    slot: 2,
                },
                super::GeneratedCachedValue {
                    name: "b".to_string(),
                    slot: 3,
                },
            ]
        );
        assert_eq!(cached_values, restored_values);
    }

