        let body = "let t0;\nlet t1;\nif ($[0] === Symbol.for(\"react.memo_cache_sentinel\")) {\n  t0 = () => setState(true);\n  t1 = [];\n  $[0] = t0;\n  $[1] = t1;\n} else {\n  t0 = $[0];\n  t1 = $[1];\n}\n";
