    #[test]
    fn analyzes_sequential_memoized_cached_values_then_return_body_shape() {
        let body = "let a;\nlet b;\nif ($[0] !== props.a || $[1] !== props.b) {\n  a = compute(props.a);\n  b = compute(props.b);\n  foo(a, b);\n  $[0] = props.a;\n  $[1] = props.b;\n  $[2] = a;\n  $[3] = b;\n} else {\n  a = $[2];\n  b = $[3];\n}\nlet t0;\nif ($[4] !== a || $[5] !== b) {\n  t0 = <Foo a={a} b={b} />;\n  $[4] = a;\n  $[5] = b;\n  $[6] = t0;\n} else {\n  t0 = $[6];\n}\nreturn t0;\n";
        let shape = super::analyze_generated_body_shape(body);

        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = shape
        else {
            panic!("expected prefixed declarations shape, got {shape:?}");
        };
        assert_eq!(declarations.len(), 2);
        assert_eq!(declarations[0].pattern, "a");
        assert_eq!(declarations[1].pattern, "b");
        let super::GeneratedBodyShape::Sequential { prefix, inner } = inner.as_ref() else {
            panic!("expected sequential inner shape, got {inner:?}");
        };
        assert!(matches!(
            prefix.as_ref(),
            super::GeneratedBodyShape::MemoizedCachedValues {
                deps,
                cached_values,
                ..
            } if deps == &vec![(0, "props.a".to_string()), (1, "props.b".to_string())]
                && cached_values
                    == &vec![
                        super::GeneratedCachedValue {
                            name: "a".to_string(),
                            slot: 2,
                        },
                        super::GeneratedCachedValue {
                            name: "b".to_string(),
                            slot: 3,
                        },
                    ]
        ));
        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = inner.as_ref()
        else {
            panic!("expected prefixed declarations around memoized return, got {inner:?}");
        };
        assert_eq!(declarations.len(), 1);
        assert_eq!(declarations[0].pattern, "t0");
        assert!(matches!(
            inner.as_ref(),
            super::GeneratedBodyShape::MultiDependencyMemoizedExistingReturn {
                value_name,
                deps,
                value_slot,
                memoized_expr,
                ..
            } if value_name == "t0"
                && deps == &vec![(4, "a".to_string()), (5, "b".to_string())]
                && *value_slot == 6
                && memoized_expr.as_deref() == Some("<Foo a={a} b={b} />")
        ));
    }

    #[test]
    fn analyzes_memoized_early_return_sentinel_body_shape() {
        let shape = super::analyze_generated_body_shape(
            "let s;\nlet t0;\nif ($[0] !== cond) {\n  t0 = Symbol.for(\"react.early_return_sentinel\");\n  bb0: {\n    if (cond) {\n      s = {};\n    } else {\n      t0 = null;\n      break bb0;\n    }\n    mutate(s);\n  }\n  $[0] = cond;\n  $[1] = t0;\n  $[2] = s;\n} else {\n  t0 = $[1];\n  s = $[2];\n}\nif (t0 !== Symbol.for(\"react.early_return_sentinel\")) {\n  return t0;\n}\nreturn s;\n",
        );

        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = shape
        else {
            panic!("expected prefixed declarations shape, got {shape:?}");
        };
        assert_eq!(declarations.len(), 2);
        assert_eq!(declarations[0].pattern, "s");
        assert_eq!(declarations[1].pattern, "t0");
        assert!(matches!(
            inner.as_ref(),
            super::GeneratedBodyShape::MemoizedEarlyReturnSentinel {
                deps,
                setup_statements,
                cached_values,
                restored_values,
                sentinel_name,
                final_return,
                fallback_body,
            } if deps == &vec![(0, "cond".to_string())]
                && sentinel_name == "t0"
                && final_return.as_deref() == Some("s")
                && fallback_body.is_none()
                && setup_statements == &vec![
                    "t0 = Symbol.for(\"react.early_return_sentinel\");".to_string(),
                    "bb0: {\n  if (cond) {\n    s = {};\n  } else {\n    t0 = null;\n    break bb0;\n  }\n  mutate(s);\n}".to_string(),
                ]
                && cached_values == &vec![
                    super::GeneratedCachedValue { name: "t0".to_string(), slot: 1 },
                    super::GeneratedCachedValue { name: "s".to_string(), slot: 2 },
                ]
                && restored_values == &vec![
                    super::GeneratedCachedValue { name: "t0".to_string(), slot: 1 },
                    super::GeneratedCachedValue { name: "s".to_string(), slot: 2 },
                ]
        ));
    }

