    #[test]
    fn canonicalizes_cached_prefix_with_leading_bindings_into_existing_return() {
        let shape = super::canonicalize_generated_body_shape(super::GeneratedBodyShape::Sequential {
            prefix: Box::new(super::GeneratedBodyShape::PrefixedDeclarations {
                declarations: vec![super::GeneratedDeclaration {
                    kind: ast::VariableDeclarationKind::Let,
                    pattern: "context".to_string(),
                }],
                inner: Box::new(super::GeneratedBodyShape::MemoizedCachedValues {
                    deps: vec![(0, "props.value".to_string())],
                    setup_statements: vec![
                        "const key = { a: \"key\" };".to_string(),
                        "const t0 = key.a;".to_string(),
                        "const t1 = identity([props.value]);".to_string(),
                        "let t2;".to_string(),
                        "if ($[2] !== t1) {\n  t2 = { [t0]: t1 };\n  $[2] = t1;\n  $[3] = t2;\n} else {\n  t2 = $[3];\n}".to_string(),
                        "context = t2;".to_string(),
                        "mutate(key);".to_string(),
                    ],
                    cached_values: vec![super::GeneratedCachedValue {
                        name: "context".to_string(),
                        slot: 1,
                    }],
                    restored_values: vec![super::GeneratedCachedValue {
                        name: "context".to_string(),
                        slot: 1,
                    }],
                }),
            }),
            inner: Box::new(super::GeneratedBodyShape::ReturnIdentifier(
                "context".to_string(),
            )),
        });

        let super::GeneratedBodyShape::PrefixedDeclarations {
            declarations,
            inner,
        } = shape
        else {
            panic!("expected prefixed declarations shape, got {shape:?}");
        };
        assert_eq!(
            declarations,
            vec![super::GeneratedDeclaration {
                kind: ast::VariableDeclarationKind::Let,
                pattern: "context".to_string(),
            }]
        );
        let super::GeneratedBodyShape::SingleDependencyMemoizedExistingReturn {
            value_name,
            dep_slot,
            dep_expr,
            value_slot,
            memoized_bindings,
            memoized_setup_statements,
            memoized_expr,
            ..
        } = inner.as_ref()
        else {
            panic!("expected single dependency existing return shape, got {inner:?}");
        };
        assert_eq!(value_name, "context");
        assert_eq!(*dep_slot, 0);
        assert_eq!(dep_expr, "props.value");
        assert_eq!(*value_slot, 1);
        assert_eq!(
            memoized_bindings.as_slice(),
            vec![
                super::GeneratedBinding {
                    kind: ast::VariableDeclarationKind::Const,
                    pattern: "key".to_string(),
                    expression: "({ a: \"key\" })".to_string(),
                    promote_to_function_declaration: false,
                },
                super::GeneratedBinding {
                    kind: ast::VariableDeclarationKind::Const,
                    pattern: "t0".to_string(),
                    expression: "key.a".to_string(),
                    promote_to_function_declaration: false,
                },
                super::GeneratedBinding {
                    kind: ast::VariableDeclarationKind::Const,
                    pattern: "t1".to_string(),
                    expression: "identity([props.value])".to_string(),
                    promote_to_function_declaration: false,
                },
            ]
            .as_slice()
        );
        assert_eq!(
            memoized_setup_statements.as_slice(),
            vec![
                "let t2;".to_string(),
                "if ($[2] !== t1) {\n  t2 = { [t0]: t1 };\n  $[2] = t1;\n  $[3] = t2;\n} else {\n  t2 = $[3];\n}".to_string(),
                "context = t2;".to_string(),
                "mutate(key);".to_string(),
            ]
            .as_slice()
        );
        assert!(memoized_expr.is_none());
    }

    #[test]
    fn analyzes_initialized_decl_then_if_then_expression_body_shape() {
        let shape = super::analyze_generated_body_shape(
            "const newSelected = new Set(selected);\nif (newSelected.has(value)) {\n  newSelected.delete(value);\n} else {\n  newSelected.add(value);\n}\nsetSelected(newSelected);\n",
        );

        let super::GeneratedBodyShape::PrefixedBindings { bindings, inner } = shape else {
            panic!("expected prefixed bindings shape, got {shape:?}");
        };
        assert_eq!(
            bindings.as_slice(),
            vec![super::GeneratedBinding {
                kind: ast::VariableDeclarationKind::Const,
                pattern: "newSelected".to_string(),
                expression: "new Set(selected)".to_string(),
                promote_to_function_declaration: false,
            }]
            .as_slice()
        );
        let super::GeneratedBodyShape::Sequential { prefix, inner } = inner.as_ref() else {
            panic!("expected sequential inner shape, got {inner:?}");
        };
        assert_eq!(
            prefix.as_ref(),
            &super::GeneratedBodyShape::ConditionalBranches {
                test: "newSelected.has(value)".to_string(),
                consequent: Box::new(super::GeneratedBodyShape::ExpressionStatements(vec![
                    "newSelected.delete(value)".to_string(),
                ])),
                alternate: Box::new(super::GeneratedBodyShape::ExpressionStatements(vec![
                    "newSelected.add(value)".to_string(),
                ])),
            }
        );
        assert_eq!(
            inner.as_ref(),
            &super::GeneratedBodyShape::ExpressionStatements(vec![
                "setSelected(newSelected)".to_string(),
            ])
        );
    }

    #[test]
    fn analyzes_callback_memo_ladder_body_shape() {
        let shape = super::analyze_generated_body_shape(
            "const { arr1, arr2 } = t0;\nlet t1;\nif ($[0] !== arr1[0]) {\n  t1 = (e) => arr1[0].value + e.value;\n  $[0] = arr1[0];\n  $[1] = t1;\n} else {\n  t1 = $[1];\n}\nconst cb1 = t1;\nlet t2;\nif ($[2] !== arr1 || $[3] !== cb1) {\n  t2 = () => arr1.map(cb1);\n  $[2] = arr1;\n  $[3] = cb1;\n  $[4] = t2;\n} else {\n  t2 = $[4];\n}\nconst getArrMap1 = t2;\nlet t3;\nif ($[5] !== arr2) {\n  t3 = (e_0) => arr2[0].value + e_0.value;\n  $[5] = arr2;\n  $[6] = t3;\n} else {\n  t3 = $[6];\n}\nconst cb2 = t3;\nlet t4;\nif ($[7] !== arr1 || $[8] !== cb2) {\n  t4 = () => arr1.map(cb2);\n  $[7] = arr1;\n  $[8] = cb2;\n  $[9] = t4;\n} else {\n  t4 = $[9];\n}\nconst getArrMap2 = t4;\nlet t5;\nif ($[10] !== getArrMap1 || $[11] !== getArrMap2) {\n  t5 = <Stringify getArrMap1={getArrMap1} getArrMap2={getArrMap2} shouldInvokeFns={true} />;\n  $[10] = getArrMap1;\n  $[11] = getArrMap2;\n  $[12] = t5;\n} else {\n  t5 = $[12];\n}\nreturn t5;\n",
        );

        let super::GeneratedBodyShape::PrefixedBindings { bindings, inner } = shape else {
            panic!("expected prefixed bindings shape, got {shape:?}");
        };
        assert_eq!(bindings.len(), 1);
        assert_eq!(bindings[0].pattern, "{ arr1, arr2 }");
        assert!(
            !matches!(inner.as_ref(), super::GeneratedBodyShape::Unknown),
            "expected structured inner shape, got {inner:?}"
        );
    }

